-- Poems batch 78
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('29038fa0-6342-43ba-a937-a7eeca7c9d2a','邵公濟求泰定山房十詩 采薇洞','蘇籀','宋','宋诗','song-poetry','','[]','以心爲形役，徇人失天真。',24,'全唐诗/poet.song.100000.json','["以心爲形役，徇人失天真。", "蕨薇與杞荑，求仁始得仁。"]'),
('82bcf452-9e5a-496c-9772-e07a51a8ec80','邵公濟求泰定山房十詩 盡山亭','蘇籀','宋','宋诗','song-poetry','','[]','蟻封于何險，醯雞豈必嗤。',24,'全唐诗/poet.song.100000.json','["蟻封于何險，醯雞豈必嗤。", "須彌一目了，亭中大然之。"]'),
('4d95f903-2fec-426e-adb0-abad86ab49a6','邵公濟求泰定山房十詩 懷伊亭','蘇籀','宋','宋诗','song-poetry','','[]','龜雒儼如故，玉靈誠有知。',24,'全唐诗/poet.song.100000.json','["龜雒儼如故，玉靈誠有知。", "歸艫带江海，澡濯我清伊。"]'),
('2dafc57d-5bf1-4925-bb06-09b6a4091aec','邵公濟求泰定山房十詩 柳陌','蘇籀','宋','宋诗','song-poetry','','[]','輞川題作浪，武昌栽屬官。',24,'全唐诗/poet.song.101000.json','["輞川題作浪，武昌栽屬官。", "愛思如孔階，茸髯擺奇觀。"]'),
('aeb4c655-bbcf-4811-aa79-21dc5f641569','邵公濟求泰定山房十詩 桃溪','蘇籀','宋','宋诗','song-poetry','','[]','懷仙津步翳，凡聖隔兩塵。',24,'全唐诗/poet.song.101000.json','["懷仙津步翳，凡聖隔兩塵。", "長統植園果，老幼分甘珍。"]'),
('d6995922-afd7-4d2c-a079-306797781e26','邵公濟求泰定山房十詩 竹溪','蘇籀','宋','宋诗','song-poetry','','[]','側生昂九霄，蕭森谷量簵。',24,'全唐诗/poet.song.101000.json','["側生昂九霄，蕭森谷量簵。", "溪嵐翠欲滴，塵外嵇阮趣。"]'),
('17c213aa-3ce8-4aaa-8f96-a5af968ff83c','避暑山寺二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','瓜瓠成時肆割烹，芰蓮相屬足逢迎。',64,'全唐诗/poet.song.101000.json','["瓜瓠成時肆割烹，芰蓮相屬足逢迎。", "掃寬堂廡囂煩解，汲冷盆壺頮濯清。", "畏景賢愚殊苦樂，凉飚遍灑不堪名。", "倦禪謾許絺衣掛，秋朔逍遥竹几橫。"]'),
('74b0247e-80ca-46c6-93ad-7d5384e02c5a','避暑山寺二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','冷澈雞蘇水，疏凉蟬翼綃。',48,'全唐诗/poet.song.101000.json','["冷澈雞蘇水，疏凉蟬翼綃。", "山林等袢燠，江浙劇枯焦。", "蔭暍恫生聚，吁雩訴泬寥。", "乾坤棋鬬劫，終局算虧饒。"]'),
('bb04b6ef-d73f-490e-a472-d520cb2c62da','六月不雨至七月中自寬一首','蘇籀','宋','宋诗','song-poetry','','[]','宿舂僅有憂將竭，嘉穗連雲委暵暘。',64,'全唐诗/poet.song.101000.json','["宿舂僅有憂將竭，嘉穗連雲委暵暘。", "厦屋珍臺求暫寓，桃笙葵扇殆難當。", "荷烝蘭藉肴溪澗，藕脆萍馨飯莽蒼。", "龍火西頹已辰浹，何時得見雨浪浪。"]'),
('194228c1-0c16-4399-afc8-aac8e06b313e','千葉白浮蕖一首','蘇籀','宋','宋诗','song-poetry','','[]','嬌酣擬誰似，韻甚莫爲憐。',48,'全唐诗/poet.song.101000.json','["嬌酣擬誰似，韻甚莫爲憐。", "矧肯媚塵俗，誠能降佛仙。", "洗君凡眼肉，嗟汝淤泥賢。", "三六駝顔侶，盪舟從妬妍。"]'),
('ec569b5b-c0b1-4f4c-a831-4b74469f23bd','僑居一首','蘇籀','宋','宋诗','song-poetry','','[]','匆匆五十化，己往固莫及。',84,'全唐诗/poet.song.101000.json','["匆匆五十化，己往固莫及。", "祠官閴中隱，歉歲尸糝粒。", "毀方非瓦合，知白無伊鬰。", "世悅鄒駱駝，我賢揚執㦸。", "浮雲儻來寄，最貴非儒術。", "塵緣且復且，只爾殊易輯。", "古人學易年，所愛豈兒劇。"]'),
('ce1026c4-fc6e-4633-98f3-8784728e2e26','歲晏即事','蘇籀','宋','宋诗','song-poetry','','[]','磑霏白雪舂雲子，盤摘黄金割蜜房。',64,'全唐诗/poet.song.101000.json','["磑霏白雪舂雲子，盤摘黄金割蜜房。", "組織翻騰不停杼，芳甘醞釀饋先漿。", "西成僅有儲囷窄，中土纔歸置枕康。", "敕賜宗盟旌德剎，扈陽珍木蔚葱蒼。"]'),
('7fbc80d8-ad5d-4301-957a-a8ffb8f13b16','連雨作寒二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','三杯卯醞雨輕寒，鼓腹侏儒恃縣官。',64,'全唐诗/poet.song.101000.json','["三杯卯醞雨輕寒，鼓腹侏儒恃縣官。", "樵指汲肩親課督，僧籤禪榻謝雕鉆。", "龕燈危蕊挑停久，編秩雌黄點𪑮乾。", "未許漢陰修渾沌，周詩三百近研觀。"]'),
('136d949c-2952-4613-a4ac-2f9dd00dbed7','連雨作寒二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','未應牢杜敬通關，寄傲足怡元亮顔。',64,'全唐诗/poet.song.101000.json','["未應牢杜敬通關，寄傲足怡元亮顔。", "冗齪凡庸何異目，粗疏潦倒幸投閒。", "平生那識賈三倍，晚節猶窺道一斑。", "調燮裁成真大治，茂弘先進實非孱。"]'),
('7bbdb4f0-0fce-4aac-bb33-255e8b282daf','擇鄰一首','蘇籀','宋','宋诗','song-poetry','','[]','天然齪騃千金子，憬彼憸民亦有徒。',64,'全唐诗/poet.song.101000.json','["天然齪騃千金子，憬彼憸民亦有徒。", "蹴踏惟應怯龍象，灌輸何足計瓶盂。", "神錐曾見汝潁士，道韻也欣山澤癯。", "栗尾著書趨聖處，老勤端恐負師模。"]'),
('596a2869-5dcd-42ea-808f-444a6dabb57b','才難一首','蘇籀','宋','宋诗','song-poetry','','[]','建安謀首先文若，武德機神重伯襃。',64,'全唐诗/poet.song.101000.json','["建安謀首先文若，武德機神重伯襃。", "此士不妨門第美，于今景仰太山高。", "卓哉二賢强百萬，何較九牛於一毛。", "異代愛才尊尚意，紛紛萎腐見兒曹。"]'),
('05416545-e604-4f36-b458-552f96145737','何武翼挽詞','蘇籀','宋','宋诗','song-poetry','','[]','橫槊褫神佩，追隨井鉞軍。',48,'全唐诗/poet.song.101000.json','["橫槊褫神佩，追隨井鉞軍。", "周旋圉徼最，首虜驛書聞。", "斡榷承心計，汙邪續力耘。", "門廬必高大，訓子擴儒文。"]'),
('74660dac-26b1-45d5-986a-89a675b0caf9','簡常次立一首','蘇籀','宋','宋诗','song-poetry','','[]','文章塵粃懶詳論，吏術粗蕪昧舊聞。',64,'全唐诗/poet.song.101000.json','["文章塵粃懶詳論，吏術粗蕪昧舊聞。", "鈍憊康莊輸軼步，精强省寺稱公孫。", "咨吁國計神資略，嚄唶戎容壯扞藩。", "咄咄書癡公事閒，蟬鳴官柳夢餘魂。"]'),
('6ebe8d62-8c9a-4871-84ff-11834837ac7e','朱亭伯改轉見過一首','蘇籀','宋','宋诗','song-poetry','','[]','三就可憐繁馬頸，一鳴須信絕雞羣。',64,'全唐诗/poet.song.101000.json','["三就可憐繁馬頸，一鳴須信絕雞羣。", "縶維才駿殊旌別，籍甚名聲奈耳聞。", "浩渺池庭輩鴻鷺，騰軒館殿擢蘭芸。", "相容歷稔逃詩債，大白惟當浮勸君。"]'),
('88084502-d897-4f0b-b94d-5081fdac5e2e','守局一首','蘇籀','宋','宋诗','song-poetry','','[]','悠悠疏逖皮冠守，朝著於何置漫郎。',64,'全唐诗/poet.song.101000.json','["悠悠疏逖皮冠守，朝著於何置漫郎。", "不計少多鳧藻汎，豈懷吞啄鶴軒昂。", "執輿投刺初嫌鬧，視蔭言歸久蹈常。", "飲酒讀書私務爾，渙然意喻俾言忘。"]'),
('63e8afb4-12b2-4c9b-b02f-5219544a5ffa','觀闍梨庵高樹梅花盛發一首','蘇籀','宋','宋诗','song-poetry','','[]','臞儒花裓戒，疇昔井眉箴。',96,'全唐诗/poet.song.101000.json','["臞儒花裓戒，疇昔井眉箴。", "危綠擅丘壑，攢叢薌弁簪。", "殷勤蒔芳墢，浪莽縱疏森。", "迥映晴空馥，乘凌陰霰任。", "狂儔縈栩蝶，尤物富芳心。", "玉蕊真人馭，鈴齋水部吟。", "燒燈助斜月，吹角伴橫參。", "樹下幽禪觀，瓊蕤政糝襟。"]'),
('c7b8031b-e43d-4fbd-8263-1f525a01e590','退士一首','蘇籀','宋','宋诗','song-poetry','','[]','賢賢高哉古黔婁，獨辨真趣肩夷由。',168,'全唐诗/poet.song.101000.json','["賢賢高哉古黔婁，獨辨真趣肩夷由。", "市朝慕誘吁競求，求仁丘壑良遠謀。", "白雲抗志耕平疇，炎天葛製冬鹿裘。", "邂逅孤豚笑肥牛，撥剌廉魚脫金鈎。", "雄雞曳尾憚俎羞，鷦鷯一枝綽餘庥。", "楚楚奢靡翾蜉蝣，下士閹然媚俗流。", "嗟嗟此病云何瘳，淵源友尚顔軻儔。", "襏襫有暇從帣韝，形爲心役無深尤。", "貂蟬夸詫出兜鍪，駟馬高蓋憂人憂，才殫力盡長不休。", "上士凌霞宅巖幽，千鎰鶴書那轉頭。"]'),
('eb2a0f49-15a0-4008-9df6-f6b184aca64c','祝舜俞少卿示曩歲葺蒙園陪遊風什一編不度枵疏上塵二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','清沂雩舞蹈前模，風詠先生于蒍于。',64,'全唐诗/poet.song.101000.json','["清沂雩舞蹈前模，風詠先生于蒍于。", "論述殊堪露門召，鎸摩已化兔園儒。", "臺評公雅銛鋒鍔，杖齒袁遺抱筆觚。", "草木溉培裁晝暇，忘憂蘭桂富芳荂。"]'),
('c2928658-a122-4b1a-8511-8b8341bc36e8','祝舜俞少卿示曩歲葺蒙園陪遊風什一編不度枵疏上塵二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','筮仕棓生繇莫京，溫凊一畝夙經營。',64,'全唐诗/poet.song.101000.json','["筮仕棓生繇莫京，溫凊一畝夙經營。", "南陔絃誦給甘旨，北闕簪裾負屈聲。", "秦刻唐刊儲墨妙，齊衢魯廟擅文鳴。", "建安正始源流遠，詳味風規躡玉清。"]'),
('6e63e6b2-a5cf-4ffc-ba76-6843885a7b13','夏日嘆二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','羣空冀北食場稭，蹙踏崔嵬憇鶴臺。',64,'全唐诗/poet.song.101000.json','["羣空冀北食場稭，蹙踏崔嵬憇鶴臺。", "泉石係心終眇邈，炎蒸爍體縱恢胎。", "蒂懷寓眼勤呵咄，專氣怡神願力陪。", "公館亦須延異士，珍包奇醞肆筵開。"]'),
('0ca4201b-696b-44d1-9666-abb80a4e4099','夏日嘆二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','褫絺肆簟扇忘閒，轎擔肩頳走市闤。',64,'全唐诗/poet.song.101000.json','["褫絺肆簟扇忘閒，轎擔肩頳走市闤。", "湫隘蛙蜩讙嘒裏，掃除風月廣輪間。", "曷云時燠長無冷，却謂天高只好還。", "傳癖詞源粗超軼，擬如梅尉樂吳山。"]'),
('8d5fffc0-b441-4412-a833-fbe4b66ba49c','休沐日','蘇籀','宋','宋诗','song-poetry','','[]','洗硯酬緘復論文，金書瑶笈忌羶葷。',64,'全唐诗/poet.song.101000.json','["洗硯酬緘復論文，金書瑶笈忌羶葷。", "搔頭冷枕遺簪弁，澣垢凉床潔帨帉。", "煬竈篳門無量燠，夏畦褐父若爲芸。", "鴻飛遵陸摶寥廓，鳧鶩胡然顧澗芹。"]'),
('00c9550f-d27c-4a85-8bb7-d3c18abc7b8d','核實一首','蘇籀','宋','宋诗','song-poetry','','[]','窺見呂臣非奉己，可憐甘茂取宜陽。',64,'全唐诗/poet.song.101000.json','["窺見呂臣非奉己，可憐甘茂取宜陽。", "敢晞激激蘇門嘯，老去悠悠孔里狂。", "公利噫乎入私帑，濫吹竊爾耗官倉。", "座銘枕几槃盂警，九鼎何心斥被𤮊。"]'),
('1b04e4ac-6bd6-433c-bb25-47107d1b69e6','遊服者二絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','墨綠螺青金翠耀，鬻謳沽笑泥娛遨。',32,'全唐诗/poet.song.101000.json','["墨綠螺青金翠耀，鬻謳沽笑泥娛遨。", "茲辰儻卜吾髯夜，陶寫醉醒雙鳳嘈。"]'),
('f63de00f-a83e-4885-9021-eebdebc41111','遊服者二絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','畸情灰灺妙齡懷，佳月澄虛適與偕。',32,'全唐诗/poet.song.101000.json','["畸情灰灺妙齡懷，佳月澄虛適與偕。", "隱几噓天嗒然趣，參同九鎖啟仙階。"]'),
('ed6cb40a-04e8-4223-a72c-af49309f3b76','園人餉果','蘇籀','宋','宋诗','song-poetry','','[]','紫絳李楊盧杏黄，紅腮脆碧磊篝箱。',64,'全唐诗/poet.song.101000.json','["紫絳李楊盧杏黄，紅腮脆碧磊篝箱。", "春風媚世葩華過，夏日薦茶冰蜜嘗。", "瓜步它時邵平意，木奴晚節李衡穰。", "君看飣坐百端輯，腐蠹蕭然自弭忘。"]'),
('309f940b-bf0b-442c-9b57-5f5c01ac3b69','送程孚叟知歸州  其一','蘇籀','宋','宋诗','song-poetry','','[]','岷江浮萬里，吳嶠駐彌年。',48,'全唐诗/poet.song.101000.json','["岷江浮萬里，吳嶠駐彌年。", "笑理歸艎去，牢愁失眼前。", "德門桑梓盛，佳郡鶺鴒聯。", "委寄參羊陸，宜知備敵先。"]'),
('2143387a-bbee-4204-a361-9f679e466dbf','送程孚叟知歸州  其二','蘇籀','宋','宋诗','song-poetry','','[]','東都人陸海，遊集若爲忘。',48,'全唐诗/poet.song.101000.json','["東都人陸海，遊集若爲忘。", "筮史同微貨，僧坊共小凉。", "卜鄰栖輦轂，返旆促囊裝。", "巽坎知人意，奔騰達侍旁。"]'),
('c0cff80f-2f3c-4a4e-996e-7565d14daf73','山齋閒詠','蘇籀','宋','宋诗','song-poetry','','[]','仲氏新裁汝南諾，元昆聊艤具區舸。',64,'全唐诗/poet.song.101000.json','["仲氏新裁汝南諾，元昆聊艤具區舸。", "一竿暇豫臨流賦，五詠荒唐處士歌。", "道號散人宜拜表，朝班都士好鳴珂。", "染髭膏面誠牽勉，老矣迂疏可若何。"]'),
('7d2ea5fd-ecf6-4b53-9c1f-e3e666147ca0','徽宗皇帝挽詞二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','朔駕虞巡陟，南沿禹會幽。',48,'全唐诗/poet.song.101000.json','["朔駕虞巡陟，南沿禹會幽。", "詒謀開上聖，多事酌鴻猷。", "道妙仙心廓，文昭帝作優。", "秋風舊汾水，海岱忽藏舟。"]'),
('5bb5b9ae-125e-4caf-98f4-9d0dbaaa55ff','徽宗皇帝挽詞二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','大器提擎力，懷生渥澤滂。',48,'全唐诗/poet.song.101000.json','["大器提擎力，懷生渥澤滂。", "本枝繁盛衍，禮樂懋容光。", "脫屣吁勤倦，置郵辭慨慷。", "申胥不爲己，定勝泣穹蒼。"]'),
('4c46b5c3-740c-46c9-b465-de2fd1e4ca63','林少伊直院母夫人柳氏挽詞  其一','蘇籀','宋','宋诗','song-poetry','','[]','英英批鳳傑，遺懿誦高堂。',48,'全唐诗/poet.song.101000.json','["英英批鳳傑，遺懿誦高堂。", "淑質宗姻慕，慈憐壽凱康。", "委蛇瞷夫子，勤苦養尊章。", "駒隙八旬促，蘭陔愴隕霜。"]'),
('cce730bc-dd65-42b0-9d86-a11b89b5dd57','林少伊直院母夫人柳氏挽詞  其二','蘇籀','宋','宋诗','song-poetry','','[]','遐年畀東榻，流慶羨停儲。',48,'全唐诗/poet.song.101000.json','["遐年畀東榻，流慶羨停儲。", "弔者九皋唳，幽夫百歲居。", "魚軒川上逝，石窌墓前書。", "絕妙斯銘勒，寧惟崔蔡如。"]'),
('9b811dc9-3b33-4dac-88b5-4a0a8dbcc2ca','聞鄰娃酣謳一絕','蘇籀','宋','宋诗','song-poetry','','[]','冶蕩淹嫺誰爾令，五陵妍騃可憐生。',32,'全唐诗/poet.song.101000.json','["冶蕩淹嫺誰爾令，五陵妍騃可憐生。", "蘭堂委巷喉呀囀，信有秦聲非越聲。"]'),
('53e2a647-ef64-4178-9d8b-6e7aa00aa31a','秋興一首','蘇籀','宋','宋诗','song-poetry','','[]','進賢譁玉青雲侶，十二陽秋閟城府。',192,'全唐诗/poet.song.101000.json','["進賢譁玉青雲侶，十二陽秋閟城府。", "飛鳴衆裏何少多，根墢道旁誠李苦。", "肅然注仰耋浮圖，珍重誰家木居士。", "袖章陳列有倫敘，終更右移聊改步。", "貝多小品老耽伽，高屋帽檐持論古。", "丹青簡素寫真行，茗醞鮝腒頻草具。", "俸清不足賑貧交，雨潦涉旬魚躍釜。", "時書檄尾文昌臺，月曳敝裾槐棘府。", "昔賢浩歌金馬門，或亦簞瓢松菊主。", "空空自笑兩端竭，志願不應惟阿堵。", "初平兄弟羝眠所，山下逍遥返民畝。", "大道安知利與榮，唐彬何人高此舉。"]'),
('ca962926-ce6a-43aa-a010-38bc75766f70','賦叢蘭一首','蘇籀','宋','宋诗','song-poetry','','[]','楚郢都梁奇韻佚，嵐溪雲壑初何僻。',224,'全唐诗/poet.song.101000.json','["楚郢都梁奇韻佚，嵐溪雲壑初何僻。", "根蒂條荂玩九春，葩葉尖萌碧逾尺。", "蕙轉東君溢寵光，露浥清華煙染色。", "蓊勃天芬透綺疏，英蕤綠艷撩詩客。", "滋榮九畹不因人，無際幽深來響屐。", "三嗅書帷嘗涉獵，滿把騷人安忍釋。", "映俎垂筵紉委佩，斸苔徙檻芳盈室。", "燥虛黏膩俗塵清，祛病析酲驅抑鬰。", "猗猗不採亦奚傷，雍容屈宋無倫匹。", "賞慨年芳次第菲，輕重憎憐從結習。", "辛夷爲塢薜蘿門，莎菼蒲蘆類非一。", "庭中絕出忘憂右，差等水仙誠莫逆。", "遥知最妙嶺頭梅，適口和羹似難及。", "更與丘明評國薌，后皇媚之殊赫奕。"]'),
('84c73123-d43f-4efb-9e30-ae86cf03c56b','次韻陪諸公湖上春遊','蘇籀','宋','宋诗','song-poetry','','[]','渠儂青門道，冶服遨蕩儔。',168,'全唐诗/poet.song.101000.json','["渠儂青門道，冶服遨蕩儔。", "一釂逞雞鞠，聯袂歌願酬。", "太伯表東吳，季子居延州。", "湖山號佳觀，籃輿肆優遊。", "肴香炙亦熟，只有空樽憂。", "娛賓不計費，拘士捐牙籌。", "詩盟得首唱，有客如此不。", "挈壺并琴奕，松石巖湍樂。", "境勝屬幽人，谿雲俗氛却。", "洞穴鎖蒼霞，探奇或云莫。", "不聞古肥遁，靜極還思家。", "高情縻圭俎，心迹何由遐。", "畸人告予言，黄庭老生涯。", "臧穀兩亡羊，初平隱金華。"]'),
('b05a06d2-cfa4-4be7-b65a-3d6a1b2c0d52','次韻孫邦求少監遊劉園一首','蘇籀','宋','宋诗','song-poetry','','[]','權使將軍勢不行，連雲鴛甃鳥烏晴。',64,'全唐诗/poet.song.101000.json','["權使將軍勢不行，連雲鴛甃鳥烏晴。", "池臺溢郭鏁扃固，林樾半空甍栱頳。", "席帽揚鞭來看鶴，綺疏褰幌政聞鶯。", "賀蘭青海勛名事，雅意未諧幽與并。"]'),
('d9dbd10d-f3eb-45c3-906a-662e9d998242','勾龍君貺求所居垂蔭亭岷堂二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','葱蔚敬亭非索漠，幾希陶宅遶扶疏。',64,'全唐诗/poet.song.101000.json','["葱蔚敬亭非索漠，幾希陶宅遶扶疏。", "江山壯觀惟人助，祖禰高情陟彼砠。", "雄筆仙才鎸勒見，屬車塵界默存書。", "柴荆雖掩漁竿掛，旌㦸嵯峩表舊廬。"]'),
('4498396b-11cc-442d-8a7a-aac8f3ee5295','勾龍君貺求所居垂蔭亭岷堂二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','岷陽英傑古賢鄉，侍史香爐今望郎。',64,'全唐诗/poet.song.101000.json','["岷陽英傑古賢鄉，侍史香爐今望郎。", "柬擢欲書丹鳳詔，夢魂勤到碧雞坊。", "已應盛美摽其茇，不比畸人愚厥堂。", "宦牒隨江歸碧海，讀書源派亦誠長。"]'),
('e3b9383f-0de8-48c9-beea-41a92c951302','眉州禪僧一首','蘇籀','宋','宋诗','song-poetry','','[]','吳蜀跨萬里，余老師非壯。',192,'全唐诗/poet.song.101000.json','["吳蜀跨萬里，余老師非壯。", "勉哉令修行，手書勞四枉。", "性命吾基本，權譎初不尚。", "蕭條寂寞中，咄咄祛礙障。", "面目認誰歟，湛研澈盡量。", "云爲遠玄旨，比喻非實相。", "愛河澄不波，苦海永無浪。", "封執即黏綴，淪落嗟滉漾。", "法流於河接，焦涸吁斷港。", "情塵欲忘世，疑網愆吾黨。", "凡心非道體，志帥凝不喪。", "瞿曇與老君，一訣歸至當。", "邈乎盧老前，古初更遐想。", "燒香傃霄極，癡絕堅願望。", "杳眇蓮社遠，早接淵明放。", "保真未易了，伽語庶倚仗。"]'),
('12fb6e12-3fd2-4ab9-97d9-570a8818d071','刺少年行','蘇籀','宋','宋诗','song-poetry','','[]','重仍印組矜蟬聯，豐屋藻井松桷梴。',160,'全唐诗/poet.song.101000.json','["重仍印組矜蟬聯，豐屋藻井松桷梴。", "金鈿翠屏珠串箔，椽燭高檠玳瑁筵。", "熾紅麒麟沈水爐，鳳紋錦褥須彌氈。", "瑣窗犀案衒珍具，瑶瑛紅珀瑩杯棬。", "兒擲梟盧喝大采，婢名素玉花月煙。", "驕世華腴詫豪舉，兩得仁富宜兼全。", "朔雲顔巷積深雪，斫桂燒金凍折弦。", "毛錐不摇汗馬却，刻槌膚髓稱才賢。", "法家拂士屹山峙，俜然窮儒衢道邊。", "遥知莫不任運力，鏃筈仰笑衝九天。"]'),
('c2eeccf9-4ca2-4b60-9b8d-d05307b57eae','永嘉周道人求詩一首','蘇籀','宋','宋诗','song-poetry','','[]','氣昇期汗漫，世法一黔婁。',48,'全唐诗/poet.song.101000.json','["氣昇期汗漫，世法一黔婁。", "啟鑰因師旨，咀芝從祖求。", "肆言諧律呂，不夢本精修。", "王室金堂邇，飄飄竹杖遊。"]'),
('0086c002-148b-4948-8d78-3576e463ccbb','調王季恭省幹','蘇籀','宋','宋诗','song-poetry','','[]','治幹怪君呼滑八，話言明府取王丞。',64,'全唐诗/poet.song.101000.json','["治幹怪君呼滑八，話言明府取王丞。", "九皋未省山雌雉，三窟不逃秋角鷹。", "僮鬻斛珠如許價，官居鼎鉞最難勝。", "孰令手版投耕耒，苦慕如湯厭若冰。"]'),
('a4f70c15-0964-4f07-8e73-1e0c6967295d','示施又新同舍','蘇籀','宋','宋诗','song-poetry','','[]','華髮些些似不公，辰申齪齪有何庸。',64,'全唐诗/poet.song.101000.json','["華髮些些似不公，辰申齪齪有何庸。", "力拋羈紲片時適，談謔槃筵一笑烘。", "山剎汲壺茶可點，匠人礲斲事方叢。", "麥秋梅潤霖淫劇，旅汎殊諳干越風。"]'),
('18cb5704-d5e9-4c16-9723-88d791ab5138','節婦吟','蘇籀','宋','宋诗','song-poetry','','[]','君不見迥妙殊憐世絕塵，脫足褰帷韞玉人。',163,'全唐诗/poet.song.101000.json','["君不見迥妙殊憐世絕塵，脫足褰帷韞玉人。", "藕絲帖體沈香熨，清瘦纖柔傷九春。", "勒芳戢翠妍無偶，嘖嘖拳拳徐叩叩。", "潔餒何嘗羨汙飫，令淑專貞絕難有。", "綠樽翠杓稽留舉，林下閒情風韻度。", "單羈拋擲幾星霜，瑣卑脅脅蓬茨伍。", "里鄰斆嚬詫又誇，傖翁詎堪眉斧加。", "想當然爾霸勾踐，豈竢再顧傾夫差。", "雲霞攏抹振瓊璫，蒨穠蕙轉婉清揚。", "此翁南郭坐忘趣，道眼不玷慵來粧。"]'),
('f8934371-a73c-4433-9463-400a1453680f','解罷京局一首','蘇籀','宋','宋诗','song-poetry','','[]','運水擔柴力分遭，挾持泥古小儒勞。',64,'全唐诗/poet.song.101000.json','["運水擔柴力分遭，挾持泥古小儒勞。", "浙潮屹起岷峨上，越巘遮蟠江海滔。", "一葉鷗湍尋婺女，半生瓢泛信魚舠。", "曩時瓜步從容侶，好糝藜羹待共轑。"]'),
('a3ae00f4-573f-4324-8511-bb161c7a84ed','甲子歲七夕與伯業伯衍遊龍井聰老出示次韻邊校理詩卷奉同雅趣一首借用嚬字','蘇籀','宋','宋诗','song-poetry','','[]','道隱祖風邈，訥齋重葺新。',144,'全唐诗/poet.song.101000.json','["道隱祖風邈，訥齋重葺新。", "猊巘下獸魅，神泓躍鰭鱗。", "緇郎踵教律，梵夾畫金銀。", "幾岸風篁幘，屢鈎崖峭紳。", "頌詩傳正眼，擊節富其人。", "漢沔曾淪碣，長康工寫神。", "思茇在封植，春蘿容抗塵。", "韡萼秀多襈，茶瓜經幾巡。", "休休墨儒行，汲汲宰官身。", "欠伸白氎褥，翻倒明璣囷。", "䔲褐嵐煙染，心脾草樹親。", "憐君深鍛煉，公鑒襃老嚬。"]'),
('66771315-aadb-42e6-ad0a-cceec0381713','秋夜雨凉一首','蘇籀','宋','宋诗','song-poetry','','[]','寸念微情浩莫緘，此生殊闕住山庵。',64,'全唐诗/poet.song.101000.json','["寸念微情浩莫緘，此生殊闕住山庵。", "老懷釣港伴侯喜，道契濤江見陸參。", "調氣從前深造孟，名官早欲問於郯。", "家書時燠何曾讀，整頓塵編拂白蟫。"]'),
('3aa9ac82-b1fc-4917-8749-193926d9265a','次韻趙德載大監餞行之什','蘇籀','宋','宋诗','song-poetry','','[]','君不見畢毛召芮强周宗，亮天不朽言行功。',195,'全唐诗/poet.song.101000.json','["君不見畢毛召芮强周宗，亮天不朽言行功。", "間平歆向漢人望，道宗孝恭唐治戎。", "一時入相九才傑，白賀胸中五色茸。", "聖朝舉親加柬擢，封植教誘從元豐。", "蕪皋卑飛華岳隼，鼓車暫屈翔麟驄。", "召還喻蜀監王國，三雍入對文清雄。", "昨者臨分勤造請，是時暑退火星中。", "公瑾之交似醇酎，吉甫之頌如清風。", "博山麝炷玉鎮席，翠璧雪乳金塗龍。", "小人自分悠悠者，裨諶謀野淵明窮。", "急觴高詠鼓英氣，颯然危冠髮上衝。", "端敏高明必貴達，果信頑鄙根中庸。"]'),
('72d3b7d9-7081-48bb-8f66-ad381a2e8503','送陳夢得省闈一首','蘇籀','宋','宋诗','song-poetry','','[]','棘闈春曉鏁南宮，文柄伊人掌握雄。',64,'全唐诗/poet.song.101000.json','["棘闈春曉鏁南宮，文柄伊人掌握雄。", "巧射穿楊驚破的，克家長箭挾良弓。", "懷經負笈雲霞集，出手成盧月桂藂。", "玉殿賜袍黄紙詔，布衣馳騖黑頭公。"]'),
('b35ce8b5-6f68-4e4f-8147-e65d0b5c2817','疏懶一首','蘇籀','宋','宋诗','song-poetry','','[]','省寺周行占姓名，老耽攝養道幾成。',64,'全唐诗/poet.song.101000.json','["省寺周行占姓名，老耽攝養道幾成。", "生緣瑣屑同甕算，居處閒靜惟瓶笙。", "求己洗心祛習氣，知非窮理勇移更。", "鴻生彥士乖遊好，道秩禪流諧此情。"]'),
('e195b364-3cfe-4de6-9d63-1564fea19efb','題善草字者一絕','蘇籀','宋','宋诗','song-poetry','','[]','獐獵包羞爵秩加，輿人捧腹只呀呀。',32,'全唐诗/poet.song.101000.json','["獐獵包羞爵秩加，輿人捧腹只呀呀。", "踏摇妍狀當壚手，如許銀鈎殆可嘉。"]'),
('cee94de6-9ad7-476d-a321-ee315aefeccc','元夕','蘇籀','宋','宋诗','song-poetry','','[]','瑠璃萬寶通明殿，珠翠千層罨畫樓。',64,'全唐诗/poet.song.101000.json','["瑠璃萬寶通明殿，珠翠千層罨畫樓。", "匝地薰天月燈影，撼山填郭蟻蜂稠。", "浚都平昔金鼇峙，雍幕尋常錦幰遊。", "今歲山城索朋侶，屠門酒醞夥酣謳。"]'),
('a66b3f32-efc3-4a46-967f-e4e23d96dfe1','春日郊外','蘇籀','宋','宋诗','song-poetry','','[]','蔥路桃溪浩莽春，彤甍栱桷曜芳晨。',64,'全唐诗/poet.song.101000.json','["蔥路桃溪浩莽春，彤甍栱桷曜芳晨。", "衣如方士客閒劇，園號儀同勢絕倫。", "梓幄桂旂端解賦，橘藩篠塢孰爲鄰。", "畦畦薑芋葵荽蓼，物物蕃滋輔主人。"]'),
('11710d4d-7432-4a00-b43a-c4acb452a677','飲東窗一首','蘇籀','宋','宋诗','song-poetry','','[]','丈夫藴挾胸懷奇，浩然幅鬰干虹蜺。',192,'全唐诗/poet.song.101000.json','["丈夫藴挾胸懷奇，浩然幅鬰干虹蜺。", "俚儒婉孌習和雅，竊笑胡爲瓶井湄。", "奈何平世事蹇蹇，奇士矯犖矜云爲。", "伏波不屑兒女暱，馬革自詭排羌夷。", "叔子逢時經廟略，入則造膝出詭辭。", "燕公異禮集賢殿，筆削金泥玉檢儀。", "賈生前席覲宣室，立談痛哭纔幾時。", "敬通杜門老著述，言溢千紙罔設施。", "骯髒黄冠遁丘壑，一旦端委偕龍夔。", "愚生尚友千載後，讀書探道無津涯。", "猖狂置章留黼座，腐塵潦倒曾何裨。", "世承朝恩萬鈞重，省思此去酬毫釐。"]'),
('b1d89934-3e5f-4b62-9da8-30f95439af9e','送蘇念八郎下第西歸梁益','蘇籀','宋','宋诗','song-poetry','','[]','金昌亭下泊舟艫，木馬關西趙郡蘇。',64,'全唐诗/poet.song.101000.json','["金昌亭下泊舟艫，木馬關西趙郡蘇。", "建鄴魚飧武昌水，延陵皋壤霸王都。", "吾髯軒軼登樓賦，汝器切磨清廟瑚。", "刷羽三餘鴻鵠舉，亨衢甲乙看先驅。"]'),
('5d861b4f-54b5-4a88-a177-304213c8a4d6','纖阿一絕','蘇籀','宋','宋诗','song-poetry','','[]','不瑕彭澤願言中，都冶姿年慧則通。',32,'全唐诗/poet.song.101000.json','["不瑕彭澤願言中，都冶姿年慧則通。", "揭調郡齋賓孺子，孅阿蒨粲駐芳蹤。"]'),
('f32155f2-ef59-4cea-897a-bd3dd69705ea','次韻李次仲赴巨山張舍人招贈之什','蘇籀','宋','宋诗','song-poetry','','[]','君無吟秋草，螢飛而露濕。',216,'全唐诗/poet.song.101000.json','["君無吟秋草，螢飛而露濕。", "曼倩古豪英，羨門深抆拭。", "五難背生路，九鑰探金碧。", "烏龍因師指，龜峯森郡㦸。", "張羅候鳧影，過客紛如織。", "子房河上翁，揮犀高讌席。", "噓呵棗如瓜，肉眼殊未識。", "西母掬露醒，東王漿霞赤。", "至哉高尚公，著書不靳惜。", "髻珠曩許學，玉版援金筆。", "仙階三洗髓，短生幾兩屐。", "岧嶤法身像，褒博烏紗幘。", "焚沃覬有遭，稽首悲涕泣。", "妙訣付神水，悃誠如皎日。", "升降摩頂踵，抽添而損益。", "勞生息奔迫，頹齡飛鳥急。", "希求九陽聚，何憚一千夕。", "近期赤水中，先覩玄珠得。"]'),
('96d31247-8c86-42e6-9a10-edeee68f71ad','冬日即事一首','蘇籀','宋','宋诗','song-poetry','','[]','蠟梔五萬酬鞭直，洴絖百金真食封。',64,'全唐诗/poet.song.101000.json','["蠟梔五萬酬鞭直，洴絖百金真食封。", "蕭散不萌爭鬧趣，真醇繆覬養生慵。", "滌清研裏憨凡筆，磨澈鑑中嚬窘容。", "晹旱玄冥僭春令，狐裘羔酒貯嚴冬。"]'),
('8e3623ec-07a6-4865-bfe3-c03c893fecb7','送孫丞法先池陽二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','樗枌里中契，年輩愧君先。',48,'全唐诗/poet.song.101000.json','["樗枌里中契，年輩愧君先。", "德邁華腴裔，才優砉剨然。", "牛刀恢勿擾，馬首峻高遷。", "交薦諸侯鶚，藍田崔未賢。"]'),
('93e8af96-626b-4ff4-9461-cd8d1a6462ec','送孫丞法先池陽二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','一薰襟趣暱，摻執便它邦。',48,'全唐诗/poet.song.101000.json','["一薰襟趣暱，摻執便它邦。", "書劍摇煙艇，鴻光醉綺窗。", "縣僚迎節蓋，齊醞綴羊腔。", "器宇青雲士，能名賦練江。"]'),
('cfdd927f-456b-41c5-89c0-51fb94bf68c6','李隱卿名谷與青城劉翁同舟至蘭溪卿大夫修生者館之道侶贈李詩云李郎涉世似虛舟片帆來渡楚江秋之句又毗陵家弟季文和此篇云夢蝶豈知真是蝶騎牛何必更尋牛老夫亦慕道者次韻和之記劉李事迹劉本書生工詩奇異飄然塵外也','蘇籀','宋','宋诗','song-poetry','','[]','白公枉識郭虛舟，劉李飛符袒劍裘。',64,'全唐诗/poet.song.101000.json','["白公枉識郭虛舟，劉李飛符袒劍裘。", "興軼壺中身混世，氣酣酒裏意橫秋。", "運調朱鳳啄白石，耕蒔金錢掣牯牛。", "赤子返真標指妙，阿伽陀藥肯言不。"]'),
('a70f0cb2-a87d-4846-a084-7e7d408a0071','韓省幹子平薦章應格朋友漠然未知忽改京秩作七言近體一首賀之','蘇籀','宋','宋诗','song-poetry','','[]','山雌澤啄競騰軒，孰有昂駒局短轅。',64,'全唐诗/poet.song.101000.json','["山雌澤啄競騰軒，孰有昂駒局短轅。", "造物至公殊弗置，窮交未喻枉焦煎。", "鳳批一諾膺天陟，馬頸三槃朝日邊。", "虎鼠獰尪隨秉筆，銓曹常格勿從旃。"]'),
('160dd50c-9f38-4591-a4d2-23c07e63c016','綿扇偶吟一首','蘇籀','宋','宋诗','song-poetry','','[]','拏雲擘繭寫蘭亭，洴絖娃宮箑柄成。',64,'全唐诗/poet.song.101000.json','["拏雲擘繭寫蘭亭，洴絖娃宮箑柄成。", "皎潔中規捐月斧，清雄消暍並桃笙。", "玉毫躔內乘鸞女，冰鑑光中墨客卿。", "愛惜御冬充便面，辟寒撫勉燠屯營。"]'),
('fdf5891f-a3ce-4de4-b0af-75b8ea0cfe32','卜居遣興一首','蘇籀','宋','宋诗','song-poetry','','[]','老懶清吟口角鈐，任真虛一性安恬。',128,'全唐诗/poet.song.101000.json','["老懶清吟口角鈐，任真虛一性安恬。", "士農軌範一身任，孔老窮探兩者兼。", "齋舍晦晨雞弗已，翱翔晚節蔗彌甜。", "平生緣業今何憾，佇返神魂倍蓰添。", "若箇生涯論屋穀，課催童子具醪鹽。", "俊遊稍謝出囊穎，道念常嗤隔日痁。", "擬古紕疏何柳骨，攝生精密必張髯。", "鶴軒發興從譏晏，雁塔乘時定合尖。"]'),
('ad762403-8bba-435e-9f91-a1466d864a15','卜居漫賦','蘇籀','宋','宋诗','song-poetry','','[]','肄習素未豐，摸索强剸裁。',120,'全唐诗/poet.song.101000.json','["肄習素未豐，摸索强剸裁。", "銖黍概聞見，諄吃奚述哉。", "三捷黜疏慵，湛潛散郎偕。", "望道幾何高，人事寧免乖。", "眼中悠悠者，樵牧供談諧。", "披卷想前芬，骯髒無敵才。", "功名不復朽，榮觀竟煙埃。", "幽幽畸人居，黄花薦醁醅。", "所求一日富，不足語時儕。", "寄言繁華侶，莫嗤鈍如槌。"]'),
('1a80b828-8d1c-45da-9333-414e1eeadac6','參雲亭納凉小集二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','設醴茲晨遨飫時，四圍青峭互巇嶷。',64,'全唐诗/poet.song.101000.json','["設醴茲晨遨飫時，四圍青峭互巇嶷。", "橐衣隨牒何曾卜，餌藥銜杯稍信醫。", "短舞不妨擎菡萏，談諧且勿負玻瓈。", "老夫直轡循吾範，無使斯民有以窺。"]'),
('75c51b81-f448-4793-9c39-5aaf652cdb56','參雲亭納凉小集二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','踽踽迂疏彼一鰥，息交絕學殆頑顔。',64,'全唐诗/poet.song.101000.json','["踽踽迂疏彼一鰥，息交絕學殆頑顔。", "時儕儻獲多謀助，少作曾希長者刪。", "餵犬孱尪玩逋竊，轅駒牽蹤曠尤瘝。", "那無上術蠲人瘼，畫㦸臨江城負山。"]'),
('e3e85ead-6d65-448a-80c7-3d1a00922f5d','後數朝復依前韻二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','下國官臣無懈時，矯然白首矚嶔嶷。',64,'全唐诗/poet.song.101000.json','["下國官臣無懈時，矯然白首矚嶔嶷。", "鼠攘翦滅雷霆令，魃虐蕭騷霈澤醫。", "廉袴移文謹鈐鍵，蕭齋絲管覆玻瓈。", "燭闌松桂冥冥霧，赤豹文貍不許窺。"]'),
('11c7ccac-7178-4abe-887d-020275c8816b','後數朝復依前韻二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','恤患周流喜逮鰥，當官掣肘汗慚顔。',64,'全唐诗/poet.song.101000.json','["恤患周流喜逮鰥，當官掣肘汗慚顔。", "預虞飄兀筏能駕，取次耕犂手欲刪。", "月窟日畿遵驛置，燕南越北洗恫瘝。", "一廛清佚陶元亮，萬斛閒愁庾子山。"]'),
('e69fc69a-c12f-444d-a648-6aa7c0d4e092','仲秋較試浄惠精舍會者六人約重九事畢置醴謝湯鞏方以詩堅約次韻酬之','蘇籀','宋','宋诗','song-poetry','','[]','稷下銖銖鑒擇分，品評一目百知聞。',64,'全唐诗/poet.song.101000.json','["稷下銖銖鑒擇分，品評一目百知聞。", "初矜月殿揮毫賦，直到龍山吹帽文。", "邀勒公榮狎嵇阮，薰塗嬙媛侍淵雲。", "塵驚珠貫纖羅襪，酹酒銀篦不怕醺。"]'),
('47166a34-f362-45d1-83bc-59be3df13f68','試闈即事三絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','鼓士揚桴警五更，爨清檠冷旋吹生。',32,'全唐诗/poet.song.101000.json','["鼓士揚桴警五更，爨清檠冷旋吹生。", "深衣鄉彥都君子，摩厲三秋衒此行。"]'),
('82df5a7f-8e20-4877-8d75-d99a166a760a','試闈即事三絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','近歲顓門不讀書，右文搜拔廣該儒。',32,'全唐诗/poet.song.101000.json','["近歲顓門不讀書，右文搜拔廣該儒。", "立言不朽非吾任，貪叩玄門隱者廬。"]'),
('0b46c349-68b4-4805-b90f-993c19a014e9','試闈即事三絕  其三','蘇籀','宋','宋诗','song-poetry','','[]','一坐據梧床刃消，五星競耀燭秋宵。',32,'全唐诗/poet.song.101000.json','["一坐據梧床刃消，五星競耀燭秋宵。", "掃廳禁近延僧孺，孰謂詩書避賦繇。"]'),
('953f5df4-90f6-420d-8557-895f17e08212','事畢湯鞏方三君再用前韻復酬一首','蘇籀','宋','宋诗','song-poetry','','[]','妙啜龍團嗇少分，寶薰婆律靳多聞。',64,'全唐诗/poet.song.101000.json','["妙啜龍團嗇少分，寶薰婆律靳多聞。", "泥封謄識遵程度，棘刺圍藩按惠文。", "採菊騷人寧避雨，登樓朝彥氣摩雲。", "蘭堂錦瑟笙簧鬧，嬉笑啁謳共惜醺。"]'),
('bf564a6e-dbb2-445e-8819-0cdb283e9baf','觀胡文恭樞密全集偶成一首','蘇籀','宋','宋诗','song-poetry','','[]','鏗鈜正始音，嚴密萃英耆。',192,'全唐诗/poet.song.101000.json','["鏗鈜正始音，嚴密萃英耆。", "上仁體勛華，四方致雍熙。", "文賦鳴升平，聲譽藝林馳。", "心口爛錦繡，欬唾皆珠璣。", "韜涵白圭玷，揮灑清風詞。", "興寄擴無窮，標望擅一時。", "聖主逢嘉祐，兩府皆龍夔。", "豈應獻納際，造次差毫釐。", "百爾賢佞評，卓絕公是非。", "獨無許郭術，人實不易窺。", "東阿昭明懵，貝錦尤疏紕。", "猶子後來傑，元祐參丞疑。", "蟬聯襲簪橐，孫侄聲華飛。", "婦韓外曾裔，稚子甥曰彌。", "撫編可勝嘆，綴緝刻棠梨。", "定評楊謝公，遺芳六一碑。"]'),
('7a275080-1802-4016-b995-a83ca05b1711','送李舉之武博學宏詞','蘇籀','宋','宋诗','song-poetry','','[]','稷下機梭纂奏篇，犀通木癭炳彪然。',64,'全唐诗/poet.song.101000.json','["稷下機梭纂奏篇，犀通木癭炳彪然。", "盛朝耆望門庭懿，哲匠宗師典據全。", "掉鞅春闈賈餘勇，賞音盟主詫稱妍。", "峻登名第高酬擢，臺閣容儀繼武傳。"]'),
('250d7bbc-08bc-4f2b-b776-0f473a892bce','擬古','蘇籀','宋','宋诗','song-poetry','','[]','六州齋榻釂分鵝，誰料延平最解歌。',64,'全唐诗/poet.song.101000.json','["六州齋榻釂分鵝，誰料延平最解歌。", "蒲阪崔姝白樓少，闔閭吳館冶容多。", "頻煩畫㦸凝薌寢，輟選鸞篦插皂羅。", "勿俾台山洞天侶，眇無劉阮醉顔酡。"]'),
('8aa1d3ba-ba79-4efc-a654-75398e0fd823','陪侍知府待制丈巾山高設竊聞是日賡和去春林倅紅樓風什奉繼一首','蘇籀','宋','宋诗','song-poetry','','[]','磴蘚梯飚最上頭，挈排犧象主觥籌。',64,'全唐诗/poet.song.101000.json','["磴蘚梯飚最上頭，挈排犧象主觥籌。", "從容北海能延客，酣適東風詠倚樓。", "獻歲順成當大有，名儒過計與私憂。", "仰看鳳德翔千仞，總領鴛鸞也狎鷗。"]'),
('d75b8296-4f68-41f8-baba-7b8464a614e2','蒙和府待制寵和前韻又承東湖水嬉之招一首','蘇籀','宋','宋诗','song-poetry','','[]','一聲巧囀柳巔頭，半丈紅芳送曉籌。',64,'全唐诗/poet.song.101000.json','["一聲巧囀柳巔頭，半丈紅芳送曉籌。", "天氣柔嘉收積雨，林花稠疊竦高樓。", "七槃長袖重新製，九醞空樽詎足憂。", "丘壑夔龍位巖石，何妨紗帽對沙鷗。"]'),
('854e933c-e0d6-476c-b170-cc29db95343f','朱從事安詩挽詞一首','蘇籀','宋','宋诗','song-poetry','','[]','文階王命渥，馴侃洽鄉闤。',48,'全唐诗/poet.song.101000.json','["文階王命渥，馴侃洽鄉闤。", "末俗賈三倍，尤能賑百鍰。", "宗盟遵倚闕，邑落舊知潸。", "翳翳佳城鬰，鑱山殆弗刪。"]'),
('7db66ba2-1512-458d-8f7c-a428a1182d21','夏日池上','蘇籀','宋','宋诗','song-poetry','','[]','諦複春秋指，祛排日務嬰。',96,'全唐诗/poet.song.101000.json','["諦複春秋指，祛排日務嬰。", "嵐巒屏郡廨，枿樾蔭衙城。", "褐父評丹首，幽齋緣督經。", "忘憂葱蒨擢，伯雅燕酣酲。", "窈窕陽春唱，鮮鹹臨海鯖。", "惠文除擾害，五百慘徒黥。", "卷籍闔還展，錢刀斂尚輕。", "珠還鳳儀政，他日儻齊聲。"]'),
('aaa33c98-7107-4224-98b0-41b9193f5a3d','公退三首  其一','蘇籀','宋','宋诗','song-poetry','','[]','披文不釋遺編慕，躭祿終慚遠賄稱。',64,'全唐诗/poet.song.101000.json','["披文不釋遺編慕，躭祿終慚遠賄稱。", "劫劫抗塵非勝趣，寥寥出世有真乘。", "轉頭值寓無窮極，措足虛邪粗可勝。", "管晏空憂覺先物，未須薄薛與卑滕。"]'),
('bdea27b0-e4d2-4cec-b95a-ccc6f3a8fc1e','公退三首  其二','蘇籀','宋','宋诗','song-poetry','','[]','繆簉康莊列大夫，沈研歷久到盤盂。',64,'全唐诗/poet.song.101000.json','["繆簉康莊列大夫，沈研歷久到盤盂。", "囊餘佔畢乾螢火，家有凌雲舊履鳧。", "般若初心依耋老，參同內事靳儒臞。", "吐音愨訒嘗聞見，邂逅周旋只小巫。"]'),
('b88a0423-8cfa-4e4a-8a48-a7d30fa3acf4','公退三首  其三','蘇籀','宋','宋诗','song-poetry','','[]','缺然資略每區區，抑冒揚清小小劬。',64,'全唐诗/poet.song.101000.json','["缺然資略每區區，抑冒揚清小小劬。", "諏律綱條思濟理，算緡公帑較輸儲。", "三科識擢才能顯，八計精研吏治孚。", "端有碩生如杜蕢，升堂洗觶降除趨。"]'),
('65bd6b1d-c6ab-4a4b-aa32-07a81b02893e','暑雨憶衢州一絕','蘇籀','宋','宋诗','song-poetry','','[]','衣裳俎豆信華風，酒聖茶顛倚獨松。',32,'全唐诗/poet.song.101000.json','["衣裳俎豆信華風，酒聖茶顛倚獨松。", "夏屋渠渠聽聚雨，數尋竹外瀉琤淙。"]'),
('dff4dea9-567d-4eb7-9db7-cfa8e9b52f0d','送滁守蔡瞻明提舉','蘇籀','宋','宋诗','song-poetry','','[]','史家汗簡編年垂，掌武集賢籌政機。',240,'全唐诗/poet.song.101000.json','["史家汗簡編年垂，掌武集賢籌政機。", "君侯祖烈冠前世，內外貽厥真天資。", "景靈審象丹青炳，端靖顒昂席慶基。", "浙港之東早乘驛，卓爾羣吏諸侯師。", "云何士元淹驥足，留滯太史周南維。", "淵源濡染由所自，甚美而度多文詞。", "猗歟兩祖揭二柄，雹凸騫翔天下知。", "奈何恬無進擢慕，鈎引吹噓衆力微。", "冷煙橫雨秋濤外，滁邦山水停一麾。", "貧交摻執空里巷，截𩍐那復留驂騑。", "氣宇前修令儀範，才具時儕高品題。", "綠綺尋繹醉吟操，清流感慨神武遺。", "側聽褒嘉最郡課，水衡促召夫何疑。", "車輪繼斲心自了，桑榆稍收宜赴時。", "珍嚮高標警衰鈍，鄙哉不敢多陳詩。"]'),
('fe77c0b7-b275-4780-9a57-154f6a8b9c0a','趙和叔大夫母安人曹氏挽詞','蘇籀','宋','宋诗','song-poetry','','[]','風規王邸韻，筮醮相夫賓。',48,'全唐诗/poet.song.101000.json','["風規王邸韻，筮醮相夫賓。", "逐子大家懿，弄孫東第新。", "百能知肖嗣，八十又三春。", "磬石無虛勒，笄珈不復晨。"]'),
('32b2913d-23b3-440e-a8e5-e596bfcd389b','壬申春雪一絕','蘇籀','宋','宋诗','song-poetry','','[]','長天頓改楚雲容，初夕依微後攪空。',32,'全唐诗/poet.song.101000.json','["長天頓改楚雲容，初夕依微後攪空。", "點綴柳條紛若絮，未妨梅蕊衒芳叢。"]'),
('ba07a638-8170-49f4-8ac1-3a51996175b5','龍井僧全示寄庵樞密程公累篇季文弟新什求余繼其末一首','蘇籀','宋','宋诗','song-poetry','','[]','程蘇中興什，同庵有後前。',144,'全唐诗/poet.song.101000.json','["程蘇中興什，同庵有後前。", "前朝沙門首，辨浄超卓然。", "耆宿失聞聰，飫參餘小全。", "龍泓風篁巘，荏苒二十年。", "緇儔幾換易，巖崿豈變遷。", "亭亭百歲杉，泠泠九淵泉。", "梵音擾龍性，玄解忘魚筌。", "有客輦瑰詭，無情施繒錢。", "佛法佇隆興，般若須人傳。", "更令觀剎麗，但俾子孫賢。", "三空正覺路，一喻實相圓。", "不替人天師，重新演教禪。"]'),
('042cdf83-4f26-4e3c-b812-5233690c04f1','武林春日一絕','蘇籀','宋','宋诗','song-poetry','','["\u897f\u6e56"]','薰膏佩服尤瑰靡，聯踏春陽特衒骹。',32,'全唐诗/poet.song.101000.json','["薰膏佩服尤瑰靡，聯踏春陽特衒骹。", "十里青樓玩芳月，西湖並舫恣娛遨。"]'),
('47280edb-7df6-47fd-ba0e-7f1f6d7a26d9','勉旃一首','蘇籀','宋','宋诗','song-poetry','','[]','歸一豈應無以返，要言湛諦滓淤淘。',64,'全唐诗/poet.song.101000.json','["歸一豈應無以返，要言湛諦滓淤淘。", "大知直截揣摩漸，積執冥迷厭離勞。", "目睫古人曾致論，根塵當念勿喧囂。", "主張名教殫才智，王霸蟠煎火上膏。"]'),
('e244109f-2a01-4fe1-a15a-0095dd9f06e4','秋冷一首','蘇籀','宋','宋诗','song-poetry','','[]','嵐煙澹澹雨颼颼，殘枿折槎陂水頭。',64,'全唐诗/poet.song.101000.json','["嵐煙澹澹雨颼颼，殘枿折槎陂水頭。", "贖爾典裘扃戶牖，饒伊夾幕閟娟柔。", "䔲蓑廛肆斗牢落，濘潦窮途强釋愁。", "箬下浮君霜露旦，豈應虛詫釣詩鈎。"]'),
('47374829-3d74-4c9f-8030-a232b1feea8f','漫述二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','理窟孰宗趣，卜居忘市闤。',48,'全唐诗/poet.song.101000.json','["理窟孰宗趣，卜居忘市闤。", "紆餘力分裏，梗概智仁間。", "導引非茫眇，耕樵未擬閒。", "寅緣任俚俗，及物念痌瘝。"]'),
('9d8afc65-ede6-478b-93ac-c1a3006fd44e','漫述二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','跏趺圍褐越雞晨，灑落生緣治水薪。',64,'全唐诗/poet.song.101000.json','["跏趺圍褐越雞晨，灑落生緣治水薪。", "一藝湛酣任疏放，百家雜揉識疵醇。", "舂炊斷斷西疇穡，書記翩翩東郭㕙。", "飄兀籃輿絕畦畛，莽蒼更訪隱湛淪。"]'),
('1852c619-b843-4c23-888f-4419e23c6e3c','春設一首','蘇籀','宋','宋诗','song-poetry','','[]','折簡王春涓勝日，執輿鄰曲集僑官。',64,'全唐诗/poet.song.101000.json','["折簡王春涓勝日，執輿鄰曲集僑官。", "奕娃紅手凌寒怯，歌頸塗薌訴白寬。", "膏沐柳梅牽屐齒，冶妍桃杏壓欄干。", "珍烹鬬賽携英黠，娛老粧樓疊肉槃。"]'),
('cc8e92f4-bb2a-4631-b315-09d050be56d1','惜花一首','蘇籀','宋','宋诗','song-poetry','','[]','豁眼桃紅思聖解，襲人蘭鬰比脩能。',64,'全唐诗/poet.song.101000.json','["豁眼桃紅思聖解，襲人蘭鬰比脩能。", "面脂靡曼負塗澤，繪綵化工夸斲冰。", "蒨粲芳穠觸吟境，艷陽風色嗾狂朋。", "傾壺簫管黳蓬鬢，沈頓金觥雹凸稜。"]'),
('cd75fa08-5d33-4445-aba4-be7b8149be10','何會卿婦清河張甥挽詩','蘇籀','宋','宋诗','song-poetry','','[]','常念注西竺，浮生付六如。',48,'全唐诗/poet.song.101000.json','["常念注西竺，浮生付六如。", "良人愴中饋，二穉未勝裾。", "妯黨抆紅淚，鄉鄰隘衆車。", "金花它日誥，封號表松樗。"]'),
('5fa5c5ce-40c3-4dc3-80de-dc5b4909b93a','閒詠一首','蘇籀','宋','宋诗','song-poetry','','[]','肆筵無釦器，釘壁但鑱碑。',48,'全唐诗/poet.song.101000.json','["肆筵無釦器，釘壁但鑱碑。", "慨歎慕前躅，咨吁亦小知。", "飪諧棋酒伴，瓶遠井泉湄。", "自許羲皇上，陶然絕曠夷。"]'),
('e948663a-9891-4339-b14d-606a453ef4b3','故孺封曹氏挽章','蘇籀','宋','宋诗','song-poetry','','[]','豪宗相承籍，遺懿本馴良。',48,'全唐诗/poet.song.101000.json','["豪宗相承籍，遺懿本馴良。", "夫息遵慈芘，汙萊化阜康。", "杯棬留燕机，丹篆勒陰堂。", "愈愈垂青紫，詵詵慶祚長。"]'),
('b9414877-9002-41f5-82e6-68e47a3cf8ff','春集僧舍一首','蘇籀','宋','宋诗','song-poetry','','[]','繡川藻野衒嫣姝，練縞穠殷亭育爐。',64,'全唐诗/poet.song.101000.json','["繡川藻野衒嫣姝，練縞穠殷亭育爐。", "二月峭寒輕抑勒，崇朝和氣畢昭蘇。", "紺青六幕無纖翳，綠縟多疇幾町區。", "居士自携三昧醞，緇流叢錯設伊蒲。"]'),
('55794b12-8859-4525-98e0-dcd412c60cca','蒔蘭一首','蘇籀','宋','宋诗','song-poetry','','[]','湘纍鞙佩南邦媚，天女襟期絕世薌。',32,'全唐诗/poet.song.101000.json','["湘纍鞙佩南邦媚，天女襟期絕世薌。", "藝植便應彌九畹，孰知苓藿與詹糖。"]'),
('7adda0f9-bf34-49a4-993c-eb7e25661829','炎夏即事一首','蘇籀','宋','宋诗','song-poetry','','[]','五詠八吟鉆古奧，四豪六逸共周旋。',64,'全唐诗/poet.song.101000.json','["五詠八吟鉆古奧，四豪六逸共周旋。", "隱囊墊幘枰棋局，輕箑珍笙蔭采椽。", "習氣崢嶸談在昔，知音推激互相然。", "至哉佛老儒宗外，聖諦冰銷濁火煎。"]'),
('1aaba6f3-e4da-4291-bb3e-9e96c0be5c44','娛老一首','蘇籀','宋','宋诗','song-poetry','','[]','多聞內殖每瞻烏，枉把春秋問蟪蛄。',64,'全唐诗/poet.song.101000.json','["多聞內殖每瞻烏，枉把春秋問蟪蛄。", "俗瑣未拋聊爾爾，古心內騖亦區區。", "繫匏於越壤田薄，雙鯉銅梁僕賃痡。", "揃白追遊味殊寡，所圖榮綺訪仙臞。"]'),
('ae16b814-996f-418a-96f1-6fc0d9e5cb44','廛居一絕','蘇籀','宋','宋诗','song-poetry','','[]','天碧綃幬障鐵牛，廛居煩促遠林丘。',32,'全唐诗/poet.song.101000.json','["天碧綃幬障鐵牛，廛居煩促遠林丘。", "赫炎熾景烘煬竈，悵望金飚玉露秋。"]'),
('2d3352fb-c404-44e3-bcca-010e8035bece','重陽一首','蘇籀','宋','宋诗','song-poetry','','[]','籬根金色小正時，醅墊風高與節期。',64,'全唐诗/poet.song.101000.json','["籬根金色小正時，醅墊風高與節期。", "耿耿挑燈聞夜誦，匆匆刈穗飫晨炊。", "閨娃犀蕊香盈把，朝士茱萸酒一巵。", "蓋世豪雄健天下，感秋應待羽觴治。"]'),
('a9a2b5fa-aaf5-4876-9d40-8dc0e6a486f9','山行入寺一首','蘇籀','宋','宋诗','song-poetry','','[]','執輿入輦蹷痿幾，陟險山農笑却時。',64,'全唐诗/poet.song.101000.json','["執輿入輦蹷痿幾，陟險山農笑却時。", "屐齒未常先雍老，翬飛久已見甍楣。", "磴扉百步猶流汗，觀閣三休豈易追。", "浪漫悠悠一雞肋，角巾東路最平夷。"]'),
('bf1fc6a4-8eb1-44e7-9052-f0d611a2d6d9','近市一首','蘇籀','宋','宋诗','song-poetry','','[]','摩肩躡足吁屠販，接衽駢顱坌駔筲。',64,'全唐诗/poet.song.101000.json','["摩肩躡足吁屠販，接衽駢顱坌駔筲。", "巷隘姑名爲小隱，賓佳不必有珍肴。", "龍鍾遊宦如投耒，瑣屑僑民一繫匏。", "丘索典墳心跡遠，煙埃咫尺自喧淆。"]'),
('6521aeed-024c-4009-b932-a48092666c82','釂飲一首','蘇籀','宋','宋诗','song-poetry','','[]','珠零醇碧郁春槽，矯首梅林釂自陶。',64,'全唐诗/poet.song.101000.json','["珠零醇碧郁春槽，矯首梅林釂自陶。", "橫槊未應隨李廣，團詞亦足擬王襃。", "俯從觴詠山陰禊，遥說笙簧錦里遨。", "取次難論禦戎策，豈知蛙臛鱣鯖臊。"]'),
('3310f1f7-ac0a-4485-89fb-dc6d016f12cf','春晴一首','蘇籀','宋','宋诗','song-poetry','','[]','高槐湯餅排朝饌，嘉菊香菹芼戛羹。',64,'全唐诗/poet.song.101000.json','["高槐湯餅排朝饌，嘉菊香菹芼戛羹。", "餉早趁墟樵墾計，澆春量腹聖賢并。", "無由屠嚼相親就，豈䛏奇章侈大烹。", "飄忽紅稠鶯燕語，康衢冶服炫春晴。"]'),
('baf3c4e6-3968-44ad-ba31-abe5da306557','往日','蘇籀','宋','宋诗','song-poetry','','[]','往日承平孰爲裁，誠能俾乂固當諧。',64,'全唐诗/poet.song.101000.json','["往日承平孰爲裁，誠能俾乂固當諧。", "豈云小辯能迴斡，際遇長才力洽該。", "大塊慘舒噓翕頃，元明迷喻唯阿開。", "斗南必有圓機士，安得一樽陳此懷。"]'),
('f361015c-2f0a-4592-8442-4e7da7a439a4','稽山漫作一首','蘇籀','宋','宋诗','song-poetry','','[]','三餐佚豫年其有，一醉陶然日不貧。',64,'全唐诗/poet.song.101000.json','["三餐佚豫年其有，一醉陶然日不貧。", "發議詎堪登膴仕，費貲端爲速嘉賓。", "屢空蜀信匱囊藥，稍傚越吟追里鄰。", "劉白殊無記人句，奇章高設豈應頻。"]'),
('14d675ee-8e25-4b36-a825-6b6d50fe1ae8','誘學徒一首','蘇籀','宋','宋诗','song-poetry','','[]','瞥聞立覩且湛研，討索思臧義理穿。',64,'全唐诗/poet.song.101000.json','["瞥聞立覩且湛研，討索思臧義理穿。", "剖析賴經宗匠手，絕羣羞拍腐儒肩。", "鴟鴉嗜鼠顓門蔽，博簺忘羊失路偏。", "警策後生文憲種，若爲準擬即真賢。"]'),
('9db91c6e-2caf-4946-9748-06071b2410d4','編聯偶作','蘇籀','宋','宋诗','song-poetry','','[]','躭飫神奇致，思研理趣幽。',216,'全唐诗/poet.song.101000.json','["躭飫神奇致，思研理趣幽。", "崎嶇由考倣，勉勵似鉏耰。", "明耀鑑頻拭，醇精酒屢酘。", "編聯存隻字，解悟失全牛。", "曷可裨宏議，于何答彼諏。", "達辭宜駕說，典學善宣猷。", "渾渾窺姚姒，專專切旦丘。", "時王資粉澤，天匠不雕鎪。", "愍惻元元意，彌綸色色優。", "雅馴鎸鄙固，切實忌飄浮。", "自古英莖肆，于今都市謳。", "近誰臻壺奧，遠孰擅風流。", "壹鬰窮居氣，荒唐失友愁。", "湛酣及醲郁，浸漬復優柔。", "斐綺資咍噱，蕪枵寡晤酬。", "不爲傷手斲，無取强顔羞。", "管氏攘戎索，元龍高卧樓。", "激昂牽老憊，書劍判悠悠。"]'),
('77a42ee1-73a0-4998-bb96-611b3709a874','舊遊一絕','蘇籀','宋','宋诗','song-poetry','','[]','慨悵秦關舊儕侶，綾袍韘䪓火鐮囊。',32,'全唐诗/poet.song.101000.json','["慨悵秦關舊儕侶，綾袍韘䪓火鐮囊。", "南來放馬遵舟楫，鱸鱖西風號本鄉。"]'),
('3564ec80-50f8-470c-a9c8-7aaa503cc7b5','嵊邑周幹辦挽詩','蘇籀','宋','宋诗','song-poetry','','[]','嶷然衷塞懿，挾操亦人難。',48,'全唐诗/poet.song.101000.json','["嶷然衷塞懿，挾操亦人難。", "唱第芝庭瑞，背城逋寇殘。", "傾殫副王命，疇曩入貲官。", "遺事鄉評著，嘉言邑里寬。"]'),
('5cd33a94-631c-4270-8f4a-d18e21e01185','酴醾一絕','蘇籀','宋','宋诗','song-poetry','','[]','梅釅蘭氳芍藥清，旃檀婆律萃天馨。',32,'全唐诗/poet.song.101000.json','["梅釅蘭氳芍藥清，旃檀婆律萃天馨。", "試開秦趙當年目，何藉珠簾翡翠屏。"]'),
('0b69bac8-662e-4532-8940-e70bdc24b285','題劉紫微貢父公是集一首','蘇籀','宋','宋诗','song-poetry','','[]','惆悵欒城舊朋執，何殊闕里孔顔徒。',96,'全唐诗/poet.song.101000.json','["惆悵欒城舊朋執，何殊闕里孔顔徒。", "達生自信誠知命，晚節遭逢德不孤。", "貫悉該明漢中壘，雍容通雅蜀相如。", "老成流輩方吹薦，典訓斯文示後儒。", "疏奏襄陽正平手，表章天策伯襃俞。", "明窗棐几一呻繹，背癢政逢長爪姑。"]'),
('6846073b-776d-4575-aa90-7ee79fe09b52','仲秋苦熱半格一首','蘇籀','宋','宋诗','song-poetry','','[]','老火薪烝鼎竈然，柔金低伏聽燔煎。',144,'全唐诗/poet.song.101000.json','["老火薪烝鼎竈然，柔金低伏聽燔煎。", "虛窗疊巘攢三崿，冷枕清飚直萬錢。", "俛仰生涯恃林井，包纏冠紱哂毹氈。", "朝蠅夕蜹嗟何集，山雪河冰渴沃湔。", "子夜凉生秋思肇，午時炎熾赫羲鮮。", "蔭饒華桷單絺叟，嬉愛清川泳月船。", "巾幨垢氛勤靧濯，菓肴剖剝萃新妍。", "芸夫望望瞻雲漢，鋜鶴聲聲唳碧天。", "瀑水何山千尺瀉，洗心安得賞懸泉。"]'),
('cbeb5053-5f82-4dd1-b8fd-bdef3717e59e','晚秋一首','蘇籀','宋','宋诗','song-poetry','','[]','曩間夏歷標花候，粗爾陶巾漉酒巵。',32,'全唐诗/poet.song.101000.json','["曩間夏歷標花候，粗爾陶巾漉酒巵。", "倣擬塵編談世諦，何人才刃趁時機。"]'),
('993d09ee-f4d1-464b-8326-fefe7ce9a563','潘令度求厥弟令表挽章一首','蘇籀','宋','宋诗','song-poetry','','[]','婉孌標儀賦了聰，優爲郎位奉車童。',64,'全唐诗/poet.song.101000.json','["婉孌標儀賦了聰，優爲郎位奉車童。", "藴奇處士未王命，好事儒流昵德風。", "姻援烏衣門闥峻，款遊騎省志懷同。", "克家致孝鍾全美，鳳羽飛翔亶待封。"]'),
('f88c894f-b344-48e7-8812-f29c09f03c6f','藥褚吟一絕','蘇籀','宋','宋诗','song-poetry','','[]','玉札丹砂寶易知，蜣蜋蘇合粗擎齋。',32,'全唐诗/poet.song.101000.json','["玉札丹砂寶易知，蜣蜋蘇合粗擎齋。", "國醫本草加繁悉，異域琛來獻麝犀。"]'),
('08d5a752-7458-4f38-a64b-12c5a27dcb18','雪齋即事一首','蘇籀','宋','宋诗','song-poetry','','[]','熾炭雪窗塵簡編，慵偎毳被藉粗氈。',64,'全唐诗/poet.song.101000.json','["熾炭雪窗塵簡編，慵偎毳被藉粗氈。", "卯晨呵筆冰膠研，乙夜橫琴凍折絃。", "郁郁烹鮮具羹戛，浮浮炊餗忍饞涎。", "鬻薪清爨庖丁粗，鼎俎逾時不解羶。"]'),
('b581e596-995d-4499-87d8-d16620d4ff2b','元夕偶成','蘇籀','宋','宋诗','song-poetry','','[]','里唱塗謳鐃吹轟，軟塵梁苑記前生。',64,'全唐诗/poet.song.101000.json','["里唱塗謳鐃吹轟，軟塵梁苑記前生。", "寶珠穿蟻嬉遊肆，蓮蕊然犀不夜城。", "透碗燈繁人晝繡，隔羅光醞酒澠清。", "春娃環舞雲階隘，邦媛鮮粧月地行。"]'),
('37d69708-7198-4aaf-b29b-bda5293225e0','送芍藥者一首','蘇籀','宋','宋诗','song-poetry','','[]','披猖二十四風花，淑美豐融殿百華。',64,'全唐诗/poet.song.101000.json','["披猖二十四風花，淑美豐融殿百華。", "畀付碧莖頩粉蕊，薰裁溫馥疊鮮葩。", "無言似笑詩魔惱，比韻侔嬌女艷加。", "壯歲逐春心欲謝，酥煎靡麗遠泥沙。"]'),
('db322d2b-91e1-4695-a200-1e97003f1516','古語','蘇籀','宋','宋诗','song-poetry','','[]','枿槎匪意稱居士，饋橐誰家號智囊。',32,'全唐诗/poet.song.101000.json','["枿槎匪意稱居士，饋橐誰家號智囊。", "鳶戾青雲莫吁訝，鵰逃炎熱利深藏。"]'),
('599aa17e-a1c2-43f4-86ce-3635db98b664','寓言一絕','蘇籀','宋','宋诗','song-poetry','','[]','輶眇豈任勝婦職，春暾桃蓓未敷蓮。',32,'全唐诗/poet.song.101000.json','["輶眇豈任勝婦職，春暾桃蓓未敷蓮。", "月娥宮額噫神護，旖旎仙舲託使旃。"]'),
('f3f47897-6efc-4b5a-ba44-05429cfef450','呂偉信求冰花詩賦得兩絕  其一','蘇籀','宋','宋诗','song-poetry','','[]','霰集柏杉霏靀鬆，瓦冰鎸畫葉柯葩。',32,'全唐诗/poet.song.101000.json','["霰集柏杉霏靀鬆，瓦冰鎸畫葉柯葩。", "密移裁化鍾纖巧，梁苑詩盟斲句佳。"]'),
('73d13d0e-d85f-4cdb-9f05-1d0f4bfbb3cf','呂偉信求冰花詩賦得兩絕  其二','蘇籀','宋','宋诗','song-poetry','','[]','墨迹扶疏凍未消，奇蹤印紙鏤刊雕。',32,'全唐诗/poet.song.101000.json','["墨迹扶疏凍未消，奇蹤印紙鏤刊雕。", "花宜道韞吟鹽絮，壓倒劉叉冰柱謠。"]'),
('d356ff55-c101-40e5-8918-2ba3cfbb2ad8','樓樞密挽詞二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','决科騰踏無前勇，比牒聯飛第一流。',64,'全唐诗/poet.song.101000.json','["决科騰踏無前勇，比牒聯飛第一流。", "召直毫端準謨誥，甄評皮裏韞陽秋。", "槐班鼎輔膺榮柬，玉陛封章究遠猷。", "楚挽凄酸洩遺恨，柏臺金殿望隆優。"]'),
('486e150c-5846-4611-af00-4d5c5760786a','樓樞密挽詞二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','岳鎮巍峩幕府雄，紫青頤旨稟趨風。',64,'全唐诗/poet.song.101000.json','["岳鎮巍峩幕府雄，紫青頤旨稟趨風。", "布宣條目都無擾，求瘼慈祥概所蒙。", "賓位樽罍人事改，影娥花月畫堂空。", "諸方故吏多才藻，撰紀徽嘉篆刻豐。"]'),
('d0c5f661-2a50-47d8-b5fb-fe1672877f23','絕句一首','蘇籀','宋','宋诗','song-poetry','','[]','雙紋八尺展雕床，蓮艷方空夜玉香。',32,'全唐诗/poet.song.101000.json','["雙紋八尺展雕床，蓮艷方空夜玉香。", "雅秀冰姿延閣彥，豈應簪斷作凄凉。"]'),
('1dd91ae3-a0a6-4508-a344-2f07fb8b4171','白菡萏一首','蘇籀','宋','宋诗','song-poetry','','[]','瑳兮容曠世，冰膩郁妖紅。',24,'全唐诗/poet.song.101000.json','["瑳兮容曠世，冰膩郁妖紅。", "姑射非無偶，能言諒不同。"]'),
('4b581a73-4cf2-4b3a-91a0-384d17d862f7','潘卿求內主令人挽章二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','擇夫先筮嫁，年俯逮期頤。',48,'全唐诗/poet.song.101000.json','["擇夫先筮嫁，年俯逮期頤。", "周南弗牆面，班誡克刑儀。", "陔蘭冀豐養，中饋失扶持。", "惻慨百金誄，君文亦漢碑。"]'),
('8ceecdcd-a6ae-4117-a97c-053935a6e2d3','潘卿求內主令人挽章二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','扊扅思舊苦，月缺白毫光。',48,'全唐诗/poet.song.101000.json','["扊扅思舊苦，月缺白毫光。", "孝懿綽馴習，德音寧詎忘。", "委禽流慶衍，偕老誓言荒。", "肖似傳孫息，綢繆卜鳳皇。"]'),
('5ba7bfa8-831e-489d-88fe-19f8e2d08107','王季海求父宣義挽詞二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','繕性克知命，鄉評行實尊。',48,'全唐诗/poet.song.101000.json','["繕性克知命，鄉評行實尊。", "傳經拾科第，綵服匝庭軒。", "韡萼專方面，良弓補諫垣。", "金坡振詞筆，品藻不勝言。"]'),
('598b8587-4098-491c-9b99-e369de287dd0','王季海求父宣義挽詞二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','里仁巾几寂，遺懿滿瞻聽。',48,'全唐诗/poet.song.101000.json','["里仁巾几寂，遺懿滿瞻聽。", "濟美珪璋質，流芳琬琰銘。", "紙灰霏似雪，巷泣灑將冰。", "念念存伽釋，超超拔九冥。"]'),
('14f56bda-5255-4660-9f7f-2493da4a1b2f','陳䋖男求厥父挽詩二首  其一','蘇籀','宋','宋诗','song-poetry','','[]','閫室良規範，萱堂子職修。',48,'全唐诗/poet.song.101000.json','["閫室良規範，萱堂子職修。", "儀形儼惇碩，積習肖風流。", "疇曩鄉鄰援，悽凉川逝愁。", "太丘純豈弟，慈愛理能周。"]'),
('8e70d73e-4188-4d1c-9494-74f47e4461bc','陳䋖男求厥父挽詩二首  其二','蘇籀','宋','宋诗','song-poetry','','[]','克家宗從譽，澗屋竹林莊。',48,'全唐诗/poet.song.101000.json','["克家宗從譽，澗屋竹林莊。", "情話非前聽，門庭付令郎。", "短生風燭頃，遠日隴丘傍。", "紅粉祠堂壁，亦應鎸短章。"]'),
('d4dbab64-f76e-4d8d-9fde-027016b3a215','潘令度送牡丹絕句','蘇籀','宋','宋诗','song-poetry','','[]','劇美溫馨逞瑰媚，膩紅殷紫疊重臺。',32,'全唐诗/poet.song.101000.json','["劇美溫馨逞瑰媚，膩紅殷紫疊重臺。", "芳晨華月臨春閣，倚麗凝嬌豈易栽。"]'),
('8c0d9b50-64cd-41b5-9e0a-6136ef7061a1','鞏采若求厥父令尹德秀挽詩','蘇籀','宋','宋诗','song-poetry','','[]','東魯懷經慕先哲，齋房僻處盛門徒。',64,'全唐诗/poet.song.101000.json','["東魯懷經慕先哲，齋房僻處盛門徒。", "勉陪流寓推鄉校，優選文華慶仕塗。", "議獄蚩氓生活路，削鋤姦軌亟揚枹。", "遺編亹亹乘儒典，濟美弓裘後世模。"]'),
('f70709d4-af6e-4a54-b223-1e40033f2e0f','松門','蘇籀','宋','宋诗','song-poetry','','[]','山川忽摇落，風雪交歲暮。',24,'全唐诗/poet.song.101000.json','["山川忽摇落，風雪交歲暮。", "堂堂十八公，正爾守門戶。"]'),
('dfc0df7a-a4b8-493d-a493-7ec4cf7ccae4','訪涌泉吳文叟隱居','蘇簡','宋','宋诗','song-poetry','','[]','水繞庭除屋近山，居人六月自清寒。',64,'全唐诗/poet.song.101000.json','["水繞庭除屋近山，居人六月自清寒。", "平時不起軒裳念，此去真輸巖穴安。", "書富五車成活計，樽開千日慰艱難。", "徑謀百畝從君隱，憑藉林泉寄一簞。"]'),
('f42997ae-4205-4013-befc-885f9720c877','次韻張正民遊智者寺','蘇簡','宋','宋诗','song-poetry','','[]','養拙何所詣，白晝門常關。',96,'全唐诗/poet.song.101000.json','["養拙何所詣，白晝門常關。", "剝啄有好懷，繞郭橫秋山。", "佛廬占山麓，清凈非人間。", "曳杖得晤語，幽尋爲怡顔。", "三峯聳而秀，羣巘抱以環。", "寺同喬木古，僧與白雲閒。", "一鳥不復鳴，流泉自潺湲。", "山林足勝踐，世路羊腸艱。"]'),
('e630c8b3-712a-4f46-ad93-ae6c5fafe1f6','至後書事','蘇簡','宋','宋诗','song-poetry','','[]','歲盡意不盡，日長愁更長。',72,'全唐诗/poet.song.101000.json','["歲盡意不盡，日長愁更長。", "將士介生蟣，黔黎疻復瘡。", "拊膺念江夏，掩面向山陽。", "大隱未高枕，巨鼇仍望洋。", "舊聞死可禱，或以酒自戕。", "廢卷三太息，撫時徒感傷。"]'),
('a03e6a5d-eb3e-485f-9471-122d0fbc2631','賦雪梨寄二孫','蘇簡','宋','宋诗','song-poetry','','[]','梨乃北方來，東陽有遺種。',120,'全唐诗/poet.song.101000.json','["梨乃北方來，東陽有遺種。", "開花如雪潔，結實論斤重。", "似聞風霜來，採摘不旋踵。", "膚瑩玉在手，剖之醴泉湧。", "甘凉宜解酲，席上賈餘勇。", "甚美非耐久，糜潰失前寵。", "長安疑父祖，壓沙豈伯仲。", "時方禁苞苴，林下喜得共。", "老人齒頰寒，食指難爲動。", "鄰牆有酒仙，雙苞可持送。"]'),
('eb12164e-5a1c-4dbd-976a-30800f49e84e','同諸孫賦冰筯','蘇簡','宋','宋诗','song-poetry','','[]','雪堆屋背已崔巍，溝瓦垂冰凍不摧。',64,'全唐诗/poet.song.101000.json','["雪堆屋背已崔巍，溝瓦垂冰凍不摧。", "乳石駢羅疑在谷，遺簪璀璨儼成堆。", "沍寒侵被憐衰老，咀嚼鳴牙憶尚孩。", "自是中原驗時令，江南春候亦難裁。"]'),
('667e410a-1e74-497e-904b-cf5323dae6c6','次韻徐惇濟久不食肉','蘇簡','宋','宋诗','song-poetry','','[]','舉家食肉迹雖陳，端有寒儒繼後塵。',64,'全唐诗/poet.song.101000.json','["舉家食肉迹雖陳，端有寒儒繼後塵。", "杜老長鑱聊卒歲，顔生陋巷不逢辰。", "啖氈竊喜全高節，食肉從來鄙要津。", "捫腹祇應多愧負，天教吾黨合清貧。"]'),
('36280fc2-c534-409a-b607-73197aba8c66','詠金橘','蘇簡','宋','宋诗','song-poetry','','[]','小小根栽出近□，□□繁實傲秋天。',64,'全唐诗/poet.song.101000.json','["小小根栽出近□，□□繁實傲秋天。", "恍如列宿掛庭樹，幾誤饑兒逐彈圓。", "荔子甘香欲爭席，赤心粗俗敢差肩。", "飲仙嚼□□□賞，賦客寡聞猶未編。"]'),
('e60b96f0-6bb5-4f49-9b6b-6103dace69dc','句  其一','蘇籍','宋','宋诗','song-poetry','','[]','醉鄉須待我，詩社莫添人。',12,'全唐诗/poet.song.101000.json','["醉鄉須待我，詩社莫添人。"]'),
('0c57647c-eabc-4b62-a86a-110bcad5af2f','句  其二','蘇籍','宋','宋诗','song-poetry','','[]','夢蝶豈知真是蝶，騎牛何必更尋牛。',16,'全唐诗/poet.song.101000.json','["夢蝶豈知真是蝶，騎牛何必更尋牛。"]'),
('c7f504bb-766e-4b9d-a4b9-68e91b7e340b','句','某道士','宋','宋诗','song-poetry','','[]','李郎涉世似虛舟，片帆來渡楚江秋。',16,'全唐诗/poet.song.101000.json','["李郎涉世似虛舟，片帆來渡楚江秋。"]'),
('51672976-d38b-4b86-ab82-ac181bad63b2','九仙山','徐師仁','宋','宋诗','song-poetry','','[]','晨逾九仙山，暮訪九鯉湖。',60,'全唐诗/poet.song.101000.json','["晨逾九仙山，暮訪九鯉湖。", "何氏兄弟跨鯉魚，同時輕舉排天衢。", "山頭雲氣故恍惚，三十六鱗今有無。", "瓊漿白日醉天酒，何時華表歸來乎。"]'),
('32d3c328-3055-499b-ba35-d91514dcfb2c','登瑞巖山','徐師仁','宋','宋诗','song-poetry','','[]','携筇登絕巘，朝爽薄危欄。',48,'全唐诗/poet.song.101000.json','["携筇登絕巘，朝爽薄危欄。", "乘勝移杯爵，憑高憶羽翰。", "泉聲穿石響，樹色入秋寒。", "對酒頻長望，心同渤澥寬。"]'),
('4df95a5a-5076-42e5-91a2-d68e0f9e4204','題晝寂軒','徐壽仁','宋','宋诗','song-poetry','','[]','輕雲扶曲檻，少坐覺幽深。',48,'全唐诗/poet.song.101000.json','["輕雲扶曲檻，少坐覺幽深。", "泛酒誰同話，敲詩獨寫心。", "竹聲流草榻，鳥語惹花陰。", "門外呼童掃，客彈月下琴。"]'),
('0a4454ff-0469-46bd-8de3-c24dfc30600e','句','徐壽仁','宋','宋诗','song-poetry','','[]','放懷追許謝，洗耳笑巢由。',12,'全唐诗/poet.song.101000.json','["放懷追許謝，洗耳笑巢由。"]'),
('71cb6b52-eb3b-4c1b-a5b2-07837d3081e6','偈','釋凈曇','宋','宋诗','song-poetry','','[]','本自深山卧白雲，偶然來此寄閑身。',32,'全唐诗/poet.song.101000.json','["本自深山卧白雲，偶然來此寄閑身。", "莫來問我禪兼道，我是吃飯屙屎人。"]'),
('789c4a85-5fb8-42c5-b59f-641b7719195b','辭衆偈','釋凈曇','宋','宋诗','song-poetry','','[]','這漢從來沒縫罅，五十六年成話霸。',32,'全唐诗/poet.song.101000.json','["這漢從來沒縫罅，五十六年成話霸。", "今朝死去見閻王，劍樹刀山得人怕。"]'),
('92a485b8-2e81-41ec-8dd0-bba66f9e2eec','項亭','徐兢','宋','宋诗','song-poetry','','[]','圖秦爭漢兩無成，霸勢先隨玉斗傾。',32,'全唐诗/poet.song.101000.json','["圖秦爭漢兩無成，霸勢先隨玉斗傾。", "惟有烏江夜深浪，至今猶作楚歌聲。"]'),
('09a5fda2-3e80-4bcf-99a6-ef819e51bb69','彭城山','徐兢','宋','宋诗','song-poetry','','[]','高館不知處，遊人空往還。',24,'全唐诗/poet.song.101000.json','["高館不知處，遊人空往還。", "亂鴉殘雪樹，荒冢夕陽山。"]'),
('0051f809-8c58-4510-ac29-1556cb306601','廣化寺','陳桷','宋','宋诗','song-poetry','','[]','山高不受暑，秋到十分凉。',48,'全唐诗/poet.song.101000.json','["山高不受暑，秋到十分凉。", "望外去程遠，閑中度日長。", "寺林投宿鳥，山路自歸羊。", "物物各有適，羈愁逐異鄉。"]'),
('f1cb0534-1beb-44b3-a837-6c041474f9a9','合掌巖','陳桷','宋','宋诗','song-poetry','','[]','合掌仙峯插漢高，下臨滄海壓波濤。',32,'全唐诗/poet.song.101000.json','["合掌仙峯插漢高，下臨滄海壓波濤。", "看來疑是金仙子，無相光輝禮玉毫。"]'),
('e1c88938-6bab-451b-bfc4-e257e7267277','和鄧至宏詠桂','崔中','宋','宋诗','song-poetry','','[]','留伴君家老圃芳，月中餘蔭带天香。',32,'全唐诗/poet.song.101000.json','["留伴君家老圃芳，月中餘蔭带天香。", "愚公縱有移山力，不入當年花石綱。"]'),
('7b3f06e5-dfb5-4f86-98d7-4703126cc6fa','花石詩十一章  其一','鄧肅','宋','宋诗','song-poetry','','[]','蔽江載石巧玲瓏，雨過嶙峋萬玉峰。',32,'全唐诗/poet.song.101000.json','["蔽江載石巧玲瓏，雨過嶙峋萬玉峰。", "艫尾相銜貢天子，坐移蓬島到深宮。"]'),
('f1e2443c-c8a9-4a87-9393-ca004b0d2185','花石詩十一章  其二','鄧肅','宋','宋诗','song-poetry','','[]','浮花浪蕊自朱白，月窟鬼方更奇絕。',32,'全唐诗/poet.song.101000.json','["浮花浪蕊自朱白，月窟鬼方更奇絕。", "繽紛萬里來如雲，上林玉砌酣春色。"]'),
('0469b882-4b23-4fc7-9bdb-6c69a9689799','花石詩十一章  其三','鄧肅','宋','宋诗','song-poetry','','[]','守令講求爭效忠，誓將花石掃地空。',32,'全唐诗/poet.song.101000.json','["守令講求爭效忠，誓將花石掃地空。", "那知臣子力可盡，報上之德要難窮。"]'),
('59b6db04-2845-4c43-a662-7d3a52db1b9f','花石詩十一章  其四','鄧肅','宋','宋诗','song-poetry','','[]','天爲黎民生父母，勝景直須盡寰宇。',32,'全唐诗/poet.song.101000.json','["天爲黎民生父母，勝景直須盡寰宇。", "豈同臣庶作園池，但隔牆籬分爾汝。"]'),
('e2e6c806-8917-4aee-9670-a86e52461fbb','花石詩十一章  其五','鄧肅','宋','宋诗','song-poetry','','[]','皇帝之圃浩無涯，日月所照同一家。',32,'全唐诗/poet.song.101000.json','["皇帝之圃浩無涯，日月所照同一家。", "北連幽薊南交趾，東極蟠木西流沙。"]'),
('a60dc629-c41a-4ffc-898f-aef25c94e232','花石詩十一章  其六','鄧肅','宋','宋诗','song-poetry','','[]','是中嵩嶽磨星斗，下視羣山真培塿。',32,'全唐诗/poet.song.101000.json','["是中嵩嶽磨星斗，下視羣山真培塿。", "千年老木矯龍蛇，天風夜作雷霆吼。"]'),
('e9972ac9-1c9e-4397-bed3-aaaf670ae5dd','花石詩十一章  其七','鄧肅','宋','宋诗','song-poetry','','[]','三月和風塞太空，天涯海角競青紅。',32,'全唐诗/poet.song.101000.json','["三月和風塞太空，天涯海角競青紅。", "不知花卉何遠近，六合內外俱春容。"]'),
('af7c5e41-8bb6-46f6-86a9-fcdf5912e2fa','花石詩十一章  其八','鄧肅','宋','宋诗','song-poetry','','[]','聖主胸襟包率土，天錫園池乃如許。',32,'全唐诗/poet.song.101000.json','["聖主胸襟包率土，天錫園池乃如許。", "坐觀塊石與根莖，無乃卑凡不足數。"]'),
('821ac806-f89e-4f79-9e28-2b6fb341415d','花石詩十一章  其九','鄧肅','宋','宋诗','song-poetry','','[]','飽食官吏不深思，務求新巧日孳孳。',32,'全唐诗/poet.song.101000.json','["飽食官吏不深思，務求新巧日孳孳。", "不知均是圃中物，遷遠而近蓋其私。"]'),
('e46581a8-7389-44c4-9197-d430915a446a','花石詩十一章  其一○','鄧肅','宋','宋诗','song-poetry','','[]','恭惟聖德高舜禹，一圃豈嘗分彼此。',32,'全唐诗/poet.song.101000.json','["恭惟聖德高舜禹，一圃豈嘗分彼此。", "世人用管妄窺天，水陸驅馳煩赤子。"]'),
('4230a4a5-b8b2-4212-9bcd-e24fab69ef03','花石詩十一章  其一一','鄧肅','宋','宋诗','song-poetry','','[]','安得守令體宸衷，不復區區踵前蹤。',32,'全唐诗/poet.song.101000.json','["安得守令體宸衷，不復區區踵前蹤。", "但爲君王安百姓，圃中無日不春風。"]'),
('644a48c5-a07e-440b-8c10-b0c6a47de1ff','巖桂','鄧肅','宋','宋诗','song-poetry','','[]','雨過西風作晚凉，連雲老翠出新黄。',32,'全唐诗/poet.song.101000.json','["雨過西風作晚凉，連雲老翠出新黄。", "清芬一日來天闕，世上龍涎不敢香。"]'),
('0e2e42f1-4c32-46a2-966d-4b4ca0ea14a5','梅','鄧肅','宋','宋诗','song-poetry','','[]','不顧冬殘自在妍，笑將疏影弄嬋娟。',32,'全唐诗/poet.song.101000.json','["不顧冬殘自在妍，笑將疏影弄嬋娟。", "小軒不用垂簾幕，我醉花香自得仙。"]'),
('96c7d1d9-acc2-4f2e-8289-5afb614cec44','泛江','鄧肅','宋','宋诗','song-poetry','','[]','風迴浪急月初圓，携得魚竿下釣船。',32,'全唐诗/poet.song.101000.json','["風迴浪急月初圓，携得魚竿下釣船。", "自是高歌星斗上，不須騎氣夜行天。"]'),
('c1bac071-dbba-41b4-ac57-f0b340975b65','姜池源廟二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','樽酒源頭一拜神，麕羊甕繭便青春。',32,'全唐诗/poet.song.101000.json','["樽酒源頭一拜神，麕羊甕繭便青春。", "當年旱魃矜餘虐，禱去陽侯失舊津。"]'),
('a7c251ee-0a3f-4fbb-aae0-0a2e0f3cd8ce','姜池源廟二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','博带峩冠新廟像，長衫紫領樂耕民。',32,'全唐诗/poet.song.101000.json','["博带峩冠新廟像，長衫紫領樂耕民。", "雨暘從此如常德，願作常山薦號人。"]'),
('b8d20a3a-a4d3-4182-9070-f86fa716a077','靈應寺二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','松篁擁翠入雲間，雅稱高人卷道閑。',32,'全唐诗/poet.song.101000.json','["松篁擁翠入雲間，雅稱高人卷道閑。", "自是紅塵飛不到，一溪流水遶青山。"]'),
('72fe84e1-58db-4b36-ae73-74a3ed53c015','靈應寺二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','老木森森小徑斜，淡烟橫鎖兩三家。',32,'全唐诗/poet.song.101000.json','["老木森森小徑斜，淡烟橫鎖兩三家。", "晚來欲寫瀟疏景，舉目遥岑更望賒。"]'),
('b42a127b-edb2-40b9-88d0-1cca5968a6fd','偶題','鄧肅','宋','宋诗','song-poetry','','[]','一葉漁舠破曉煙，山環碧玉水連天。',32,'全唐诗/poet.song.101000.json','["一葉漁舠破曉煙，山環碧玉水連天。", "滿傾竹葉倚紅玉，天遣行雲慰謫仙。"]'),
('c0639648-cdf1-4295-82a4-ea66e5f6b5e1','靖節先生祠下','鄧肅','宋','宋诗','song-poetry','','[]','五柳歸來昔陶公，七閩召還今鄧子。',32,'全唐诗/poet.song.101000.json','["五柳歸來昔陶公，七閩召還今鄧子。", "不將出處作殊觀，便了陶鄧無生死。"]'),
('3e381799-31b1-4e54-a6a1-452b32a630ac','鄲州道中早行','鄧肅','宋','宋诗','song-poetry','','[]','疏簾不下縱荷香，夢破紗厨月滿廊。',32,'全唐诗/poet.song.101000.json','["疏簾不下縱荷香，夢破紗厨月滿廊。", "笑盡一杯鞭馬走，恍疑山色是家鄉。"]'),
('efceeb9b-5aed-4b39-9f98-243f517b72cb','寄張應和運副二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','當年曾忝從官班，再拜天顔咫尺間。',32,'全唐诗/poet.song.101000.json','["當年曾忝從官班，再拜天顔咫尺間。", "今歷千山嫌未穩，芒鞋明日又登山。"]'),
('9c3652d7-3692-4289-8e51-8cd1e5aef9d8','寄張應和運副二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','土屋茅茨山萬重，陰雲不解雨濛濛。',32,'全唐诗/poet.song.101000.json','["土屋茅茨山萬重，陰雲不解雨濛濛。", "桃源目斷知何處，身在杜陵詩句中。"]'),
('b343bc94-8c2c-4d11-bb1e-f74bbb3f187a','詠史二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','雨過東山春意濃，但携桃李步春風。',32,'全唐诗/poet.song.101000.json','["雨過東山春意濃，但携桃李步春風。", "眼高四海無勍敵，百萬胡奴一□空。"]'),
('fa4cff90-2218-40e2-8f1d-6ce1a3d56256','詠史二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','五湖范蠡携西子，三國周郎嫁小喬。',32,'全唐诗/poet.song.101000.json','["五湖范蠡携西子，三國周郎嫁小喬。", "蓋世功名聊唾手，何妨樽酒醉妖嬈。"]'),
('45c95080-7928-42f1-98a0-8b655ee5ca48','戲題','鄧肅','宋','宋诗','song-poetry','','[]','我欲開樽百物無，鄰家酒熟各觴吾。',32,'全唐诗/poet.song.101000.json','["我欲開樽百物無，鄰家酒熟各觴吾。", "扶杖出門又應供，三生恐是賓頭盧。"]'),
('c3a25eba-6c55-42f0-97d1-62f22f23f340','訪故人','鄧肅','宋','宋诗','song-poetry','','[]','天寒歲暮兩無聊，訪戴那辭千里遥。',32,'全唐诗/poet.song.101000.json','["天寒歲暮兩無聊，訪戴那辭千里遥。", "直上洞天三十六，馬蹄迤邐步瓊瑶。"]'),
('5af861b4-e6ee-423b-8036-9210e5f2f789','題枕碧閣','鄧肅','宋','宋诗','song-poetry','','[]','清流繩斷炎洲境，松響挾將寒意來。',32,'全唐诗/poet.song.101000.json','["清流繩斷炎洲境，松響挾將寒意來。", "坐上逸情留不住，欲隨風月過蓬萊。"]'),
('b7bad591-f7ae-428f-b8b3-97eda8f66c3c','次韻李狀元送酒','鄧肅','宋','宋诗','song-poetry','','[]','年來樽酒是生涯，赤脚曾無解語花。',32,'全唐诗/poet.song.101000.json','["年來樽酒是生涯，赤脚曾無解語花。", "明日可來文字飲，新詩共吐半天霞。"]'),
('96e4abe1-ff67-4690-a0c8-94e9d93c933c','次韻順之奏雅四首  其一','鄧肅','宋','宋诗','song-poetry','','[]','誰回厄會作民祿，憑君上天厭人欲。',32,'全唐诗/poet.song.101000.json','["誰回厄會作民祿，憑君上天厭人欲。", "要將勳業稱貂蟬，世間豈曰無衣六。"]'),
('a97ea815-5c96-470e-8f48-54479aaee919','次韻順之奏雅四首  其二','鄧肅','宋','宋诗','song-poetry','','[]','謫仙酒渴要吞江，劉毅一呼從此欲。',32,'全唐诗/poet.song.101000.json','["謫仙酒渴要吞江，劉毅一呼從此欲。", "當知明瓊亦有神，引上洞天三十六。"]'),
('365ceba0-7ab8-4d96-91aa-a59cbc2a0397','次韻順之奏雅四首  其三','鄧肅','宋','宋诗','song-poetry','','[]','夢蝶莊周心槁木，入柳穿花本無欲。',32,'全唐诗/poet.song.101000.json','["夢蝶莊周心槁木，入柳穿花本無欲。", "杯酒行春當此時，忽遇清明一百六。"]'),
('5b560b26-b54d-458b-abde-0c26c61a88d9','次韻順之奏雅四首  其四','鄧肅','宋','宋诗','song-poetry','','[]','神仙醉歌天上曲，暖春肯念人間欲。',32,'全唐诗/poet.song.101000.json','["神仙醉歌天上曲，暖春肯念人間欲。", "謾將郊島繼韓豪，五出那配天葩六。"]'),
('30b8fde2-4547-4ec8-8b8d-c400fa285df7','鳳池小飲','鄧肅','宋','宋诗','song-poetry','','[]','北山知有出郊心，爲霽春寒十日陰。',32,'全唐诗/poet.song.101000.json','["北山知有出郊心，爲霽春寒十日陰。", "水石本爲遷客共，一枝端欲寄深林。"]'),
('ca21424d-6c73-471d-a8f2-4166965565ab','落梅二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','一夕狂風雨萬英，醉扶筇竹踏疏星。',32,'全唐诗/poet.song.101000.json','["一夕狂風雨萬英，醉扶筇竹踏疏星。", "歸來衫袖天香冷，一洗人間龍麝腥。"]'),
('b07f1b52-f1a0-41e4-91df-874b34317884','落梅二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','飄零不用嘆春工，風味端期鼎鼐中。',32,'全唐诗/poet.song.101000.json','["飄零不用嘆春工，風味端期鼎鼐中。", "欲攬陽和歸宇宙，何妨飛舞作先鋒。"]'),
('3b56f9ff-572e-47c0-bee0-fb9c196671a4','和鄧成材五絕  其一','鄧肅','宋','宋诗','song-poetry','','[]','扶筇欲過北山來，政賴詩囊一笑開。',32,'全唐诗/poet.song.101000.json','["扶筇欲過北山來，政賴詩囊一笑開。", "故走溪山尋勝景，爲君携向筆端來。"]'),
('78b7e011-1154-45ea-95ac-cda001bf9b69','和鄧成材五絕  其二','鄧肅','宋','宋诗','song-poetry','','[]','酒兵招我破愁城，頓覺春風拂面生。',32,'全唐诗/poet.song.101000.json','["酒兵招我破愁城，頓覺春風拂面生。", "却廹豺狼飛小艇，當知捩手又翻羹。"]'),
('6ba607bf-1cc9-45cc-a2cb-75c911c56c49','和鄧成材五絕  其三','鄧肅','宋','宋诗','song-poetry','','[]','朱紫紛趨左衽班，羨君不動屹如山。',32,'全唐诗/poet.song.101000.json','["朱紫紛趨左衽班，羨君不動屹如山。", "卷將禹稷平生志，掉首歸爲陋巷顔。"]'),
('07e03c24-fab5-49da-a76e-bafaa1b571d3','和鄧成材五絕  其四','鄧肅','宋','宋诗','song-poetry','','[]','句法徒能泣鬼神，文窮欲餞嘆無因。',32,'全唐诗/poet.song.101000.json','["句法徒能泣鬼神，文窮欲餞嘆無因。", "臨存多謝知音鮑，爲洗胸中萬斛塵。"]'),
('9479ab0d-3e70-4ab3-9037-7b1c3752bb3a','和鄧成材五絕  其五','鄧肅','宋','宋诗','song-poetry','','[]','卧龍何日起南陽，萬騎追風競挽强。',32,'全唐诗/poet.song.101000.json','["卧龍何日起南陽，萬騎追風競挽强。", "射落長庚作頑石，坐令四海復農桑。"]'),
('3f009bfc-8ca6-4abb-a94c-ff34e068f4c8','南歸醉題家圃二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','填海我如精衛，當車人笑螳螂。',28,'全唐诗/poet.song.101000.json','["填海我如精衛，當車人笑螳螂。", "六合羣黎有補，一身萬段何妨。"]'),
('2217b872-ae53-4913-9384-d6e3efb158b4','南歸醉題家圃二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','近輔暴迫狼虎，聖君德大乾坤。',28,'全唐诗/poet.song.101000.json','["近輔暴迫狼虎，聖君德大乾坤。", "萬里去黄金闕，一杯得杏花村。"]'),
('91bb5c3c-2f8b-45b0-96fa-39516f3456cb','凝翠閣陪李梁溪次韵','鄧肅','宋','宋诗','song-poetry','','[]','欄前碧玉四圍寬，滿座清風文字歡。',64,'全唐诗/poet.song.101000.json','["欄前碧玉四圍寬，滿座清風文字歡。", "霜氣襲人秋更爽，溪光耿月夜生寒。", "登臨顧我那能賦，姓字從公遂不漫。", "此景此時難再得，相思但把錦囊看。"]'),
('f6824cdc-ce50-42d8-bd95-f759104bd5e1','謝見招者','鄧肅','宋','宋诗','song-poetry','','[]','機鋒不契更何圖，便合浮杯出上都。',64,'全唐诗/poet.song.101000.json','["機鋒不契更何圖，便合浮杯出上都。", "此去定須安短褐，平生那肯曳長裾。", "迴天儻是奇男子，綰印原非大丈夫。", "揮手出門殊不惡，一帆秋水及鱸魚。"]'),
('afff4ca9-4378-4097-8fcd-d2b2b1bd3503','謝朱喬年','鄧肅','宋','宋诗','song-poetry','','[]','歸帽納毫真得策，要牋留带計何疏。',64,'全唐诗/poet.song.101000.json','["歸帽納毫真得策，要牋留带計何疏。", "公如買萊苦求益，我已忘要何用渠。", "閉戶羽衣聊自適，堆窗柿葉對人書。", "帝都聲價君知否，寄付新傳折檻朱。"]'),
('b5f6458e-66fe-482b-a167-33828a5f4225','哭陳興宗先生三首  其一','鄧肅','宋','宋诗','song-poetry','','[]','森森松竹鎖春風，半掩柴門一徑通。',64,'全唐诗/poet.song.101000.json','["森森松竹鎖春風，半掩柴門一徑通。", "獨步水雲情似鶴，對人談論氣如虹。", "詩書當日三冬富，光燄他時萬丈雄。", "忽馭冷風徑歸去，長庚依舊耿秋空。"]'),
('b8c82be6-b7d6-4bc1-a81c-f34731246aa5','哭陳興宗先生三首  其二','鄧肅','宋','宋诗','song-poetry','','[]','虀鹽昔者謾儒宮，葦白茅黄處處同。',64,'全唐诗/poet.song.101000.json','["虀鹽昔者謾儒宮，葦白茅黄處處同。", "十載從公煩點鐵，寸毫令我稍披聾。", "一泓漸笑牛蹄水，萬里初觀羊角風。", "欲反三隅嗟已矣，兩行衰淚付春風。"]'),
('6021c2c5-af5f-4f03-985e-73aac54f1c3a','哭陳興宗先生三首  其三','鄧肅','宋','宋诗','song-poetry','','[]','滿腹悲辛誰與言，叩門不應更依然。',64,'全唐诗/poet.song.101000.json','["滿腹悲辛誰與言，叩門不應更依然。", "一斑昔我嘗窺豹，五色還公自補天。", "新隴只今堪挂劍，枯桐從此不調絃。", "典刑今有阿戎在，定與相從對白蓮。"]'),
('7ade7f13-5d92-4f6d-a822-e365cf951790','無題','鄧肅','宋','宋诗','song-poetry','','[]','風行水上偶成文，暖入園林自在春。',64,'全唐诗/poet.song.101000.json','["風行水上偶成文，暖入園林自在春。", "換國雖工非我有，嘔心得句爲誰珍。", "三生戒老詩堪畫，千古長庚筆有神。", "不用臨風嘆奔逸，簞瓢一笑舜何人。"]'),
('f15931d2-dcff-4369-b9f3-7410e3b707f8','西庵餞春','鄧肅','宋','宋诗','song-poetry','','[]','傍水禪房半掩門，乍晴簾幕捲黄昏。',64,'全唐诗/poet.song.101000.json','["傍水禪房半掩門，乍晴簾幕捲黄昏。", "風驅紅雨春何在，酒入香肌玉自溫。", "勿笑饑腸充笋蕨，須將醉眼蓋乾坤。", "杖頭更有百錢在，明日還尋未到村。"]'),
('20293916-1a60-402f-9def-8272376688a4','喜雨二章  其一','鄧肅','宋','宋诗','song-poetry','','[]','萬里炎洲政鬰蒸，阿香搥鼓忽砰轟。',64,'全唐诗/poet.song.101000.json','["萬里炎洲政鬰蒸，阿香搥鼓忽砰轟。", "雲驅鐵騎千山合，雨挽銀河一夜傾。", "龜坼有田皆灌灌，蝟毛無稻不生生。", "高樓破曉朱簾卷，六合無塵萬象清。"]'),
('eb02df37-6b70-40b9-93f9-07d2a2b292ae','喜雨二章  其二','鄧肅','宋','宋诗','song-poetry','','[]','暘蟲赫赫欲流金，夾岸垂楊失翠陰。',64,'全唐诗/poet.song.101000.json','["暘蟲赫赫欲流金，夾岸垂楊失翠陰。", "已恐人間被湯旱，誰從天上作商霖。", "崇墉定有千箱積，果腹同傾四海心。", "我亦不須憂脫粟，聊賡既醉入瑶琴。"]'),
('f8477323-e6a3-423d-b2d1-65500184bc36','再和宰公二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','誰向人間脫甑蒸，煩公大句激雷轟。',64,'全唐诗/poet.song.101000.json','["誰向人間脫甑蒸，煩公大句激雷轟。", "高才自是百夫特，出語當令四座傾。", "霖雨雖從天上降，煙雲要自筆端生。", "吹噓六合無凡骨，例欲乘風款太清。"]'),
('aaa06e49-5e7b-45fa-b026-02eba479d9ba','再和宰公二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','斗樞不見走蛇金，萬里晴空無寸陰。',64,'全唐诗/poet.song.101000.json','["斗樞不見走蛇金，萬里晴空無寸陰。", "郗扇雖交更揮汗，嵩車才出輒成霖。", "詩如翻水驚黄絹，力可迴天在赤心。", "百里敢煩天下手，豐年無事但鳴琴。"]'),
('5868a95a-0142-49f7-8d90-ff0a1fdc76c8','次韵龍學丈','鄧肅','宋','宋诗','song-poetry','','[]','水色山光入畫屏，浩然相對自由身。',64,'全唐诗/poet.song.101000.json','["水色山光入畫屏，浩然相對自由身。", "芳菲莫恨無情去，天地常藏不盡春。", "儻得江河化酒醴，何須瓦礫點金銀。", "花開花謝兩休問，且向樽前一笑頻。"]'),
('7ffcddef-785b-4c33-b945-d3e56bd2357c','和姜季資','鄧肅','宋','宋诗','song-poetry','','[]','入手新詩奪化機，一天星斗夜無輝。',64,'全唐诗/poet.song.101000.json','["入手新詩奪化機，一天星斗夜無輝。", "想君佳思真泉湧，索我强辭似箭飛。", "平昔端爲覆醬用，臨時那得錦囊歸。", "不如且遣長鬚去，兀坐冥搜更下帷。"]'),
('bffcda59-1b2f-4e67-9219-b2375bd6c848','雲際嶺','鄧肅','宋','宋诗','song-poetry','','[]','狂直初無涉世才，雷公斥下九天來。',64,'全唐诗/poet.song.101000.json','["狂直初無涉世才，雷公斥下九天來。", "面衝風雪吹三月，馬避干戈易四迴。", "带雪燒柴平體粟，瀝槽沽酒慰饑雷。", "如聞明日登閩嶺，茅舍春風夜滿懷。"]'),
('dee8fb5d-126a-458d-b534-144e97cb834a','和鄒宣教','鄧肅','宋','宋诗','song-poetry','','[]','未須絕跡便餐霞，且飲當朝諫議茶。',64,'全唐诗/poet.song.101000.json','["未須絕跡便餐霞，且飲當朝諫議茶。", "法水有緣隨遠浪，污泥無計染蓮花。", "千篇信筆初無語，萬里浮螺觸處家。", "已悟色空元不兩，夔蚿何用更憐蛇。"]'),
('c9f99612-f84a-4fd6-bf8f-bbe768056dcb','仲子叔明二邦君兼濟子安德和文明四使者同過逐客於文殊偶食無肉客既滿意而主人略無愧色作詩一首','鄧肅','宋','宋诗','song-poetry','','[]','謫宦亡聊又出奔，敢期冠蓋也臨存。',64,'全唐诗/poet.song.101000.json','["謫宦亡聊又出奔，敢期冠蓋也臨存。", "豪華自厭蒸人乳，冷落能來叩席門。", "莫嘆愁腸充苜蓿，從來醉眼蓋乾坤。", "相知政在世情外，賜達回窮不足論。"]'),
('c42ccd24-3b82-41ce-93f5-093073a816ff','送丹霞','鄧肅','宋','宋诗','song-poetry','','[]','白蓮結社記前緣，偶到人間共一年。',64,'全唐诗/poet.song.101000.json','["白蓮結社記前緣，偶到人間共一年。", "對學三生形已改，相逢一笑性猶全。", "法緣振地公今佛，逸思磨天我亦仙。", "明日清風飛短棹，羨師先去得林泉。"]'),
('b9680383-9dd3-4456-b481-d21ea97e972f','遣妓','鄧肅','宋','宋诗','song-poetry','','[]','吾徒得酒便超然，何用紅粧惱醉眠。',64,'全唐诗/poet.song.101000.json','["吾徒得酒便超然，何用紅粧惱醉眠。", "密約自憐非宋玉，官差聊復浼梅仙。", "樽前起舞無鸜鵒，坐上求歸似杜鵑。", "去去眼中無俗物，却將詩律絆春妍。"]'),
('7e432bf2-7674-48a9-8169-08b2af04fc70','遊山','鄧肅','宋','宋诗','song-poetry','','[]','花柳年來不忍春，出郊聊復寫憂熏。',64,'全唐诗/poet.song.101000.json','["花柳年來不忍春，出郊聊復寫憂熏。", "天因御史欲飛雨，山爲文公却霽雲。", "寸舌不須論理亂，一犁安得遂耕耘。", "憑君且盡杯中物，酒惡花香自在聞。"]'),
('425777dc-f8d9-43b6-8116-80574486089b','謝呂友善見和','鄧肅','宋','宋诗','song-poetry','','[]','扶筇西去謾尋春，獨學無人沐且熏。',64,'全唐诗/poet.song.101000.json','["扶筇西去謾尋春，獨學無人沐且熏。", "便欲問津從桀溺，當時折檻愧朱雲。", "陰霾滿目憑誰掃，芳草連空未易耘。", "家學定須興尚父，威聲一振九夷聞。"]'),
('0ec56b10-18ec-4159-9d83-c295051d30eb','謝吳少綝和','鄧肅','宋','宋诗','song-poetry','','[]','茅齋對語夜生春，簾幕低園沉水熏。',64,'全唐诗/poet.song.101000.json','["茅齋對語夜生春，簾幕低園沉水熏。", "冷坐顧余心似鐵，題詩羨子氣如雲。", "山巔有蕨應同采，郭外無田可獨耘。", "市酒盈樽且狂飲，兒曹昵昵不須聞。"]'),
('74b5b085-be0a-4177-8dce-bc0e301e6a8b','次韵茂實之才','鄧肅','宋','宋诗','song-poetry','','[]','謫官誰道不知春，出郭猶能一醉熏。',64,'全唐诗/poet.song.101000.json','["謫官誰道不知春，出郭猶能一醉熏。", "銀筆爭題追鮑謝，席門琢句擬機雲。", "東垣敢念百朋錫，南畝當從千耦耘。", "剩乞新詩殊不惡，恐因叩角徹天聞。"]'),
('1854a315-d5ef-42a4-9559-6e0d7d2e56b3','秋日白蓮','鄧肅','宋','宋诗','song-poetry','','[]','竹外玻璃十頃寬，水芝高下刻琅玕。',64,'全唐诗/poet.song.101000.json','["竹外玻璃十頃寬，水芝高下刻琅玕。", "冷香翦翦秋風動，孤艷泠泠曉月寒。", "康樂氣豪猶出社，易之韵俗更誰看。", "笑談今日親姑射，太華高吟不數韓。"]'),
('9ba1b550-d863-48bd-824d-ccfc96196c0e','訪故人','鄧肅','宋','宋诗','song-poetry','','[]','扁舟載月隨夜風，曉到溪源訪老農。',64,'全唐诗/poet.song.101000.json','["扁舟載月隨夜風，曉到溪源訪老農。", "水骨借風鳴活活，澗毛被雨綠茸茸。", "竹萌已削瓊瑶白，村酒仍沽琥珀濃。", "醉倒田間無一事，九衢車馬自衝衝。"]'),
('4086e0e5-b1c5-4eab-8373-c7c83efe4cd8','瑞鷓鴣','鄧肅','宋','宋诗','song-poetry','','[]','北書一紙慘天容，花柳春風不敢穠。',64,'全唐诗/poet.song.101000.json','["北書一紙慘天容，花柳春風不敢穠。", "未學宣尼歌鳳德，姑從阮籍哭途窮。", "此身已落千山外，舊事迴思一夢中。", "何日中興煩吉甫，洗開陰翳放晴空。"]'),
('343f1fff-eccb-4fcf-a704-31458a5cfed0','羅知縣挽詩','鄧肅','宋','宋诗','song-poetry','','[]','閉門經史自優遊，氣宇凌凌上斗牛。',64,'全唐诗/poet.song.101000.json','["閉門經史自優遊，氣宇凌凌上斗牛。", "從政逝將驅鳥鼠，傳家那肯墜箕裘。", "人間端欲揮銀筆，天上俄聞記玉樓。", "山北山南何處問，翩翩丹旐舞殘秋。"]'),
('9748d26a-b1b1-4ed1-b03e-bea9fb93ae98','次宋左司韵','鄧肅','宋','宋诗','song-poetry','','[]','往事無如今日新，鑾輿一再冒胡塵。',64,'全唐诗/poet.song.101000.json','["往事無如今日新，鑾輿一再冒胡塵。", "陽微陰極故多雨，柳怨花愁不忍春。", "已遣侈心傾虜帳，行收淚眼拜楓宸。", "眼前惡景君休問，勝負相資臂屈伸。"]'),
('85463f1e-d1b6-4cdb-80b8-899c4ce4f6ce','戲彥成端友','鄧肅','宋','宋诗','song-poetry','','[]','一天梅雨亂繽紛，二陸超然樂事并。',64,'全唐诗/poet.song.101000.json','["一天梅雨亂繽紛，二陸超然樂事并。", "師命炙牛携越妥，相如滌器對文君。", "閉門嗟我如孫敬，載酒誰人過子雲。", "窺竇有心公肯否，要將文字雜紅裙。"]'),
('b0ffc503-5c5d-42ef-b42f-818a13b9e0a0','寄張子猷','鄧肅','宋','宋诗','song-poetry','','[]','九州胡馬闇塵埃，政恐狂瀾不可迴。',64,'全唐诗/poet.song.101000.json','["九州胡馬闇塵埃，政恐狂瀾不可迴。", "敢念陶潜舊彭澤，當尋阮肇過天台。", "三朝我乏迴天力，一壑君還釣月來。", "便好相從長夜飲，簞瓢新有脯青苔。"]'),
('5d0c06c9-d2e9-47ba-8214-716c69973ff0','自嘲','鄧肅','宋','宋诗','song-poetry','','[]','蹤跡平生半九區，醉倒時得蛾眉扶。',64,'全唐诗/poet.song.101000.json','["蹤跡平生半九區，醉倒時得蛾眉扶。", "連年兵火四方沸，一飽雞豚半月無。", "住世今非孔北海，分司自到賓頭盧。", "卷簾月色招人醉，三百青銅徑自沽。"]'),
('7868a78a-4476-45e8-8325-d85c2810901c','偶成三首  其一','鄧肅','宋','宋诗','song-poetry','','[]','蒼苔白石兩清幽，縹緲虹橋跨碧流。',64,'全唐诗/poet.song.101000.json','["蒼苔白石兩清幽，縹緲虹橋跨碧流。", "日過窗間騰野馬，雨餘牆角篆蝸牛。", "饑寒不作妻孥念，笑語那知天地秋。", "一炷水沉參鼻觀，掃空六鑿自天遊。"]'),
('8d1ffebf-baec-4c5f-a236-0311a9665aff','偶成三首  其二','鄧肅','宋','宋诗','song-poetry','','[]','夢破南窗裊水沉，卧看素壁挂瑶琴。',64,'全唐诗/poet.song.101000.json','["夢破南窗裊水沉，卧看素壁挂瑶琴。", "絲絲細雨晚煙合，閣閣鳴蛙蔓草深。", "但得甕邊眠吏部，不妨跨下辱淮陰。", "何時樓上登晴景，一醉聊舒萬里心。"]'),
('255ed5cb-2bc3-487f-9c20-d6958af3074c','偶成三首  其三','鄧肅','宋','宋诗','song-poetry','','[]','萬里歸來卧白雲，蚍蜉撼樹政紛紛。',64,'全唐诗/poet.song.101000.json','["萬里歸來卧白雲，蚍蜉撼樹政紛紛。", "大兒文舉知何在，巨擘於陵亦謾云。", "空洞能容數百輩，蒙朧如見二三分。", "小槽誰有真珠滴，徑覓吾徒作半醺。"]'),
('3d24fda7-84f8-468d-97e6-37f5addb25a9','次韵王信州三首  其一','鄧肅','宋','宋诗','song-poetry','','[]','逐客難參國士憂，扶筇萬里過閩甌。',64,'全唐诗/poet.song.101000.json','["逐客難參國士憂，扶筇萬里過閩甌。", "藜羹充腹初無憾，楛矢踰江生計愁。", "長夜漫漫不肯旦，梅霖灌灌未應休。", "醉中我欲呼風伯，一掃陰霾霽九州。"]'),
('b7bd8a7f-2333-4ee2-8661-12234744ec36','次韵王信州三首  其二','鄧肅','宋','宋诗','song-poetry','','[]','風波未暇怨浮萍，多謝朋來慰此情。',64,'全唐诗/poet.song.101000.json','["風波未暇怨浮萍，多謝朋來慰此情。", "君似張憑真理窟，我慚侯喜得詩聲。", "酒杯莫向吾徒淺，句法當令叔世驚。", "又恐諸公連茹去，堂堂王室要扶傾。"]'),
('90c173f4-e640-43c0-873e-6a529f163c32','次韵王信州三首  其三','鄧肅','宋','宋诗','song-poetry','','[]','平生恥爲一身謀，枘鑿方員兩不投。',64,'全唐诗/poet.song.101000.json','["平生恥爲一身謀，枘鑿方員兩不投。", "蟣虱但知貪肉食，醯雞何足語天遊。", "雪餘自閉袁安戶，月皎時登王粲樓。", "更得吾人詩句好，當知此樂與天侔。"]'),
('8e418357-bf2e-4a5e-91be-9cf84135864c','和李梁溪春雪韵二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','白白朱朱春已深，那知雪意更陰陰。',64,'全唐诗/poet.song.101000.json','["白白朱朱春已深，那知雪意更陰陰。", "落花幾陣遮山密，穿褐餘寒賴酒禁。", "騎馬不前真有恨，留衣過臘豈無心。", "等爲遷客俱逢雪，誰似梁溪獨醉吟。"]'),
('02517546-d10e-430a-a32b-7f7b4ebaf788','和李梁溪春雪韵二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','玄冥忽欲作春容，不許東君利自封。',64,'全唐诗/poet.song.101000.json','["玄冥忽欲作春容，不許東君利自封。", "已使素英拖暖絮，更摧妖艷別寒松。", "那知往事思飛燕，預慶豐年免象龍。", "向有謫仙詩句好，何妨閉戶醉金鍾。"]'),
('c9d56377-6c51-45c0-9aa1-126ceadca01e','送春','鄧肅','宋','宋诗','song-poetry','','[]','宿雨初開萬翠屏，相携雲水自由身。',64,'全唐诗/poet.song.101000.json','["宿雨初開萬翠屏，相携雲水自由身。", "寸心未逐鶯花老，一笑能留天地春。", "儻得新詩同刻燭，不妨濁酒共傾銀。", "往來一氣何須問，蝙蝠飛時日正晨。"]'),
('6c8d136c-3a0c-4cda-91c7-b1966885b34d','分歲','鄧肅','宋','宋诗','song-poetry','','[]','餘臘羈人少共歡，那堪瑞雪降雲端。',64,'全唐诗/poet.song.101000.json','["餘臘羈人少共歡，那堪瑞雪降雲端。", "四時欲盡三更鼓，六出番成兩歲寒。", "欺壓嶺梅殘艷白，密敲亭竹碎聲乾。", "公卿休掃黌堂下，留與來朝賀客看。"]'),
('cac5ee58-d9e7-445c-b663-d468a4604a8f','鄰家翁挽辭二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','凜然風韵老尤癯，方寸經營包九區。',64,'全唐诗/poet.song.101000.json','["凜然風韵老尤癯，方寸經營包九區。", "窖粟巧爲任氏策，縛船冷笑退之迂。", "深藏未肯驕僮僕，儉德端能率里閭。", "故使考終踰七十，不因財害似齊奴。"]'),
('bf0e1fa5-b96f-4096-9f6f-f64bb61df20b','鄰家翁挽辭二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','高堂宴坐亦何忙，金水聊觀毀與穰。',64,'全唐诗/poet.song.101000.json','["高堂宴坐亦何忙，金水聊觀毀與穰。", "遠配刁間籠桀黠，未饒倚頓埒侯王。", "桑麻有畝今千計，牛馬難言用谷量。", "可惜一朝螺變麥，千金無藥治膏肓。"]'),
('78a770e7-ff7a-4880-b915-5ec9ee7ef359','從昭祖乞糖霜','鄧肅','宋','宋诗','song-poetry','','[]','甜滿中邊一夜冰，璀璀璨璨自天成。',64,'全唐诗/poet.song.101000.json','["甜滿中邊一夜冰，璀璀璨璨自天成。", "冷香入骨追瓊液，秀色當筵瑩水晶。", "絳闕不須餐沆瀣，玉池何事養胎津。", "從公乞取洗蒸鬰，一馭寒風上太清。"]'),
('dae08ec7-524a-4059-bf92-bcead0e39001','避地過雷霹灘','鄧肅','宋','宋诗','song-poetry','','[]','門前又見馬如流，兵革繽紛幾日休。',64,'全唐诗/poet.song.101000.json','["門前又見馬如流，兵革繽紛幾日休。", "嶺似車盤方稅駕，灘如雷霹更行舟。", "豺狼敢侮乾坤大，江海徒深蟣虱憂。", "安得將壇登李郭，挽回羲御照神州。"]'),
('479d675e-bba2-475c-9d66-dbcd47a59112','偶題','鄧肅','宋','宋诗','song-poetry','','[]','才薄難趨供奉班，歸來作意水雲閑。',64,'全唐诗/poet.song.101000.json','["才薄難趨供奉班，歸來作意水雲閑。", "謫官謾說九年計，客枕曾無一夕安。", "渭水不應藏釣艇，淮陰便合起登壇。", "喚回勝景憑夫子，使我甘歸苜蓿盤。"]'),
('76b96fa9-7c46-4f81-b4c7-0d3531e4fd28','次韵謝明遠和','鄧肅','宋','宋诗','song-poetry','','[]','乞身天上爲溪山，征鼓不容蓑笠閑。',64,'全唐诗/poet.song.101000.json','["乞身天上爲溪山，征鼓不容蓑笠閑。", "酷暑扁舟同海角，暖風杯酒念長安。", "高情我自歸蓮社，妙譽君應冠杏壇。", "更約三山少從款，赬虬吐卵粲金盤。"]'),
('f726b022-2e39-47ff-a195-c363250f07bb','題步瀛閣','鄧肅','宋','宋诗','song-poetry','','[]','玲瓏畫閣入鴻冥，隱約鴻冥入太清。',64,'全唐诗/poet.song.101000.json','["玲瓏畫閣入鴻冥，隱約鴻冥入太清。", "紫氣氤氳隨去步，青霞杳靄逐行旌。", "桃花浪透三山近，龜角屏高七朵橫。", "解逐梅仙在塵世，誰知塵世有蓬瀛。"]'),
('8e02e3b9-c8ce-448e-a928-d937706e6821','子安提舉二首  其一','鄧肅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','南奔千里已途窮，更向長江避賊鋒。',64,'全唐诗/poet.song.101000.json','["南奔千里已途窮，更向長江避賊鋒。", "十口未容謀去住，片帆那暇擇西東。", "乞錢不忍從司業，食粥新來似魯公。", "賴有詩情摧不老，時將新句吐長虹。"]'),
('3f03881f-0456-4a61-9685-f901e24bb165','子安提舉二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','征鼓驅人夜發船，別來無處寫憂煎。',64,'全唐诗/poet.song.101000.json','["征鼓驅人夜發船，別來無處寫憂煎。", "高吟自答㗀嚶嘯，旅食時開鬰屈筵。", "君去青天纔尺五，我今白髮已三千。", "何當却飲南湖月，顛倒衣裳舞謫仙。"]'),
('15653b6d-a930-4ac3-8a7c-5863f4682f89','次韵二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','玉殿曾叨侍冕旒，才疏意廣誤旁求。',64,'全唐诗/poet.song.101000.json','["玉殿曾叨侍冕旒，才疏意廣誤旁求。", "彙征那敢私連茹，勇退何妨在急流。", "蓬蓽已無原憲室，江山要飽子長遊。", "西庵軒檻多風月，幸子時來共茗甌。"]'),
('7a52a57c-ad1b-40f8-aa98-b14394998d05','次韵二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','怪底祥光夜滿門，朝來入社得詩人。',64,'全唐诗/poet.song.101000.json','["怪底祥光夜滿門，朝來入社得詩人。", "空疏嗟我句無眼，俊逸知君筆有神。", "共隱兵戈不到處，相携雲水自由身。", "便當痛飲追河朔，紅雪繽紛膾錦鱗。"]'),
('0c714b7a-30aa-4c7a-8549-30003b5ee50b','次韵郭宰兼簡丞尉三首  其一','鄧肅','宋','宋诗','song-poetry','','[]','獨領詩壇卧北窗，故應落筆士夫降。',64,'全唐诗/poet.song.101000.json','["獨領詩壇卧北窗，故應落筆士夫降。", "笑談自掃剡籐萬，聲價曾高魏闕雙。", "六合便當歸化筆，一同聊復賞澄江。", "初無肯綮煩遊刃，夜飲何妨取萬缸。"]'),
('bb0f473b-edaf-4063-a457-5617798b898a','次韵郭宰兼簡丞尉三首  其二','鄧肅','宋','宋诗','song-poetry','','[]','只將詩律對晴窗，我本無爲人自降。',64,'全唐诗/poet.song.101000.json','["只將詩律對晴窗，我本無爲人自降。", "曹子棒頭施色五，崔侯廳下植松雙。", "千篇堪友騎鯨李，八詠當奴夢筆江。", "文字興餘行樂耳，肯容碧玉自盈缸。"]'),
('fba6fead-7c11-4b18-8b8c-15de1abe1f3d','次韵郭宰兼簡丞尉三首  其三','鄧肅','宋','宋诗','song-poetry','','[]','一點螢燈續曉窗，已千人十未甘降。',64,'全唐诗/poet.song.101000.json','["一點螢燈續曉窗，已千人十未甘降。", "見聞僅得豹斑一，勝負猶爭蛙角雙。", "山聳劍鋒登九坂，浪翻銀屋度三江。", "歸來自在春風裏，時得萱堂獻酒缸。"]'),
('5b61c5ef-d078-4b4e-96f9-081c877c8420','洪丞和來再次韵  其一','鄧肅','宋','宋诗','song-poetry','','[]','堂堂國士洪夫子，刻燭從渠心自降。',64,'全唐诗/poet.song.101000.json','["堂堂國士洪夫子，刻燭從渠心自降。", "妙手故應釣鰲六，得君那用射鳶雙。", "定隨國老興東海，肯效騷人慟楚江。", "酒醴祇今須麯糵，要今六合共盈缸。"]'),
('a1b4d860-91ec-46ad-818a-cdfe49f23421','洪丞和來再次韵  其二','鄧肅','宋','宋诗','song-poetry','','[]','世事無由到竹窗，只餘心賞獨難降。',64,'全唐诗/poet.song.101000.json','["世事無由到竹窗，只餘心賞獨難降。", "雨餘翡翠山連七，春漲玻璃溪自雙。", "萬壑不須看越嶠，千尋端可配吳江。", "摳衣便欲同清景，安得黄封列萬缸。"]'),
('7613a9e2-2c37-4144-bfe7-3a089f5a074d','洪丞和來再次韵  其三','鄧肅','宋','宋诗','song-poetry','','[]','萬里歸來一小窗，利名心滅不須降。',64,'全唐诗/poet.song.101000.json','["萬里歸來一小窗，利名心滅不須降。", "雖無何子食錢萬，未到潘郎雪鬢雙。", "樓上詩狂欲騎月，晚來酒渴思吞江。", "從今痛飲須論日，瑣瑣那能問幾缸。"]'),
('d446e512-0661-40bb-8668-2e55090f870d','成彥女奴琵琶','鄧肅','宋','宋诗','song-poetry','','[]','婷婷裊裊出紗窗，坐使紅妝萬目降。',64,'全唐诗/poet.song.101000.json','["婷婷裊裊出紗窗，坐使紅妝萬目降。", "翠袖薄籠春笋十，玉釵初合綠雲雙。", "四絃對客追三疊，萬喚令人憶九江。", "曼倩酒狂本無量，爲渠瀲灧倒銀缸。"]'),
('ea6aeb6a-a911-4ccd-bb30-17bd395e95da','寄璨老西軒','鄧肅','宋','宋诗','song-poetry','','[]','水沉一炷裊晴窗，默坐無心可得降。',64,'全唐诗/poet.song.101000.json','["水沉一炷裊晴窗，默坐無心可得降。", "浥露菖蒲能寸寸，語晴新燕自雙雙。", "祇今得兔不鉆紙，那用浮杯更度江。", "前世遠公只師是，好從元亮供千缸。"]'),
('dde994ca-70cf-4d9c-9783-60deaeb927db','林提學挽詞','鄧肅','宋','宋诗','song-poetry','','[]','文陣曾驚賢士關，青衿袖手仰登壇。',64,'全唐诗/poet.song.101000.json','["文陣曾驚賢士關，青衿袖手仰登壇。", "當年聲價輝暘谷，晚節清貧奈歲寒。", "地下修文屈顔子，人間談易失丁寬。", "傳家賴有千人傑，三接天衢不作難。"]'),
('d6240e21-a97c-4d7c-9743-2bb762309689','和陳少卿','鄧肅','宋','宋诗','song-poetry','','[]','懶從蒿目世間憂，緩步招提味九丘。',64,'全唐诗/poet.song.101000.json','["懶從蒿目世間憂，緩步招提味九丘。", "正論羨君無鄭衛，窮途慰我在商周。", "飄然忽作遷喬興，卓爾難追跨海遊。", "別去詞源應萬斛，幸分涓滴洗離愁。"]'),
('2f38a1ad-bbc0-437b-8f19-020958bf8d91','謹次第三章','鄧肅','宋','宋诗','song-poetry','','[]','海角誰能寫客憂，童顔鶴髮顧崇丘。',64,'全唐诗/poet.song.101000.json','["海角誰能寫客憂，童顔鶴髮顧崇丘。", "風流君似東山謝，勳業余慚赤壁周。", "落筆敢陪風雨疾，扶筇時共水雲遊。", "明朝却羨先生去，萬頃煙波醉莫愁。"]'),
('26e34e4d-ff51-427a-9136-26dd21a784cd','別陳少卿','鄧肅','宋','宋诗','song-poetry','','[]','平生杯酒百無憂，四海風流陳太丘。',64,'全唐诗/poet.song.101000.json','["平生杯酒百無憂，四海風流陳太丘。", "據景筆端凌鮑謝，當年門下得伊周。", "那知避世嶔𡼭迹，也許從公汗漫遊。", "聞說片帆今又舉，三山無處著人愁。"]'),
('98e36a86-ed8f-47db-8943-92955f5cb2a5','偶成二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','我生詩酒弄林泉，紫詔三呼出洞天。',64,'全唐诗/poet.song.101000.json','["我生詩酒弄林泉，紫詔三呼出洞天。", "高視塵寰但蚊睫，冷看時輩聳鳶肩。", "山間已袖嬰鱗手，物外今還釣月船。", "若使兒曹知此樂，人人同得地行仙。"]'),
('6820cd1d-f95e-4a5a-9a7c-c2df414330e9','偶成二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','數椽茅屋傍山隈，野草如雲徑不開。',64,'全唐诗/poet.song.101000.json','["數椽茅屋傍山隈，野草如雲徑不開。", "小院縱橫行蟻陣，孤燈明滅縱蚊雷。", "并包益見乾坤大，掃滅何時風雪來。", "磊塊胸中何處洗，酒行到手莫停杯。"]'),
('4b0d94ba-3aed-4de1-8b9e-3055541aeece','鳳池小飲','鄧肅','宋','宋诗','song-poetry','','[]','愁見孤城萬馬屯，山行飄若出塵樊。',64,'全唐诗/poet.song.101000.json','["愁見孤城萬馬屯，山行飄若出塵樊。", "臨池想鳳心皆妄，據檻觀魚道更尊。", "笑吸百川淋酒渴，旁看三峽倒詞源。", "人生適意須觴詠，世事升沉不足論。"]'),
('5e6659b6-7e5c-477b-af2f-38ad0e0d5e19','次韵鄧成彥','鄧肅','宋','宋诗','song-poetry','','[]','槍榆不羨貼天飛，冷落柴門半掩扉。',64,'全唐诗/poet.song.101000.json','["槍榆不羨貼天飛，冷落柴門半掩扉。", "花榭水軒催客老，飯囊酒甕與心違。", "風流沈約自應瘦，美好陳平今已非。", "誰似宗盟重山嶽，九環金带稱腰圍。"]'),
('63021138-dcc2-4f6d-8abc-dc74dbcf9da8','戲洪丞','鄧肅','宋','宋诗','song-poetry','','[]','萬里歸來雲水鄉，逢春得酒且彷徨。',64,'全唐诗/poet.song.101000.json','["萬里歸來雲水鄉，逢春得酒且彷徨。", "好賢誰似雙松吏，使我時終一石狂。", "忽與高唐來鼠目，却令朱戶鎖梅粧。", "先生取瑟吾知己，安得從今不舉觴。"]'),
('7b9e11d2-4cf2-4941-8dcc-f668c586967c','次韵凝翠閣看水','鄧肅','宋','宋诗','song-poetry','','[]','欄桿十二俯烟濤，冒雨從君一醉陶。',64,'全唐诗/poet.song.101000.json','["欄桿十二俯烟濤，冒雨從君一醉陶。", "頗覺寒窗侵島瘦，故將勝景助韓豪。", "波聲裂岸魚歌遠，水勢橫天釣艇高。", "前日主人今國老，乘桴何處泛滔滔。"]'),
('6a79c757-1d6e-4ee1-a401-e61e86c78b12','再次前韵二首  其一','鄧肅','宋','宋诗','song-poetry','','[]','蕭條門巷半萊蒿，杯酒田間亦自陶。',64,'全唐诗/poet.song.101000.json','["蕭條門巷半萊蒿，杯酒田間亦自陶。", "採栗久要工部拙，騎鯨偶厠謫仙豪。", "狂波故作風雷噫，逸興何妨日月高。", "勝景賴君佳句壓，胸中江漢更滔滔。"]'),
('512cd175-249d-4d0b-a68a-dc6f59ea864c','再次前韵二首  其二','鄧肅','宋','宋诗','song-poetry','','[]','琢磨佳句敵離騷，賴得朋來漉酒陶。',64,'全唐诗/poet.song.101000.json','["琢磨佳句敵離騷，賴得朋來漉酒陶。", "時遣紆餘資卓犖，更將華妙濟雄豪。", "閣臨巨浸南溟近，簾捲晴空北極高。", "更約高談句法外，可憐天下政滔滔。"]'),
('3e84726d-c118-4675-b030-bab8bc76899b','陳大夫華嚴閣','鄧肅','宋','宋诗','song-poetry','','[]','星郎德望欲摩天，坎止流行任自然。',64,'全唐诗/poet.song.101000.json','["星郎德望欲摩天，坎止流行任自然。", "直道不回真鐵石，高懷未老已林泉。", "宗門夙了風幡動，傑閣聊修香火緣。", "顧我驅馳成底事，羨公真是地行仙。"]'),
('9f5d877f-24ff-48cc-84e3-4397923528f7','靖康迎駕行','鄧肅','宋','宋诗','song-poetry','','[]','女真作意厭人肝，揮鞭直視無長安。',384,'全唐诗/poet.song.101000.json','["女真作意厭人肝，揮鞭直視無長安。", "南渡黄河如履地，東有太行不能山。", "帝城周遭八十里，二十萬兵氣裂眥。", "旌旗城上亂雲煙，腰間寶劍凝秋水。", "雪花一日故濛濛，皂幟登城吹黑風。", "我師舉頭不敢視，脫兔放豚一掃空。", "夜起火光迷鳳闕，鉦鼓砰轟地欲裂。", "斯民嗷嗷將焉之，相顧無言惟泣血。", "僕射何公叩龍墀，圍閉相臣臣噬臍。", "奇兵化作乞和使，誓捐一死生羣黎。", "遊談似霽胡帥怒，九鼎如山疑弗顧。", "郊南期稅上皇輿，截破黄流徑歸去。", "陛下仁孝有虞均，忍令胡騎聳吾親。", "不龜太史自鞭馬，一出喚回社稷春。", "虜人慕得猶貪利，千乘載金未滿意。", "釵鈿那爲六宮留，大索民居幾卷地。", "六龍再爲蒼生出，身磨虎牙恬不恤。", "重城突兀萬胡奴，杳隔鑾輿今十日。", "南門赤子日駢闐，爭掬香膏自頂然。", "忿氣爲雲淚爲雨，漫漫白晝無青天。", "太王事狄空金帛，坐使卜年踰八百。", "天聽端在民心耳，蒼蒼誰云九萬隔。", "會看春風擁赭黄，萬民歌呼喜欲狂。", "天宇無塵瞻北極，旄頭落地化頑石。"]'),
('7a699e48-c45e-4b4c-9811-5f53849bf590','寄司錄朝奉兼簡伯壽','鄧肅','宋','宋诗','song-poetry','','[]','老松古柏爭清勁，社稷元勳李文正。',160,'全唐诗/poet.song.101000.json','["老松古柏爭清勁，社稷元勳李文正。", "風流千古照人寒，家有白眉聲益振。", "十年遊宦落窮山，妾無衣帛日號寒。", "只餘凈業磨不去，駸駸筆勢江河寬。", "阿戎作詩更難偶，銀鈎仍復規顔柳。", "蒼藤千尺練敲冰，萬軸晶熒照窗牖。", "明月夜光兩相酬，束笋堆床曾不休。", "公家自有嘔心戒，豈容雕琢損天遊。", "嗟我無文出月脇，惟有蓬窗堆柿葉。", "如何分我三百萬，試掃危言助調燮。"]'),
('8fe5525e-7af0-41f4-8ebd-fd0b0244a4c3','道原惠茗以長句報謝','鄧肅','宋','宋诗','song-poetry','','[]','太丘官清百物無，青衫半作蕉葉枯。',128,'全唐诗/poet.song.101000.json','["太丘官清百物無，青衫半作蕉葉枯。", "尚念故人家四壁，郝原春雪隨雙魚。", "榴火雨餘烘滿院，宿酒攻人劇刀箭。", "李白起觀仙人掌，盧仝欣覩諫議面。", "瓶笙已作魚眼從，楊花傍碾輕隨風。", "擊拂共看三昧手，白雲洞中騰玉龍。", "堆胸磊塊一澆散，乘風便欲款天漢。", "却憐世士不偕來，爲借干將誅趙贊。"]'),
('43dfbea5-0568-4af0-9807-076d55755de1','大雨','鄧肅','宋','宋诗','song-poetry','','[]','夜夜陰雲如潑墨，雨勢欲挽銀河竭。',96,'全唐诗/poet.song.101000.json','["夜夜陰雲如潑墨，雨勢欲挽銀河竭。", "春工十八落泥塗，驟雨誰云不終日。", "魏紫姚黄業已空，嬉遊何足介心胸。", "只恐年年禾黍地，浸淫盡入陽侯宮。", "憑誰爲我呼少女，掃空陰翳開天宇。", "光風霽日暖層霄，坐令六合同歌舞。"]'),
('0634ee28-bb52-452d-ba18-f4d4e123d930','芙蓉軒','鄧肅','宋','宋诗','song-poetry','','[]','我聞幽軒榜芙蓉，琉璃十頃浸新紅。',96,'全唐诗/poet.song.101000.json','["我聞幽軒榜芙蓉，琉璃十頃浸新紅。", "此來踏雪空無有，黄蘆敗葦爭號風。", "却坐明窗弄書史，新詞仍試佳毫楮。", "香風忽到簾幕開，一朵芙蓉却能語。", "我生眼中萬妖嬈，爲渠還作夢魂勞。", "炙牛未數劉師命，驂鸞便學王子喬。"]'),
('cc2144ec-7211-48a8-8aef-96078f73876a','賀朱喬年生日','鄧肅','宋','宋诗','song-poetry','','[]','三春一半入羣芳，朱朱白白競天香。',96,'全唐诗/poet.song.101000.json','["三春一半入羣芳，朱朱白白競天香。", "人間無處著此景，付與長庚作肺腸。", "長庚乘風下天宇，明窗萬卷飽今古。", "筆端著處皆春容，文墨林中三角虎。", "祇今聲價高雲煙，要轍故應歲九遷。", "便當折檻追家世，與國同休億萬年。"]'),
('67e1dd40-80da-44a7-9bc7-eca39d13dbb5','謝虞守送酒','鄧肅','宋','宋诗','song-poetry','','[]','瑟瑟嚴風鼓蓬戶，對話春圍兩亡趣。',96,'全唐诗/poet.song.101000.json','["瑟瑟嚴風鼓蓬戶，對話春圍兩亡趣。", "使君送酒喚春來，坐使漫空翻柳絮。", "雪榭懸知雪未消，一目千里皆瓊瑶。", "詩仙冷坐清入骨，便合九萬摶扶摇。", "迴首故園歸未得，天意留人亦奇絕。", "我今幸得賢主人，公亦未易有此客。"]'),
('3b4fcc1c-36e5-4d08-a401-738523925a79','別虞守','鄧肅','宋','宋诗','song-poetry','','[]','閩山去天惟尺五，傍立怪石如蹲虎。',96,'全唐诗/poet.song.101000.json','["閩山去天惟尺五，傍立怪石如蹲虎。", "點額龍墀萬里歸，未能赤脚走風雨。", "慚愧使君肯相延，十日傾酒如流泉。", "文字興餘亦不惡，紅粧執樂艷神仙。", "明日馮驩出有車，遠借仁風歸故廬。", "不用回頭重引領，行矣商霖到海隅。"]'),
('86c3da42-f9dc-4e93-8c3f-e654fb100658','昭祖送韓文','鄧肅','宋','宋诗','song-poetry','','[]','兩鳥相酬不肯休，欲令日月無旋輈。',192,'全唐诗/poet.song.101000.json','["兩鳥相酬不肯休，欲令日月無旋輈。", "斯文未喪得韓子，掃滅陰霾霽九州。", "古來散文與詩律，二手方圓不兼筆。", "獨渠星斗列心胸，散落毫端俱第一。", "陋巷嗟余四壁空，惡本雕殘付蠹蟲。", "雖得一班時可意，魚魯紛紛意莫窮。", "好古誰似城南杜，平生不矜潤屋富。", "力刊善本妙毫釐，日費千金曾不顧。", "老藤截玉奴側理，千古松煤騰碧烟。", "入手五行俱可下，兀兀短檠忘夜眠。", "我生嗜好隨時改，獨有此書心不解。", "欲酬厚意錐也無，更爲先生作阿買。"]'),
('ae3bf65d-39d4-45ba-a432-326b51f5adcd','偶成','鄧肅','宋','宋诗','song-poetry','','[]','乘風上天款天語，天公不怒雷公怒。',96,'全唐诗/poet.song.101000.json','["乘風上天款天語，天公不怒雷公怒。", "烟霄一斥下人間，豺狼旁午歸無路。", "欲度三吳血盈川，欲泛九江兵闇天。", "扶筇却出徽城去，去天一握五危巔。", "水陸辛勤已足矣，雪花更開九萬里。", "英雄困餓古猶今，莫學兒曹生慍喜。"]'),
('1b3d53db-5b5b-4f82-8d02-9fed0e07ef93','題顯親庵謹次嚴韵','鄧肅','宋','宋诗','song-poetry','','[]','寒蘆敗葦秋風嚴，魏紫姚黄春色妍。',128,'全唐诗/poet.song.101000.json','["寒蘆敗葦秋風嚴，魏紫姚黄春色妍。", "誰能不隨天地轉，開闔自我古無前。", "秋花忽從三月盛，引得好詩來相慶。", "爲見漫空兒女姿，義氣稍回君子正。", "我頃失魚緣鈎直，抱璞未酬不須泣。", "天生我輩豈偶然，但驅百怪歸篇什。", "慚愧梅仙情最親，期我看花三省身。", "已趁春風聊一笑，更倣秋霜不改春。"]'),
('e680cb21-b613-4528-a893-3c4117b44fc1','送思道福唐','鄧肅','宋','宋诗','song-poetry','','[]','狂風一過天如洗，四卷陰雲空萬里。',128,'全唐诗/poet.song.101000.json','["狂風一過天如洗，四卷陰雲空萬里。", "高樓月色三更寒，魚歌相應起寒葦。", "一樽初對謫仙人，只用瀾翻細論文。", "半夜拂衣翩欲往，飄飄逸興凌秋雲。", "破浪扁舟一葉細，問君去去端君意。", "笑言演峽隘心胸，要觀閩海浩無際。", "顧我虀鹽尚泮宮，安得化雲便從龍。", "好景欲觀今未遂，憑君驅入錦囊中。"]'),
('43eb6c70-cb88-4e9c-823c-bbaeda1edf6c','與郭舜欽朝請','鄧肅','宋','宋诗','song-poetry','','[]','成均冷坐窮吞紙，額叩龍墀濱九死。',160,'全唐诗/poet.song.101000.json','["成均冷坐窮吞紙，額叩龍墀濱九死。", "背負琴書偶生還，賴有春風滿故里。", "故里渺居天一隅，因仍蔓草不堪除。", "多謝先生肯遊刃，號令雷霆一掃驅。", "舊弊忽消新慶長，老稚相携紛擊壤。", "坐使牛蹄一泓中，九萬共摶羊角上。", "只恐朝廷急英雄，割雞不用煩屠龍。", "政須太山來壓卵，金闕喚回小令公。", "陋巷嗟余空四壁，餓死平生無枉尺。", "知音今有昌黎公，玉川得卧三竿日。"]'),
('c556d8cf-7c14-4762-bf2d-6acd429c26dc','遣興','鄧肅','宋','宋诗','song-poetry','','[]','醉中飛夢到神清，夜半高樓借水明。',320,'全唐诗/poet.song.101000.json','["醉中飛夢到神清，夜半高樓借水明。", "下瞰寒溪凝水晶，孺子相呼同濯纓。", "樓上天人百寶瓔，瑞色天香充棟楹。", "步雲一曲語春鶯，千山洗空烟霧橫。", "酒醒簾外竹陰行，夜風更爲芭蕉生。", "愁腸起向謫仙呈，夢境憑君指顧成。", "一開後堂花柳盈，香肌可萬六出霙。", "珮玉步蓮不自輕，寒眼那能更指令。", "春葱斜捧玉壺傾，真珠紅滴濃無聲。", "一醉花間豈易營，歸來十日寸心縈。", "蘭亭家風類帝京，爲余亦復出花城。", "柳腰隨風萬里征，安焉不復數歸程。", "坐令鐵心宋廣平，夜揩醉眼賞梅英。", "歌燕舞趙藝更精，遏雲迴雪未可評。", "人間不復數娥嬴，神仙遊戲肉眼驚。", "我生不顧萬鍾榮，對花有酒即蓬瀛。", "高會何須四者并，赤脚亦能寫高情。", "最恨蘇公世公卿，家聲往往九夷傾。", "風流陣中却寢兵，酒甌但借鄰姬擎。", "何日高堂鐘鼓鳴，如我心醉如春酲。"]'),
('12236e5a-ce68-4f2b-93ac-741b6b16bb07','題天慶觀','鄧肅','宋','宋诗','song-poetry','','[]','真人躡身凌紫霞，下憫濁世長咨嗟。',64,'全唐诗/poet.song.101000.json','["真人躡身凌紫霞，下憫濁世長咨嗟。", "崇樓傑閣耀金碧，開闡至道非雄夸。", "仙茅連山可度世，守此規規如井蛙。", "靈雲一笑萬事畢，到今福地空桃花。"]'),
('1f3d571a-4a81-43d4-9b3a-c1701a39bf38','寒梅上李舍人','鄧肅','宋','宋诗','song-poetry','','[]','窮山觸目紛茅葦，此意昏昏誰可洗。',128,'全唐诗/poet.song.101000.json','["窮山觸目紛茅葦，此意昏昏誰可洗。", "竹間忽破一枝梅，對月嫣然耿寒水。", "吟詩索酒滿高堂，穿簾的皪射晶光。", "世上羶葷來不到，翦翦天風吹冷香。", "人言百花睡未起，獨冠羣芳差可喜。", "那知和羹自有期，未用爭雄壓桃李。", "但憐雨雪正濛濛，寒意未舒萬象窮。", "故作選鋒驅殘臘，挽回天地變春風。"]'),
('21420cd7-9dce-46b8-bac0-c2424db41904','送李狀元還朝','鄧肅','宋','宋诗','song-poetry','','[]','元戎簾幕海濱開，謫仙騎鯨天上來。',160,'全唐诗/poet.song.101000.json','["元戎簾幕海濱開，謫仙騎鯨天上來。", "尊前談笑贊籌畫，一洗八郡無氛埃。", "功成揮鞭朝玉闕，九重閶闔開春色。", "要傳天意下人間，翰苑政須萬人傑。", "我今去國已五年，天子令伴黄冠仙。", "邂逅相逢君復去，林泉還我擅雲煙。", "君去上天款天語，莫畏雷霆作强禦。", "人間疾苦欲扣天，天門嵯峨隔雲雨。", "紅巾十萬今已無，致此紅巾本何如。", "撥亂儻知原始末，制梃自可鞭匈奴。"]'),
('0a8ec923-6048-4210-b5e6-c04de8779934','霹靂松','鄧肅','宋','宋诗','song-poetry','','[]','老榦千年如削鐵，蟄龍釀春未肯泄。',64,'全唐诗/poet.song.101000.json','["老榦千年如削鐵，蟄龍釀春未肯泄。", "阿香推車動地來，振起虬髭上天闕。", "砰轟一聲驚倒人，雨勢更挽銀河傾。", "炎洲六月塵生海，一朝化作無邊春。"]'),
('40d84220-a55e-492a-b289-d7f53f6c60d5','題梅齋','鄧肅','宋','宋诗','song-poetry','','[]','江邊蘆葦風颼颼，東君一點破寒愁。',64,'全唐诗/poet.song.101000.json','["江邊蘆葦風颼颼，東君一點破寒愁。", "窗間疏影橫春瘦，枕上冷香尋夢幽。", "夜半竹折驚殘雪，醉起捲簾千山月。", "肺腑洗空龍麝腥，落筆天香鬬清絕。"]'),
('4fb36970-4970-47e5-8b87-9094c1d67775','賀梁溪李先生除右府','鄧肅','宋','宋诗','song-poetry','','[]','虜兵震地喧鼙鼓，黑幟插城遍樓櫓。',256,'全唐诗/poet.song.101000.json','["虜兵震地喧鼙鼓，黑幟插城遍樓櫓。", "蔽空戈甲來如雲，羣盜相隨劇豺虎。", "胡塵漠漠四壁昏，諸將變名竄軍伍。", "十萬兵譟龍德宮，上皇避狄幾無所。", "嗣君匹馬詣行營，朕躬有罪非君父。", "奸臣草表遽書降，身率百官先拜舞。", "那知馮道冷笑渠，立晉猶存中國主。", "翠華竟作沙漠行，望雲頓有關河阻。", "九天宮殿鬰岧嶤，目斷離離變禾黍。", "生靈日夕望中興，猶幸君王自神武。", "相公特起爲蒼生，下視蕭曹無足數。", "詞議雲湧紛盈庭，羣策但以二三取。", "老謀大節數子并，行見犂庭滅金虜。", "立馬常依仗下鳴，日詠杜鵑懷杜甫。", "飛鳥猶尊古帝魂，激烈浩歌來義旅。", "規模共佐李西平，廟貌不移舊鐘簴。"]'),
('6a5ddef2-3533-4325-8204-2694234762f6','上先生','鄧肅','宋','宋诗','song-poetry','','[]','疲馬踏殘月，荷策來泮宮。',128,'全唐诗/poet.song.101000.json','["疲馬踏殘月，荷策來泮宮。", "入門見先生，先生何雍容。", "循循言語能下誘，青蒿因得附長松。", "短檠挑燈一千二百夜，高談雄辯磊落沃胸中。", "吾皇求士苦匆匆，不許先生久卧龍。", "玉鞭斜指長安道，祇緣此去何猶從。", "嗚唏吁，小軒從此冷如水，虀鹽朝暮欣欣爾。", "空留絳帳照孤燈，窗外西風起寒葦。"]'),
('72632558-4a65-4e38-8d81-67bc809f47a2','龍興避難','鄧肅','宋','宋诗','song-poetry','','[]','傍山怪石如蹲虎，絕頂去天無尺五。',128,'全唐诗/poet.song.101000.json','["傍山怪石如蹲虎，絕頂去天無尺五。", "却披叢棘下山腰，丹碧照空飛棟宇。", "道人養道厭塵勞，避世只嫌山不高。", "那知行空老曼倩，竊食不遺王母桃。", "松檜參天門晝閉，碧玉擷蔬飯炊雪。", "百年冷坐無車音，一旦偕來真惡客。", "當知喧寂無殊觀，出世何妨在世間。", "能致吾人師作古，龍興今日始開山。"]'),
('3e511cc7-dc40-4201-ac68-3badf5b5d53b','和明遠喜雨作','鄧肅','宋','宋诗','song-poetry','','[]','絳狗鳴空朱虎攫，神焦鬼爛不堪虐。',128,'全唐诗/poet.song.101000.json','["絳狗鳴空朱虎攫，神焦鬼爛不堪虐。", "自嗟筆力無韓豪，不敢讒風干鼎鑊。", "聞說祥符物外臣，能將念力蘇罷民。", "挽出洞天肩未息，飛雲驅雨已生春。", "曹侯德我詩如洗，無乃采葑遺下體。", "當知此雨非人功，政賴曹溪浩無底。", "君看連天六日陰，檐聲夜和蓬窗吟。", "羲和知師今日去，自行天上約秋霖。"]'),
('ef17d1b2-72de-491b-b7b7-8c627b00bd5b','寄亨甫','鄧肅','宋','宋诗','song-poetry','','[]','晴空當晝棲暘蟲，目林欲焚深甑中。',96,'全唐诗/poet.song.101000.json','["晴空當晝棲暘蟲，目林欲焚深甑中。", "多謝吾君肯相訪，袖中詩句來清風。", "愛主我堪犬馬比，采蕨山巔行餓死。", "豈能五絕比天人，疾讀君詩汗如洗。", "君今師友人中豪，琢磨事業當日高。", "若扣天門自求試，速爲奉天留陸贄。"]'),
('d8c0ef02-e7e7-492a-b492-78839dbecd87','東林一枝庵','鄧肅','宋','宋诗','song-poetry','','[]','世間傑棟俯飛翰，簾旌不動天風寒。',96,'全唐诗/poet.song.101000.json','["世間傑棟俯飛翰，簾旌不動天風寒。", "但得一身自安逸，誰思寒士三萬間。", "東林天下推第一，凈几明窗萬禪客。", "主人幽棲僅一枝，便覺寬容無迫窄。", "一身六尺何足患，蠢動當知俱欲安。", "誰識曹溪一滴許，能令法雨遍塵寰。"]'),
('8c478820-6688-4a6e-9cdd-924ca21b3b54','醉吟軒','鄧肅','宋','宋诗','song-poetry','','[]','淵明句法古無有，頭上幅巾供漉酒。',96,'全唐诗/poet.song.101000.json','["淵明句法古無有，頭上幅巾供漉酒。", "李白豪篇驚倒人，舉目望天不計斗。", "二子風流不可追，公作幽軒爲喚迴。", "長鯨渴興沉江海，錦囊妙句生風雷。", "安得一廛在公側，時時去作孔融客。", "愁腸得酒生和風，也向毫端寫春色。"]'),
('b2e99393-7668-4884-a80a-70222ea3a90c','嘲蛇傷足','鄧肅','宋','宋诗','song-poetry','','[]','責官只得林泉幽，也有曲膂潛相讎。',64,'全唐诗/poet.song.101000.json','["責官只得林泉幽，也有曲膂潛相讎。", "肆毒不知分彼是，後身那解癖春秋。", "我嬰逆鱗龍不怒，誰知蠢蠢敢當路。", "要我迷陽不作難，祇恐壽光劾君去。"]'),
('68798d0f-5663-4b48-aea1-c3b2e9627b88','送丹霞','鄧肅','宋','宋诗','song-poetry','','[]','山壓濃陰勢欲頹，阿香推車振不開。',96,'全唐诗/poet.song.101000.json','["山壓濃陰勢欲頹，阿香推車振不開。", "君來論詩風四起，挽出羲和照九垓。", "別君八年驚電掃，霜髭已失童顔好。", "逝者姑從造物流，吾人一笑初不老。", "明朝飛錫過平津，浩歌歸耕隴上雲。", "巖竇不應藏一滴，要須化作無邊春。"]'),
('f22208e8-bdb5-4ac7-b5cb-516492538679','玩芳亭','鄧肅','宋','宋诗','song-poetry','','[]','蔓草芊芊迷舊圃，日號狐猩走鼯鼠。',128,'全唐诗/poet.song.101000.json','["蔓草芊芊迷舊圃，日號狐猩走鼯鼠。", "世欲去之嗟未能，竭力米鹽汗如雨。", "先生人間第一流，目中萬事無全牛。", "割雞已覺無多子，斬新亭柳作清遊。", "紛紛姚魏爭黄紫，醉眼雖觀心似水。", "但搜佳景付吟魂，吐作新詩爛盈紙。", "慚愧知音太史公，爲榜佳名字畫雄。", "二公連茹歸霄漢，此亭萬古揚清風。"]'),
('1200b162-288b-4f8c-ae73-f111012dae06','小飲','鄧肅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','斷臂一朝續狼肉，楛矢漫空夜相逐。',64,'全唐诗/poet.song.101000.json','["斷臂一朝續狼肉，楛矢漫空夜相逐。", "海鳧亂飛三丈毛，藍田不行四寸玉。", "何如南嶽追祖風，雲間坐致桃李穠。", "笑盡酒船三百斛，醉吹簫管上晴空。"]'),
('01b63047-c4b7-40fb-8540-64fce2fdd52c','質夫和來','鄧肅','宋','宋诗','song-poetry','','[]','我生不顧四壁空，千金買笑醉春風。',192,'全唐诗/poet.song.101000.json','["我生不顧四壁空，千金買笑醉春風。", "半夜酒紅潮玉頰，亭亭秋水影芙蓉。", "作文忽慕元和格，遂入賢關親眉白。", "遽聞皇甫語穿天，淵源蓋是退之客。", "琢句出人數等高，要令天下無英豪。", "擊節一觀百憂失，不覺此身猶布袍。", "平生自足牛蹄水，爲公辟易數百里。", "願得佳句時飛來，此間幸有子期耳。", "雨意朝來猶許重，安得相從恣嘲弄。", "虀鹽充腹燈一螢，兀坐亡聊真夢夢。", "會鞭匹馬城東陬，對床臭味兩相投。", "歸來筆下飽奇怪，不須更事子長遊。"]'),
('bd79752f-db62-4b17-adbc-b635d6bddea0','紫芝和來','鄧肅','宋','宋诗','song-poetry','','[]','雨餘榴火欲燒空，宮槐老翠闇薰風。',192,'全唐诗/poet.song.101000.json','["雨餘榴火欲燒空，宮槐老翠闇薰風。", "即今此景那可恃，忽觀玉露泣芙蓉。", "請公文急出新格，一變茅黄兼葦白。", "坐令鼠輩掃地空，毋使再來相主客。", "異日光芒李杜高，聲價豈但一時豪。", "故應高視空四海，紛紛過眼萬銀袍。", "我生作意遊弱水，蓬萊杳隔三萬里。", "何如平地揖詩仙，一洗從來鄭衛耳。", "期公便作九鼎重，雲水未容扁舟弄。", "漫天霖雨在胸襟，半夜吹作高宗夢。", "鬼方月窟雖殊陬，願治之心輒相投。", "澤民事業無多子，要使人人鼓腹遊。"]'),
('30d86393-3027-4f9a-adf1-0348d38057b5','邂逅宇文','鄧肅','宋','宋诗','song-poetry','','[]','閩山去天餘尺五，漁浦撼舟濱九死。',160,'全唐诗/poet.song.101000.json','["閩山去天餘尺五，漁浦撼舟濱九死。", "臨水登山萬里來，却向春圍飲墨水。", "白雲目斷無飛翰，夜將劍鋏於誰彈。", "世人相馬例嫌瘦，餓死首陽不作難。", "側聞天下有人傑，洗出新詩耿冰雪。", "年來亦復坐文窮，空使品流居第一。", "摳衣浩歌起相從，雨意那憂潑墨濃。", "匆匆對語一笑粲，萬斛窮愁一洗空。", "公今清譽高星斗，我乃棲遲事奔走。", "收拾政賴退之豪，瘦寒不復麾郊島。"]'),
('cc716619-c120-44fd-9bec-4e8c1d5164fa','別施君叔异','鄧肅','宋','宋诗','song-poetry','','[]','泮水儒生急寸祿，白袍干人如立鵠。',160,'全唐诗/poet.song.101000.json','["泮水儒生急寸祿，白袍干人如立鵠。", "爭注蟲魚股置錐，世外語言不到目。", "我嫌人醉還啜醨，常嗟心迹兩相離。", "邂逅得君能我意，筆端聊復出新奇。", "愛君未冠少年郎，語出輒驚鵷鷺行。", "若不紛華替初志，事業他時未易量。", "今被青衫走塵土，滿面春風歸仕路。", "拄笏政可望西山，莫見輶軒腰傴僂。", "我今縶維猶未釋，相思何處訪縱跡。", "爲君時望斗牛間，期君光芒高萬尺。"]'),
('4ce6882e-f62d-489d-9e07-2e6294584696','雨花軒','鄧肅','宋','宋诗','song-poetry','','[]','君不見解空宴坐寂無侶，寶花忽爾窺巖戶。',134,'全唐诗/poet.song.101000.json','["君不見解空宴坐寂無侶，寶花忽爾窺巖戶。", "已將精進聳人天，是用色相旌其苦。", "又不見毗耶居士坐高堂，四落天花趁揮麈。", "若人猶有空可談，真機何處遁天女。", "豐巖寂寂梵王家，誰把幽巖名雨花。", "我知此誠齊人耳，但識解空與毗耶。", "誰知豐巖了無取，口角瀾翻初不語。", "吾宗未出天莫窺，豈復有花可爲雨。"]'),
('4b5bac32-a354-4f8f-850f-f1d39d4c95f6','訪丹霞','鄧肅','宋','宋诗','song-poetry','','[]','煙雲著天無寸空，寒窗瑟瑟夜號風。',160,'全唐诗/poet.song.101000.json','["煙雲著天無寸空，寒窗瑟瑟夜號風。", "浩歌出門何所詣，故人飛錫梵王宮。", "扣門兀坐寂無語，衲破蒙頭面如土。", "逢場聊復觸機鋒，千偈瀾翻疾風雨。", "我生鼻孔自撩天，笑將龍肉比談禪。", "針水相投得吾子，帖肉汗衫今脫然。", "但憐凈業猶詩酒，醉筆時作蛟龍走。", "儻惟語默兩無妨，憑公刻燭聯千首。", "况是雪意政相留，慎勿匆匆撫刀頭。", "明日談笑作春色，同在瓊瑶十二樓。"]'),
('1589adf4-5ce4-49ba-9c06-d808026487d9','戲吳少綝','鄧肅','宋','宋诗','song-poetry','','[]','短檠對君同泮水，虀鹽不給窮吞紙。',96,'全唐诗/poet.song.101000.json','["短檠對君同泮水，虀鹽不給窮吞紙。", "君今載紙連數艘，貧富相懸九萬里。", "崇寧政事先方田，紛紛訟牒亂雲烟。", "祗今列屋飽蟲蠹，官折羊酒壽高年。", "夫子談笑收餘慶，不復塵埃生釜甑。", "便當痛飲天津橋，一網盡呼天下俊。"]'),
('440528ae-d14c-4dc7-baf9-5764df9ed935','寄興國福聖二老','鄧肅','宋','宋诗','song-poetry','','[]','我本窮山采薇蕨，偶上丹霄騎日月。',160,'全唐诗/poet.song.101000.json','["我本窮山采薇蕨，偶上丹霄騎日月。", "雲端不著癡仙人，天公雖笑雷公斥。", "今我在陳糧殆絕，不夢杏漿澆細肋。", "詹成炊飯似摶沙，牛革薦甘真嚼鐵。", "慚愧忘形二禪客，倒屣相迎作禪悅。", "竹萌瀹水瑩瓊瑶，土芝借糟凝琥珀。", "余不供僧僧供余，是事顛倒古所無。", "要知人我兩無有，此飽便當均太虛。", "昨日龍興飛尺書，挽我登山有籃輿。", "試問二師肯俱否，一飽還君欲借渠。"]'),
('b96004c9-6c79-4b5f-a100-26a243e61437','送游教授','鄧肅','宋','宋诗','song-poetry','','[]','世事齪齪饑寒語，恩怨嘈然相爾汝。',160,'全唐诗/poet.song.101000.json','["世事齪齪饑寒語，恩怨嘈然相爾汝。", "蠅營狗苟端可憐，不見秋風黄鵠舉。", "君看三山夜降神，鍾成人傑超不羣。", "堂堂勁氣薄霄漢，藐視四海豈無人。", "簞瓢陋巷誰知己，自足一樽釣秋水。", "誰使文星射紫微，天書遂敕川龍起。", "笑來南國開絳帳，議論清明森萬象。", "已令爐錘無頑金，九萬却摶羊角上。", "飄飄歸興凌秋空，莫恨丁寬易已東。", "天生若人不私子，當令四海遍春風。"]'),
('8fbd1529-7198-4e12-bb65-87d98c040b5d','廬山','鄧肅','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','平生作意廬山遊，往來却貪吳越舟。',64,'全唐诗/poet.song.101000.json','["平生作意廬山遊，往來却貪吳越舟。", "陛下許臣鞭匹馬，芒鞋因得款清幽。", "是時六月蒸炎暑，六合黄塵空一雨。", "上方冷翠襲衣襟，便覺笑談在天宇。"]'),
('e55d23ab-6ca8-4a4b-af9f-a379b2f11f62','和謝吏部鐵字韵三十四首 紀德十一首 其一','鄧肅','宋','宋诗','song-poetry','','[]','切切寒蟲常在耳，未識詞源萬斛水。',96,'全唐诗/poet.song.101000.json','["切切寒蟲常在耳，未識詞源萬斛水。", "忽開玉軸見奇文，光怪摩空亂眸子。", "太傅江左風流人，靈運在家元不嗔。", "家世千年今復振，落筆飄飄語更真。", "頓足忘言驚妙絕，欲續貂蟬恨才拙。", "鉛刀那敢望神劍，舒屈無方豈常鐵。"]'),
('37ac019f-0ba3-423e-b2f8-eb82a623c5c4','和謝吏部鐵字韵三十四首 紀德十一首 其二','鄧肅','宋','宋诗','song-poetry','','[]','窮居如將豆塞耳，一泓自足牛蹄水。',96,'全唐诗/poet.song.101000.json','["窮居如將豆塞耳，一泓自足牛蹄水。", "那知鄰境有人豪，笑觀造化但兒子。", "筆端萬字驚倒人，春色秋風隨喜嗔。", "一讀錦囊殆仙去，欲借雲軿遂朝真。", "更當負笈慰愁絕，憑公一掃平生拙。", "門人益親自得回，會觀踏破門限鐵。"]'),
('716392ed-6f5c-45a3-b716-05edf972baec','和謝吏部鐵字韵三十四首 紀德十一首 其三','鄧肅','宋','宋诗','song-poetry','','[]','世上區區蠅狗耳，不復解纓濯清水。',96,'全唐诗/poet.song.101000.json','["世上區區蠅狗耳，不復解纓濯清水。", "只知貪雀不留珠，可憐認賊翻爲子。", "珍重謝公天下人，冷居林泉曾不嗔。", "雲煙萬木觀不足，却把新詩爲寫真。", "高節凌雲亦奇絕，不綰六印未爲拙。", "何妨笑學杜陵翁，只有布衾冷似鐵。"]'),
('3fceb16c-d130-4b49-b091-0c3c9eeae25b','和謝吏部鐵字韵三十四首 紀德十一首 其四','鄧肅','宋','宋诗','song-poetry','','[]','仕途例皆諂笑耳，隨盤方圓無定水。',96,'全唐诗/poet.song.101000.json','["仕途例皆諂笑耳，隨盤方圓無定水。", "前年天子思奇才，霜臺曾擢古君子。", "泛觀中外儻非人，髮上衝冠聊一嗔。", "那顧城狐并社鼠，好惡無私喜怒真。", "底事年來迹又絕，笑遁林泉似藏拙。", "憑誰去斬佞臣頭，請公速鑄楚山鐵。"]'),
('1701a7c2-978a-4798-82bd-7f3ca4f38959','和謝吏部鐵字韵三十四首 紀德十一首 其五','鄧肅','宋','宋诗','song-poetry','','[]','四海紛紛箏笛耳，誰識子期志流水。',96,'全唐诗/poet.song.101000.json','["四海紛紛箏笛耳，誰識子期志流水。", "韵高調古自難酬，得意政須副墨子。", "我公聲價第一人，積薪居上笑不嗔。", "但將佳句妙今古，逝變雕蟲返太真。", "孟軻嘗續吾道絕，功與神禹論工拙。", "先生今復迴狂瀾，豈減旌陽柱鑄鐵。"]'),
('279e9f5c-6a88-4094-89a8-daf33c971a39','和謝吏部鐵字韵三十四首 紀德十一首 其六','鄧肅','宋','宋诗','song-poetry','','[]','引領門牆數舍耳，劍之水源自樵水。',96,'全唐诗/poet.song.101000.json','["引領門牆數舍耳，劍之水源自樵水。", "裹糧問道嗟未能，參前倚衡見夫子。", "自笑昔爲塵土人，春狂時逐賣符嗔。", "年來懶惰百事廢，洗空人僞惟葆真。", "更餘凈業磨未絕，强繼彌明不知拙。", "豈是螳螂敢當車，貘獸從來食銅鐵。"]'),
('d7656357-7ad2-4e70-a263-89c8bdc2f9a9','和謝吏部鐵字韵三十四首 紀德十一首 其七','鄧肅','宋','宋诗','song-poetry','','[]','李白嘗言人有耳，不當徑洗潁川水。',96,'全唐诗/poet.song.101000.json','["李白嘗言人有耳，不當徑洗潁川水。", "男兒出處自有時，何須銳意楚狂子。", "公今無意世間人，北山有靈定不嗔。", "天子政作唐虞計，谷口那留鄭子真。", "佇觀大手稱奇絕，致君却笑前賢拙。", "坐使梯航到鬼方，來尋九州貢璆鐵。"]'),
('b84ebb95-e726-4b0b-b5e8-0496cec894f6','和謝吏部鐵字韵三十四首 紀德十一首 其八','鄧肅','宋','宋诗','song-poetry','','[]','眼中儒生聊爾耳，僅免春闈飲墨水。',96,'全唐诗/poet.song.101000.json','["眼中儒生聊爾耳，僅免春闈飲墨水。", "可憐四海萬青衿，却愧建安六七子。", "誰似丘侯獨可人，日無千篇即怒嗔。", "腐語陳言俱掃滅，奇文秀句出天真。", "虎頭固已稱詩絕，更逢安石分工拙。", "新詩爲侯特發揮，照人之明鑑磨鐵。"]'),
('68b4a850-e523-4ad9-a41a-9bfddaccd1dd','和謝吏部鐵字韵三十四首 紀德十一首 其九','鄧肅','宋','宋诗','song-poetry','','[]','結交要在相知耳，趣向不殊水投水。',96,'全唐诗/poet.song.101000.json','["結交要在相知耳，趣向不殊水投水。", "請看丘侯對謝公，箭鋒相契無多子。", "丘侯平日論律人，詳及謝公喜與嗔。", "一得新詩即傳借，許久誇談今見真。", "車馬爭看紛不絕，新詩那簡茅檐拙。", "脫腕供人嗟未能，安得畢昇二板鐵。"]'),
('5b0e850a-a1f3-460a-876c-8150166bc0f0','和謝吏部鐵字韵三十四首 紀德十一首 其一○','鄧肅','宋','宋诗','song-poetry','','[]','三吳惡少飛綠耳，殺人如麻壅流水。',96,'全唐诗/poet.song.101000.json','["三吳惡少飛綠耳，殺人如麻壅流水。", "餘風往往到七閩，魚爛鳥驚父離子。", "紛然回顧作流人，我侯正色聊一嗔。", "坐使倉黄萬老弱，復歌太平養性真。", "百弊紛紛俱杜絕，四境無虞安樸拙。", "方信哲夫自成城，不須十仞堅削鐵。"]'),
('6408131a-1398-47fd-893b-b6e262724ed1','和謝吏部鐵字韵三十四首 紀德十一首 其一一','鄧肅','宋','宋诗','song-poetry','','[]','忘心政須麯糵耳，醉仙如吸百川水。',96,'全唐诗/poet.song.101000.json','["忘心政須麯糵耳，醉仙如吸百川水。", "男兒不復問聖賢，杯酒力辭真豎子。", "我侯度量壓千人，不滿金鍾却怒嗔。", "酒酣那復迷朱碧，苗莠猶分僞與真。", "人言狂藥要須絕，恐潰肺腸語亦拙。", "那知真氣不可侵，烏府如今肝是鐵。"]'),
('e70c0858-2d6f-4fb4-bec1-9304340c0f7e','和謝吏部鐵字韵三十四首 邑官有和者亦以詩寄之其人自云禦方寇有功','鄧肅','宋','宋诗','song-poetry','','[]','寂寞相如四壁耳，陋巷蕭然窮飲水。',96,'全唐诗/poet.song.101000.json','["寂寞相如四壁耳，陋巷蕭然窮飲水。", "雖似退之厭權門，時作封人慕君子。", "慚愧知音個中人，近前不學丞相嗔。", "掀髯抵掌論今古，肺腑恢然笑語真。", "頃余學問非三絕，操瑟干齊謀更拙。", "棲遲何以酬己知，吾道不移硯鑄鐵。"]'),
('da86981f-9b43-498f-843b-12670be96f92','和謝吏部鐵字韵三十四首 丘宰生日二首 其一','鄧肅','宋','宋诗','song-poetry','','[]','律管才吹九寸耳，帝遣玄冥下司水。',96,'全唐诗/poet.song.101000.json','["律管才吹九寸耳，帝遣玄冥下司水。", "天度稍多百四十，愛日差長斗建子。", "已剝羣陰驅小人，四海熙熙語復嗔。", "因闢金關謫太白，不許天庭久練真。", "太白塵緣固未絕，肯將天巧形世拙。", "會施霖雨滿人間，歸對千年忘恙鐵。"]'),
('fd303440-a23a-4454-828d-5c57a8306de6','和謝吏部鐵字韵三十四首 丘宰生日二首 其二','鄧肅','宋','宋诗','song-poetry','','[]','陽復朋來七日耳，黎明當動有泉水。',96,'全唐诗/poet.song.101000.json','["陽復朋來七日耳，黎明當動有泉水。", "陰陰寒谷未生春，天閔斯民如赤子。", "遂因天下生奇人，俾歌襦袴無怨嗔。", "朅來割雞多暇日，逸韵飄飄騰九真。", "瓊室瑶池津不絕，冷笑人間衛生拙。", "三竊蟠桃顔益童，那復虬髯面如鐵。"]'),
('11940299-e7b2-48db-8056-fd96d3d92c52','和謝吏部鐵字韵三十四首 和謝吏部','鄧肅','宋','宋诗','song-poetry','','[]','昔年怨聲常滿耳，紛紛女巫未沉水。',96,'全唐诗/poet.song.101000.json','["昔年怨聲常滿耳，紛紛女巫未沉水。", "天教我侯慰遠人，坐令盜賊化君子。", "期年仁政遍人人，撫之如子不須嗔。", "吏民欲欺亦不忍，出言洞見胸中真。", "要圖書問久已絕，人皆巧中渠寧拙。", "優遊黄卷有餘歡，此志不回端截鐵。"]'),
('fc21a472-970f-4be7-af43-96b39ee532e7','和謝吏部鐵字韵三十四首 自敘三首 其一','鄧肅','宋','宋诗','song-poetry','','[]','瑟瑟霜風夜聒耳，小院枕衾如潑水。',96,'全唐诗/poet.song.101000.json','["瑟瑟霜風夜聒耳，小院枕衾如潑水。", "夜清火冷不成眠，起就短檠閱諸子。", "掩卷嗟嗟今古人，遺風可喜仍可嗔。", "風日相憐紛無已，一笑玄之妄亦真。", "我今是非兩俱絕，百巧百中不如拙。", "寂然無復一念邪，那有黄冠下鞭鐵。"]'),
('3c8de159-9490-4a6a-b8f5-9a1e7f4e7cd8','和謝吏部鐵字韵三十四首 自敘三首 其二','鄧肅','宋','宋诗','song-poetry','','[]','惡聲不入伯夷耳，嚴陵拂袖釣寒水。',96,'全唐诗/poet.song.101000.json','["惡聲不入伯夷耳，嚴陵拂袖釣寒水。", "古來豪傑例幽居，佩𩍚肯隨舟人子。", "造化爐中忽爲人，笑笑隨緣又何嗔。", "細語粗言俱入妙，醉中不必更陶真。", "年來三復韋編絕，得趣無多一味拙。", "物外翛然我已仙，不愁石髓堅如鐵。"]'),
('9c4e3f49-06cf-43fe-81cb-1dc256dbd340','和謝吏部鐵字韵三十四首 自敘三首 其三','鄧肅','宋','宋诗','song-poetry','','[]','萬物紛紛一馬耳，百川不同均一水。',96,'全唐诗/poet.song.101000.json','["萬物紛紛一馬耳，百川不同均一水。", "不將彼是作殊觀，坐使須彌納芥子。", "李白高視空無人，審言更作牙官嗔。", "可憐紙上較輕重，畫餅象龍俱未真。", "我師宣尼四病絕，抱甕寧作漢陰拙。", "萬變紛紛不敢侵，真室何須樞楗鐵。"]'),
('c1784b04-0a04-4dbc-9343-3b5c0968ad81','和謝吏部鐵字韵三十四首 遊山三首 其一','鄧肅','宋','宋诗','song-poetry','','[]','高巖去天尺五耳，下飛瀑布千尋水。',96,'全唐诗/poet.song.101000.json','["高巖去天尺五耳，下飛瀑布千尋水。", "山間瘦竹映枯松，歲寒相對凜君子。", "杖藜去去尋幽人，剝啄扣門公勿嗔。", "凡骨膻腥儻不厭，願供薪水看脩真。", "高人隱几語言絕，大巧深藏端若拙。", "無乃誤遊天目山，偶見唐公冠带鐵。"]'),
('9e9cc59c-873c-45da-97fa-72c1db714bc5','和謝吏部鐵字韵三十四首 遊山三首 其二','鄧肅','宋','宋诗','song-poetry','','[]','人生要在行樂耳，四化相磨逝流水。',96,'全唐诗/poet.song.101000.json','["人生要在行樂耳，四化相磨逝流水。", "溪山佳處飽遨遊，莫爲羶葷親俗子。", "解龜誰顧謫仙人，玉局題牆亦遭嗔。", "世人例作葉公解，但喜畫龍誰識真。", "何如便與塵寰絕，醉倒莫嫌茅店拙。", "青驄門外繫垂楊，旋乞青禾剉白鐵。"]'),
('ccfa3963-2f60-4cd5-824a-840c6147db2e','和謝吏部鐵字韵三十四首 遊山三首 其三','鄧肅','宋','宋诗','song-poetry','','[]','門前如市不入耳，忘言隱几心如水。',96,'全唐诗/poet.song.101000.json','["門前如市不入耳，忘言隱几心如水。", "紛華時逐長安兒，清爽何似毛錐子。", "我雖事業未如人，天公不等吾弗嗔。", "獨步高山尋兀室，默坐燒香已悟真。", "世事繽紛俱謝絕，叩角自歌愚且拙。", "誰暇投書追賈誼，更憂銅弊雜鉛鐵。"]'),
('bd9970b1-0a95-411b-9096-4967ad892b52','和謝吏部鐵字韵三十四首 對酒二首 其一','鄧肅','宋','宋诗','song-poetry','','[]','世上紛華蟻穴耳，東流不作西歸水。',96,'全唐诗/poet.song.101000.json','["世上紛華蟻穴耳，東流不作西歸水。", "號寒那用學孟郊，捉月要須追李子。", "一樽忽爾逢故人，高談往往鬼神嗔。", "人間目下多忌諱，忘形惟有醉鄉真。", "但得如意酒不絕，四壁莫愁生事拙。", "鑄成此錯吾安之，何妨與費數州鐵。"]'),
('a16c20c7-521d-4c60-b2a9-acfbf9e2d1d6','和謝吏部鐵字韵三十四首 對酒二首 其二','鄧肅','宋','宋诗','song-poetry','','[]','八斗一傾聊熱耳，開匣時觀三尺水。',96,'全唐诗/poet.song.101000.json','["八斗一傾聊熱耳，開匣時觀三尺水。", "指天喝月使倒行，揚波直欲斬蛟子。", "安得知音吾黨人，相看青眼不余嗔。", "笑驅八蠻有奇策，開懷聊與話誠真。", "可憐吐哺風流絕，乞巧未遑姑守拙。", "坐觀明月侵蝦蟆，空使玉川懷寸鐵。"]'),
('9f3c73cc-324f-48b5-92bb-a0a09843e5fa','和謝吏部鐵字韵三十四首 送成彥尉邵武三首 其一','鄧肅','宋','宋诗','song-poetry','','[]','萬竅于喁風割耳，梅影橫斜耿煙水。',96,'全唐诗/poet.song.101000.json','["萬竅于喁風割耳，梅影橫斜耿煙水。", "殺雞爲黍政追隨，七峰共作隱君子。", "忽舉陽關餞行人，去去莫愁官長嗔。", "但知所領馬曹似，清談更覺子猷真。", "谷風嘗譏朋友絕，子貢毋輕原憲拙。", "期公鴻雁不空回，開緘八行劃如鐵。"]'),
('8df15972-87d1-432a-9efa-7d3e65e11c1f','和謝吏部鐵字韵三十四首 送成彥尉邵武三首 其二','鄧肅','宋','宋诗','song-poetry','','[]','汗血神駒卓錐耳，去似蒼崖决積水。',96,'全唐诗/poet.song.101000.json','["汗血神駒卓錐耳，去似蒼崖决積水。", "據鞍年少笑西征，神仙中人梅氏子。", "平生胸抱不由人，點額再歸曾未嗔。", "儀舌尚存斯足矣，卞玉那愁無識真。", "一官聊續箕裘絕，登山莫厭芒鞋拙。", "會使狗偷掃地無，不須蜂蠆揮鉅鐵。"]'),
('8487adfd-3c7c-4e07-9629-d277102a03aa','和謝吏部鐵字韵三十四首 送成彥尉邵武三首 其三','鄧肅','宋','宋诗','song-poetry','','[]','山頭枯木半生耳，山下琉璃剪碧水。',96,'全唐诗/poet.song.101000.json','["山頭枯木半生耳，山下琉璃剪碧水。", "登山臨水兩超然，刻燭千篇對夫子。", "我生也是不羈人，白眼望天人共嗔。", "相逢賴有知音鮑，揮麈不疑咳唾真。", "子今更與竹林絕，我獨凄然守株拙。", "望公聲譽騰九天，不惟去作錚錚鐵。"]'),
('aab980d0-d052-4090-992a-7ba249f3b7e7','和謝吏部鐵字韵三十四首 別僧永肩','鄧肅','宋','宋诗','song-poetry','','[]','號寒啼饑自聒耳，火中蓮花那著水。',96,'全唐诗/poet.song.101000.json','["號寒啼饑自聒耳，火中蓮花那著水。", "超然不復顧塵寰，空色兩冥舍利子。", "冠巾賈島齒平人，當時僅免退之嗔。", "何如伯升雲水去，萬劫不磨一點真。", "公今更恐情難絕，泛作飛蓬謀未拙。", "挽袖牽裳浩不迴，當知若人是真鐵。"]'),
('ecb44e33-2ef6-47a9-8bad-b838a36be29d','和謝吏部鐵字韵三十四首 謝楊休三首 其一','鄧肅','宋','宋诗','song-poetry','','[]','人生相值梗萍耳，無酒投錢亦飲水。',96,'全唐诗/poet.song.101000.json','["人生相值梗萍耳，無酒投錢亦飲水。", "况公家世足風流，封胡羯末又賢子。", "匹馬來尋物外人，坐上無氈寒不嗔。", "傾蓋相逢已如故，洗空機械情更真。", "公今在陳糧屢絕，惡圓喜方我尤拙。", "窮愁相守兩蕭然，富驕何事如意鐵。"]'),
('ece55be7-d3c3-4197-abcb-bb7e392150cc','和謝吏部鐵字韵三十四首 謝楊休三首 其二','鄧肅','宋','宋诗','song-poetry','','[]','半夜絲簧紛養耳，舞袖香風散沉水。',96,'全唐诗/poet.song.101000.json','["半夜絲簧紛養耳，舞袖香風散沉水。", "高堂嬉笑坐生春，不誦式微驚遊子。", "孟公投轄雖知人，故鄉千里兒曹嗔。", "毅然竟把刀頭舞，百日夢歸今日真。", "依前瘦馬登高絕，未應却笑此行拙。", "邑人脂膏子弗求，况是丘侯帽無鐵。"]'),
('ecd0cac1-d14a-4e52-99fd-b418eb5f32fe','和謝吏部鐵字韵三十四首 謝楊休三首 其三','鄧肅','宋','宋诗','song-poetry','','[]','一歲無多數日耳，歸心應逐東流水。',96,'全唐诗/poet.song.101000.json','["一歲無多數日耳，歸心應逐東流水。", "遥想解鞍在於門，滿室生春舞妻子。", "明朝去拜絳帷人，遲遲他邦冀勿嗔。", "願及散才求入社，寓詩千里欲尋真。", "醫門不與多病絕，無鹽自獻那羞拙。", "誰知此質非良金，政須乃翁爲點鐵。"]'),
('bddd36a9-acda-4084-a312-d74a988a2c0b','和謝吏部鐵字韵三十四首 呈幾叟儀曹四首 其一','鄧肅','宋','宋诗','song-poetry','','[]','管中窺豹一斑耳，敢對江海更言水。',96,'全唐诗/poet.song.101000.json','["管中窺豹一斑耳，敢對江海更言水。", "賴公不作揚雄尾，舞雩曾許隨童子。", "綈袍至今念故人，世人欲殺渠不嗔。", "更將妙語爲高價，坐令玉表欲侔真。", "期公終始不相絕，回愚參魯余亦拙。", "異時報德但脩身，那用張良袖中鐵。"]'),
('69195974-fff6-40fa-a7e0-011dadaa5233','和謝吏部鐵字韵三十四首 呈幾叟儀曹四首 其二','鄧肅','宋','宋诗','song-poetry','','[]','世上乞憐帖雙耳，得失毫芒汗流水。',96,'全唐诗/poet.song.101000.json','["世上乞憐帖雙耳，得失毫芒汗流水。", "轅駒厠鼠端可憐，笑殺物外奇男子。", "先生眼中無可人，將軍污足渠亦嗔。", "儻欲眠時遣客去，兩忘物我淵明真。", "世間勢位日懸絕，不能變渠平日拙。", "政如强弓五十步，無力可貫青唐鐵。"]'),
('74097ffa-96cb-4689-aab5-f285e9102100','和謝吏部鐵字韵三十四首 呈幾叟儀曹四首 其三','鄧肅','宋','宋诗','song-poetry','','[]','嶺雲去天一握耳，取死一分山下水。',96,'全唐诗/poet.song.101000.json','["嶺雲去天一握耳，取死一分山下水。", "不辭舟車千里來，賴有陳蕃知孺子。", "當堂得酒觴故人，醉倒花前夜不嗔。", "我來一見欣如故，險語聊攄肺腑真。", "安得眼邊萬事絕，與君千首較工拙。", "樂死初無鍤自隨，那學祠東墓費鐵。"]'),
('28bb092d-ecf7-436b-9d35-290fc8f52c05','和謝吏部鐵字韵三十四首 呈幾叟儀曹四首 其四','鄧肅','宋','宋诗','song-poetry','','[]','忽忽百年石火耳，偃鼠不踰一腹水。',96,'全唐诗/poet.song.101000.json','["忽忽百年石火耳，偃鼠不踰一腹水。", "胡椒百斛何爲哉，簞瓢便可安顔子。", "君看世間容悅人，脅肩摇尾恐人嗔。", "所得僅能毛髮許，抵掌無由一笑真。", "期公便與此曹絕，折脚鐺中歸養拙。", "富貴鼎來即應之，鄂公未遇姑冶鐵。"]'),
('175487f7-9af9-49f4-9346-f078a74974c2','劉忠顯挽詞','鄧肅','宋','宋诗','song-poetry','','[]','城頭皂幟作雲飛，城中不縱胡馬嘶。',256,'全唐诗/poet.song.101000.json','["城頭皂幟作雲飛，城中不縱胡馬嘶。", "虎狼那顧百萬衆，政期生載人傑歸。", "天王遣公赴狂虜，胡奴列拜聽奇語。", "軍中相慶得左車，便覺笑談混天宇。", "先生一笑凜長虹，此膝那屈穹廬中。", "平生數奇似李廣，自許孤忠如魯公。", "氈帳歸來眥欲裂，北望紫微湮涕血。", "更期結草報君王，夜半無人徑自絕。", "城門初開聞訃書，參騫哭往萬人俱。", "義色忠軀略不變，忠言凜凜在襟裾。", "當時中國滿朱紫，不臣女真即臣楚。", "聞公高節端不回，身雖亡恙氣先死。", "英風吹到新冕旒，天恩夜破九泉幽。", "佳城可葬不可沒，時有紅光上斗牛。", "我昔從公子弟列，欲報公知效公節。", "公騎箕尾我誰依，獨上山巔采薇蕨。"]'),
('33930539-e4f4-41fa-b862-585b24dbee06','寄德裕縣丞','鄧肅','宋','宋诗','song-poetry','','[]','世人齪齪例卑嘶，槍榆不識南冥飛。',128,'全唐诗/poet.song.101000.json','["世人齪齪例卑嘶，槍榆不識南冥飛。", "邂逅逢公能可意，笑呼文舉作羣兒。", "扁舟十日繫楊柳，未忍憤然誇疾走。", "官長雖嗔渠不聞，且覓吾徒絕詩酒。", "笑談便覺無樊籠，勝景况復煩天公。", "眼前突兀萬銀屋，河伯欲以山爲宮。", "期公定非噲等伍，愛公高氣塞寰宇。", "此行要須上九天，利磨干將斬張禹。"]'),
('2b1a0caf-9877-4c83-9462-808d37bd6f64','再韵明復和來','鄧肅','宋','宋诗','song-poetry','','[]','男兒匹馬追風嘶，朝燕暮越去如飛。',128,'全唐诗/poet.song.101000.json','["男兒匹馬追風嘶，朝燕暮越去如飛。", "談笑功名在鐘鼎，卵破草折驅胡兒。", "悲吟誤學愚溪柳，落筆幸無龍蛇走。", "詩成不直水一杯，誰解金龜與換酒。", "能言嗟我閉雕籠，九萬扶摇政屬公。", "好振雷威養霖雨，要須奏賦未央宮。", "遊戲詩壇整部伍，筆鋒光怪橫天宇。", "異時請賡七月篇，惡食卑宮贊神禹。"]'),
('12faf0bf-a9b5-4a66-b070-d491377b3289','口占','鄧肅','宋','宋诗','song-poetry','','[]','白鶴一去斷消息，白鶴嶺高高無極。',64,'全唐诗/poet.song.101000.json','["白鶴一去斷消息，白鶴嶺高高無極。", "仙人望汝久不歸，珠花撩亂瑶海碧。", "當時同伴有飛鸞，雪浪掀天翻綵翼。", "世間千歲會重來，過眼不須尋鳥跡。"]'),
('d7a26e33-5391-4765-9b10-cb55bf8bb697','送李君上洞天','鄧肅','宋','宋诗','song-poetry','','[]','北風于喁萬竅號，落雪紛紛燖鵠毛。',128,'全唐诗/poet.song.101000.json','["北風于喁萬竅號，落雪紛紛燖鵠毛。", "好向高堂護帷幕，新醪入臉殷春桃。", "居士何爲囂不顧，叩戶長歌辭我去。", "行行逸興高白雲，千里江山入芒屨。", "問君無乃急所求，笑指南安作勝遊。", "南安老師初不死，一聞消息即歸休。", "嗟我平生污詩酒，未能赤脚走巖竇。", "在家自得忘家禪，託問老師印可否。"]'),
('1b7852cf-3267-49fd-8819-80509af7ca72','戲天啟作時文','鄧肅','宋','宋诗','song-poetry','','[]','君不見晉陽作垣期自固，中藏荻蒿勁箘簵。',67,'全唐诗/poet.song.101000.json','["君不見晉陽作垣期自固，中藏荻蒿勁箘簵。", "知音會遇張孟談，安趙有才終一顧。", "人生會遇自有時，兩股何須欲置錐。", "快將好景供詩酒，嗟嗟戚戚非男兒。"]'),
('03e8633a-946b-41f8-9c35-a34f37aa1bd4','哭施叔异','鄧肅','宋','宋诗','song-poetry','','[]','天上樓成求俊筆，今古共嗟李長吉。',128,'全唐诗/poet.song.101000.json','["天上樓成求俊筆，今古共嗟李長吉。", "那知施侯更可憐，只向人間二十一。", "平生疾惡端如讎，高視青衫氣橫秋。", "豈惟落筆動驚俗，政事入眼無全牛。", "汗血共期千里足，狂風忽已摧秀木。", "生前萬事且置之，白頭老母將焉屬。", "管鮑交情我最深，訃來一慟幾失音。", "相思通昔不作夢，對床蟋蟀更秋吟。"]'),
('f22d581a-99de-4824-9673-cc2abc98cdfa','招成老','鄧肅','宋','宋诗','song-poetry','','[]','萬竅于喁北風烈，烏雲貼地欲飛雪。',96,'全唐诗/poet.song.101000.json','["萬竅于喁北風烈，烏雲貼地欲飛雪。", "醉乘一葉上玻璃，忽霽陰威行夜月。", "鳳凰山頭想大顛，芒鞋竹杖弄清泉。", "胸中得句自春色，散入草木騰雲煙。", "安得今宵對揮麈，快然別作二歲語。", "遥知今吾非故吾，便當刻燭追風雨。"]'),
('361de55c-4bcf-4426-8628-355083ff469f','送成材','鄧肅','宋','宋诗','song-poetry','','[]','伯夷自甘首陽蕨，商臣不戴周日月。',159,'全唐诗/poet.song.101000.json','["伯夷自甘首陽蕨，商臣不戴周日月。", "那知世人冷笑渠，却言馮道有全節。", "紛紛過眼萬飛蚊，何如閉目日飲醇。", "議論不從流俗變，吾宗賴有謫仙人。", "謫仙品流居第一，射策王庭恣狂直。", "不知天上聞不聞，見說奸臣俱辟易。", "秋風鞭馬衫藍，一官聊渡試江南。", "羣從相從得髯尹，家學當須與劇談。", "江南風月歸詩酒，二陸相從真得友。", "無人肯伴栟櫚狂，爲我喚回脫帽張。"]'),
('3062d17f-c45d-4c4d-b360-7ea5e854e14e','避賊引','鄧肅','宋','宋诗','song-poetry','','[]','羽檄星馳暴客起，西望烽烟無百里。',160,'全唐诗/poet.song.101000.json','["羽檄星馳暴客起，西望烽烟無百里。", "夜半驚呼得漁舠，老稚相携三百指。", "蠖屈蛇盤破蓬底，忽欲騫身風刮耳。", "沙汀𫇢岸少依劉，萬斛愁情空一洗。", "迴思當年侍玉皇，禁垣夜直宮漏長。", "驅馳誰謂遽如許，客枕不安雲水鄉。", "前日蹇驢衝火烈，今此扁舟壓殘雪。", "隆暑祁寒欲少休，鉦鼓迫人如地裂。", "草廬安得無卧龍，奉天政賴陸宣公。", "憑誰急呼人傑起，使我叩角歌堯風。"]'),
('d6493b01-a012-4103-8e86-662b8153e626','次韵師皋','鄧肅','宋','宋诗','song-poetry','','[]','平生論兵輕白起，端欲採芝追甪里。',160,'全唐诗/poet.song.101000.json','["平生論兵輕白起，端欲採芝追甪里。", "誰遣聲名到人間，役役十年空血指。", "天狗墮地嗟未已，雷聲屢迫君王耳。", "閩山今復暗旌旗，四望長安淚如洗。", "羨君好古慕羲皇，品流不減劉真長。", "舍我帡幪得甘寢，徬徨忽在無何鄉。", "安得大明如火烈，坐令鼠輩消春雪。", "六合內外還桑田，乾坤不容異姓裂。", "看君躣馬如遊龍，醉中脫帽造王公。", "高堂請志中興事，吉甫作誦穆清風。"]'),
('7a9a0ccd-e0a9-4bf9-929d-056a6a15440a','聚星行','鄧肅','宋','宋诗','song-poetry','','[]','昴星下天扶漢德，長庚乃向開元謫。',96,'全唐诗/poet.song.101000.json','["昴星下天扶漢德，長庚乃向開元謫。", "光芒相照數百年，一尊不得聞風月。", "何如今日出城闉，高堂共享無邊春。", "風流皆在煙霞表，不數當年荀與陳。", "江湖我今方卷舌，君等上天環北極。", "箕斗虛名不必多，要斥旄頭作頑石。"]'),
('b3e42ca3-4217-4500-bcc9-4bfacda8bf0b','寄李狀元','鄧肅','宋','宋诗','song-poetry','','[]','渡頭送君泛小舟，絲絲細雨織寒愁。',64,'全唐诗/poet.song.101000.json','["渡頭送君泛小舟，絲絲細雨織寒愁。", "自聞君來天亦喜，急掃陰霾霽九州。", "聚星高會古難續，也欲從君勤秉燭。", "期君指顧蘇甌閩，一笑春風不忍獨。"]'),
('ddb77361-ad32-4bd8-b4f6-5449f39910e9','送張巨源','鄧肅','宋','宋诗','song-poetry','','[]','我頃天上遭雷斥，萬里南歸弄泉石。',96,'全唐诗/poet.song.101000.json','["我頃天上遭雷斥，萬里南歸弄泉石。", "慚愧張侯著眼看，詩卷光芒射奎壁。", "一朝逸氣見眉間，浩歌依劉出閩山。", "渠今得客君得主，寧復回首更悲酸。", "陰雨初生腐草翼，破併行空夜的皪。", "何時歸伴栟櫚狂，一吐長虹貫白日。"]'),
('4c3d08f6-970e-47c0-a704-3977fb6f31c3','送呂友善','鄧肅','宋','宋诗','song-poetry','','[]','火雲燒空汗如雨，江北江南俱豺虎。',96,'全唐诗/poet.song.101000.json','["火雲燒空汗如雨，江北江南俱豺虎。", "君侯不顧溪山幽，鞭馬一朝去莫禦。", "挽君少竢秋風清，君言倚門有雙親。", "千里歸從綵衣舞，死生不計萬鍾輕。", "過眼紛紛青與紫，顛倒重輕真可鄙。", "憑君天上整乾坤，自古忠臣多孝子。"]'),
('1609944b-e24f-4605-8181-b83da7b9cb37','黄楊巖','鄧肅','宋','宋诗','song-poetry','','[]','石壁巉巖驚鬼劃，異草幽花鎖春色。',160,'全唐诗/poet.song.101000.json','["石壁巉巖驚鬼劃，異草幽花鎖春色。", "羣山迤邐不能高，突兀獨磨霄漢碧。", "芒鞋千尺上崔嵬，手摘星辰脚底雷。", "撥破烟雲得洞戶，醉眼恐是天門開。", "入門嵯峨森紫玉，冷風吹面天香馥。", "箕踞胡床揮麈尾，萬指未充空洞腹。", "我因避地訪名山，扁舟夜渡沙溪寒。", "辛勤博此一笑喜，太平猶在水雲間。", "猛將今無三角虎，狐狸晝號鰍鱔舞。", "靈巖知有老龍藏，挽出人間作霖雨。"]'),
('a2f1a0e4-f9ea-4e9d-8f43-a5a196359853','雹','鄧肅','宋','宋诗','song-poetry','','[]','黑雲壓山山欲頹，阿香推車震不開。',96,'全唐诗/poet.song.101000.json','["黑雲壓山山欲頹，阿香推車震不開。", "廣寒宮中珠徑寸，狂風傾下九天來。", "高堂砰轟倒四壁，萬瓦飛空如轉石。", "燈火青熒不敢明，世間誰有膽三尺。", "年來蠢動敢爭豪，鰍鱔起舞狐狸嗥。", "一振天威百怪息，夜半雲收北極高。"]'),
('94a5e1e6-7d27-4832-aeed-b7a1f946eb68','送李丞相四路宣撫','鄧肅','宋','宋诗','song-poetry','','[]','冷風吹海煙霧開，繡衣使者天上來。',192,'全唐诗/poet.song.101000.json','["冷風吹海煙霧開，繡衣使者天上來。", "手持天書傳天語，促起天下豪傑魁。", "下堂拜命汗如雨，上堂鳴鼓旌旄舉。", "要令南國生清風，不辭馬上蒸溽暑。", "平生直氣高蒼穹，四海草木聞威風。", "業以自任如伊尹，那使流言動周公。", "君臣今日機鋒契，六十九州歸重寄。", "屠龍事業警狗偷，談笑定縛吳元濟。", "功成上天相都俞，指呼瓦皪化華胥。", "日闢農桑三萬里，二十四考書中書。", "我今流落窮吞紙，蟾蜍爬沙鞭不起。", "歸歟自築茅三間，爲作野史書雄偉。"]'),
('f937f579-7778-40eb-af2d-c4828523dd14','大水雜言','鄧肅','宋','宋诗','song-poetry','','[]','前日雨如絲，繽紛雜朝霧。',208,'全唐诗/poet.song.101000.json','["前日雨如絲，繽紛雜朝霧。", "昨日雨如注，萬壑爭馳騖。", "今朝有霽色，作意在芒屨。", "那知復如傾，漫天飛瀑布。", "介休借車振蒼穹，十八葉幡如火紅。", "濤頭起伏萬銀屋，河伯盡以山爲宮。", "門前小艇疾飛鴻，挽我同趨急流中。", "人生如夢貴適意，乘此可食千頭龍。", "醉中舉杯謝舟子，口腹自營吁可鄙。", "不聞大禹不過門，血指爲疏九年水。", "何如乘風拜張堅，喚取女媧來補天。", "坐令赤子脫魚腹，六合內外還桑田。", "柳枝却下蛟龍約，談笑支奇付鐵索。", "異時天上敢驚呼，斥作人間鐺折脚。"]'),
('6ec52e5c-8b33-4dee-a3da-6f03e8779262','次韵王信州','鄧肅','宋','宋诗','song-poetry','','[]','煤炱飛上天，沉沉三日霧。',208,'全唐诗/poet.song.101000.json','["煤炱飛上天，沉沉三日霧。", "銀河一壓摧，狂雨恣橫騖。", "我恐鐵騎來，疾馳不納屨。", "氣豪如項羽，勢猛似黥布。", "瀰漫江海接高穹，石牛未洗血泥紅。", "天吳八首真奇怪，咄嗟平地作銀宮。", "我貧家火不星竈，赤脚滅沒泥塗中。", "目斷曉風生少女，又復茅檐飛白龍。", "慚愧北來王夫子，籍籍聲名滿都鄙。", "朝吟千賦暮千詩，松腴亦須枯海水。", "莫倚文章似孟堅，未用風流追樂天。", "且以光芒破陰晦，挽回日色到桑田。", "樂歲天公有嚴約，斥落旄頭沉貫索。", "從公日醉三百杯，不怕西風動旗脚。"]'),
('ff1c8af3-7fc4-4121-90d8-09975a7bc4bb','再次韵','鄧肅','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','我聞張微子，仰天能服霧。',208,'全唐诗/poet.song.101000.json','["我聞張微子，仰天能服霧。", "又聞填海神，揮鞭石欲騖。", "二子呼不來，登山自糾屨。", "雷鼓速雲陣，忽忽千巖布。", "誰云九萬隔高穹，玉女笑眼逼人紅。", "銀浦遂傾瓜蔓水，雪浪欲浮天梁宮。", "孤孫得糟時哺翁，汎汎浮家烟浪中。", "競呼力士來西域，臨江吹縮十丈龍。", "那知夏雨逢甲子，身如豬鴨不須鄙。", "赤松作此豈無謀，門生主兵渠主水。", "長江正欲截苻堅，夜亡智伯水如天。", "此功朝成暮可霽，便當對月飲青田。", "一雨從今十日約，要賡豐年入絃索。", "憑君喚取阿戎俱，笑上天門同軟脚。"]'),
('966e6266-4440-469c-a190-8a6be2213f0c','鼓腹謠','鄧肅','宋','宋诗','song-poetry','','[]','當時大鑊四十石，餡粗如柱餅八尺。',96,'全唐诗/poet.song.101000.json','["當時大鑊四十石，餡粗如柱餅八尺。", "飽食起來舞金剛，揮戈天上駐斜日。", "底事年來到骨窮，炙蒲脯苔誑腹空。", "鬬牛一飯期五日，一半又聽闍黎鐘。", "啄腐吞腥將日削，天公作意殊不惡。", "十圍漸化楊柳輕，因馭冷風上寥廓。"]'),
('24db2b19-f8e4-4a38-b59f-08dfe91f03bf','次鼓腹謠元韻','鄧肅','宋','宋诗','song-poetry','','[]','我心不轉本非石，世路爬沙任退尺。',96,'全唐诗/poet.song.101000.json','["我心不轉本非石，世路爬沙任退尺。", "杯酒高懷獨未忘，只有三萬六千日。", "原憲雖貧亦非窮，石髮溪毛放筯空。", "已遣寸毫飽風月，安得高堂列鼎鐘。", "明朝莫怕山如削，夾路花香破酒惡。", "世間得失競雞蟲，一笑危岑天地廓。"]'),
('a0127ed3-43a1-489e-953c-0d63cf71f3e9','戲王子和','鄧肅','宋','宋诗','song-poetry','','[]','豪華相陵豆粥石，坐上珊瑚碎三尺。',96,'全唐诗/poet.song.101000.json','["豪華相陵豆粥石，坐上珊瑚碎三尺。", "那知蕭條洙泗間，竈火不星連七日。", "我生不復餞文窮，醉眼從來四海空。", "一飽便令百憂失，三合紅陳等萬鍾。", "君家况有柳枝弱，客惡不容主人惡。", "造門果腹姑置之，杜陵寒眼憑君廓。"]'),
('6561cd39-3aae-44bc-b97f-cce834c6ac62','鼓腹謠謝許令','鄧肅','宋','宋诗','song-poetry','','[]','東坡不戀二千石，却羨黄州芋徑尺。',96,'全唐诗/poet.song.101000.json','["東坡不戀二千石，却羨黄州芋徑尺。", "一飽何妨作許難，千古光芒貫白日。", "我生不暇哭途窮，入戶青錢轉手空。", "肉食不容久青瑣，齒牢但可叩天鐘。", "許侯詩成謝斲削，飛流來洗徐凝惡。", "開緘百里已生春，九州更賴此心廓。"]'),
('94672eb3-030e-46f8-bd3a-69fecdbf886c','風雨損荔子','鄧肅','宋','宋诗','song-poetry','','[]','前日雨聲如隕石，昨日風狂退六鷁。',96,'全唐诗/poet.song.101000.json','["前日雨聲如隕石，昨日風狂退六鷁。", "荔子吐華漫如雲，結實定知無十一。", "南來無以慰愁煎，端期一飽果中仙。", "山頭看花日千轉，默想香味空流涎。", "事類翻羹慎勿恤，風雨在天非人力。", "要及豐年天下同，那爲海邦私一物。"]'),
('21641b78-05c5-47c2-b9cc-2ccda2f01abc','題吹衣亭','鄧肅','宋','宋诗','song-poetry','','[]','馬上衣衫涴塵土，斂板權門腰傴僂。',96,'全唐诗/poet.song.101000.json','["馬上衣衫涴塵土，斂板權門腰傴僂。", "冷風天上呼不來，厚顔如甲汗如雨。", "星郎高韵凌雲烟，天籟喚歸酌流泉。", "人間熱惱醺不到，亭上鶴衣飄欲仙。", "君方醉樂人愁絕，何如御此登天闕。", "叩天借取衣上風，吹下九州作春色。"]'),
('38702bd7-83ec-4605-95ff-b712166b97a9','遊鼓山','鄧肅','宋','宋诗','song-poetry','','["\u8861\u5c71"]','蘭橈𫇢岸雷霆駭，疾雨狂風欲翻海。',128,'全唐诗/poet.song.101000.json','["蘭橈𫇢岸雷霆駭，疾雨狂風欲翻海。", "吾人作意水石間，素志豈因風雨改。", "悟適當如未悟人，衡山不知爲開雲。", "魯陽莫試揮戈手，郭泰何妨墊角巾。", "山僧導我飛芒屨，要看渠師得道處。", "雪噴鼎烹一斥迴，千古澗流不東注。", "我笑老師太豪雄，故令鬼物窺吾蹤。", "安得廓然無聖解，蒼崖依舊飛白龍。"]'),
('9804eccd-b6fb-4ce6-94ef-3c9cf101348e','別珠公','鄧肅','宋','宋诗','song-poetry','','[]','我頃詩成准敕惡，寒江夜度秋蕭索。',128,'全唐诗/poet.song.101000.json','["我頃詩成准敕惡，寒江夜度秋蕭索。", "曳杖從師得摩尼，洗空愁腸天地廓。", "年來狂妄嬰逆鱗，去國三秋又出奔。", "隔牆後得綈袍舊，一笑喚回逆旅春。", "我心不轉嗟匪石，方壯兩遭天上斥。", "處處逢君道價高，萬指方袍趨法席。", "白雲天下妙林泉，看君又作新法緣。", "儻能容此無歸客，便當結社追白蓮。"]'),
('baf692be-52eb-4640-89b7-ae240af5a5e0','送許丈赴行在','鄧肅','宋','宋诗','song-poetry','','[]','狄犬夜吠夷門月，乾坤易位人泣血。',160,'全唐诗/poet.song.101000.json','["狄犬夜吠夷門月，乾坤易位人泣血。", "那知千官舞蹈迴，馬上洋洋面不熱。", "許侯逆風敢孤騫，黄金圍腰挽不前。", "大明昇天狐兔遯，再拜丹墀吾節全。", "我時上天恣狂直，權臣舌端飛霹靂。", "當時陷穽皆交遊，侯獨臨存真鐵石。", "此來邂逅一笑間，夜傾閩酒赤如丹。", "胸中磊塊澆未下，征旆匆匆又吳山。", "山前鮫鰐翻平陸，殺人如麻未充腹。", "憑君仗劍追祖風，坐令四海桑田復。"]'),
('7f625cf6-e3d8-4810-afb1-8c618c9f9ce0','後迎駕行','鄧肅','宋','宋诗','song-poetry','','[]','揮鞭衝曉露，歸鞍載夕陽。',156,'全唐诗/poet.song.101000.json','["揮鞭衝曉露，歸鞍載夕陽。", "一日復一日，不見御袍黄。", "左衽須文繡，氈車奉珪璋。", "作意禮樂盛，而乃訪毛嬙。", "上皇襲太平，珍怪乘四方。", "奇器驚鬼劃，舞要欲雲翔。", "端爲大盜積，萬里來貪狼。", "文移急星火，搜抉到毫芒。", "伐柯則不遠，吾道其復昌。", "君看天宇間，紫微已輝光。", "躣馬今朝去，定拜御爐香。", "惡衣供禹御，茅茨覆堯堂。", "爲邦消底物，人心歸則王。"]'),
('ec7ca55f-9f2d-467b-bc40-155167b212d7','鄧成彥邀李益之朱喬年及某一飯適忌日無侑觴者遂遲明日成彥偶在式假以食素謝吾三人朱且行僕因以詩促之','鄧肅','宋','宋诗','song-poetry','','[]','點額萬里歸，兀坐冷如水。',144,'全唐诗/poet.song.101000.json','["點額萬里歸，兀坐冷如水。", "慚愧北阮賢，爲余欣設醴。", "既邀折檻朱，仍約騎鯨李。", "人乳已方丈，清歌遲皓齒。", "那知事大謬，反誤占食指。", "得鹿儻是夢，翻羹得無鬼。", "我生飲紅裙，萬事空一洗。", "所失如蝟毛，豈惟一飯耳。", "端恐荀陳會，自此參辰矣。", "憑公反高陽，勿專蘭亭美。", "主人或素餐，蘇晉端可擬。", "何妨具大烹，肉食從客鄙。"]'),
('f41bbcf7-0494-473f-a333-adf21fcba8ac','偶成','鄧肅','宋','宋诗','song-poetry','','[]','我涉江東路，平地雪盈尺。',120,'全唐诗/poet.song.101000.json','["我涉江東路，平地雪盈尺。", "明日登芙蓉，晴天開曉日。", "朅自婺源來，陰雨連朝夕。", "瘦馬逼雲際，又斷檐間滴。", "顧我亦何人，市朝欲掃迹。", "平生詩酒交，落井仍下石。", "那知涉畏途，乃煩造化力。", "要知萬里行，人謫非天謫。", "衡雲霽韓愈，海市呈蘇軾。", "君知此理不，鬼物護狂直。"]'),
('7f94d85a-adad-456c-8b93-5c676724fa6f','古意三首  其一','鄧肅','宋','宋诗','song-poetry','','[]','妾身如暮雲，陰霾愁漸濃。',48,'全唐诗/poet.song.101000.json','["妾身如暮雲，陰霾愁漸濃。", "郎來如曉色，日高雲自空。", "曉色未應夜，愁雲不可重。", "會持一杯酒，舉室生春風。"]'),
('d072958a-5bb3-49c7-9629-93cfa340d630','古意三首  其二','鄧肅','宋','宋诗','song-poetry','','[]','妾心如寒梅，隨郎遍江東。',48,'全唐诗/poet.song.101000.json','["妾心如寒梅，隨郎遍江東。", "妾身如飛雪，知落何亭中。", "雪花故清絕，何人能擊節。", "梅花歲歲春，千秋香不滅。"]'),
('3528c0dd-5c5e-448b-9afd-3d71b21f60f6','古意三首  其三','鄧肅','宋','宋诗','song-poetry','','[]','妾如傍籬菊，不肯嫁春風。',48,'全唐诗/poet.song.101000.json','["妾如傍籬菊，不肯嫁春風。", "郎如出谷鶯，飛鳴醉亂紅。", "亂紅有何好，風雨一夕空。", "菊英雖枯淡，不愁霜露濃。"]'),
('06a2ed94-483c-4b36-948e-eb5124656712','觀子陵畫像','鄧肅','宋','宋诗','song-poetry','','[]','陶朱防狡兔，渭濱兆非熊。',72,'全唐诗/poet.song.101000.json','["陶朱防狡兔，渭濱兆非熊。", "先生但釣月，君王友不從。", "我昔訪其迹，溪光磨青銅。", "呼公公不應，天籟自號空。", "何人知此景，携歸梵王宮。", "乃知夜半力，端在寸毫中。"]'),
('62a29395-661d-4e7c-9064-d66e112c17e8','謁南齋諸友','鄧肅','宋','宋诗','song-poetry','','[]','青青門外竹，練練澗中流。',120,'全唐诗/poet.song.101000.json','["青青門外竹，練練澗中流。", "水竹自相激，天壤無炎洲。", "我友有高韵，來爲扶策遊。", "氛埃飛不到，軒窗寸寸秋。", "高文穿天心，細字編蠅頭。", "氣豪欲騎月，志銳定焚舟。", "我來初過雨，衣衫空翠浮。", "平生百斛塵，一洗空不留。", "歸來短檠下，清風入夢幽。", "不知白蓮社，肯容靈運不。"]'),
('53ced583-a14c-4a77-a142-04d127963a33','再用南齋韵謝','鄧肅','宋','宋诗','song-poetry','','[]','沙溪清可啜，遠山翠欲流。',120,'全唐诗/poet.song.101000.json','["沙溪清可啜，遠山翠欲流。", "翩然航一葦，浩歌入蘆洲。", "高堂上木杪，幽人事勝遊。", "但足簞瓢樂，不知天地秋。", "我筆嗟無口，冥搜空掉頭。", "何如三才傑，等是濟川舟。", "開卷騰光怪，天上卿雲浮。", "阿雲又嗣音，吾硯不欲留。", "平生浪詩聲，寒蟲號清幽。", "已對狂道士，從此敢吟不。"]'),
('f5cde4ad-4b2d-4da1-aecf-ada23a28fae1','登妙峰閣','鄧肅','宋','宋诗','song-poetry','','[]','維舟古木陰，故人能倒屣。',120,'全唐诗/poet.song.101000.json','["維舟古木陰，故人能倒屣。", "相携步高閣，千尺誇雄偉。", "雨餘天氣清，宇宙空如洗。", "對面碧玉峰，去天不盈咫。", "憑欄一超然，欲摶九萬里。", "下視囂塵間，蠢蠢魚蟲耳。", "平生浪自苦，馬上肉消髀。", "匆匆欲何之，燒香更隱几。", "入夜寂無人，波聲欄下起。", "坐覺非塵寰，雷霆生脚底。"]'),
('694ef384-9a97-4a70-ab82-52e26f5393fa','遊東山','鄧肅','宋','宋诗','song-poetry','','[]','草木得新露，襲人吹冷香。',72,'全唐诗/poet.song.101000.json','["草木得新露，襲人吹冷香。", "泉水夜相激，衾枕自清凉。", "我携謫仙人，眉目秀而長。", "高懷洗塵累，抵掌論老莊。", "若人不世有，此景那可忘。", "終當跨皓鶴，同作雲間翔。"]'),
('81cbbc18-5f3b-42fb-89f4-6cc322a0f854','雲際嶺','鄧肅','宋','宋诗','song-poetry','','[]','蒼蒼九萬里，拍塞雨天葩。',48,'全唐诗/poet.song.101000.json','["蒼蒼九萬里，拍塞雨天葩。", "雲際在天上，我去更携家。", "不知山高低，晶熒浩無涯。", "迴頭見侍香，濛濛隔瓊花。"]'),
('b191d0f9-e9ec-493f-a2c1-600017c325a4','謝丹霞老師','鄧肅','宋','宋诗','song-poetry','','[]','丹霞脩何行，天花雨紅英。',144,'全唐诗/poet.song.101000.json','["丹霞脩何行，天花雨紅英。", "草莽化金碧，宴坐十年成。", "落筆多奇語，酬唱皆名卿。", "微言寄禍福，無心天籟鳴。", "頃年來七峰，見我眼增明。", "西來的的意，一語貫三乘。", "坐令塵土人，彈指悟無生。", "別來今許久，夜夢飛爽靈。", "新詩忽入手，春風死草萌。", "公以慧生定，我自明而誠。", "相望雖千里，秋風共一清。", "去去勿作念，明鑑無將迎。"]'),
('4fdc47a2-1ead-4491-aa11-b989985be4a7','玉山避寇','鄧肅','宋','宋诗','song-poetry','','[]','前年十月間，胡兵滿大梁。',276,'全唐诗/poet.song.101000.json','["前年十月間，胡兵滿大梁。", "小臣阻天對，血涕夜霑裳。", "去年十月間，左省謫征商。", "扁舟歸無處，江浙俱豺狼。", "今年十月間，叛卒起南方。", "官兵且二萬，一旦忽已亡。", "一身幸無責，奉親走窮荒。", "天宇如許大，八口無處藏。", "空山四十日，畫餅誑饑腸。", "朅來古招提，和氣靄脩廊。", "迎門有禪伯，梵行照穹蒼。", "却念客無歸，燒豬飯蘇郎。", "方袍二百指，祖燈其復光。", "中有護法人，義氣干天槍。", "倒床得甘寢，不知冬夜長。", "明朝曹夫子，破浪飛危檣。", "入門郁春色，滿船載瓊漿。", "高談驚霹靂，佳句刻琳琅。", "那知奔竄中，一樂得未嘗。", "何當掃陰雪，四海共春陽。", "便携我輩人，浩歌歸醉鄉。", "世事如奕棋，臧否均亡羊。", "簑衣可釣月，底處是金章。"]'),
('22d0b5f6-2160-4eb3-82cf-0e962bd1464e','次韵李舍人','鄧肅','宋','宋诗','song-poetry','','[]','道山文章伯，杖履作幽棲。',240,'全唐诗/poet.song.101000.json','["道山文章伯，杖履作幽棲。", "筆硯爲戲事，業落翻墨螭。", "平生百萬言，定相初不離。", "更憐世間士，塵網深相闈。", "笑踵雙林轍，誓破萬夫疑。", "八面列神王，劍戟森携持。", "怒目幹龍宮，機緘絕謀惟。", "佛語浩無際，天地如可彌。", "笑談一轉畢，璿璣時未移。", "見者皆了了，鈍根化神機。", "不然分三藏，誰能俱不遺。", "白頭鉆故紙，底是出頭時。", "此恩今欲報，四顧將誰依。", "在佛本無說，於公亦何爲。", "珍重謫仙人，登山力未疲。", "天涯渺萬里，著處即爲歸。", "隨緣作贊嘆，妙語何奇奇。", "置之天壤間，千古無敢非。", "我生多肉障，煩公示寶篦。", "請作一言蔽，牟尼即仲尼。"]'),
('905a18f6-91f0-437f-bc75-9bf03af8bbaa','送李司錄西赴','鄧肅','宋','宋诗','song-poetry','','[]','晴雲聳奇峰，烈日破昏霧。',72,'全唐诗/poet.song.101000.json','["晴雲聳奇峰，烈日破昏霧。", "謫仙有行色，朋僚傷遠送。", "嗟哉君子人，簿書久倥傯。", "文星應長庚，勁氣模螮蝀。", "幡然玉京去，佇聽朝陽鳳。", "巖野豈能留，端肖高宗夢。"]'),
('4c2a0a2d-501e-4b01-a66d-07e12b204d21','塵外堂','鄧肅','宋','宋诗','song-poetry','','[]','俯仰天地間，紛紛塵垢耳。',72,'全唐诗/poet.song.101000.json','["俯仰天地間，紛紛塵垢耳。", "市井與山林，累人均一體。", "有真故有妄，無彼那取此。", "謂是爲塵外，政應在塵裏。", "憑師一埽空，六塵不用洗。", "淵默即雷聲，萬川同一水。"]'),
('7d6c9204-ffc5-4996-b807-84e8762fbfa8','謝李舍人題額','鄧肅','宋','宋诗','song-poetry','','[]','寸草春未報，秋風樹不停。',192,'全唐诗/poet.song.101000.json','["寸草春未報，秋風樹不停。", "三年真忽爾，過隙白駒奔。", "廬墳吾豈敢，北堂有老人。", "作庵居釋子，佛事勤朝昏。", "太史憐此意，高額揭顯親。", "梁間垂玉筯，壁上靄飛雲。", "顧我何爲者，傳家空一經。", "栖遲已三十，寒燈尚短檠。", "北轅將適楚，捩手或翻羹。", "那能爲親顯，只可充添丁。", "但念我先人，白首困飄零。", "射策不逢賞，青衫脫王庭。", "今焉逢太史，發揮身後名。", "坐令九泉下，冷骨復生春。", "顯揚政在此，松楸萬世榮。", "作詩敢論報，欲爲肌上銘。"]'),
('8ba4f095-2e0a-4ee5-a2c3-08f779aafa08','陪李梁溪遊泛碧','鄧肅','宋','宋诗','song-poetry','','[]','凉天夜無雲，寒江秋更碧。',120,'全唐诗/poet.song.101000.json','["凉天夜無雲，寒江秋更碧。", "冷照月華中，水天同一色。", "畫船渺中流，三更羣動寂。", "清風遠相隨，蘆花秋瑟瑟。", "近山得桂香，隔烟起漁笛。", "樓臺半有無，疑是化人國。", "我生本無事，釣竿勤水石。", "今宵更可人，仍侍君子側。", "浪登元禮舟，本非謫仙敵。", "斂手看揮毫，光芒騰萬尺。"]'),
('d152756d-b67a-47f6-91b2-6fa6372b4a8c','本上人','鄧肅','宋','宋诗','song-poetry','','[]','乞食自王城，駿筆揮萬紙。',120,'全唐诗/poet.song.101000.json','["乞食自王城，駿筆揮萬紙。", "開緘動心目，忽忽龍蛇起。", "便可老煙霞，聲價日千里。", "那知未滿意，更訪栟櫚子。", "栟櫚亦何人，是心如灰死。", "惡語滿人間，春風自桃李。", "憑君一笑揮，萬事空一洗。", "但了風動幡，在處針投水。", "願將廣長舌，語出亦糠粃。", "迴到我輩人，政堪覆醬耳。"]'),
('9c009a31-5759-4264-86af-664202c37b94','和作哲送令德','鄧肅','宋','宋诗','song-poetry','','[]','我瓠非五石，安能枵不用。',120,'全唐诗/poet.song.101000.json','["我瓠非五石，安能枵不用。", "但恃少年氣，未肯就羈鞚。", "越人已斷髮，章甫浪出宋。", "何如子建文，脫口人爭諷。", "笑示善者機，綺語時一弄。", "妙竟秘不傳，尺管閣雲夢。", "固應羞芹藻，清明奴隸共。", "明年鬰梧桐，定作喈喈鳳。", "歸來訪原憲，慎毋學子貢。", "故人猶未病，反己能求中。"]'),
('cb14784f-26a4-4c81-9202-708cd2510e08','宴坐軒','鄧肅','宋','宋诗','song-poetry','','[]','客食突不黔，馬上肉消髀。',108,'全唐诗/poet.song.101000.json','["客食突不黔，馬上肉消髀。", "所得知幾何，此生亦茅靡。", "何如豐巖公，一室萬緣止。", "竹林能清幽，巖竇富奇偉。", "關門寂無人，燒香坐隱几。", "今年忽猿驚，杖屨數百里。", "持此凝宴坐，老師一啟齒。", "我豈死灰如，春風吹不起。", "請君看九淵，止水即一洗。"]'),
('81a452b9-6e4c-4aec-bfb0-0671a6f704d7','舫齋','鄧肅','宋','宋诗','song-poetry','','[]','寓形天宇間，一枝慎所處。',96,'全唐诗/poet.song.101000.json','["寓形天宇間，一枝慎所處。", "到眼無溪山，堆胸自塵土。", "陳子作舫齋，端能世外趣。", "笑傲風波境，恬無風波慮。", "循本魚可觀，灰心鷗自舞。", "風景雖可人，公乎聊四顧。", "紛紛逐末流，誰援沉迷苦。", "吾事在濟川，慎勿五湖去。"]'),
('79a57551-105e-41ec-a189-4d5f36f00b1e','泛舟示子','鄧肅','宋','宋诗','song-poetry','','[]','秋江十日雨，破浪飛危檣。',96,'全唐诗/poet.song.101000.json','["秋江十日雨，破浪飛危檣。", "恍如在天上，萬頃煙茫茫。", "狂風自南來，桂華雨新黄。", "停杯不須飲，且飲空中香。", "平生四海心，老大愧周郎。", "聊復隨孺子，解纓濯滄浪。", "北斗挹酒漿，天孫織衣裳。", "乘興拏舟去，一笑上銀潢。"]'),
('cdf35487-e4d0-4ac5-86b7-3a4b167fbdcb','萬卷堂','鄧肅','宋','宋诗','song-poetry','','[]','世人無遠韵，挾策干浮雲。',120,'全唐诗/poet.song.101000.json','["世人無遠韵，挾策干浮雲。", "識字僅有數，得志無短檠。", "太丘妙家法，不肯鹵耕耘。", "藏書浩無際，兀坐觀滄溟。", "寒陋鄙李邕，假書勤朝昏。", "過眼如杜甫，散爲筆下神。", "一家今四傑，射策到王庭。", "自視猶細事，家塾方討論。", "嗟我未聞道，政作鉆紙蠅。", "會同阿戎去，從公問斲輪。"]'),
('6dc0ca8b-7b9b-479c-af61-cb38b09e6ff4','過黄楊巖','鄧肅','宋','宋诗','song-poetry','','[]','朔風夜號空，于喁幾枝木。',168,'全唐诗/poet.song.101000.json','["朔風夜號空，于喁幾枝木。", "深山自春色，芳草不凋綠。", "朋來得佳遊，招提藏翠麓。", "新酒赤如丹，竹萌肥勝肉。", "一醉出門去，缺月挂脩竹。", "歸路沙溪淺，危橋踐寒玉。", "夜過渭濱居，門庭故不俗。", "對坐寂無語，泉聲如擊筑。", "宗盟更可人，相邀勤秉燭。", "開緘得捷音，豺狼俱面北。", "迴棹今可矣，賞心嗟未足。", "西去有奇巖，佳名配王屋。", "箕踞列十人，未充空洞腹。", "更約林宗俱，來伴白雲宿。"]'),
('e640c978-c799-4d1e-9383-5bdb06db8c84','飛螢','鄧肅','宋','宋诗','song-poetry','','[]','谷雨已十日，不散陰雲頑。',48,'全唐诗/poet.song.101000.json','["谷雨已十日，不散陰雲頑。", "夜風翼腐草，借光蒲葦間。", "往來自相照，似欣天地寬。", "何時東方白，紅日開雲端。"]'),
('da66ca94-6e4e-4638-a1e6-73a8cb435574','次韵王信州古風','鄧肅','宋','宋诗','song-poetry','','[]','我昔少年日，氣與風雷壯。',240,'全唐诗/poet.song.101000.json','["我昔少年日，氣與風雷壯。", "一言既不合，掉頭歸望望。", "誓將老煙霞，叩角耕閑曠。", "一日煩干旌，叩天舒孟浪。", "自譬舟一葉，沙溪春蕩漾。", "百川儻已東，吾力那能障。", "尚賴天地寬，未即崇山放。", "栟櫚付冷居，乃爲世所長。", "老妻畫紙棋，赤脚沽村釀。", "醉起舞彩衣，吾道頗休暢。", "人傑又鼎來，不怕供詩帳。", "酬唱激清風，洗空煙雨瘴。", "故人化鶴仙，穹廬共悽愴。", "生還義更高，裹飯遠相餉。", "演山見長庚，醉眼不敢仰。", "便結騎鯨遊，不知飛燕謗。", "蘭亭最後來，德齒均所尚。", "傷時雖慷慨，論事尤倜儻。", "杯酒七峰下，逸思九天上。", "萬事俱可人，祇欠蛾眉唱。"]'),
('50e25c3f-8f94-40e9-ae65-11564b927190','再次韵謝之  其一','鄧肅','宋','宋诗','song-poetry','','[]','四海王信州，志氣老益壯。',240,'全唐诗/poet.song.101000.json','["四海王信州，志氣老益壯。", "家學九夷聞，人物萬夫望。", "若使在廟堂，天下無怨曠。", "胡爲一葉舟，也泛閩溪浪。", "顧余真斷梗，江淮付摇漾。", "逢人輒傾倒，涉世無隄障。", "既念越人瘠，仍欲鄭聲放。", "斥下九天來，宜似幽怪長。", "邂逅忽相逢，琥珀傾新釀。", "大急賡歌詩，胸臆賴舒暢。", "我語無餘韻，日書甲乙帳。", "得君驅鰐手，不憂潮陽瘴。", "三年去國心，海隅日悽愴。", "東家久不燔，稚子將無餉。", "詩成皆置之，萬事吾不仰。", "那復思重裘，區區欲止謗。", "明朝更可人，芒鞋窮好尚。", "遥知翠微中，高談得縱儻。", "至樂麯糵間，虛名鐘鼎上。", "輕重不須論，杯行且酬唱。"]'),
('404cfeba-f241-4c0e-bbd4-1ef3dfa2592c','再次韵謝之  其二','鄧肅','宋','宋诗','song-poetry','','[]','昌黎論佛骨，南行氣亦壯。',240,'全唐诗/poet.song.101000.json','["昌黎論佛骨，南行氣亦壯。", "獻書請鏤玉，却起北歸望。", "香山最風流，詩酒事夷曠。", "那知聞琵琶，淚濺九江浪。", "此身苦海中，風波隨蕩漾。", "妄見分南北，無乃眼中障。", "嗟我果何人，楚狂本天放。", "外物不須論，有身今已長。", "斥歸水雲鄉，日醉蓮花釀。", "茗飲過陸羽，禪悅得文暢。", "安此更何求，萬里脫氈帳。", "死生則置之，北邙豈俱瘴。", "使君憐我愚，了無逐客愴。", "謂我耕白雲，不獨齊眉餉。", "詩來覓歡處，光芒不可仰。", "欲醉桃李春，那憂貝錦謗。", "赤脚敢云無，社舞非時尚。", "侯門列蛾眉，一見吾其儻。", "拋磚此當先，積薪君在上。", "更爲李與蘇，兩家按新唱。"]'),
('61f978d6-4f95-4df2-8044-c4f9c44dce6a','第四章兼簡其子','鄧肅','宋','宋诗','song-poetry','','[]','虱卜雖蕭條，虎筮固豪壯。',240,'全唐诗/poet.song.101000.json','["虱卜雖蕭條，虎筮固豪壯。", "要皆有得失，未息胸中望。", "那知方寸地，太空等虛曠。", "川逝水不流，石高風自浪。", "鄭五相府榮，謝三漁舟漾。", "窮達安在哉，但瞞肉眼障。", "鼓瑟鏗爾捨，扶杖曝然放。", "在我本不虧，底處更求長。", "獨掛百錢遊，無人捉私釀。", "醉歸一腹春，滿紙揮琴暢。", "珍重江左王，德卲宜絳帳。", "天遣千里來，不顧閩山瘴。", "人言臭味同，政可慰悽愴。", "誰知金玉予，詩成即相餉。", "筆力到天心，開卷人爭仰。", "但勿賦兔葵，小兒易生謗。", "獻之詩更奇，句法晉宋尚。", "從渠得精深，嗟余真恍儻。", "何當日相從，煩君更語上。", "徑追太古風，三嘆聊十唱。"]'),
('47d1189b-efc3-49ef-981c-268a5441370a','荔子','鄧肅','宋','宋诗','song-poetry','','[]','荔子有佳品，乃在府城東。',96,'全唐诗/poet.song.101000.json','["荔子有佳品，乃在府城東。", "我來方秀發，黄雲幾萬重。", "遥知香味色，已具碎花中。", "憑欄一念足，不食意自充。", "人世如夢耳，當體色即空。", "謂是爲真實，便可侑千鍾。", "謂是爲非實，真飽亦何從。", "虛實兩無有，樓高雨濛濛。"]'),
('f71699ca-d2a7-4a87-a0b3-4166017e911b','避地山谷','鄧肅','宋','宋诗','song-poetry','','[]','大禹不到處，石壁誰鑿開。',168,'全唐诗/poet.song.101000.json','["大禹不到處，石壁誰鑿開。", "雲端欲相搏，飛出白雲來。", "餘沫亂飛雪，雄聲敵春雷。", "泝流湧百尺，銀山陟崔嵬。", "顧我雖逐客，解雨已春迴。", "嗟此天盡處，胡爲乎來哉。", "萱堂有垂白，蓬室紛提孩。", "內外三百指，奔竄若爲懷。", "我疑雲水間，亦有天下才。", "何時日三錫，一振紀律頹。", "羲和儻中天，六合無氛埃。", "鼠壤與蟻穴，不風當自摧。", "坐令陋巷中，依舊樂顔回。", "亦能書夷狄，朝會叩天階。"]'),
('2802af48-2e5c-40bd-b074-069703ec61f6','次韵王信州遊棲雲','鄧肅','宋','宋诗','song-poetry','','[]','勝遊出林杪，參天僅一分。',48,'全唐诗/poet.song.101000.json','["勝遊出林杪，參天僅一分。", "從君如附驥，顧我願爲雲。", "野色連空碧，幽香襲露薰。", "耦耕當卜此，橫笛夜相聞。"]'),
('a7c14835-3093-408b-a714-68fcf93708a2','偈頌七十八首  其一','釋正覺','宋','宋诗','song-poetry','','[]','易外家風未兆時，三更黑馬上烏雞。',32,'全唐诗/poet.song.101000.json','["易外家風未兆時，三更黑馬上烏雞。", "而今撥轉機輪也，剎剎塵塵更是誰。"]'),
('98748fa5-aff1-44f9-8fc7-d1c2b9ea4459','偈頌七十八首  其二','釋正覺','宋','宋诗','song-poetry','','[]','同聲相應，同氣相求。',36,'全唐诗/poet.song.101000.json','["同聲相應，同氣相求。", "同風千里，不隔絲頭。", "脫盡情塵消息在，蘆花江上月明秋。"]'),
('8211710b-193b-4eee-9270-944211198559','偈頌七十八首  其三','釋正覺','宋','宋诗','song-poetry','','[]','山雲冉冉，江水茫茫。',46,'全唐诗/poet.song.101000.json','["山雲冉冉，江水茫茫。", "正不居位，偏不涉傍。", "顯而不露，隱而彌彰。", "猿啼古木音聲急，鶴宿枯松夢寐長。"]'),
('099f57c8-5486-4ab9-bf19-a513bcfb719f','偈頌七十八首  其四','釋正覺','宋','宋诗','song-poetry','','[]','朔風作寒色，愛日流恩光。',48,'全唐诗/poet.song.101000.json','["朔風作寒色，愛日流恩光。", "處處相逢遇，明明不覆藏。", "山河無隔越，草木盡敷揚。", "剎說衆生說，毗盧舌廣長。"]'),
('87c5408b-29ae-40b5-bf31-6218924d62f6','偈頌七十八首  其五','釋正覺','宋','宋诗','song-poetry','','[]','十五日已前，有口說不得。',42,'全唐诗/poet.song.101000.json','["十五日已前，有口說不得。", "十五日已後，無心却自然。", "正當十五日，雲籠無縫襖，花笑不萌枝。"]'),
('16e3efc9-20ef-462d-b31c-4581bdf35d1c','偈頌七十八首  其六','釋正覺','宋','宋诗','song-poetry','','[]','一亘清虛夜正央，桂宮老兔冷噴霜。',32,'全唐诗/poet.song.101000.json','["一亘清虛夜正央，桂宮老兔冷噴霜。", "混融明暗無分處，誰辨箇中偏正方。"]'),
('30b2e054-db69-4eed-bf89-61775ce93c2f','偈頌七十八首  其七','釋正覺','宋','宋诗','song-poetry','','[]','明明百草頭，明明祖師意。',24,'全唐诗/poet.song.101000.json','["明明百草頭，明明祖師意。", "於佗未嘗一，於我未嘗異。"]'),
('4ea0fa8a-4111-4043-9cdb-af2c91c5490e','偈頌七十八首  其八','釋正覺','宋','宋诗','song-poetry','','[]','丙丁童子來求火，南海波斯鼻孔大。',68,'全唐诗/poet.song.101000.json','["丙丁童子來求火，南海波斯鼻孔大。", "狤獠舌頭會者難，直下而今照得破。", "照得破，沒功過。", "知你被底穿，曾與同床卧。", "廉纖脫盡舊時疑，杯影蛇絃留再坐。"]'),
('6d805936-5d15-4bbb-8623-2046a258aff3','偈頌七十八首  其九','釋正覺','宋','宋诗','song-poetry','','[]','心不自心始是心，眼不見眼始是眼。',62,'全唐诗/poet.song.101000.json','["心不自心始是心，眼不見眼始是眼。", "堂堂無影跡，歷歷絕思惟。", "明滿環中，兔懷夜月。", "翠橫海上，犀暈秋山。", "直須及盡玄微，始解承當底事。"]'),
('baa99d42-29fc-4c3a-b4b2-d2e2aa00d0d4','偈頌七十八首  其一○','釋正覺','宋','宋诗','song-poetry','','[]','一不是，二不成。',64,'全唐诗/poet.song.101000.json','["一不是，二不成。", "介然獨立，法爾雙行。", "柳線漸摇風力嫩，草針齊上燒痕青。", "一點靈光普天地，更嫌何處不分明。", "閒裏摸著鼻孔，忙時換却眼睛。"]'),
('a6e4803a-8141-4d81-9eca-8adf9068eab8','偈頌七十八首  其一一','釋正覺','宋','宋诗','song-poetry','','[]','半夜誰傳無盡燈，黄梅席上許盧能。',32,'全唐诗/poet.song.101000.json','["半夜誰傳無盡燈，黄梅席上許盧能。", "虛明自照非心力，分付叢林了事僧。"]'),
('048fec7f-09d4-4ae0-8056-8ddaf08e3390','偈頌七十八首  其一二','釋正覺','宋','宋诗','song-poetry','','[]','習習春風，絲絲春雨。',60,'全唐诗/poet.song.101000.json','["習習春風，絲絲春雨。", "一等沾濡，十方周普。", "甘草得之甜，黄連得之苦。", "天意發叢林，檐聲鬧窗戶。", "古德嘗云己不迷，等閑教壞人男女。"]'),
('49e33a3d-3680-4709-b79d-72ad57975fe9','偈頌七十八首  其一三','釋正覺','宋','宋诗','song-poetry','','[]','法界無塵心月圓，本光還照未萌前。',32,'全唐诗/poet.song.101000.json','["法界無塵心月圓，本光還照未萌前。", "而今直下分明去，猶較南泉二十年。"]'),
('4d8d301d-809f-4e84-8152-1cfa47c81460','偈頌七十八首  其一四','釋正覺','宋','宋诗','song-poetry','','[]','心不能緣，口不能議。',40,'全唐诗/poet.song.101000.json','["心不能緣，口不能議。", "直須退步荷擔，切忌當頭觸諱。", "風月寒清古渡頭，夜船撥轉琉璃地。"]'),
('8ee14104-4632-4225-a2fb-0cfe0d5bc93e','偈頌七十八首  其一五','釋正覺','宋','宋诗','song-poetry','','[]','青山白雲父，白雲青山兒。',24,'全唐诗/poet.song.101000.json','["青山白雲父，白雲青山兒。", "白雲終日倚，青山總不知。"]'),
('fe35dbcf-af88-48cf-88dd-189f47f02f57','偈頌七十八首  其一六','釋正覺','宋','宋诗','song-poetry','','[]','當生不生，借光現三十六應。',36,'全唐诗/poet.song.101000.json','["當生不生，借光現三十六應。", "當滅不滅，忘照攝千百億身。", "祇如絕去，來無動靜。"]'),
('4ff19e50-68b9-480f-a76d-5c949a6922be','偈頌七十八首  其一七','釋正覺','宋','宋诗','song-poetry','','[]','雲斂長空風日和，太平樵牧共高歌。',32,'全唐诗/poet.song.101000.json','["雲斂長空風日和，太平樵牧共高歌。", "衲僧飯飽無佗事，密密機前弄玉梭。"]'),
('1876f56b-2b63-4f0d-a44c-301cd116e3a2','偈頌七十八首  其一八','釋正覺','宋','宋诗','song-poetry','','[]','誰將活眼窺空劫，我道宗枝染浩春。',32,'全唐诗/poet.song.101000.json','["誰將活眼窺空劫，我道宗枝染浩春。", "頭角崢嶸藏不得，青原門下有祥麟。"]'),
('b00f2176-a3cc-4bb6-b264-5534051cfb5f','偈頌七十八首  其一九','釋正覺','宋','宋诗','song-poetry','','[]','寥寥無異轍，密密去玄功。',40,'全唐诗/poet.song.101000.json','["寥寥無異轍，密密去玄功。", "月轉蘆花岸，水秋吞太空。", "欲識誕生王子父，鶴騰霄漢出銀籠。"]'),
('d8656902-cb97-46d2-bf66-44c4f02a1de9','偈頌七十八首  其二○','釋正覺','宋','宋诗','song-poetry','','[]','百骸俱潰散，一物鎮長靈。',52,'全唐诗/poet.song.101000.json','["百骸俱潰散，一物鎮長靈。", "白雲功盡青山秀，青山路轉白雲迎。", "不曾死，不曾生。", "金繩拽轉泥牛鼻，半夜驅來海上耕。"]'),
('6889602f-62d9-4678-b1bf-65d1c2fcab0d','偈頌七十八首  其二一','釋正覺','宋','宋诗','song-poetry','','[]','一言盡十方，萬卷該不得。',24,'全唐诗/poet.song.101000.json','["一言盡十方，萬卷該不得。", "一步周八絃，駟馬追不及。"]'),
('f4c93394-c05b-46da-b3fb-9505aae9c62f','偈頌七十八首  其二二','釋正覺','宋','宋诗','song-poetry','','[]','性覺妙明，本覺明妙。',64,'全唐诗/poet.song.101000.json','["性覺妙明，本覺明妙。", "與太虛等量，與物情同道。", "應色應聲，隨聽隨眺。", "入三世而非去來，混萬緣而無正倒。", "雲日低時字雁橫，夜蟾落處孤猿叫。"]'),
('6c82e686-5040-4d3f-b705-df8852c7dac3','偈頌七十八首  其二三','釋正覺','宋','宋诗','song-poetry','','[]','雲在青天水在瓶，幾人錯認定盤星。',32,'全唐诗/poet.song.101000.json','["雲在青天水在瓶，幾人錯認定盤星。", "藥山八字轟開也，恰到而今話大行。"]'),
('0848effa-f306-4b4d-987c-8e631aa31fc4','偈頌七十八首  其二四','釋正覺','宋','宋诗','song-poetry','','[]','寒灰發焰舊家風，恰恰當人受用中。',32,'全唐诗/poet.song.101000.json','["寒灰發焰舊家風，恰恰當人受用中。", "片雪飛來爐上盡，通身無像不同功。"]'),
('c4b11a27-be5d-414e-b3a4-362a803b9e72','偈頌七十八首  其二五','釋正覺','宋','宋诗','song-poetry','','[]','佛病法病，佛藥法藥。',56,'全唐诗/poet.song.101000.json','["佛病法病，佛藥法藥。", "本色衲僧，俱不染著。", "遇飯開口，要行移脚。", "自是現成，誰能造作。", "言滿天下無口過，行滿天下無怨惡。"]'),
('4279d928-42fe-42b7-87e6-4dd985b6569b','偈頌七十八首  其二六','釋正覺','宋','宋诗','song-poetry','','[]','衲僧祇麽是家風，隱顯磨礱入混融。',32,'全唐诗/poet.song.101000.json','["衲僧祇麽是家風，隱顯磨礱入混融。", "歸子返擲全歸火，羚羊掛角不同功。"]'),
('9a94a861-7fca-4953-adb9-1897e904c037','偈頌七十八首  其二七','釋正覺','宋','宋诗','song-poetry','','[]','藏身須要無蹤跡，碧眼胡僧難辨白。',80,'全唐诗/poet.song.101000.json','["藏身須要無蹤跡，碧眼胡僧難辨白。", "沒蹤跡處莫藏身，門門廓達了諸塵。", "獨來將謂無儔侶，鬧裏忽然逢故人。", "柳線含金猶畏冷，梅花破雪已成春。", "阿儂千眼通身是，善應無方處處真。"]'),
('cda707de-2a8a-47a3-aedc-d89c868e5ba2','偈頌七十八首  其二八','釋正覺','宋','宋诗','song-poetry','','[]','一點環中照極微，智無功處却存知。',32,'全唐诗/poet.song.101000.json','["一點環中照極微，智無功處却存知。", "緣思浄盡無餘事，半夜星河斗柄垂。"]'),
('47a9fa5e-32bf-46e5-9907-59072dbc1669','偈頌七十八首  其二九','釋正覺','宋','宋诗','song-poetry','','[]','脫去還如鳥出籠，水雲將與舊來同。',32,'全唐诗/poet.song.101000.json','["脫去還如鳥出籠，水雲將與舊來同。", "依俙似曲纔堪聽，又被風吹別調中。"]'),
('9a291907-5d79-46d2-865d-a7297031a958','偈頌七十八首  其三○','釋正覺','宋','宋诗','song-poetry','','[]','不可以色見，不可以聲求。',48,'全唐诗/poet.song.101000.json','["不可以色見，不可以聲求。", "風定花猶落，鳥啼山更幽。", "四衢明自曉，六戶冷如秋。", "再坐不疑處，杯中弓影浮。"]'),
('2612f1c2-d960-421b-953b-9254de780b72','偈頌七十八首  其三一','釋正覺','宋','宋诗','song-poetry','','[]','一雨一晴，底事分明。',62,'全唐诗/poet.song.101000.json','["一雨一晴，底事分明。", "六塵昏擾，世界崢嶸。", "一心虛泊，萬法齊平。", "出得氣是你鼻孔，覷得破是你眼睛。", "有緣不是余朋友，無用雙眉却弟兄。"]'),
('aaa576ef-c3ed-4a46-8535-8c2578628415','偈頌七十八首  其三二','釋正覺','宋','宋诗','song-poetry','','[]','即日貴人，舊家富漢。',52,'全唐诗/poet.song.101000.json','["即日貴人，舊家富漢。", "兄弟相成，尊賓互換。", "突曉途中眼不開，夜明簾外機旋轉。", "騎牛戴帽異中來，百煉真金色不變。"]'),
('085d0fbd-cd7c-4a4c-830a-80f8b2f16a0a','偈頌七十八首  其三三','釋正覺','宋','宋诗','song-poetry','','[]','心月孤圓，義天洞曉。',52,'全唐诗/poet.song.101000.json','["心月孤圓，義天洞曉。", "照中之虛，虛中之照。", "不萌枝上鳥初惺，無影樹頭春不老。", "垢衣權掛類中來，出門信手拈來草。"]'),
('bb83adc8-010a-4434-94bb-61c5c6b649c9','偈頌七十八首  其三四','釋正覺','宋','宋诗','song-poetry','','[]','掣鼓奪旗，往往光影裏走作。',70,'全唐诗/poet.song.101000.json','["掣鼓奪旗，往往光影裏走作。", "停機息杼，往往死水裏浸却。", "衲僧家，穩下脚。", "沒窠臼，莫棲泊。", "月樹不啼猿，雲巢無宿鶴。", "玄微及盡類難齊，千手大悲難摸索。"]'),
('b5e281c3-d247-4adc-9988-c121767b49c8','偈頌七十八首  其三五','釋正覺','宋','宋诗','song-poetry','','[]','大雄父子許雍容，消息傳通到劫空。',32,'全唐诗/poet.song.101000.json','["大雄父子許雍容，消息傳通到劫空。", "寒卧老蟾呼不覺，扶疏丹桂月朦朧。"]'),
('3e1e2136-4f8a-431e-bb15-6252b9973af9','偈頌七十八首  其三六','釋正覺','宋','宋诗','song-poetry','','[]','雲從龍，風從虎。',44,'全唐诗/poet.song.101000.json','["雲從龍，風從虎。", "雪峰輥毬，禾山打鼓。", "意不立玄，機不停午。", "恰恰相當用不窮，道吾覷破樂神舞。"]'),
('288e6fc8-d3a7-402f-961d-2dbe74663a91','偈頌七十八首  其三七','釋正覺','宋','宋诗','song-poetry','','[]','去時踏雪似來時，來去途中一色迷。',32,'全唐诗/poet.song.101000.json','["去時踏雪似來時，來去途中一色迷。", "妙得轉身賓是主，宗家正令付全提。"]'),
('e63ce7af-fa8e-4b34-8d89-b3417d1362f9','偈頌七十八首  其三八','釋正覺','宋','宋诗','song-poetry','','[]','去時不出戶，來時不入門。',48,'全唐诗/poet.song.101000.json','["去時不出戶，來時不入門。", "清癯山有骨，閑澹雲無根。", "歸家奉祖禰，了事還兒孫。", "雲水通方士，相期報佛恩。"]'),
('9b368227-4b73-4659-a657-cfad40710a31','偈頌七十八首  其三九','釋正覺','宋','宋诗','song-poetry','','[]','內若不動，外必不亂，箇是叢林知有漢。',66,'全唐诗/poet.song.101000.json','["內若不動，外必不亂，箇是叢林知有漢。", "而今識得不爲冤，自家兵馬何須戰。", "心因不生境緣斷，體若虛空勿崖岸。", "霜天皎月上中峰，一段光明洗癡暗。"]'),
('4f36af7f-c9e6-401e-b6a8-a48664373007','偈頌七十八首  其四○','釋正覺','宋','宋诗','song-poetry','','[]','衲僧須瀝髑髏乾，透出威音世外看。',32,'全唐诗/poet.song.101000.json','["衲僧須瀝髑髏乾，透出威音世外看。", "歲月不能遷變處，箇人肯共你同盤。"]'),
('93c7fcd9-5b34-48fd-9a02-b06211548640','偈頌七十八首  其四一','釋正覺','宋','宋诗','song-poetry','','[]','五九四十五，春風吹斷前山雨。',62,'全唐诗/poet.song.101000.json','["五九四十五，春風吹斷前山雨。", "行雲歸去復何心，轉背飄然無覓處。", "無覓處，知不知，坐斷十方還是誰。", "東弗于代鬰單越，西瞿耶尼閻浮提。"]'),
('226fa5fd-efff-4599-a323-905b5ac0c198','偈頌七十八首  其四二','釋正覺','宋','宋诗','song-poetry','','[]','聲色見聞鬧浩浩，怡似兒時鬬百草。',32,'全唐诗/poet.song.101000.json','["聲色見聞鬧浩浩，怡似兒時鬬百草。", "兩家拈出一般般，相對無言點頭笑。"]'),
('3587aece-4e5c-4f33-a1a8-ca3dc89da419','偈頌七十八首  其四三','釋正覺','宋','宋诗','song-poetry','','[]','碧琉璃色水澄清，紫磨金光身瑩明。',32,'全唐诗/poet.song.101000.json','["碧琉璃色水澄清，紫磨金光身瑩明。", "洗浄方知不受垢，釋迦老子此時生。"]'),
('f35ea61c-1c57-44b6-b368-99c0e7ab3548','偈頌七十八首  其四四','釋正覺','宋','宋诗','song-poetry','','[]','尊貴位中尊貴身，綿綿不斷轉金輪。',32,'全唐诗/poet.song.101000.json','["尊貴位中尊貴身，綿綿不斷轉金輪。", "剎塵壽量無窮已，箇是乾坤舊主人。"]'),
('68fd83ab-020b-466a-8dc6-f55677544544','偈頌七十八首  其四五','釋正覺','宋','宋诗','song-poetry','','[]','五月半，農忙亂，插田心是秋成飯。',72,'全唐诗/poet.song.101000.json','["五月半，農忙亂，插田心是秋成飯。", "却道禾熟不臨場，祇麽任從風雨爛。", "禪和子，一身了。", "一身兩眼對兩眼，箇中絲髮初無間。", "老狐涎盡復何疑，再坐盤中弓落盞。"]'),
('8bda0997-fa95-48bf-a9e9-91ffdc421213','偈頌七十八首  其四六','釋正覺','宋','宋诗','song-poetry','','[]','衲僧去就水雲姿，偶墮夤緣出應時。',32,'全唐诗/poet.song.101000.json','["衲僧去就水雲姿，偶墮夤緣出應時。", "今日又歸林壑去，得便宜了得便宜。"]'),
('df117a08-f9b5-4baa-96ff-a4ff035e93eb','偈頌七十八首  其四七','釋正覺','宋','宋诗','song-poetry','','[]','祇解恁麽去，沙禽夜宿滄洲樹。',44,'全唐诗/poet.song.101000.json','["祇解恁麽去，沙禽夜宿滄洲樹。", "不解恁麽來，石笋穿開古路苔。", "莫道鯤鯨無羽翼，今日親從鳥道回。"]'),
('4b53b393-e32c-48e2-89fe-ff036dd04891','偈頌七十八首  其四八','釋正覺','宋','宋诗','song-poetry','','[]','淅淅西風斂氣浮，遠天野水一般秋。',32,'全唐诗/poet.song.101000.json','["淅淅西風斂氣浮，遠天野水一般秋。", "衲僧歇到茲時節，坐照寒光湛不流。"]'),
('323d4931-9fde-4b64-bb61-f0b96126f651','偈頌七十八首  其四九','釋正覺','宋','宋诗','song-poetry','','[]','日照晝，月照夜。',62,'全唐诗/poet.song.101000.json','["日照晝，月照夜。", "天清而高，地厚而下。", "不我處者大功，不可逃者至化。", "舉起鎮州羅蔔，酬却廬陵米價。", "阿嚕勒繼薩婆訶，佳作人可知禮也。"]'),
('b7c206e6-7968-4c67-9337-8a774dd392ed','偈頌七十八首  其五○','釋正覺','宋','宋诗','song-poetry','','[]','祇箇是家風，明明入混融。',48,'全唐诗/poet.song.101000.json','["祇箇是家風，明明入混融。", "江光蘆映月，夜色水吞空。", "攃手懸崖下，分身萬像中。", "回塗登鳥道，恰恰是神通。"]'),
('03157a75-7271-4b43-bf5e-14a5bfbffb94','偈頌七十八首  其五一','釋正覺','宋','宋诗','song-poetry','','[]','南畝黄雲禾弄穟，中洲白雪葦成花。',32,'全唐诗/poet.song.101000.json','["南畝黄雲禾弄穟，中洲白雪葦成花。", "歸舟恰向其閒過，一棹清風夜到家。"]'),
('5e823f44-b538-4af9-b168-b2e9f6c5f59e','偈頌七十八首  其五二','釋正覺','宋','宋诗','song-poetry','','[]','空劫有真宗，聲前問己躬。',48,'全唐诗/poet.song.101000.json','["空劫有真宗，聲前問己躬。", "赤窮新活計，清白舊家風。", "的的三乘外，寥寥一印中。", "却來行異類，萬派自朝東。"]'),
('0279d5ed-d026-453e-97c5-827b44285903','偈頌七十八首  其五三','釋正覺','宋','宋诗','song-poetry','','[]','道綿綿兮用也不勤，道綿綿兮寂也不滅。',104,'全唐诗/poet.song.101000.json','["道綿綿兮用也不勤，道綿綿兮寂也不滅。", "二乘困墮於空無，衆生執迷於分別。", "菩薩區區於進修，諸佛嘮嘮於演說。", "一句子妙出三乘，一念閒功超萬劫。", "水月茫茫兮舟棹閑，雪雲冉冉兮路岐絕。", "明明靈靈兮唯己自知，大辯若訥兮大巧若拙。"]'),
('eebea167-446f-4c9b-9453-7d7091cc2e2f','偈頌七十八首  其五四','釋正覺','宋','宋诗','song-poetry','','[]','恰恰無綾縫，明明不覆藏。',58,'全唐诗/poet.song.101000.json','["恰恰無綾縫，明明不覆藏。", "鷲嶺豈傳迦葉，少林那付神光。", "現成處處合頭句，具足人人知見香。", "虛空說法森羅聽，不掛唇皮解舉揚。"]'),
('0daeacab-bc69-4547-ada4-9162c1a21842','偈頌七十八首  其五五','釋正覺','宋','宋诗','song-poetry','','[]','玉線金針相續難，劫壺空處妙投關。',64,'全唐诗/poet.song.101000.json','["玉線金針相續難，劫壺空處妙投關。", "香林煙暖風排雪，月窟冰寒影轉山。", "裏許借功方得活，那時退位不知閑。", "宗家密密綿綿事，布施多人莫要慳。"]'),
('03d7dfaf-0b26-4245-97b8-4e92092e8320','偈頌七十八首  其五六','釋正覺','宋','宋诗','song-poetry','','[]','直下無窠窟，不用求奇特。',24,'全唐诗/poet.song.101000.json','["直下無窠窟，不用求奇特。", "皓玉本無瑕，雕文喪君德。"]'),
('de773ba1-3625-422d-8c6b-46551009a51f','偈頌七十八首  其五七','釋正覺','宋','宋诗','song-poetry','','[]','本來田地無涯岸，極目寒光成一片。',48,'全唐诗/poet.song.101000.json','["本來田地無涯岸，極目寒光成一片。", "消息平沈佛也迷，機輪轉側誰能辨。", "雪山山下擁蓑人，白牛一掣芒繩斷。"]'),
('11d3abf3-2b31-482f-98c0-7781b68eab4a','偈頌七十八首  其五八','釋正覺','宋','宋诗','song-poetry','','[]','靈苗發種，覺樹敷春。',28,'全唐诗/poet.song.101000.json','["靈苗發種，覺樹敷春。", "冷湫湫處却要溫和，乾爆爆時還須津潤。"]'),
('8c0759e3-abc4-4217-9a6f-f44570a1e0af','偈頌七十八首  其五九','釋正覺','宋','宋诗','song-poetry','','[]','借婆裙子拜婆年，買盡風光不著錢。',32,'全唐诗/poet.song.101000.json','["借婆裙子拜婆年，買盡風光不著錢。", "劈面來時莫回避，箇人裏許有生緣。"]'),
('5198b238-e88d-4d51-8b77-021d8fe34ef5','偈頌七十八首  其六○','釋正覺','宋','宋诗','song-poetry','','[]','同中有異，功亡就位。',62,'全唐诗/poet.song.101000.json','["同中有異，功亡就位。", "異中有同，在位借功。", "一步密移玄路轉，全身放下劫壺空。", "隱隱密密，玲玲瓏瓏。", "記取深雲須變豹，自然死水不藏龍。"]'),
('75fd09e4-f316-4353-aec3-e7630be5336c','偈頌七十八首  其六一','釋正覺','宋','宋诗','song-poetry','','[]','麟龍不爲瑞，珠璧不爲貴。',112,'全唐诗/poet.song.101000.json','["麟龍不爲瑞，珠璧不爲貴。", "衲僧眼豁開，徹見生死蔕。", "生死蔕，第一義。", "諸佛心，祖師鼻。", "少林傳燈，靈山授記。", "隨高隨下，何此何彼。", "假諸因緣，神通遊戲。", "有時五教三乘，有時三德六味。", "有時屋裏主財，有時門頭了事。", "處處清白家風，人人見成活計。"]'),
('05679801-f05d-46e7-b41f-083c5f78782e','偈頌七十八首  其六二','釋正覺','宋','宋诗','song-poetry','','[]','一二三四五，禾山打鼓金牛舞。',30,'全唐诗/poet.song.101000.json','["一二三四五，禾山打鼓金牛舞。", "劈面來時著眼看，全身放下休回互。"]'),
('c1632430-298d-4cea-a813-ab0b4b2b13b2','偈頌七十八首  其六三','釋正覺','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','活計如今付舊人，版頭疏久又還親。',64,'全唐诗/poet.song.101000.json','["活計如今付舊人，版頭疏久又還親。", "星河月與長江混，渺渺清光一色勻。", "底時節，落功勳。", "卧穩須知却轉身，轉得了來相識麽，寒窮面觜黑皴皴。"]'),
('ef234383-4ae2-44f5-9ea2-a0246c2efab4','偈頌七十八首  其六四','釋正覺','宋','宋诗','song-poetry','','[]','萬物自有功，當言用極處。',24,'全唐诗/poet.song.101000.json','["萬物自有功，當言用極處。", "事存函蓋合，理應箭鋒柱。"]'),
('fe805fda-5587-4abf-8699-4e99b341d4f9','偈頌七十八首  其六五','釋正覺','宋','宋诗','song-poetry','','[]','何須更舉揚，全體露堂堂。',56,'全唐诗/poet.song.101000.json','["何須更舉揚，全體露堂堂。", "溼暑時時雨，薰風陣陣香。", "秧針初透水痕淺，蒲刀欲剪柳絲長。", "雙六盤中休喝彩，分明觸事恰相當。"]'),
('33ca10bb-b096-4478-8a4f-108218d5dd05','偈頌七十八首  其六六','釋正覺','宋','宋诗','song-poetry','','[]','一塵具無量剎土，一念超無量劫數。',32,'全唐诗/poet.song.101000.json','["一塵具無量剎土，一念超無量劫數。", "一身現無量衆生，一體合無量諸佛。"]'),
('9f5ee855-6303-4419-9905-9bc8d6e7e38a','偈頌七十八首  其六七','釋正覺','宋','宋诗','song-poetry','','[]','吾家種草古今難，針鼻纔分度線端。',64,'全唐诗/poet.song.101000.json','["吾家種草古今難，針鼻纔分度線端。", "混處相期君把手，到時不與汝同盤。", "却來大用縱橫是，向去全功轉側看。", "底事要憑師印可，輪回生死不相干。"]'),
('d883f805-3a4e-4426-aa9c-c7657757276e','偈頌七十八首  其六八','釋正覺','宋','宋诗','song-poetry','','[]','寒巖異草，坐著成功。',36,'全唐诗/poet.song.101000.json','["寒巖異草，坐著成功。", "明月白雲，步時分影。", "幽洞不拘關鎖意，縱橫那涉兩頭人。"]'),
('34f7ecce-9e04-4539-952c-63ec539acb12','偈頌七十八首  其六九','釋正覺','宋','宋诗','song-poetry','','[]','雲無心而自閑，天無際而能寬。',86,'全唐诗/poet.song.101000.json','["雲無心而自閑，天無際而能寬。", "道無像而普應，神無慮而常安。", "隨之也不見去弔，迎之也不見來端。", "一藏教祇成讚歎，三世佛止可傍觀。", "燭曉堂虛，織婦轉機梭路細。", "水明夜靜，漁老擁蓑船月寒。"]'),
('4e1d530b-cb07-473e-aa7e-5ce3916f070e','偈頌七十八首  其七○','釋正覺','宋','宋诗','song-poetry','','[]','芝麻壓得油，秔米炊得飯，還我叢林飽參漢。',72,'全唐诗/poet.song.101000.json','["芝麻壓得油，秔米炊得飯，還我叢林飽參漢。", "衲僧履道貴平懷，何必臨機爭轉換。", "活計自然，家風成現。", "順水便風，歸舟到岸。", "寒山拾得笑呵呵，此心分付知音辨。"]'),
('8dffdb28-7a31-482a-9f46-f913f6879efd','偈頌七十八首  其七一','釋正覺','宋','宋诗','song-poetry','','[]','浪爪拏舟雪濺空，十年胸際著慈風。',32,'全唐诗/poet.song.101000.json','["浪爪拏舟雪濺空，十年胸際著慈風。", "如今堂上時相見，分付飲茶談笑中。"]'),
('8e326193-365a-4656-86f2-7b300181c423','偈頌七十八首  其七二','釋正覺','宋','宋诗','song-poetry','','[]','髑髏前有本來靈，照徹毗盧頂𩕳平。',64,'全唐诗/poet.song.101000.json','["髑髏前有本來靈，照徹毗盧頂𩕳平。", "玉馬過關方半夜，木雞喚月恰三更。", "寥寥跡絕全功轉，歷歷光生借位明。", "却著弊衣垂化手，合同船子順流行。"]'),
('445b5a27-5941-4bff-b103-bcc641234708','偈頌七十八首  其七三','釋正覺','宋','宋诗','song-poetry','','[]','一盤黑白互交羅，生殺其中細琢磨。',32,'全唐诗/poet.song.101000.json','["一盤黑白互交羅，生殺其中細琢磨。", "樵人疑著當頭著，不覺腰閒爛斧柯。"]'),
('8485749e-673e-42cf-9e63-b4aceb0f6a12','偈頌七十八首  其七四','釋正覺','宋','宋诗','song-poetry','','[]','生滅心盡是寂滅，露柱懷胎底時節。',64,'全唐诗/poet.song.101000.json','["生滅心盡是寂滅，露柱懷胎底時節。", "寂滅心起是生滅，石女生兒解言說。", "用時萬象不盈餘，休處一真無空缺。", "藤枯樹倒笑呵呵，依舊清風與明月。"]'),
('1c2c2f74-004a-4df7-8f29-aee1132e4b90','偈頌七十八首  其七五','釋正覺','宋','宋诗','song-poetry','','[]','不是男，不是女。',82,'全唐诗/poet.song.101000.json','["不是男，不是女。", "不是神，不是鬼。", "不是佛，不是物。", "祇知白雲無心，誰辨青山在目。", "夜明識取斷蛇珠，潭寒退下蒼龍骨。", "等閑掣斷紫絲絛，天上人間收不得。", "收不得，底事從來沒窠窟。"]'),
('6c773caa-1d6b-4bb6-93d8-1bbf017a4268','偈頌七十八首  其七六','釋正覺','宋','宋诗','song-poetry','','[]','趙州四門長開，不礙諸方往來。',30,'全唐诗/poet.song.101000.json','["趙州四門長開，不礙諸方往來。", "十字街頭人大叫，平鋪買賣沒相猜。"]'),
('b59ae560-8438-4892-91a2-0a082adb29a1','偈頌七十八首  其七七','釋正覺','宋','宋诗','song-poetry','','[]','本源無風波，真界絕涯畛。',24,'全唐诗/poet.song.101000.json','["本源無風波，真界絕涯畛。", "木人步月歸，轉側功勳盡。"]'),
('66f96618-1ac7-4a08-aa1c-9bf2abcd9182','偈頌七十八首  其七八','釋正覺','宋','宋诗','song-poetry','','[]','地水火風休假藉，一切不留還脫灑。',64,'全唐诗/poet.song.101000.json','["地水火風休假藉，一切不留還脫灑。", "家風廓落等虛空，田地虛明非晝夜。", "鳥道須知舉足難，玄機不許絲頭掛。", "同中有異異中同，徹底渾淪無縫罅。"]'),
('933464fd-4a56-4e1f-8453-84716a88f3dc','偈頌七十八首  其七九','釋正覺','宋','宋诗','song-poetry','','[]','趙州道有，趙州道無。',50,'全唐诗/poet.song.101000.json','["趙州道有，趙州道無。", "狗子佛性，天下分疏。", "面赤不如語直，心真莫怪言粗。", "七百甲子老禪伯，驢糞逢人換眼珠。"]'),
('c6e6e46e-b234-4044-b47c-67f3a4c046b7','偈頌七十八首  其八○','釋正覺','宋','宋诗','song-poetry','','[]','一亘清虛衲子家，十方三世箇生涯。',64,'全唐诗/poet.song.101000.json','["一亘清虛衲子家，十方三世箇生涯。", "光明照夜觸髏眼，消息含春枯木花。", "曉色依依雲冉冉，天容淡淡月斜斜。", "母陀羅臂通身是，今日逢場便攃沙。"]'),
('67ef120a-6c08-44bf-a38e-b6ec5640864a','頌古一百則  其一','釋正覺','宋','宋诗','song-poetry','','[]','一段真風見也麽，綿綿化母理機梭。',32,'全唐诗/poet.song.101000.json','["一段真風見也麽，綿綿化母理機梭。", "織成古錦含春像，無奈東君漏洩何。"]'),
('d8896640-071b-4def-9d87-b642a3a6fa94','頌古一百則  其二','釋正覺','宋','宋诗','song-poetry','','[]','廓然無聖，來機徑挺。',70,'全唐诗/poet.song.101000.json','["廓然無聖，來機徑挺。", "得非犯鼻而揮斤，失不回頭而墮甑。", "寥寥冷坐少林，默默全提正令。", "秋清月轉霜輪，河淡斗垂夜柄。", "繩繩衣鉢付兒孫，從此人天成藥病。"]'),
('72b54e5a-bd46-43ca-adbf-33358244f7bd','頌古一百則  其三','釋正覺','宋','宋诗','song-poetry','','[]','雲犀玩月璨含輝，木馬遊春駿不羈。',70,'全唐诗/poet.song.101000.json','["雲犀玩月璨含輝，木馬遊春駿不羈。", "眉底一雙寒碧眼，看經那到透牛皮。", "明白心超曠劫，英雄力破重圍。", "妙圓樞口轉靈機，寒山忘却來時路，拾得相將携手歸。"]'),
('8e82b0ee-3838-4da3-bc88-0b69524973af','頌古一百則  其四','釋正覺','宋','宋诗','song-poetry','','[]','百草頭上無邊春，信手拈來用得親。',60,'全唐诗/poet.song.101000.json','["百草頭上無邊春，信手拈來用得親。", "丈六金身功德聚，等閑携手入紅塵。", "塵中能作主，化外自來賓。", "觸處生涯隨分足，未嫌伎倆不如人。"]'),
('03ca7be4-416f-44bd-adc1-21339ef56ec7','頌古一百則  其五','釋正覺','宋','宋诗','song-poetry','','[]','太平治業無像，野老家風至淳。',28,'全唐诗/poet.song.101000.json','["太平治業無像，野老家風至淳。", "只管村歌社飲，那知舜德堯仁。"]'),
('ae6f8011-26fd-478e-a0b5-46e8f2b9463c','頌古一百則  其六','釋正覺','宋','宋诗','song-poetry','','[]','藥之作病，鑒乎前聖。',56,'全唐诗/poet.song.101000.json','["藥之作病，鑒乎前聖。", "病之作醫，必也其誰。", "白頭黑頭兮克家之子，有句無句兮截流之機。", "堂堂坐斷舌頭路，應笑毗耶老古錐。"]'),
('bccbdf5c-88b3-4a59-89d5-3c2b124e174b','頌古一百則  其七','釋正覺','宋','宋诗','song-poetry','','[]','癡兒刻意止啼錢，良駟追風顧影鞭。',32,'全唐诗/poet.song.101000.json','["癡兒刻意止啼錢，良駟追風顧影鞭。", "雲掃長空巢月鶴，寒清入骨不成眠。"]'),
('97272d04-5383-447a-8884-3c9f7be4dcbe','頌古一百則  其八','釋正覺','宋','宋诗','song-poetry','','[]','一尺水，一丈波，五百生前不奈何。',72,'全唐诗/poet.song.101000.json','["一尺水，一丈波，五百生前不奈何。", "不落不昧商量也，依前撞入葛藤窠。", "阿呵呵，會也麽。", "若是你灑灑落落，不妨我哆哆和和。", "神歌社舞自成曲，拍手其間唱哩囉。"]'),
('edbf8fbf-abd1-4001-998d-9bfa6b4cfe11','頌古一百則  其九','釋正覺','宋','宋诗','song-poetry','','[]','兩堂雲水盡分拏，王老師能驗正邪。',94,'全唐诗/poet.song.101000.json','["兩堂雲水盡分拏，王老師能驗正邪。", "利刀斬斷具亡像，千古令人愛作家。", "此道未喪，知音可嘉。", "鑿山透海兮唯尊大禹，鍊石補天兮獨賢女媧。", "趙州老，有生涯，草鞋頭戴較些些。", "異中來也還明鑒，只箇真金不混沙。"]'),
('be5b8a18-e509-4efd-90cc-e4aa1fb6ce6b','頌古一百則  其一○','釋正覺','宋','宋诗','song-poetry','','[]','年老成精不謬傳，趙州古佛嗣南泉。',47,'全唐诗/poet.song.101000.json','["年老成精不謬傳，趙州古佛嗣南泉。", "枯龜喪命因圖象，良馬追風累纏牽。", "勘破了老婆禪，說向人前不直錢。"]'),
('2f9fa508-7481-4443-8cac-ee5f93686446','頌古一百則  其一一','釋正覺','宋','宋诗','song-poetry','','[]','森羅萬象許崢嶸，透脫無方礙眼睛。',64,'全唐诗/poet.song.101000.json','["森羅萬象許崢嶸，透脫無方礙眼睛。", "掃彼門庭誰有力，隱人胸次自成情。", "船橫野渡涵秋碧，棹入蘆花照雪明。", "串錦老漁懷就市，飄飄一葉浪頭行。"]'),
('30f6326e-51de-4b45-a218-d2e5bd54ce1f','頌古一百則  其一二','釋正覺','宋','宋诗','song-poetry','','[]','宗說般般盡强爲，流傳耳口便支離。',64,'全唐诗/poet.song.101000.json','["宗說般般盡强爲，流傳耳口便支離。", "種田博飯家常事，不是飽參人不知。", "參飽明知無所求，子房終不貴封侯。", "忘機歸去同魚鳥，濯足滄浪煙水秋。"]'),
('f6214a9a-af86-48b2-8dec-2214bf806d35','頌古一百則  其一三','釋正覺','宋','宋诗','song-poetry','','[]','言衣半夜付盧能，攪攪黄梅七百僧。',68,'全唐诗/poet.song.101000.json','["言衣半夜付盧能，攪攪黄梅七百僧。", "臨際一枝正法眼，瞎驢滅却得人憎。", "心心相印，祖祖傳燈。", "夷平海岳，變化鯤鵬。", "只箇名言難比擬，大都手段解翻騰。"]'),
('7e6f4736-d27d-46cf-b16f-5d8510b7a80a','頌古一百則  其一四','釋正覺','宋','宋诗','song-poetry','','[]','覿面來時作者知，可中石火電光遲。',60,'全唐诗/poet.song.101000.json','["覿面來時作者知，可中石火電光遲。", "輸機謀主有深意，欺敵兵家無遠思。", "發必中，更謾誰。", "腦後見腮兮人難觸犯，眉底著眼兮渠得便宜。"]'),
('6d292c4a-b306-4a21-9a8f-13df359c37ff','頌古一百則  其一五','釋正覺','宋','宋诗','song-poetry','','[]','老覺情多念子孫，而今慚愧起家門。',32,'全唐诗/poet.song.101000.json','["老覺情多念子孫，而今慚愧起家門。", "是須記取南山語，鏤骨銘肌共報恩。"]'),
('900d7c07-1a6b-43de-ae0b-5f241b84a1b2','頌古一百則  其一六','釋正覺','宋','宋诗','song-poetry','','[]','是與不是，好看棬。',66,'全唐诗/poet.song.101000.json','["是與不是，好看棬。", "似抑似揚，難兄難弟。", "縱也彼既臨時，奪也我何特地。", "金錫一振太孤標，繩床三繞閑遊戲。", "叢林擾擾是非生，想像觸髏前見鬼。"]'),
('14dbea49-a516-4346-a069-70e4f6f25d23','頌古一百則  其一七','釋正覺','宋','宋诗','song-poetry','','[]','秤頭蠅坐便欹傾，萬世權衡照不平。',32,'全唐诗/poet.song.101000.json','["秤頭蠅坐便欹傾，萬世權衡照不平。", "斤兩錙銖見端的，終歸輸我定盤星。"]'),
('02e04287-ce92-4acb-90cb-e90f0e3911bb','頌古一百則  其一八','釋正覺','宋','宋诗','song-poetry','','[]','狗子佛性有，狗子佛性無，直鈎元求負命魚。',68,'全唐诗/poet.song.101000.json','["狗子佛性有，狗子佛性無，直鈎元求負命魚。", "逐氣尋香雲水客，嘈嘈雜雜作分疏。", "平展演，大鋪舒，莫怪儂家不慎初。", "指點瑕疵還奪璧，秦王不識藺相如。"]'),
('566cc733-7757-4817-9966-076021ac5026','頌古一百則  其一九','釋正覺','宋','宋诗','song-poetry','','[]','不起一念須彌山，韶陽法施意非慳。',64,'全唐诗/poet.song.101000.json','["不起一念須彌山，韶陽法施意非慳。", "肯來兩手相分付，擬去千尋不可攀。", "滄海闊，白雲閑，莫將毫髮著其間。", "假雞聲韻難謾我，未肯模胡放過關。"]'),
('d56af0bd-05a6-46ae-8111-b6c34bf60826','頌古一百則  其二○','釋正覺','宋','宋诗','song-poetry','','[]','而今參飽似當時，脫盡廉纖到不知。',64,'全唐诗/poet.song.101000.json','["而今參飽似當時，脫盡廉纖到不知。", "任短任長休剪綴，隨高隨下自平持。", "家門豐儉臨時用，田地優遊信步移。", "三十年前行脚事，分明辜負一雙眉。"]'),
('e4067718-6df6-4b42-a956-e0db138aa974','頌古一百則  其二一','釋正覺','宋','宋诗','song-poetry','','[]','借來聊爾了門頭，得用隨宜即便休。',32,'全唐诗/poet.song.101000.json','["借來聊爾了門頭，得用隨宜即便休。", "象骨巖前弄蛇手，兒時做處老知羞。"]'),
('aa408c55-4225-4021-b91c-c47d4e715b96','頌古一百則  其二二','釋正覺','宋','宋诗','song-poetry','','[]','挫來機，總權柄。',52,'全唐诗/poet.song.101000.json','["挫來機，總權柄。", "事有必行之威，國有不犯之令。", "賓尚奉而主驕，君忌諫而臣佞。", "底意巖頭問德山，一擡一搦看心行。"]'),
('d575abe6-0625-49ba-a094-555da6bcca69','頌古一百則  其二三','釋正覺','宋','宋诗','song-poetry','','[]','淡中有味，妙超情謂。',60,'全唐诗/poet.song.101000.json','["淡中有味，妙超情謂。", "綿綿若存兮象先，兀兀如愚兮道貴。", "玉雕文以喪淳，珠在淵而自媚。", "十分爽氣兮清磨暑秋，一片閑雲兮遠分天水。"]'),
('c205f029-ab64-4ea3-a70f-a6f4265557d8','頌古一百則  其二四','釋正覺','宋','宋诗','song-poetry','','[]','玄沙太剛，長慶少勇，南山鱉鼻死無用。',78,'全唐诗/poet.song.101000.json','["玄沙太剛，長慶少勇，南山鱉鼻死無用。", "風雲際會頭角生，果見韶陽下手弄。", "下手弄，激電光中看變動。", "在我也能遣能呼，於彼也有擒有縱。", "底事如今付阿誰，冷口傷人不知痛。"]'),
('b7d242a0-d273-41a9-a2c1-29672b816701','頌古一百則  其二五','釋正覺','宋','宋诗','song-poetry','','[]','扇子破，索犀牛，棬攣中字有來由。',32,'全唐诗/poet.song.101000.json','["扇子破，索犀牛，棬攣中字有來由。", "誰知桂轂千年魄，妙作通明一點秋。"]'),
('d202575b-a9bc-49e0-8f18-eb1c2f730674','頌古一百則  其二六','釋正覺','宋','宋诗','song-poetry','','[]','一倒一起，雪庭師子。',78,'全唐诗/poet.song.101000.json','["一倒一起，雪庭師子。", "慎於犯而懷仁，勇於爲而見義。", "清光照眼似迷家，明白轉身還墮位。", "衲僧家，了無寄，同死同生，何此何彼。", "暖信破梅兮春到寒枝，凉飚脫葉兮秋澄潦水。"]'),
('aee08fae-89d0-4511-884b-8e4f6a4b836b','頌古一百則  其二七','釋正覺','宋','宋诗','song-poetry','','[]','松直棘曲，鶴長鳧短。',78,'全唐诗/poet.song.101000.json','["松直棘曲，鶴長鳧短。", "羲皇世人，俱忘治亂。", "其安也潜鱗在淵，其逸也翔鳥脫絆。", "無何祖禰西來，裏許得失相半。", "蓬隨風而轉空，船截流而到岸。", "箇中靈利衲僧，看取清凉手段。"]'),
('38609759-8f4a-405b-8d38-7fc0d5ea5ac6','頌古一百則  其二八','釋正覺','宋','宋诗','song-poetry','','[]','壯志稜稜鬢未秋，男兒不憤不封侯。',32,'全唐诗/poet.song.101000.json','["壯志稜稜鬢未秋，男兒不憤不封侯。", "翻思清白傳家客，洗耳溪頭不飲牛。"]'),
('3a2d5c26-c0f7-451a-99a6-edb12d7e90d4','頌古一百則  其二九','釋正覺','宋','宋诗','song-poetry','','[]','鐵牛之機，印住印破。',62,'全唐诗/poet.song.101000.json','["鐵牛之機，印住印破。", "透出毗盧頂𩕳行，却來化佛舌頭坐。", "風穴當衡，盧陂負墮。", "棒頭喝下，電光石火。", "歷歷分明珠在盤，眨起眉毛還蹉過。"]'),
('e70cad5c-cd24-46ed-a038-110797d7f215','頌古一百則  其三○','釋正覺','宋','宋诗','song-poetry','','[]','壞不壞，隨他去也。',56,'全唐诗/poet.song.101000.json','["壞不壞，隨他去也。", "大千界句裏了無鈎鎖機，脚頭多被葛藤礙。", "會不會分明，底事丁寧殺。", "知心拈出勿商量，還我當行相買賣。"]'),
('f0bdaa5f-4776-4df8-8935-d23baa8b38b2','頌古一百則  其三一','釋正覺','宋','宋诗','song-poetry','','[]','一道神光，初不覆藏。',64,'全唐诗/poet.song.101000.json','["一道神光，初不覆藏。", "超見緣也是而無是，出情量也當而無當。", "巖花之粉兮蜂房成蜜，野草之滋兮麝臍作香。", "隨類三尺一丈六，明明觸處露堂堂。"]'),
('b03b4250-3690-446b-b79c-37595dd072e4','頌古一百則  其三二','釋正覺','宋','宋诗','song-poetry','','[]','無外而容，無礙而沖。',54,'全唐诗/poet.song.101000.json','["無外而容，無礙而沖。", "門牆岸岸，關鎖重重。", "酒常酣而卧客，飯雖飽而頹農。", "突出虛空兮鳳摶妙翅，踏翻滄海兮雷送遊龍。"]'),
('ef2e37e6-c8e6-49c0-8f5f-21e8b2d7b555','頌古一百則  其三三','釋正覺','宋','宋诗','song-poetry','','[]','浪汲初昇，雲雷相送，騰躍稜稜看大用。',82,'全唐诗/poet.song.101000.json','["浪汲初昇，雲雷相送，騰躍稜稜看大用。", "燒尾分明度禹門，華鱗未肯淹虀甕。", "老成人，不驚衆，慣臨大敵初無恐。", "泛泛端如五兩輕，堆堆何翅千鈞重。", "高名四海復誰同，介立八風吹不動。"]'),
('9f7e4f14-7ebf-4168-a5e1-624867f0df79','頌古一百則  其三四','釋正覺','宋','宋诗','song-poetry','','[]','皤然渭水起垂綸，何似首陽清餓人。',32,'全唐诗/poet.song.101000.json','["皤然渭水起垂綸，何似首陽清餓人。", "只在一塵分變態，高名勳業兩難泯。"]'),
('3b17b54e-631e-4bd5-831d-c07feb6fdaa3','頌古一百則  其三五','釋正覺','宋','宋诗','song-poetry','','[]','摇頭擺尾赤梢鱗，徹底無依解轉身。',84,'全唐诗/poet.song.101000.json','["摇頭擺尾赤梢鱗，徹底無依解轉身。", "截斷舌頭饒有術，拽回鼻孔妙通神。", "夜明簾外兮風月如晝，枯木巖前兮花卉長春。", "無舌人，無舌人，正令全提一句親。", "獨步環中明了了，任從天下樂欣欣。"]'),
('5507cb30-4510-4b33-a2ea-da0596751264','頌古一百則  其三六','釋正覺','宋','宋诗','song-poetry','','[]','日面月面，星流電卷。',43,'全唐诗/poet.song.101000.json','["日面月面，星流電卷。", "鏡對像而無私，珠在盤而自轉。", "君不見鉗鎚前百鍊之金，刀尺下一機之絹。"]'),
('4a7c63aa-cf36-4b25-9db7-4389797734fd','頌古一百則  其三七','釋正覺','宋','宋诗','song-poetry','','[]','一喚回頭識我不，依俙蘿月又成鈎。',32,'全唐诗/poet.song.101000.json','["一喚回頭識我不，依俙蘿月又成鈎。", "千金之子纔流落，漠漠塗窮有許愁。"]'),
('877f7179-37ae-4f41-9475-54d28e8df4d3','頌古一百則  其三八','釋正覺','宋','宋诗','song-poetry','','[]','迷悟相返，妙傳而簡。',52,'全唐诗/poet.song.101000.json','["迷悟相返，妙傳而簡。", "春拆百花兮一吹，力回九牛兮一挽。", "無奈泥沙撥不開，分明塞斷甘泉眼。", "忽然突出肆橫流，險。"]'),
('6d209273-396a-483e-b3a0-912cdb753b60','頌古一百則  其三九','釋正覺','宋','宋诗','song-poetry','','[]','粥罷令教洗鉢盂，豁然心地自相符。',32,'全唐诗/poet.song.101000.json','["粥罷令教洗鉢盂，豁然心地自相符。", "而今參飽叢林客，且道其間有悟無。"]'),
('c12730d8-fea9-4a3a-9cf6-7dfe1b103f65','頌古一百則  其四○','釋正覺','宋','宋诗','song-poetry','','[]','絃筈相銜，網珠相對。',60,'全唐诗/poet.song.101000.json','["絃筈相銜，網珠相對。", "發百中而箭箭不虛，攝衆景而光光無礙。", "得言句之總，持住遊戲之三昧。", "妙其間也宛轉偏圓，必如是也縱橫自在。"]'),
('d1f5d695-9025-4465-91a0-cf1e29712136','頌古一百則  其四一','釋正覺','宋','宋诗','song-poetry','','[]','餌雲鈎月釣清津，年老心孤未得鱗。',32,'全唐诗/poet.song.101000.json','["餌雲鈎月釣清津，年老心孤未得鱗。", "一曲離騷歸去後，汨羅江上獨醒人。"]'),
('17af0404-0e79-401a-9687-646c7624bfe3','頌古一百則  其四二','釋正覺','宋','宋诗','song-poetry','','[]','鳥之行空，魚之在水。',40,'全唐诗/poet.song.101000.json','["鳥之行空，魚之在水。", "江湖相忘，雲天得志。", "擬心一絲，對面千里。", "知恩報恩，人間幾幾。"]'),
('e95ee1b5-ded1-4d61-90c4-1ce37d4f74db','頌古一百則  其四三','釋正覺','宋','宋诗','song-poetry','','[]','斫斷老葛藤，打破狐窠窟。',36,'全唐诗/poet.song.101000.json','["斫斷老葛藤，打破狐窠窟。", "豹披霧而變文，龍乘雷而換骨。", "咄，起滅紛紛是何物。"]'),
('2b6f5375-56a6-4e63-a462-f16f7cefa802','頌古一百則  其四四','釋正覺','宋','宋诗','song-poetry','','[]','絲綸降，號令分，寰中天子，塞外將軍。',58,'全唐诗/poet.song.101000.json','["絲綸降，號令分，寰中天子，塞外將軍。", "不待雷驚出蟄，那知風遏行雲。", "機底聯綿兮，自有金針玉線。", "印前恢廓兮，元無鳥篆蟲文。"]'),
('c45c5f0c-078a-4d46-9249-430efdea5fed','頌古一百則  其四五','釋正覺','宋','宋诗','song-poetry','','[]','巍巍堂堂，磊磊落落。',48,'全唐诗/poet.song.101000.json','["巍巍堂堂，磊磊落落。", "鬧處刺頭，穩處下脚。", "脚下線斷我自由，鼻端泥盡君休斲。", "莫動著，千年故紙中合藥。"]'),
('36ade33d-d5a8-4ac5-b432-499dc0d92911','頌古一百則  其四六','釋正覺','宋','宋诗','song-poetry','','[]','收把斷襟喉，風磨雲拭，水冷天秋。',32,'全唐诗/poet.song.101000.json','["收把斷襟喉，風磨雲拭，水冷天秋。", "錦鱗莫謂無滋味，釣盡滄浪月一鉤。"]'),
('70c5ba7d-5d51-4ed6-89c7-12d6fb950944','頌古一百則  其四七','釋正覺','宋','宋诗','song-poetry','','[]','岸眉橫雪，河目含秋。',66,'全唐诗/poet.song.101000.json','["岸眉橫雪，河目含秋。", "海口鼓浪，航舌駕流。", "撥亂之手，太平之籌。", "老趙州，老趙州，攪攪叢林卒未休。", "徒費工夫也造車合轍，本無伎倆也塞壑填溝。"]'),
('7b259ff3-56de-43d0-a848-507d27fabf65','頌古一百則  其四八','釋正覺','宋','宋诗','song-poetry','','[]','曼殊問疾老毗耶，不二門開看作家。',68,'全唐诗/poet.song.101000.json','["曼殊問疾老毗耶，不二門開看作家。", "珉表粹中誰賞鑒，忘前失後莫咨嗟。", "區區抱璞兮楚庭臏士，璨璨報珠兮隋城斷蛇。", "休點破，絕疵瑕，俗氣渾無却較些。"]'),
('b3c2b744-0bb0-47d2-a596-709957c8f44a','頌古一百則  其四九','釋正覺','宋','宋诗','song-poetry','','[]','爭解恁麽道，五更雞唱家林曉。',64,'全唐诗/poet.song.101000.json','["爭解恁麽道，五更雞唱家林曉。", "爭肯恁麽道，千年鶴與雲松老。", "寶鑑澄明驗正偏，玉機轉側看兼到。", "門風大振兮規步綿綿，父子變通兮聲光浩浩。"]'),
('13dc594c-2998-444e-b064-b46a0ad4c787','頌古一百則  其五○','釋正覺','宋','宋诗','song-poetry','','[]','切瑳琢磨，變態肴訛。',54,'全唐诗/poet.song.101000.json','["切瑳琢磨，變態肴訛。", "葛陂化龍之杖，陶家居蟄之梭。", "同條生兮有數，同條死兮無多。", "末後句，只這是，風舟載月浮秋水。"]'),
('52094671-e84a-4e1f-93c8-5c14c4b573d3','頌古一百則  其五一','釋正覺','宋','宋诗','song-poetry','','[]','水不洗水，金不博金。',40,'全唐诗/poet.song.101000.json','["水不洗水，金不博金。", "昧毛色而得馬，靡絲絃而樂琴。", "結繩畫卦有許事，喪盡真淳盤古心。"]'),
('e99e43d0-a1b7-4368-9dd2-9905a23e10f6','頌古一百則  其五二','釋正覺','宋','宋诗','song-poetry','','[]','驢覷井，井覷驢。',46,'全唐诗/poet.song.101000.json','["驢覷井，井覷驢。", "智容無外，浄涵有餘。", "肘後誰分印，家中不蓄書。", "機絲不掛梭頭事，文彩縱橫意自殊。"]'),
('b2eb80dc-ed11-431c-bf6b-ca3aa559b671','頌古一百則  其五三','釋正覺','宋','宋诗','song-poetry','','[]','岐分絲染太嘮嘮，果綴花聯敗祖曹。',68,'全唐诗/poet.song.101000.json','["岐分絲染太嘮嘮，果綴花聯敗祖曹。", "妙握司南造化柄，水雲器具在甄陶。", "屏割繁碎，剪除氄毛。", "星衡藻鑑，玉尺金刀。", "黄蘗老，察秋毫，坐斷春風不放高。"]'),
('5f6e3e04-b1a9-46bb-b837-48db18d9489a','頌古一百則  其五四','釋正覺','宋','宋诗','song-poetry','','[]','一竅虛通，八面玲瓏。',58,'全唐诗/poet.song.101000.json','["一竅虛通，八面玲瓏。", "無象無私春入律，不留不礙月行空。", "清浄寶目功德臂，遍身何似通身是。", "現前手眼顯全機，大用縱橫何諱忌。"]'),
('5691f1ad-c14f-4400-aa76-37aff2178be3','頌古一百則  其五五','釋正覺','宋','宋诗','song-poetry','','[]','末後句，會也無，德山父子太含胡。',32,'全唐诗/poet.song.101000.json','["末後句，會也無，德山父子太含胡。", "座中亦有江南客，莫向人前唱鷓鴣。"]'),
('ec982607-ce52-4680-ba9a-c3a497e87e9e','頌古一百則  其五六','釋正覺','宋','宋诗','song-poetry','','[]','抗力霜雪，平步雲霄。',52,'全唐诗/poet.song.101000.json','["抗力霜雪，平步雲霄。", "下惠黜國，相如過橋。", "蕭曹謀略能成漢，巢許身心欲避堯。", "寵辱若驚深自信，真情參跡混漁樵。"]'),
('3800ab59-c646-4261-8823-a2cd74ab1790','頌古一百則  其五七','釋正覺','宋','宋诗','song-poetry','','[]','不妨行細輸先手，自覺心粗愧撞頭。',32,'全唐诗/poet.song.101000.json','["不妨行細輸先手，自覺心粗愧撞頭。", "局破腰間斧柯爛，洗清凡骨共仙遊。"]'),
('29ae3827-b7d2-4884-ae70-ba74e5a3149a','頌古一百則  其五八','釋正覺','宋','宋诗','song-poetry','','[]','綴綴功過，膠膠因果。',42,'全唐诗/poet.song.101000.json','["綴綴功過，膠膠因果。", "鏡外狂奔演若多，杖頭擊著破竈墮。", "竈墮破，來相賀，却道從前辜負我。"]'),
('471eb449-f5ad-4ccd-bb4b-732c46da15ea','頌古一百則  其五九','釋正覺','宋','宋诗','song-poetry','','[]','三老暗轉舵，孤舟夜回頭。',40,'全唐诗/poet.song.101000.json','["三老暗轉舵，孤舟夜回頭。", "蘆花兩岸雪，煙水一江秋。", "風力扶帆行不棹，笛聲喚月下滄洲。"]'),
('52892703-f18c-42ad-8136-498f8ce6a9f0','頌古一百則  其六○','釋正覺','宋','宋诗','song-poetry','','[]','百戰成功老太平，優柔誰肯苦爭衡。',32,'全唐诗/poet.song.101000.json','["百戰成功老太平，優柔誰肯苦爭衡。", "玉鞭金馬閑終日，明月清風富一生。"]'),
('ec4a4a83-46bf-4a7e-ab68-c9724a15c94b','頌古一百則  其六一','釋正覺','宋','宋诗','song-poetry','','[]','入手還將死馬醫，反魂香欲起君危。',32,'全唐诗/poet.song.101000.json','["入手還將死馬醫，反魂香欲起君危。", "一朝拶出通身汗，方信儂家不惜眉。"]'),
('54f3da03-674b-426e-bc76-466a8f998139','頌古一百則  其六二','釋正覺','宋','宋诗','song-poetry','','[]','第二頭分悟破迷，快須攃手捨筌蹄。',64,'全唐诗/poet.song.101000.json','["第二頭分悟破迷，快須攃手捨筌蹄。", "功兮未盡成駢拇，智也難知覺噬臍。", "兔老冰盤秋露泣，烏寒玉樹曉風凄。", "持來大仰辨真假，痕玷渾無貴白珪。"]'),
('9577c294-45c1-4ce1-8be4-4bb061054d07','頌古一百則  其六三','釋正覺','宋','宋诗','song-poetry','','[]','芥城劫石妙窮初，活眼環中照廓虛。',32,'全唐诗/poet.song.101000.json','["芥城劫石妙窮初，活眼環中照廓虛。", "不許夜行投曉到，家音未肯付鴻魚。"]'),
('9ddaa862-1361-4d8c-b8a2-f3bd2b544dfb','頌古一百則  其六四','釋正覺','宋','宋诗','song-poetry','','[]','離念見佛，破塵出經。',60,'全唐诗/poet.song.101000.json','["離念見佛，破塵出經。", "現成家法，誰立門庭。", "月逐舟行江練浄，春隨草上燒痕青。", "撥不撥，聽丁寧，三徑就荒歸便得，舊時松菊尚芳馨。"]'),
('d983d01c-56e8-40db-b699-d53b2d916162','頌古一百則  其六五','釋正覺','宋','宋诗','song-poetry','','[]','新婦騎驢阿家牽，體段風流得自然。',32,'全唐诗/poet.song.101000.json','["新婦騎驢阿家牽，體段風流得自然。", "堪笑效顰鄰舍女，向人添醜不成妍。"]'),
('33d475aa-36f5-4c6a-bdb7-a864852f4cbf','頌古一百則  其六六','釋正覺','宋','宋诗','song-poetry','','[]','規圓矩方，用行舍藏。',80,'全唐诗/poet.song.101000.json','["規圓矩方，用行舍藏。", "鈍置棲蘆之鳥，進退觸藩之羊。", "喫人家飯，卧自家床。", "雲騰致雨，露結爲霜。", "玉線相投透針鼻，錦絲不斷吐梭腸。", "石女機停兮夜色向午，木人路轉兮月影移央。"]'),
('27c6f1de-3d17-43bb-a554-f87d213a9dd1','頌古一百則  其六七','釋正覺','宋','宋诗','song-poetry','','[]','天蓋地載，成團成塊。',58,'全唐诗/poet.song.101000.json','["天蓋地載，成團成塊。", "周法界而無邊，折鄰虛而無內。", "及盡玄微，誰分向背。", "佛祖來償口業債，問取南泉王老師，人人只喫一莖菜。"]'),
('7dd59eae-d6cd-4664-a0b9-9b9f70084dbf','頌古一百則  其六八','釋正覺','宋','宋诗','song-poetry','','[]','拂牛劍氣洗兵威，定亂歸功更是誰。',32,'全唐诗/poet.song.101000.json','["拂牛劍氣洗兵威，定亂歸功更是誰。", "一旦氛埃清四海，垂衣皇化自無爲。"]'),
('f167e62e-ca46-40cd-9ec0-cd07d42d2f10','頌古一百則  其六九','釋正覺','宋','宋诗','song-poetry','','[]','跛跛挈挈，㲯㲯毿毿。',52,'全唐诗/poet.song.101000.json','["跛跛挈挈，㲯㲯毿毿。", "百不可取，一無所堪。", "默默自知田地穩，騰騰誰謂肚皮憨。", "普周法界渾成飯，鼻孔纍垂信飽參。"]'),
('b83b9ba2-4937-44c7-89f8-df00a4f4f942','頌古一百則  其七○','釋正覺','宋','宋诗','song-poetry','','[]','豁落亡依，高閑不羈，家邦平貼到人稀。',46,'全唐诗/poet.song.101000.json','["豁落亡依，高閑不羈，家邦平貼到人稀。", "些些力量分階級，蕩蕩身心絕是非。", "是非絕，介立大方無軌轍。"]'),
('eb11428a-513a-450a-93c0-7722f3777265','頌古一百則  其七一','釋正覺','宋','宋诗','song-poetry','','[]','作賊心，過人膽，歷歷縱橫對機感。',72,'全唐诗/poet.song.101000.json','["作賊心，過人膽，歷歷縱橫對機感。", "保福雲門也垂鼻欺唇，翠巖長慶也脩眉映眼。", "杜禪和，有何限，剛道意句一齊剗。", "埋沒自己也飲氣吞聲，带累先宗也面牆檐版。"]'),
('60df14de-852b-4f1c-92b1-d9790e6e681c','頌古一百則  其七二','釋正覺','宋','宋诗','song-poetry','','[]','凍眠雪屋歲摧頹，窈窕蘿門夜不開。',32,'全唐诗/poet.song.101000.json','["凍眠雪屋歲摧頹，窈窕蘿門夜不開。", "寒槁園林看變態，春風吹起律筒灰。"]'),
('5a965867-1380-4f1a-b872-5d860a8038d0','頌古一百則  其七三','釋正覺','宋','宋诗','song-poetry','','[]','清白門庭四絕鄰，長年關掃不容塵。',64,'全唐诗/poet.song.101000.json','["清白門庭四絕鄰，長年關掃不容塵。", "光明轉處傾殘月，爻象分時却建寅。", "新滿孝，便逢春，醉步狂歌任墮巾。", "散髮夷猶誰管系，太平無事酒顛人。"]'),
('5d13884f-4487-4d6f-96ff-745155964a36','頌古一百則  其七四','釋正覺','宋','宋诗','song-poetry','','[]','沒蹤跡，斷消息。',66,'全唐诗/poet.song.101000.json','["沒蹤跡，斷消息。", "白雲無根，清風何色。", "散乾蓋而非心，持坤輿而有力。", "洞千古之淵源，造萬像之模則。", "剎塵道會也處處普賢，樓閣門開也頭頭彌勒。"]'),
('8223ef7a-03bc-4a54-aa37-f28a0d262e64','頌古一百則  其七五','釋正覺','宋','宋诗','song-poetry','','[]','圓珠不穴，大璞不琢，道人所貴無稜角。',34,'全唐诗/poet.song.101000.json','["圓珠不穴，大璞不琢，道人所貴無稜角。", "拈却肯路根塵空，脫體無依活卓卓。"]'),
('df36615a-9b62-4768-b5f9-3ea934a374e1','頌古一百則  其七六','釋正覺','宋','宋诗','song-poetry','','[]','佛祖髑髏穿一串，宮漏沈沈密傳箭。',68,'全唐诗/poet.song.101000.json','["佛祖髑髏穿一串，宮漏沈沈密傳箭。", "人天機要發千鈞，雲陣煇煇急飛電。", "箇中人，看轉變，遇賤則貴貴則賤。", "得珠罔象兮至道綿綿，遊刃亡牛兮赤心片片。"]'),
('5d3784de-ef74-4010-89dd-7afe2d7b7579','頌古一百則  其七七','釋正覺','宋','宋诗','song-poetry','','[]','道環之虛靡盈，空印之字未形。',58,'全唐诗/poet.song.101000.json','["道環之虛靡盈，空印之字未形。", "妙運天輪地軸，密羅武緯文經。", "放開捏聚，獨立周行。", "機發玄樞兮青天激電，眼含紫光兮白日見星。"]'),
('540470e9-19ee-4d99-9ca7-db06c737249b','頌古一百則  其七八','釋正覺','宋','宋诗','song-poetry','','[]','胡餅云超佛祖談，句中無味若爲參。',32,'全唐诗/poet.song.101000.json','["胡餅云超佛祖談，句中無味若爲參。", "衲僧一日如知飽，方見雲門面不慚。"]'),
('f957c15c-72e9-43c4-9dec-bd79f2fdc076','頌古一百則  其七九','釋正覺','宋','宋诗','song-poetry','','[]','玉人夢破一聲雞，轉盼生涯色色齊。',48,'全唐诗/poet.song.101000.json','["玉人夢破一聲雞，轉盼生涯色色齊。", "有信風雷催出蟄，無言桃李自成蹊。", "及時節，力耕犁，誰怕春疇沒脛泥。"]'),
('893d07e7-bdfe-4f96-a66f-2a42bd72649a','頌古一百則  其八○','釋正覺','宋','宋诗','song-poetry','','[]','蒲團禪版對龍牙，何事當機不作家。',76,'全唐诗/poet.song.101000.json','["蒲團禪版對龍牙，何事當機不作家。", "未意成褫明目下，恐將流落在天涯。", "虛空那掛劍，星漢却浮槎。", "不萌草解藏香象，無底籃能著活蛇。", "今日江湖何障礙，通方津渡有船車。"]'),
('dc73e007-b6a3-4b27-b5ed-da630fdf8f27','頌古一百則  其八一','釋正覺','宋','宋诗','song-poetry','','[]','夜壑藏舟，澄源著棹。',60,'全唐诗/poet.song.101000.json','["夜壑藏舟，澄源著棹。", "龍魚未知水爲命，折筯不妨聊一攪。", "玄沙師，小塘老，函蓋箭鋒，探竿影草。", "潜縮也老龜巢蓮，遊戲也華鱗弄藻。"]'),
('a1171af4-6f86-43da-ac93-9170d5e600f6','頌古一百則  其八二','釋正覺','宋','宋诗','song-poetry','','[]','出門躍馬掃欃搶，萬國煙塵自肅清。',32,'全唐诗/poet.song.101000.json','["出門躍馬掃欃搶，萬國煙塵自肅清。", "十二處亡閑影響，三千界放浄光明。"]'),
('0050148f-b0d8-4d42-94aa-2b83c82f9bf5','頌古一百則  其八三','釋正覺','宋','宋诗','song-poetry','','[]','妙藥何曾過口，神醫莫能投手。',70,'全唐诗/poet.song.101000.json','["妙藥何曾過口，神醫莫能投手。", "若存也渠本非無，至虛也渠本非有。", "不滅而生，不亡而壽。", "全超威音之前，獨步劫空之後。", "成平也天蓋地擎，運轉也烏飛兔走。"]'),
('3ce25e70-a519-4fba-aedc-b0f42504e4a0','頌古一百則  其八四','釋正覺','宋','宋诗','song-poetry','','[]','俱胝老子指頭禪，三十年來用不殘。',76,'全唐诗/poet.song.101000.json','["俱胝老子指頭禪，三十年來用不殘。", "信有道人方外術，了無俗物眼前看。", "所得甚簡，施設彌寬，大千剎海飲毛端。", "鱗龍無限落誰手，珍重任公把釣竿。", "師復豎起一指云，看。"]'),
('9a3ba72c-87b8-4fee-8985-4c751198e2fd','頌古一百則  其八五','釋正覺','宋','宋诗','song-poetry','','[]','孤迥迥，圓陀陀，眼力盡處高峩峩。',70,'全唐诗/poet.song.101000.json','["孤迥迥，圓陀陀，眼力盡處高峩峩。", "月落潭空夜色重，雲收山瘦秋容多。", "八封位正，五行氣和，身先在裏見來麽。", "南陽父子兮却似知有，西竺佛祖兮無如奈何。"]'),
('013c9b5f-e9cc-47a2-ba16-7f917fd9aabb','頌古一百則  其八六','釋正覺','宋','宋诗','song-poetry','','[]','九包之雛，千里之駒。',52,'全唐诗/poet.song.101000.json','["九包之雛，千里之駒。", "真風度籥，靈機發樞。", "劈面來時飛電急，迷雲破處太陽孤。", "捋虎鬚，見也無，箇是雄雄大丈夫。"]'),
('0cf93164-2f61-4e15-ac33-6782481219fa','頌古一百則  其八七','釋正覺','宋','宋诗','song-poetry','','[]','藤枯樹倒問溈山，大笑呵呵豈等閑。',32,'全唐诗/poet.song.101000.json','["藤枯樹倒問溈山，大笑呵呵豈等閑。", "笑裏有刀窺得破，言思無路絕機關。"]'),
('070707ce-4bfc-4112-819e-517410bcedf3','頌古一百則  其八八','釋正覺','宋','宋诗','song-poetry','','[]','滄海瀝乾，太虛充滿。',50,'全唐诗/poet.song.101000.json','["滄海瀝乾，太虛充滿。", "衲僧鼻孔長，古佛舌頭短。", "珠絲度九曲，玉機纔一轉。", "直下相逢誰識渠，始信斯人不合伴。"]'),
('7e2948e7-1336-47a8-a9b4-a97964334e9b','頌古一百則  其八九','釋正覺','宋','宋诗','song-poetry','','[]','草漫漫，門裏門外君自看。',51,'全唐诗/poet.song.101000.json','["草漫漫，門裏門外君自看。", "荆棘林中下脚易，夜明簾外轉身難。", "看看，幾何般。", "且隨老木同寒瘠，將逐春風入燒瘢。"]'),
('127fd629-2eec-4a87-9461-f16eb47d00c0','頌古一百則  其九○','釋正覺','宋','宋诗','song-poetry','','[]','夢中擁衲參耆舊，列聖森森坐其右。',84,'全唐诗/poet.song.101000.json','["夢中擁衲參耆舊，列聖森森坐其右。", "當仁不讓犍穉鳴，說法無畏師子吼。", "心安如海，膽量如斗。", "鮫目淚流，蚌腸珠剖。", "譫語誰知洩我機，厖眉應笑揚家醜。", "離四句，絕百非，馬師父子病休醫。"]'),
('a9366041-fe3e-44c7-9b4f-d9e4175f4b20','頌古一百則  其九一','釋正覺','宋','宋诗','song-poetry','','[]','照徹離微造化根，紛紜出沒見其門。',64,'全唐诗/poet.song.101000.json','["照徹離微造化根，紛紜出沒見其門。", "遊神劫外問何有，著眼身前知妙存。", "虎嘯蕭蕭巖吹作，龍吟冉冉洞雲昏。", "南泉點破時人夢，要識堂堂補處尊。"]'),
('d2edcc52-c5a8-4470-9deb-3a5a4ddd7af1','頌古一百則  其九二','釋正覺','宋','宋诗','song-poetry','','[]','收盡餘懷厭事華，歸來何所是生涯。',64,'全唐诗/poet.song.101000.json','["收盡餘懷厭事華，歸來何所是生涯。", "爛柯樵子疑無路，掛樹壺公妙有家。", "夜水金波浮桂影，秋風雪陣擁蘆花。", "寒魚著底不吞餌，興盡清歌却轉槎。"]'),
('4131ab7d-8128-45b2-8e67-787f65e2decf','頌古一百則  其九三','釋正覺','宋','宋诗','song-poetry','','[]','別是非，明得喪。',58,'全唐诗/poet.song.101000.json','["別是非，明得喪。", "應之心，指諸掌。", "往來不往來，只者俱是藏。", "輪王賞之有功，黄帝得之罔象。", "轉樞機，能伎倆，明眼衲僧無鹵莽。"]'),
('6fdf44e3-4d96-496c-952e-df3b305d28e1','頌古一百則  其九四','釋正覺','宋','宋诗','song-poetry','','[]','卸却臭皮袋，拈轉赤肉團。',80,'全唐诗/poet.song.101000.json','["卸却臭皮袋，拈轉赤肉團。", "當頭鼻孔正，直下髑髏乾。", "老醫不見從來癖，少子相看向近難。", "野水瘦時秋潦退，白雲斷處舊山寒。", "須剿絕，莫顢頇。", "轉盡無功伊就位，孤標不與汝同盤。"]'),
('ad11b229-bb4a-4d73-8c01-7cc7873ff3a8','頌古一百則  其九五','釋正覺','宋','宋诗','song-poetry','','[]','臨際全機格調高，棒頭有眼辨秋毫。',64,'全唐诗/poet.song.101000.json','["臨際全機格調高，棒頭有眼辨秋毫。", "掃除狐兔家風峻，變化魚龍雷火燒。", "活人劍，殺人刀，倚天照雪利吹毛。", "一等令行滋味別，十分痛處是誰遭。"]'),
('5823b83f-05c5-415c-a7af-44472682b569','頌古一百則  其九六','釋正覺','宋','宋诗','song-poetry','','[]','石霜一宗，親傳九峰。',52,'全唐诗/poet.song.101000.json','["石霜一宗，親傳九峰。", "香煙脫去，正脈難通。", "月巢鶴作千年夢，雪屋人迷一色功。", "坐斷十方猶點額，密移一步看飛龍。"]'),
('bc0bd38a-cf10-4165-929b-c5ea26e558e2','頌古一百則  其九七','釋正覺','宋','宋诗','song-poetry','','[]','君王底意語知音，天下傾誠葵藿心。',32,'全唐诗/poet.song.101000.json','["君王底意語知音，天下傾誠葵藿心。", "掇出中原無價寶，不同趙璧與燕金。"]'),
('0bb711b3-619c-4374-9895-411c80b3eb78','頌古一百則  其九八','釋正覺','宋','宋诗','song-poetry','','[]','中原之寶呈興化，一段光明難定價。',32,'全唐诗/poet.song.101000.json','["中原之寶呈興化，一段光明難定價。", "帝業堪爲萬世師，金輪景燿四天下。"]'),
('f5b8f61c-5631-47d7-9d70-dffc6f54acca','頌古一百則  其九九','釋正覺','宋','宋诗','song-poetry','','[]','不入世，未循緣，劫壺空處有家傳。',32,'全唐诗/poet.song.101000.json','["不入世，未循緣，劫壺空處有家傳。", "白蘋風細秋江暮，古岸船歸一带煙。"]'),
('40cdcd33-e1a7-4ecf-98b8-e58d1027d4a8','頌古一百則  其一○○','釋正覺','宋','宋诗','song-poetry','','[]','鉢裏飯，桶裏水，開口見膽求知己。',60,'全唐诗/poet.song.101000.json','["鉢裏飯，桶裏水，開口見膽求知己。", "擬思便落二三機，對面忽成千萬里。", "韶陽師，較些子。", "斷金之義兮誰與相同，匪石之心兮獨能如此。"]'),
('d05294f2-4e6b-4ae8-acce-e0969078bafb','頌古一百則  其一○一','釋正覺','宋','宋诗','song-poetry','','[]','見有不有，翻手覆手。',22,'全唐诗/poet.song.101000.json','["見有不有，翻手覆手。", "瑯琊山裏人，不落瞿曇後。"]'),
('418f8059-d3fe-437c-8fa1-409f26bdfa80','偈頌二百零五首  其一','釋正覺','宋','宋诗','song-poetry','','[]','陰極而陽生，力窮而位轉。',82,'全唐诗/poet.song.101000.json','["陰極而陽生，力窮而位轉。", "蒼龍退骨而驤，玄豹披霧而變。", "要將三世佛髑髏，穿作數珠子一穿。", "莫道明頭暗頭，真箇日面月面。", "直饒你斗滿秤平，也輸我賣貴買賤。", "槃裏明珠，不撥自轉。"]'),
('2d72f0ff-1c4d-46ad-81fc-41eee3f62b2f','偈頌二百零五首  其二','釋正覺','宋','宋诗','song-poetry','','[]','妙存湛湛不爲無，真照靈靈不爲有。',32,'全唐诗/poet.song.101000.json','["妙存湛湛不爲無，真照靈靈不爲有。", "更向其間退步看，白雲斷處青山瘦。"]'),
('d9a0ad7f-6bdc-424a-8a6f-170b981618ac','偈頌二百零五首  其三','釋正覺','宋','宋诗','song-poetry','','[]','恁麽去底錯，恁麽去底親。',36,'全唐诗/poet.song.101000.json','["恁麽去底錯，恁麽去底親。", "錯時錯到底，親時親見真。", "相識滿天下，知心能幾人。"]'),
('9c39fae3-51e2-41aa-89d5-68c7f68fd9ab','偈頌二百零五首  其四','釋正覺','宋','宋诗','song-poetry','','[]','生也死也，不道不道。',42,'全唐诗/poet.song.101000.json','["生也死也，不道不道。", "只知憨狗怒逐塊，誰見死蛇驚出草。", "著眼家林裏許看，不萌枝上春陽早。"]'),
('488456a0-5b1f-43b8-91e3-5728d33812d6','偈頌二百零五首  其五','釋正覺','宋','宋诗','song-poetry','','[]','來來去去山中人，識得青山便是身。',32,'全唐诗/poet.song.101000.json','["來來去去山中人，識得青山便是身。", "青山是身身是我，更於何處著根塵。"]'),
('38c891d7-f15c-4b15-aefb-e3b4d2c71754','偈頌二百零五首  其六','釋正覺','宋','宋诗','song-poetry','','[]','溶溶曳曳山上雲，潺潺湲湲山下水。',32,'全唐诗/poet.song.101000.json','["溶溶曳曳山上雲，潺潺湲湲山下水。", "試問其間雲水人，更於何處求諸己。"]'),
('716ede6b-7ab9-4927-84e8-9117c4035c92','偈頌二百零五首  其七','釋正覺','宋','宋诗','song-poetry','','[]','吸盡西江向汝道，馬師不肯落荒草。',32,'全唐诗/poet.song.101000.json','["吸盡西江向汝道，馬師不肯落荒草。", "三千剎海一成秋，明月珊瑚冷相照。"]'),
('eaba6bff-39f7-4ee2-8812-2f736d8eb4c4','偈頌二百零五首  其八','釋正覺','宋','宋诗','song-poetry','','[]','孤筇長作水雲遊，底事而今放下休。',64,'全唐诗/poet.song.101000.json','["孤筇長作水雲遊，底事而今放下休。", "一點破幽明歷歷，十分合體冷湫湫。", "暗中須透金針穴，轉處還藏玉線頭。", "劫外家風茲日辨，渠儂真與我儂儔。"]'),
('ce7a3368-f202-41eb-8c9f-d5c13eef9b1e','偈頌二百零五首  其九','釋正覺','宋','宋诗','song-poetry','','[]','劫前機，肘後印，用而無痕，空而不盡。',46,'全唐诗/poet.song.101000.json','["劫前機，肘後印，用而無痕，空而不盡。", "是誰造作大千，出自虛明方寸。", "你儂欲去泥瘢，匠石不慳斤運。"]'),
('393934af-851b-49b4-94c2-81bc40fc1777','偈頌二百零五首  其一○','釋正覺','宋','宋诗','song-poetry','','[]','五月五日天中節，百草頭上看生殺。',64,'全唐诗/poet.song.101000.json','["五月五日天中節，百草頭上看生殺。", "甘草黄連自苦甜，人參附子分寒熱。", "薰蕕難昧雙垂爪，滋味那瞞初偃月。", "圓明了知心念閒，摩訶迦葉能分別。"]'),
('a34dfdf3-7423-4568-b8f5-2b255ad92181','偈頌二百零五首  其一一','釋正覺','宋','宋诗','song-poetry','','[]','你也住，我也住，十方三世一時捏。',33,'全唐诗/poet.song.101000.json','["你也住，我也住，十方三世一時捏。", "聚月醉雲酣離水犀，轉身觸倒珊瑚樹。"]'),
('3e8b0957-4c24-4c88-a21f-47ccb53e28c3','偈頌二百零五首  其一二','釋正覺','宋','宋诗','song-poetry','','[]','萬里西來坐少林，燈燈相續至如今。',64,'全唐诗/poet.song.101000.json','["萬里西來坐少林，燈燈相續至如今。", "泥牛鬬裏同歸海，玉線聯時妙契鍼。", "未墜綿綿吾祖緒，不忘切切老婆心。", "風前一弄無弦曲，會有叢林人賞音。"]'),
('585ed1fa-f95a-4e0c-995c-9f2a88a2ce01','偈頌二百零五首  其一三','釋正覺','宋','宋诗','song-poetry','','[]','菩提無樹鏡非臺，虛浄光明不受埃。',64,'全唐诗/poet.song.101000.json','["菩提無樹鏡非臺，虛浄光明不受埃。", "照處易分雪裏粉，轉時難辨墨中煤。", "鳥歸無影樹頭宿，華在不萌枝上開。", "際會風雲底時節，寒梭出蟄一聲雷。"]'),
('ce9f8d63-b7ac-4141-be8b-b78565c89082','偈頌二百零五首  其一四','釋正覺','宋','宋诗','song-poetry','','[]','開爐歲歲是今朝，暖氣潜通稱我曹。',32,'全唐诗/poet.song.101000.json','["開爐歲歲是今朝，暖氣潜通稱我曹。", "可惜丹霞燒木佛，翻令院主墮眉毛。"]'),
('8da2ce1b-4264-4a0a-b3d2-de70915c8b7b','偈頌二百零五首  其一五','釋正覺','宋','宋诗','song-poetry','','[]','蛇鉆不入，鳥飛不度，我道人人在裏許。',34,'全唐诗/poet.song.101000.json','["蛇鉆不入，鳥飛不度，我道人人在裏許。", "三更明月下西山，一陣清霜脫寒樹。"]'),
('cfde3f5b-55b6-456d-b6dc-92dc33a3856f','偈頌二百零五首  其一六','釋正覺','宋','宋诗','song-poetry','','[]','阿那是祖，位崇家譜。',52,'全唐诗/poet.song.101000.json','["阿那是祖，位崇家譜。", "二儀之根，萬象之母。", "建化門未要轉機，實際地如何進步。", "青山一線路相通，月落寒猿啼斷處。"]'),
('61697686-21cc-40a4-837a-4ea800dbda3b','偈頌二百零五首  其一七','釋正覺','宋','宋诗','song-poetry','','[]','肉團無主，空劫有家。',72,'全唐诗/poet.song.101000.json','["肉團無主，空劫有家。", "清白十分活計，丕平一段生涯。", "月戶風高兮雲凝古路，星河浪靜兮夜泛靈槎。", "唯心成萬法，化佛現千華。", "快須拽鼻回香象，切忌當頭觸死蛇。"]'),
('254b4e13-6042-4d7e-a4dd-a55560872223','偈頌二百零五首  其一八','釋正覺','宋','宋诗','song-poetry','','[]','劫火炎炎是事灰，劫空空處有靈臺。',32,'全唐诗/poet.song.101000.json','["劫火炎炎是事灰，劫空空處有靈臺。", "更無妍醜成痕垢，妍醜俱從箇裏來。"]'),
('84853ea3-3cc0-4ce9-95a5-78b69e41b772','偈頌二百零五首  其一九','釋正覺','宋','宋诗','song-poetry','','[]','夤緣心，和合相，傀儡棚頭呈伎倆。',62,'全唐诗/poet.song.101000.json','["夤緣心，和合相，傀儡棚頭呈伎倆。", "打破畫屏歸去來，家山田地還清曠。", "掃斷情塵，瀝乾識浪。", "虛明遊踐兮風月一壺，夢冷轉身兮雪雲萬丈。"]'),
('bf4f1781-2534-47f3-85cf-3b9654eb6aaa','偈頌二百零五首  其二○','釋正覺','宋','宋诗','song-poetry','','[]','舌頭一臠肉，口唇兩片皮。',58,'全唐诗/poet.song.101000.json','["舌頭一臠肉，口唇兩片皮。", "其間無固必，分外莫猜疑。", "趙州古佛，雲門聖師，歷歷機頭不掛絲。", "自然桃李成蹊去，那是春風作意吹。"]'),
('48944d0d-c108-4fb6-898a-8c89940f5606','偈頌二百零五首  其二一','釋正覺','宋','宋诗','song-poetry','','[]','深明無底，靈異無根。',62,'全唐诗/poet.song.101000.json','["深明無底，靈異無根。", "案山行盡，不見有家。", "識浪瀝乾，不見有己。", "石女掣開金鎖鑰，木人撥動玉輪機。", "方信道從佛口生，法化生得佛法分。"]'),
('c05451c2-1420-4911-ae51-54535c6a9644','偈頌二百零五首  其二二','釋正覺','宋','宋诗','song-poetry','','[]','柳線垂金鶯語滑，華棚張錦蝶飛忙。',32,'全唐诗/poet.song.101000.json','["柳線垂金鶯語滑，華棚張錦蝶飛忙。", "見聞裏許通消息，誰得先生點鐵方。"]'),
('ef7c4d3e-4ba3-4f53-8e92-b5cc57de092a','偈頌二百零五首  其二三','釋正覺','宋','宋诗','song-poetry','','[]','露，超宗越祖。',64,'全唐诗/poet.song.101000.json','["露，超宗越祖。", "人言渠爇返魂香，我道伊撾塗毒皷。", "苦苦，更若咬文嚼字，規行矩步。", "上唱下隨，前瞻後顧。", "張三裹帽新有錢，富漢不是恁麽做。"]'),
('ede8b3ad-82b3-4556-acb9-c15555541fb7','偈頌二百零五首  其二四','釋正覺','宋','宋诗','song-poetry','','[]','巢知風，穴知雨。',42,'全唐诗/poet.song.101000.json','["巢知風，穴知雨。", "不用安排，自成規矩。", "歷歷靡緣，閒閒何偶。", "樂哉林鳥淵魚，一笑相忘爾汝。"]'),
('115891c2-a389-48d9-8725-1d217a3e8210','偈頌二百零五首  其二五','釋正覺','宋','宋诗','song-poetry','','[]','衲僧舌頭真箇自由，渾侖裏許沒錐鈎。',33,'全唐诗/poet.song.101000.json','["衲僧舌頭真箇自由，渾侖裏許沒錐鈎。", "輪扁斲工不授子，庖丁遊刃無全牛。"]'),
('9356fcef-017b-45c0-b327-635d82d77528','偈頌二百零五首  其二六','釋正覺','宋','宋诗','song-poetry','','[]','身非塵聚，卓卓妙存。',72,'全唐诗/poet.song.101000.json','["身非塵聚，卓卓妙存。", "心非情緣，冥冥獨尊。", "其體也出諸障礙，其用也得大自在。", "無去無來，非顯非晦。", "應色應聲，亡對亡待。", "饅頭胡餅觀世音，還我當行家賣買。"]'),
('bb6e9ff0-b56a-42f0-927b-9ad492804413','偈頌二百零五首  其二七','釋正覺','宋','宋诗','song-poetry','','[]','華鳥不來空過春，牛頭山上懶慵人。',32,'全唐诗/poet.song.101000.json','["華鳥不來空過春，牛頭山上懶慵人。", "自心浄故元無作，放下許多閒苦辛。"]'),
('bb843f63-90d9-44db-907f-b10eba14c46c','偈頌二百零五首  其二八','釋正覺','宋','宋诗','song-poetry','','[]','眼裏拈却翳，空中那有華。',28,'全唐诗/poet.song.101000.json','["眼裏拈却翳，空中那有華。", "路不拾遺君子事，民無侵擾太平家。"]'),
('5b08d3ad-6764-4cc6-97d6-3ba477657669','偈頌二百零五首  其二九','釋正覺','宋','宋诗','song-poetry','','["\u534e\u5c71"]','檐頭雨滴聲，問你要惺惺。',50,'全唐诗/poet.song.101000.json','["檐頭雨滴聲，問你要惺惺。", "直下成己事，途中作主盟。", "剎剎見佛，塵塵出經。", "擘開華嶽連天色，放出黄河到海聲。"]'),
('cbbc1b3d-8618-4836-b0a1-d7d26d0f7a74','偈頌二百零五首  其三○','釋正覺','宋','宋诗','song-poetry','','[]','只箇家風，八面玲瓏。',98,'全唐诗/poet.song.101000.json','["只箇家風，八面玲瓏。", "斗柄橫而河淡，夢鶴起而巢空。", "功中退步就位，位裏移身借功。", "靈靈了了處同中有異，湛湛澄澄處異中有同。", "隨宜也機輪宛轉，妙應也關捩虛通。", "佛子住此地，即是佛受用。", "經行及坐卧，常在於其中。"]'),
('0457d7fc-0608-4b5d-b092-f74dbbca4503','偈頌二百零五首  其三一','釋正覺','宋','宋诗','song-poetry','','[]','玉麒麟，鐵昆侖。',20,'全唐诗/poet.song.101000.json','["玉麒麟，鐵昆侖。", "金繩在渠手，歸步月黄昏。"]'),
('858ff66c-fe2f-4e11-a7fa-e1fa40525553','偈頌二百零五首  其三二','釋正覺','宋','宋诗','song-poetry','','[]','九重尊貴位中人，燦燦星圖拱北辰。',64,'全唐诗/poet.song.101000.json','["九重尊貴位中人，燦燦星圖拱北辰。", "活計四時調玉燭，家風萬世運金輪。", "區分群象布淳化，囊括二儀懷至仁。", "算數不能窮壽量，南山蒼翠鎮長春。"]'),
('79c52a65-3417-4b1d-80e2-6970edf25362','偈頌二百零五首  其三三','釋正覺','宋','宋诗','song-poetry','','[]','人平不語，水平不流。',38,'全唐诗/poet.song.101000.json','["人平不語，水平不流。", "風定華猶落，鳥啼山更幽。", "只麽天真無少剩，莫於裏許著絲頭。"]'),
('0595da1c-b0d0-4c4b-b407-e18675795e10','偈頌二百零五首  其三四','釋正覺','宋','宋诗','song-poetry','','[]','不居功，不合伴，脫體其間過一遍。',32,'全唐诗/poet.song.101000.json','["不居功，不合伴，脫體其間過一遍。", "夢覺船浮明月波，眼寒雪擁蘆華岸。"]'),
('439619ee-bb34-4396-84c2-379f8478267e','偈頌二百零五首  其三五','釋正覺','宋','宋诗','song-poetry','','[]','祖華五葉發靈根，端的知恩解報恩。',64,'全唐诗/poet.song.101000.json','["祖華五葉發靈根，端的知恩解報恩。", "大仰未忘東寺會，玄沙相繼雪峯存。", "機梭傳處難通路，針芥投時有妙門。", "鼻孔放光出氣快，當年一斲盡泥痕。"]'),
('a49a195d-5fb7-455b-ae04-92062b1368c7','偈頌二百零五首  其三六','釋正覺','宋','宋诗','song-poetry','','[]','一月雨，半夏凉，蒲團禪板坐相當。',32,'全唐诗/poet.song.101000.json','["一月雨，半夏凉，蒲團禪板坐相當。", "泥牛踏破澄潭月，光影芒芒夜未央。"]'),
('a5609a5c-191e-4f3d-8eae-0298d180e859','偈頌二百零五首  其三七','釋正覺','宋','宋诗','song-poetry','','[]','黄河九曲，七斤布衫。',36,'全唐诗/poet.song.101000.json','["黄河九曲，七斤布衫。", "胡馬嘶北，越鳥巢南。", "衲僧恰到真常處，語不欺人面不慚。"]'),
('72b16fe9-141f-43bb-8b0e-87f32ffb47c2','偈頌二百零五首  其三八','釋正覺','宋','宋诗','song-poetry','','[]','直到劫空明自己，有無不墮超生死。',32,'全唐诗/poet.song.101000.json','["直到劫空明自己，有無不墮超生死。", "夜船載月釣滄浪，清白傳家只如此。"]'),
('7272b7d0-dde0-4bdb-8c5b-6ef6f3945aaa','偈頌二百零五首  其三九','釋正覺','宋','宋诗','song-poetry','','[]','大衆退後，妙超窠臼。',52,'全唐诗/poet.song.101000.json','["大衆退後，妙超窠臼。", "不用安排，何須飣餖。", "動絃別曲孰知音，舒腸瀝膽渠開口。", "叢林切莫亂商量，三世諸佛不知有。"]'),
('3b57291c-1e3f-4cc5-afcf-5634fae5e7ee','偈頌二百零五首  其四○','釋正覺','宋','宋诗','song-poetry','','[]','主中之主天中天，家勢金輪萬代傳。',64,'全唐诗/poet.song.101000.json','["主中之主天中天，家勢金輪萬代傳。", "退步不居尊貴位，借功却作誕生緣。", "廓虛印上無瑕垢，明白機頭有轉旋。", "劫數不能知壽量，湛存象外自綿綿。"]'),
('7b22bdfc-a991-4b84-a25f-801a066ec9b1','偈頌二百零五首  其四一','釋正覺','宋','宋诗','song-poetry','','[]','愛結成身，想澄成界，從此漂流生死海。',72,'全唐诗/poet.song.101000.json','["愛結成身，想澄成界，從此漂流生死海。", "照徹靈源湛不渾，方知幻泡同無礙。", "六門氣秋，四大緣壞，了了一真常自在。", "明月混融兮雪蘆眼迷，清風相送兮夜船歸快。"]'),
('6a317c15-efc5-456e-b73d-41eec33f4e7c','偈頌二百零五首  其四二','釋正覺','宋','宋诗','song-poetry','','[]','藏山於澤，藏舟於壑。',38,'全唐诗/poet.song.101000.json','["藏山於澤，藏舟於壑。", "一真不可藏，怕爾滿寥廓。", "傳家清白有風規，圓陀陀地無稜角。"]'),
('9770fac0-9df6-4cfe-a2cc-84924aa9c86a','偈頌二百零五首  其四三','釋正覺','宋','宋诗','song-poetry','','[]','朔風拂旦吹秋過，時節薄寒宜就火。',64,'全唐诗/poet.song.101000.json','["朔風拂旦吹秋過，時節薄寒宜就火。", "拱默威音世外遊，放閑枯木堂中坐。", "塵劫空時却有家，道環虛處元無我。", "靈靈不昧寂而知，衣鉢少林分付可。"]'),
('3002b74c-fb69-40f5-b326-b2d42312f813','偈頌二百零五首  其四四','釋正覺','宋','宋诗','song-poetry','','[]','青山不用白雲朝，白雲不用青山管。',32,'全唐诗/poet.song.101000.json','["青山不用白雲朝，白雲不用青山管。", "雲常在山山在雲，青山自閑雲自緩。"]'),
('a7474b8f-92c6-44ca-95ad-f0a0aa187e7e','偈頌二百零五首  其四五','釋正覺','宋','宋诗','song-poetry','','[]','去時還復似來時，明月蘆華夜不迷。',32,'全唐诗/poet.song.101000.json','["去時還復似來時，明月蘆華夜不迷。", "轉棹又歸何處去，秋光目斷水天低。"]'),
('8823cbb4-b70c-48e4-a9c6-ad1ca89be275','偈頌二百零五首  其四六','釋正覺','宋','宋诗','song-poetry','','[]','去也五年，分疏不下，一句元無縫罅。',62,'全唐诗/poet.song.101000.json','["去也五年，分疏不下，一句元無縫罅。", "只知推過商量，誰信分明酬價。", "玲瓏底相知，莽鹵底相訝。", "寧可與曉事人相罵，不可共不曉事人說話。"]'),
('449a8c05-cd37-42b9-9351-3034734f7e49','偈頌二百零五首  其四七','釋正覺','宋','宋诗','song-poetry','','[]','忒團圞，不相瞞。',16,'全唐诗/poet.song.101000.json','["忒團圞，不相瞞。", "冬不寒，臘下看。"]'),
('d0a148dd-0a35-4830-99f0-5c6e13aff0e5','偈頌二百零五首  其四八','釋正覺','宋','宋诗','song-poetry','','[]','一陣清霜，千峯寒色，裏許是誰看轉側。',34,'全唐诗/poet.song.101000.json','["一陣清霜，千峯寒色，裏許是誰看轉側。", "家風克紹紹非功，撫背忽驚兒脫白。"]'),
('3e7cce77-cac0-4f7e-acd9-425cdd0c8a82','偈頌二百零五首  其四九','釋正覺','宋','宋诗','song-poetry','','[]','不習禪，不論義，鋪箇破席日裏睡。',32,'全唐诗/poet.song.101000.json','["不習禪，不論義，鋪箇破席日裏睡。", "想料上方兜率天，也無如此日炙背。"]'),
('72caeaeb-4fee-44ba-a271-baaa3b153709','偈頌二百零五首  其五○','釋正覺','宋','宋诗','song-poetry','','[]','唯只一真心，三緣坐斷誰昇沉。',80,'全唐诗/poet.song.101000.json','["唯只一真心，三緣坐斷誰昇沉。", "遂成十法界，六道輪迴自障礙。", "不見一法即如來，方得名爲觀自在。", "見怪不怪，其怪自壞。", "靈從何來，聖亦何在。", "拄杖敲時竈墮摧，一片虛明絕中外。"]'),
('2e280b02-cd43-4a6d-a3ea-eb2bb12f502d','偈頌二百零五首  其五一','釋正覺','宋','宋诗','song-poetry','','[]','凜凜將軍令已行，八荒四海要澄清。',32,'全唐诗/poet.song.101000.json','["凜凜將軍令已行，八荒四海要澄清。", "提來劍氣干牛斗，洗蕩氛埃見太平。"]'),
('ba2b94a3-4cba-4c8d-9561-2a08f53e0105','偈頌二百零五首  其五二','釋正覺','宋','宋诗','song-poetry','','[]','春雨洗園林，春風動簾箔。',40,'全唐诗/poet.song.101000.json','["春雨洗園林，春風動簾箔。", "百城人已歸，彈指開樓閣。", "入門俱是佛家風，帝網光明相映奪。"]'),
('29166bf4-1d32-4c2d-8457-4928350f9fcc','偈頌二百零五首  其五三','釋正覺','宋','宋诗','song-poetry','','[]','三十六物一時空，空空空處自光通。',60,'全唐诗/poet.song.101000.json','["三十六物一時空，空空空處自光通。", "轉側末山不露頂，非男女相主人翁。", "主人翁，借伴能來用莫窮。", "百草頭上俱胝老，塵塵剎剎是家風。"]'),
('8d4b507d-c5f4-47e9-8db5-e6c491c784e4','偈頌二百零五首  其五四','釋正覺','宋','宋诗','song-poetry','','[]','拽石般土，打鼓作舞。',56,'全唐诗/poet.song.101000.json','["拽石般土，打鼓作舞。", "意不立玄，機不停午。", "踏破草鞋赤脚行，見成底事休回互。", "不回互，大龍不受玄沙瞞，前面斑斑元是虎。"]'),
('340de5ee-dfd1-42cd-9017-9431d6837529','偈頌二百零五首  其五五','釋正覺','宋','宋诗','song-poetry','','[]','心心相印，葉葉聯芳，自己光明不覆藏。',34,'全唐诗/poet.song.101000.json','["心心相印，葉葉聯芳，自己光明不覆藏。", "剎剎塵塵如是說，廣長舌相解敷揚。"]'),
('2ce8349b-77a2-4af5-aa23-c8e8a7baf3e2','偈頌二百零五首  其五六','釋正覺','宋','宋诗','song-poetry','','[]','釣盡滄波月一鈎，月低烟樹夜維舟。',58,'全唐诗/poet.song.101000.json','["釣盡滄波月一鈎，月低烟樹夜維舟。", "寒雞抖擻呼天曉，笑對春風百草柔。", "中外夷猶，縱橫自由。", "志公不是閒和尚，刀尺相將拄杖頭。"]'),
('8290e2e2-104f-4622-ad1c-28acef305d0e','偈頌二百零五首  其五七','釋正覺','宋','宋诗','song-poetry','','[]','無事題取一首，我儂不落他人後。',61,'全唐诗/poet.song.101000.json','["無事題取一首，我儂不落他人後。", "略略綽綽思大口，醇醇釅釅白家酒。", "醉中猶道未沾唇，被人問著還打手。", "不打手，三年一閏，冬後數九。"]'),
('d77633ce-2497-4d69-8ad7-af23dbb22aa5','偈頌二百零五首  其五八','釋正覺','宋','宋诗','song-poetry','','[]','小雪纖纖洗霽色，新春冉冉入燒痕。',64,'全唐诗/poet.song.101000.json','["小雪纖纖洗霽色，新春冉冉入燒痕。", "三千界現非佗物，百億分身有妙門。", "白雲兒是青山用，青山父是白雲根。", "寄語白雲數迴首，青山免見瘦稜稜。"]'),
('12ddde8f-e4dd-4415-a195-aa6ab6f0fe92','偈頌二百零五首  其五九','釋正覺','宋','宋诗','song-poetry','','[]','一雨一晴，蓋載生成。',54,'全唐诗/poet.song.101000.json','["一雨一晴，蓋載生成。", "桃華濯錦而麗，楊柳弄風而輕。", "决决野泉發響，關關林鳥和鳴。", "歷歷見聞中得妙，更嫌何處不分明。"]'),
('d4d08837-6fff-46fb-aa55-8473c6e545b7','偈頌二百零五首  其六○','釋正覺','宋','宋诗','song-poetry','','[]','雲開青山橫屋頭，雨住流水漲門底。',72,'全唐诗/poet.song.101000.json','["雲開青山橫屋頭，雨住流水漲門底。", "南無家家觀世音，迴避不及鼻相抵。", "非唯鼻相抵，亦乃同見同聞，同齅同舐，同身同意，同得同智。", "果滿菩提圓，華開世界起。"]'),
('bb72e9db-67d3-4914-85fd-b7cdcff22e16','偈頌二百零五首  其六一','釋正覺','宋','宋诗','song-poetry','','[]','靈雲却解見桃華，老眼如今冷淡些。',32,'全唐诗/poet.song.101000.json','["靈雲却解見桃華，老眼如今冷淡些。", "拈却面前案山子，柱門路直不橫斜。"]'),
('1507135c-0e49-4114-b24b-5765c11c3ae9','偈頌二百零五首  其六二','釋正覺','宋','宋诗','song-poetry','','[]','乳粥當年得善生，心開成道見明星。',32,'全唐诗/poet.song.101000.json','["乳粥當年得善生，心開成道見明星。", "而今各各恁麽去，猶較瞿曇半月程。"]'),
('4422fe8c-6c30-4352-b662-b0c95523a262','偈頌二百零五首  其六三','釋正覺','宋','宋诗','song-poetry','','[]','人平不語，水平不流。',36,'全唐诗/poet.song.101000.json','["人平不語，水平不流。", "嘉州大象，陜府鐵牛。", "莫怪扶桑最先照，大都家住海門洲。"]'),
('e6826455-de6b-4987-9c05-dbddff2203ba','偈頌二百零五首  其六四','釋正覺','宋','宋诗','song-poetry','','[]','風不鳴條，雨不破塊，會不會兮還信采。',48,'全唐诗/poet.song.101000.json','["風不鳴條，雨不破塊，會不會兮還信采。", "廓廓落落兮大方無外，跛跛挈挈兮大功不宰，穩穩密密兮心安如海。"]'),
('9ea68f8c-a2a5-4be9-b783-9e209f745bd7','偈頌二百零五首  其六五','釋正覺','宋','宋诗','song-poetry','','[]','功勳密處轉身難，轉後家風又覺寬。',32,'全唐诗/poet.song.101000.json','["功勳密處轉身難，轉後家風又覺寬。", "黯黯舊山青落眼，渙然霜雪洗蓑寒。"]'),
('1df6710b-5b92-4e33-998d-9137e8ec8c6d','偈頌二百零五首  其六六','釋正覺','宋','宋诗','song-poetry','','[]','空劫威音前，別有一壺天。',24,'全唐诗/poet.song.101000.json','["空劫威音前，別有一壺天。", "御樓觀射獵，不是刈茅田。"]'),
('4deb2f67-6f26-465d-8474-40d067b565d5','偈頌二百零五首  其六七','釋正覺','宋','宋诗','song-poetry','','[]','生滅去來，本如來藏。',54,'全唐诗/poet.song.101000.json','["生滅去來，本如來藏。", "清浄妙明，虛融通暢。", "六門我絕，攀緣三界。", "渠無身相，無生路上。", "底人識取，萬迴和尚。", "持鉢歸。"]'),
('70d10c99-2794-4ce7-88d8-0c18992fd8b1','偈頌二百零五首  其六八','釋正覺','宋','宋诗','song-poetry','','[]','不可得一，不可得異，我如是也彼如是。',50,'全唐诗/poet.song.101000.json','["不可得一，不可得異，我如是也彼如是。", "兩莖眉現燄光身，百草頭揚祖師意。", "歸雲誰使就青山，落華自得隨流水。"]'),
('c53cb9ce-03ef-4e54-8407-5da5b1b86700','偈頌二百零五首  其六九','釋正覺','宋','宋诗','song-poetry','','[]','密密住其中，靈然空不空。',48,'全唐诗/poet.song.101000.json','["密密住其中，靈然空不空。", "一牛纔飲水，五馬不嘶風。", "位裏亡消息，機頭有變通。", "三千大千事，彈指入圓融。"]'),
('f476ba59-f3c4-49bb-8f9e-00b7b90f37a9','偈頌二百零五首  其七○','釋正覺','宋','宋诗','song-poetry','','[]','三界唯心，唯心三界，一切法空觀自在。',68,'全唐诗/poet.song.101000.json','["三界唯心，唯心三界，一切法空觀自在。", "處處光明處處身，者回泡幻同無礙。", "吐雲如山，吞川如海，了無毛髮居其外。", "萬象森羅盡我家，只箇虛空肚皮大。"]'),
('78a71d24-8fbc-405b-94dd-5c194de6647a','偈頌二百零五首  其七一','釋正覺','宋','宋诗','song-poetry','','[]','佛身光明了無垢，性水清浄常不渾。',80,'全唐诗/poet.song.101000.json','["佛身光明了無垢，性水清浄常不渾。", "降生沐浴吉祥事，要以大開功德門。", "哆哆和和增口業，膠膠綴綴添塵結。", "大家浄洗佛渾身，徹底洞然明皎潔。", "長時諸佛洗我身，今日衆僧洗我佛。"]'),
('3b4f351b-c80d-4291-8ea4-e457aa0c886c','偈頌二百零五首  其七二','釋正覺','宋','宋诗','song-poetry','','[]','時行即行卓然何倚，時止即止廓爾獨靈。',36,'全唐诗/poet.song.101000.json','["時行即行卓然何倚，時止即止廓爾獨靈。", "歷萬變而不我求功，住一如而不我藏用。"]'),
('7e1aeb72-1212-4ab3-9079-870915663ef5','偈頌二百零五首  其七三','釋正覺','宋','宋诗','song-poetry','','[]','淵默之津，皓然之色。',36,'全唐诗/poet.song.101000.json','["淵默之津，皓然之色。", "混處功齊，細看轉側。", "昆侖脫手黄金繩，鼻孔纍垂收不得。"]'),
('206a76cc-e9ee-43a2-afd9-81b1218cbe1d','偈頌二百零五首  其七四','釋正覺','宋','宋诗','song-poetry','','[]','長者長法身，短者短法身。',72,'全唐诗/poet.song.101000.json','["長者長法身，短者短法身。", "虛空已是色，大地却非塵。", "覷得破阿那律祖，放得穩舜若多神。", "飄飄閑戲白鷗水，栩栩夢遊蝴蝶春。", "拶頭拶面推來也，眼裏無筋一世貧。"]'),
('c8d2c068-6643-4511-a5ce-18a3a179a9da','偈頌二百零五首  其七五','釋正覺','宋','宋诗','song-poetry','','[]','不可得而有，不可得而無。',58,'全唐诗/poet.song.101000.json','["不可得而有，不可得而無。", "寂寂十方坐斷，寥寥一境清虛。", "妍醜那能瞞浄鏡，青黄莫我染明珠。", "剎海不能關鎖月，夜來流影在珊瑚。"]'),
('017f3d0c-de50-4951-9096-a0dc235dc124','偈頌二百零五首  其七六','釋正覺','宋','宋诗','song-poetry','','[]','渠非老朽，不禮不受。',50,'全唐诗/poet.song.101000.json','["渠非老朽，不禮不受。", "威音世前，毗盧頂後。", "把定壺中白日長，觸著匣內青蛇吼。", "良醫叮囑病人，服藥不如忌口。"]'),
('d2f32738-25f4-48d7-b04a-4467e8f8a942','偈頌二百零五首  其七七','釋正覺','宋','宋诗','song-poetry','','[]','不是心，不是物。',72,'全唐诗/poet.song.101000.json','["不是心，不是物。", "非天非人，非僧非俗。", "南北東西莫我尋，長短方圓莫我測。", "牛飲星河，兔眠月窟，徹底靈明破昏塞。", "末山超拔兮頂相不形，鐵磨變通兮舌頭無骨。"]'),
('72683c38-686d-410f-bc7e-32e537443463','偈頌二百零五首  其七八','釋正覺','宋','宋诗','song-poetry','','[]','吾家日日選場開，及第心空有大才。',32,'全唐诗/poet.song.101000.json','["吾家日日選場開，及第心空有大才。", "莫把桂枝零碎折，爲佗和月抱將來。"]'),
('2ab0de8d-f17c-4cb2-80e8-20cf76d862e9','偈頌二百零五首  其七九','釋正覺','宋','宋诗','song-poetry','','[]','十方大地是我一箇身便能禁足，十方衆生是我一箇漢方解護生。',46,'全唐诗/poet.song.101000.json','["十方大地是我一箇身便能禁足，十方衆生是我一箇漢方解護生。", "禁足也步步不妄行，護生也心心不妄動。"]'),
('64564da1-498a-4508-9c30-61373d94406f','偈頌二百零五首  其八○','釋正覺','宋','宋诗','song-poetry','','[]','十方法侶共安居，雲月身心照處虛。',64,'全唐诗/poet.song.101000.json','["十方法侶共安居，雲月身心照處虛。", "轉側蘆汀飛鶴鷺，亡機林壑混樵漁。", "瘢痕若盡光無際，絲糝纔萌念有餘。", "廊下相逢休放喝，且容興化撒珍珠。"]'),
('d1440d0f-243d-4046-8366-81ae52366c77','偈頌二百零五首  其八一','釋正覺','宋','宋诗','song-poetry','','[]','踏破草鞋赤脚走，拄杖頭上挑日月。',66,'全唐诗/poet.song.101000.json','["踏破草鞋赤脚走，拄杖頭上挑日月。", "智門真得祖家風，放出雲門廣長舌。", "大智如愚，大功若拙，用盡工夫參不徹。", "莫於平地上增堆，休向虛空裏釘橛。"]'),
('a9bc3b31-7625-42f1-80ec-6e288ce41911','偈頌二百零五首  其八二','釋正覺','宋','宋诗','song-poetry','','[]','途中久客憶家山，一線蹊通入翠寒。',64,'全唐诗/poet.song.101000.json','["途中久客憶家山，一線蹊通入翠寒。", "望處霽雲收素練，跨門殘月墮金盤。", "十虛俱殞眼方闊，三世齊吞肚覺寬。", "變化鯤鵬底時節，霄程九萬看風摶。"]'),
('ac05039e-f7f7-4434-98c4-15c3499112cd','偈頌二百零五首  其八三','釋正覺','宋','宋诗','song-poetry','','[]','正晝熱，深夜凉，冰壺誰復到中央。',60,'全唐诗/poet.song.101000.json','["正晝熱，深夜凉，冰壺誰復到中央。", "身心直許摩雲月，脾肺都將洗雪霜。", "莫守一色處，莫坐萬年床。", "玉人轉側機梭動，細辨裏頭偏正方。"]'),
('234ef3e4-3cc5-4556-94f8-9a21f5b1bffa','偈頌二百零五首  其八四','釋正覺','宋','宋诗','song-poetry','','[]','身裏出門，門裏出身。',22,'全唐诗/poet.song.101000.json','["身裏出門，門裏出身。", "白雲能作客，明月解隨人。"]'),
('9ecf9eb7-08f3-4c81-994a-83eb069b40b7','偈頌二百零五首  其八五','釋正覺','宋','宋诗','song-poetry','','[]','一句超然，良馬影鞭。',60,'全唐诗/poet.song.101000.json','["一句超然，良馬影鞭。", "道出語默，理合方圓。", "運斤之妙，賓主可憐。", "斲輪之伎，父子不傳。", "莫將爻象兮相求龜殻，纔落是非兮底事驢年。"]'),
('80c9e55a-359e-4eae-92f5-5dc81536a5d4','偈頌二百零五首  其八六','釋正覺','宋','宋诗','song-poetry','','[]','鑑像谷神，雲心月影。',74,'全唐诗/poet.song.101000.json','["鑑像谷神，雲心月影。", "閒閒不宰於功，歷歷無私於應。", "莫問正偏，誰論動靜。", "自方自圓，誰欠誰剩。", "能來異類中行，常處那伽大定。", "雲水叢林自恣人，果如是也須相慶。"]'),
('94ce05ae-4ff6-42d4-bd74-1a6339e2f306','偈頌二百零五首  其八七','釋正覺','宋','宋诗','song-poetry','','[]','父母所生眼，悉見三千界，拈却案山誰我礙。',70,'全唐诗/poet.song.101000.json','["父母所生眼，悉見三千界，拈却案山誰我礙。", "直饒全象無全牛，未免依前還礙塞。", "衲僧家，真慶快。", "物我虛空，混成一塊。", "更於何處著根塵，祇箇堂堂觀自在。"]'),
('27fcd6a8-2ff3-44d8-bbd3-7a1992508933','偈頌二百零五首  其八八','釋正覺','宋','宋诗','song-poetry','','[]','不展事，不投機。',42,'全唐诗/poet.song.101000.json','["不展事，不投機。", "不徇緣，不答話。", "箇是出格，轍脫窠臼。", "平生肝膽向人傾，相識猶如不相識。"]'),
('f7f467ae-7c41-48f6-b4f3-f9981d3fd0c1','偈頌二百零五首  其八九','釋正覺','宋','宋诗','song-poetry','','[]','雨從何來，不離問處。',77,'全唐诗/poet.song.101000.json','["雨從何來，不離問處。", "森羅大千，出乎方寸。", "照中之虛，靜中之動，衲僧分上常相共。", "寒露濡松夜氣清，皋禽驚起月巢夢。", "舉劉端公問雲居：雨從何來？居云：從端公問處來。"]'),
('d6ae3763-411f-4cd3-828c-e157a6df5ef7','偈頌二百零五首  其九○','釋正覺','宋','宋诗','song-poetry','','[]','主中主，須辨取。',48,'全唐诗/poet.song.101000.json','["主中主，須辨取。", "動犯威嚴，細看規矩。", "貴不可得其名，壽不可窮其數。", "四溟潮落露仙山，萬里雲開廓天宇。"]'),
('92bdb151-2bcb-43bc-b9ad-1e35e8767160','偈頌二百零五首  其九一','釋正覺','宋','宋诗','song-poetry','','[]','蘇秦嘗佩六國印，許由還厭一瓢風。',32,'全唐诗/poet.song.101000.json','["蘇秦嘗佩六國印，許由還厭一瓢風。", "了無佗相能通變，可笑僧繇畫誌公。"]'),
('02caeb07-c64c-4e42-bf62-36b0f9aa9e2f','偈頌二百零五首  其九二','釋正覺','宋','宋诗','song-poetry','','[]','靈機未動，道環先入。',72,'全唐诗/poet.song.101000.json','["靈機未動，道環先入。", "極理也妙得窮通，順事也聊分借借。", "無象無私，何固何必。", "娟娟印水之月魂，冉冉在華之春律。", "巍巍堂堂兮煒煒煌煌，三千大千兮周行獨立。"]'),
('6e79e0d9-4935-479e-8c5e-adecb8d9516d','偈頌二百零五首  其九三','釋正覺','宋','宋诗','song-poetry','','["\u534e\u5c71"]','幾許歡心幾許愁，好看野老兩眉頭。',78,'全唐诗/poet.song.101000.json','["幾許歡心幾許愁，好看野老兩眉頭。", "家風平貼清如鏡，水瘦山空一樣秋。", "手段通變，身心自由，不怕風濤雪擁舟。", "海上三山頹一掣，六鼇連落上金鈎。", "華嶽連天秀，黄河輥底流。"]'),
('39aa3ef4-c3c1-4e0f-bca9-4cf71da92ee5','偈頌二百零五首  其九四','釋正覺','宋','宋诗','song-poetry','','[]','大而無外，小而無內。',78,'全唐诗/poet.song.101000.json','["大而無外，小而無內。", "合虛空而無欠無餘，混萬象而成團成塊。", "不出不在，不失不壞。", "我不與物爭，物不爲我礙。", "路逢達道人，不將語默對。", "三千界裏放光明，雙六盤中休喝彩。"]'),
('7fa5ca02-5192-40b2-b2ab-e39ffb5fa9d5','偈頌二百零五首  其九五','釋正覺','宋','宋诗','song-poetry','','[]','裏頭看，勿暑寒，直下滄溟瀝得乾。',32,'全唐诗/poet.song.101000.json','["裏頭看，勿暑寒，直下滄溟瀝得乾。", "我道巨鼇能俯拾，笑君沙際弄釣竿。"]'),
('e75c5b90-2bc7-4ddf-86de-320bed38afe4','偈頌二百零五首  其九六','釋正覺','宋','宋诗','song-poetry','','[]','雲門老子能施設，胡餅佛祖俱超越。',64,'全唐诗/poet.song.101000.json','["雲門老子能施設，胡餅佛祖俱超越。", "哆哆和和兩片皮，狤狤獠獠三寸舌。", "不是特地展家風，也非投機應時節。", "生鐵鑄成無孔鎚，忒團圞兮難下楔。"]'),
('d2bacf13-8ec7-489e-bdeb-87e30c2e4a9b','偈頌二百零五首  其九七','釋正覺','宋','宋诗','song-poetry','','[]','皓然雪月浄無埃，一色功中更放開。',32,'全唐诗/poet.song.101000.json','["皓然雪月浄無埃，一色功中更放開。", "喚起牧童蓑底夢，白牛鼻孔拽教回。"]'),
('f1bc4a96-2009-4843-b5c0-8a4d53c0e0a1','偈頌二百零五首  其九八','釋正覺','宋','宋诗','song-poetry','','[]','陰陽爻象此爲宗，殺活機頭看變通。',64,'全唐诗/poet.song.101000.json','["陰陽爻象此爲宗，殺活機頭看變通。", "玉女退身功後位，木人引步異中同。", "一塵不受能虛廓，萬像無遺却混融。", "借得因緣成現用，玲瓏八面盡家風。"]'),
('502f358f-178c-474d-b6e0-a72544419a46','偈頌二百零五首  其九九','釋正覺','宋','宋诗','song-poetry','','[]','飲乾巨海，推倒須彌，廓大靈通更是誰。',78,'全唐诗/poet.song.101000.json','["飲乾巨海，推倒須彌，廓大靈通更是誰。", "馨香秀林栴檀枝，哮吼出屈師子兒。", "三千界現一彈指，八萬門開雙用眉。", "知不知，爲不爲。", "道滿十處兮心超億劫，影流萬象兮氣分二儀。"]'),
('8998991c-bf96-42c0-8887-98a04eaaba29','偈頌二百零五首  其一○○','釋正覺','宋','宋诗','song-poetry','','[]','宿雨洗去山面塵，東君料理山家春。',68,'全唐诗/poet.song.101000.json','["宿雨洗去山面塵，東君料理山家春。", "浩劫壺中勿新歲，枯木巖前有古人。", "寒暑不到以法界爲處，齒髮不老以虛空爲身。", "坐間默有相傳意，川上乾無逝去津。"]'),
('2645fe23-eef4-44a5-8c91-6d671e4a00d9','偈頌二百零五首  其一○一','釋正覺','宋','宋诗','song-poetry','','[]','生滅夤緣不著人，一年纔盡又逢春。',58,'全唐诗/poet.song.101000.json','["生滅夤緣不著人，一年纔盡又逢春。", "森羅借得爲他用，法界渾侖是我身。", "不受雜毒，自然純真。", "拈却千差亡彼此，打成一片沒根塵。"]'),
('a95e6a06-860d-4854-8faf-68dcbe38c957','偈頌二百零五首  其一○二','釋正覺','宋','宋诗','song-poetry','','[]','非男女之相，出有無之量。',46,'全唐诗/poet.song.101000.json','["非男女之相，出有無之量。", "透萬機之前，超三界之上。", "窮而通，簡而當。", "松含月兮夜寒，溪带雨而春漲。"]'),
('e67952e8-099c-4135-a80e-da22a4431b17','偈頌二百零五首  其一○三','釋正覺','宋','宋诗','song-poetry','','[]','管籥真風暗度韶，春恩如許在芳條。',32,'全唐诗/poet.song.101000.json','["管籥真風暗度韶，春恩如許在芳條。", "志公不是閑和尚，拄杖頭邊有剪刀。"]'),
('6c6beeb2-c5e2-4d84-a120-4e24575ad635','偈頌二百零五首  其一○四','釋正覺','宋','宋诗','song-poetry','','[]','鶯弄歌喉華弄妍，如許春事在門前。',32,'全唐诗/poet.song.101000.json','["鶯弄歌喉華弄妍，如許春事在門前。", "道沖而用亡機者，買盡風流不著錢。"]'),
('1da74dcd-d8d7-4cb1-8ebb-4dde97d5b0b7','偈頌二百零五首  其一○五','釋正覺','宋','宋诗','song-poetry','','[]','壽等南山，位崇北斗。',40,'全唐诗/poet.song.101000.json','["壽等南山，位崇北斗。", "機運象先，體同道久。", "明逾日月兮普及幽深，德合乾坤兮廓無前後。"]'),
('93235367-336e-4630-bd88-d7755a694e8d','偈頌二百零五首  其一○六','釋正覺','宋','宋诗','song-poetry','','[]','清徹性空水，圓明浄智身。',88,'全唐诗/poet.song.101000.json','["清徹性空水，圓明浄智身。", "箇中不洗體，直下了無塵。", "有成佛，有降神。", "有彼岸，有迷津。", "哆哆和和此其始，膠膠綴綴此其因。", "底時節，釋迦文，惡水驀頭澆莫嗔。", "何須念彼觀音力，自然還著於本人。"]'),
('b8fdcaae-08c4-41ef-8c79-a6c42e325d3a','偈頌二百零五首  其一○七','釋正覺','宋','宋诗','song-poetry','','[]','不起一念，向道須彌。',38,'全唐诗/poet.song.101000.json','["不起一念，向道須彌。", "舌頭一臠肉，口唇兩邊皮。", "雲門得用妙如許，不落是非知不知。"]'),
('2ec6d9bf-acc6-4e50-ab63-23b97f47715e','偈頌二百零五首  其一○八','釋正覺','宋','宋诗','song-poetry','','[]','蕭然一念未萌初，露柱懷胎辨得無。',32,'全唐诗/poet.song.101000.json','["蕭然一念未萌初，露柱懷胎辨得無。", "風掃餘雲月未上，霽虛廓浄絕方隅。"]'),
('be33c771-a676-4309-ac40-78584218f854','偈頌二百零五首  其一○九','釋正覺','宋','宋诗','song-poetry','','[]','嶺頭功德眼，倦足等閑垂。',24,'全唐诗/poet.song.101000.json','["嶺頭功德眼，倦足等閑垂。", "紅爐一點雪，直下廓亡依。"]'),
('b2aa3e7d-415f-4be5-a035-71b381f969bd','偈頌二百零五首  其一一○','釋正覺','宋','宋诗','song-poetry','','[]','百草頭上平生事，鬧市門前百億身。',80,'全唐诗/poet.song.101000.json','["百草頭上平生事，鬧市門前百億身。", "及盡如許閑影響，體明空劫那邊人。", "那邊人，何所有，白雲斷處青山秀。", "絕他緣，唯自守，結夏須教醭生口。", "有說便是野干鳴，無說自然師子吼。"]'),
('6e93b1fe-b977-4687-9712-665314ba0295','偈頌二百零五首  其一一一','釋正覺','宋','宋诗','song-poetry','','[]','凡聖通同共一家，寂光田地看生涯。',32,'全唐诗/poet.song.101000.json','["凡聖通同共一家，寂光田地看生涯。", "而今選佛心空去，自有丘園開覺華。"]'),
('622a91c6-54bb-4c42-9e26-5965789aaf1c','偈頌二百零五首  其一一二','釋正覺','宋','宋诗','song-poetry','','[]','三千世界出彈指，百億莊嚴集化身。',32,'全唐诗/poet.song.101000.json','["三千世界出彈指，百億莊嚴集化身。", "壽域無疆同道久，河沙劫數一成春。"]'),
('c609c481-9a5a-449a-94ac-da238a745cdf','偈頌二百零五首  其一一三','釋正覺','宋','宋诗','song-poetry','','[]','世尊無說說，迦葉不聞聞。',28,'全唐诗/poet.song.101000.json','["世尊無說說，迦葉不聞聞。", "默默到時良自慶，家山元在白雲根。"]'),
('373a4f39-6315-4555-8c15-85b156d87c40','偈頌二百零五首  其一一四','釋正覺','宋','宋诗','song-poetry','','[]','歸根得旨，葉落知秋。',64,'全唐诗/poet.song.101000.json','["歸根得旨，葉落知秋。", "拈得鼻孔，失却舌頭。", "照徹三世佛之頂𩕳，把定歷代祖之襟喉。", "玉井涵碧，冰壺斷流。", "諸法空寂爲之座，是須坐處不停囚。"]'),
('6f245a57-941d-4783-b92d-9dfaad7f89f3','偈頌二百零五首  其一一五','釋正覺','宋','宋诗','song-poetry','','[]','當處出生，當處滅盡。',36,'全唐诗/poet.song.101000.json','["當處出生，當處滅盡。", "三世如來，相授此印。", "石人放意卧煙寒，玉女摇頭看曉信。"]'),
('bf259350-a7b9-411c-8ac3-a8803c328dd2','偈頌二百零五首  其一一六','釋正覺','宋','宋诗','song-poetry','','[]','雪峯之子，德山之孫，葛藤牽轉難窮根。',66,'全唐诗/poet.song.101000.json','["雪峯之子，德山之孫，葛藤牽轉難窮根。", "截斷衆流見源底，相應函蓋同乾坤。", "長長短短無節奏，綿綿密密忒鶻侖。", "隨波逐浪恁麽去，上船便到家前門。"]'),
('8d39caaa-ecb5-40c7-8f39-a99659d9ddb3','偈頌二百零五首  其一一七','釋正覺','宋','宋诗','song-poetry','','[]','端公問處來，徑直勿迂回。',28,'全唐诗/poet.song.101000.json','["端公問處來，徑直勿迂回。", "善財處處逢彌勒，彈指作聲樓閣開。"]'),
('48a77df4-016f-4c2d-8bfa-edcd833ed4d6','偈頌二百零五首  其一一八','釋正覺','宋','宋诗','song-poetry','','[]','冰鑑浄，玉壺寒。',40,'全唐诗/poet.song.101000.json','["冰鑑浄，玉壺寒。", "一亙清處擡脚易，十分明白轉身難。", "混身轉却舌頭短，轉却渾身鼻孔寬。"]'),
('b6c4178f-eb53-4ce6-ba6d-9b66ac0e0801','偈頌二百零五首  其一一九','釋正覺','宋','宋诗','song-poetry','','[]','一人之父，百王之師。',68,'全唐诗/poet.song.101000.json','["一人之父，百王之師。", "道機有餘兮，動若四時。", "壽域無疆兮，量同二儀。", "大功不宰，至化無爲。", "妙兮雖喻，智也不知。", "權挂垢衣云是佛，却裝珍御復名誰。"]'),
('2d55829d-12e4-4c89-90e9-5c7e1ac5adae','偈頌二百零五首  其一二○','釋正覺','宋','宋诗','song-poetry','','[]','耳應聲而無響，眼有照而亡緣，曠劫清規裏許圓。',38,'全唐诗/poet.song.101000.json','["耳應聲而無響，眼有照而亡緣，曠劫清規裏許圓。", "生死死生不到處，雲磨秋色水連天。"]'),
('debb4a12-b4e4-435c-ab4d-2e2948bd8b30','偈頌二百零五首  其一二一','釋正覺','宋','宋诗','song-poetry','','[]','寒林濡露，明月濯波。',52,'全唐诗/poet.song.101000.json','["寒林濡露，明月濯波。", "時節恁麽，衲僧如何。", "廓一念不見有自，極十方不見有它。", "遍界通身無背面，莫教絲緒落機梭。"]'),
('828f2715-6119-440c-98a7-4bb3fd64ec87','偈頌二百零五首  其一二二','釋正覺','宋','宋诗','song-poetry','','[]','十月朔，風雨肇寒天意作。',58,'全唐诗/poet.song.101000.json','["十月朔，風雨肇寒天意作。", "叢席地爐今日開，免燒木佛無斟酌。", "丹霞將錯就錯，院主眉鬚墮落。", "如聾如盲大家翁，攪擾殺你不要惡。"]'),
('f7f6c19d-8ab3-413f-abf8-50afa4f4fd81','偈頌二百零五首  其一二三','釋正覺','宋','宋诗','song-poetry','','[]','深深處，細細行。',48,'全唐诗/poet.song.101000.json','["深深處，細細行。", "隱隱時，密密覷。", "若能恁麽徹根徹，源旁參回互宛轉。", "虛玄不觸尊貴機，橫梭度針露線穿。"]'),
('100138b6-3d6b-4033-a0c5-91896d9bdd3c','偈頌二百零五首  其一二四','釋正覺','宋','宋诗','song-poetry','','[]','一日不作，一日不食，歇者無心穫者力。',34,'全唐诗/poet.song.101000.json','["一日不作，一日不食，歇者無心穫者力。", "分明只箇是家風，會得種田博飯喫。"]'),
('917f9b49-7e16-444b-bbe3-abc85feb386f','偈頌二百零五首  其一二五','釋正覺','宋','宋诗','song-poetry','','[]','唯心唯識，平出平入。',36,'全唐诗/poet.song.101000.json','["唯心唯識，平出平入。", "金刀之齊，玉尺之直。", "你喚甚麽作三界，真箇不曾遺顆粒。"]'),
('ae760463-1c1b-4a37-bff1-c4d2fccb970b','偈頌二百零五首  其一二六','釋正覺','宋','宋诗','song-poetry','','[]','王老師，足意氣，是是非非蕩情謂。',32,'全唐诗/poet.song.101000.json','["王老師，足意氣，是是非非蕩情謂。", "倚天照雪爛光芒，掃盡攙搶千萬里。"]'),
('49fb4ce8-120d-4422-b5ac-993f36b2345f','偈頌二百零五首  其一二七','釋正覺','宋','宋诗','song-poetry','','[]','一枝秀出栴檀林，想見馨香慰衆心。',32,'全唐诗/poet.song.101000.json','["一枝秀出栴檀林，想見馨香慰衆心。", "不負老兄開鑿力，當風子和鶴鳴陰。"]'),
('5a0ab9e5-542a-4891-aae2-a3ba9fd0bc68','偈頌二百零五首  其一二八','釋正覺','宋','宋诗','song-poetry','','[]','影略門前倒剎竿，箇中消息授傳難。',32,'全唐诗/poet.song.101000.json','["影略門前倒剎竿，箇中消息授傳難。", "玲瓏侍者能相委，盤走明珠珠走盤。"]'),
('a7a8b40d-c850-48ee-a9cc-da767f956f2c','偈頌二百零五首  其一二九','釋正覺','宋','宋诗','song-poetry','','[]','功勳消，階級盡。',46,'全唐诗/poet.song.101000.json','["功勳消，階級盡。", "尊貴不知名，威嚴莫得近。", "子退步而就父，臣轉身以合君。", "機轉玉輪側，妙葉正當風。"]'),
('5ce50d0c-8f1d-4b4a-8061-c6eac0b23ed6','偈頌二百零五首  其一三○','釋正覺','宋','宋诗','song-poetry','','[]','湛湛不昏，綿綿若存。',46,'全唐诗/poet.song.101000.json','["湛湛不昏，綿綿若存。", "三世佛護持爲之頂相，歷代祖傳受爲之命根。", "蒼頭祖父寒居位，白髮兒孫夜過門。"]'),
('22f7f71f-b572-483a-ba8c-322a2c38dfb6','偈頌二百零五首  其一三一','釋正覺','宋','宋诗','song-poetry','','[]','道契如如，非有非無。',84,'全唐诗/poet.song.101000.json','["道契如如，非有非無。", "靜也神之在谷，應也像之在珠。", "了無所住，照不失虛，無影杖子兩人扶。", "清華臨於至鑑，深密守於元樞，機輪文彩妙窮初。", "霽色廓澄兮秋懷月滿，秀稜重疊兮雲卷山癯。"]'),
('d2758fb3-e681-4c75-8790-05c0eafcc2e7','偈頌二百零五首  其一三二','釋正覺','宋','宋诗','song-poetry','','[]','不即不離，非取非捨。',52,'全唐诗/poet.song.101000.json','["不即不離，非取非捨。", "自東自西，誰上誰下。", "委曲也順俗亡功，驀直也應真不借。", "珠中有火君須信，休向天邊問太陽。"]'),
('b3259e89-459d-4ba8-aee0-e0470cdeffd5','偈頌二百零五首  其一三三','釋正覺','宋','宋诗','song-poetry','','[]','只者一縫大小，飽叢林漢分曉。',40,'全唐诗/poet.song.101000.json','["只者一縫大小，飽叢林漢分曉。", "點頭言語，丁寧擺手。", "舌頭狤獠不狤獠，人人脚下長安道。"]'),
('1dcd7ec4-c336-4f6a-a05e-dd7d5922fd28','偈頌二百零五首  其一三四','釋正覺','宋','宋诗','song-poetry','','[]','不問維摩經，看底甚麽經，大千卷出破塵情。',54,'全唐诗/poet.song.101000.json','["不問維摩經，看底甚麽經，大千卷出破塵情。", "水中鹽味，色裏膠青，機前有路妙難名。", "纔形言像迢然去，又是泥團換眼睛。"]'),
('4b1d7438-bfbd-4731-baf4-cd6e6fb9507f','偈頌二百零五首  其一三五','釋正覺','宋','宋诗','song-poetry','','[]','一陽生，萬物潜萌。',63,'全唐诗/poet.song.101000.json','["一陽生，萬物潜萌。", "隱隱有像，寥寥未形。", "蚌腸含妙藴，犀角暈通星。", "密密用，細細行，本智虛融與理冥。", "露地白牛肥膩飽，擁蓑人駕雪山耕。"]'),
('5cf06373-60bb-4207-a8fa-4e366a39c5d9','偈頌二百零五首  其一三六','釋正覺','宋','宋诗','song-poetry','','[]','今朝臘月二十五，衲僧一曲和雲門。',64,'全唐诗/poet.song.101000.json','["今朝臘月二十五，衲僧一曲和雲門。", "誰將節奏亂孔竅，不到瘢痕傷斧斤。", "舌無骨，眼有筋，方見韶陽老子能。", "拍拍元來渾是令，哩鳴囉了邏鳴稜。"]'),
('0c6df388-51e6-4679-8817-df304885a301','偈頌二百零五首  其一三七','釋正覺','宋','宋诗','song-poetry','','[]','喫茶去，喫茶去，明明指人無異語。',60,'全唐诗/poet.song.101000.json','["喫茶去，喫茶去，明明指人無異語。", "家風平展沒機關，誰道趙州謾院主。", "苦苦苦，往往邯鄲學唐步。", "恰恰長安道上行，分明有眼如天瞽。"]'),
('31e45b84-81ec-46a1-9635-2f774ac19cd3','偈頌二百零五首  其一三八','釋正覺','宋','宋诗','song-poetry','','[]','歲朝坐禪，萬事自然。',36,'全唐诗/poet.song.101000.json','["歲朝坐禪，萬事自然。", "心心絕待，佛佛現前。", "清白十分江上雪，謝郎滿意釣漁船。"]'),
('55bccd37-6b43-4ce2-81c2-7394410f65d3','偈頌二百零五首  其一三九','釋正覺','宋','宋诗','song-poetry','','[]','明月蘆華四望連，轉身人上合同船。',32,'全唐诗/poet.song.101000.json','["明月蘆華四望連，轉身人上合同船。", "借功自有旁參事，歷歷機頭看正偏。"]'),
('0198b5b0-4811-41d9-94e0-bcd2eb3a8450','偈頌二百零五首  其一四○','釋正覺','宋','宋诗','song-poetry','','[]','浄不涉緣，照不對物。',50,'全唐诗/poet.song.101000.json','["浄不涉緣，照不對物。", "用無去來之相，混無彼我之心。", "穩穩密密，玲玲瓏瓏。", "宛轉虛玄事不彰，明暗只在影中圓。"]'),
('47c9c31a-f4bd-4546-a473-5d0e1ed15269','偈頌二百零五首  其一四一','釋正覺','宋','宋诗','song-poetry','','[]','雲無心成何處雨，蜜有味是誰家華。',32,'全唐诗/poet.song.101000.json','["雲無心成何處雨，蜜有味是誰家華。", "一鉢上方分得飯，歸來香氣滿毗耶。"]'),
('a665c797-ab86-43b2-ba89-32f506db5dce','偈頌二百零五首  其一四二','釋正覺','宋','宋诗','song-poetry','','[]','輕煙羃羃衲僧家，節物迎春氣象華。',32,'全唐诗/poet.song.101000.json','["輕煙羃羃衲僧家，節物迎春氣象華。", "流水落華無限意，遊山消息付長沙。"]'),
('25d98e6d-41aa-4faf-9730-54b263549ec3','偈頌二百零五首  其一四三','釋正覺','宋','宋诗','song-poetry','','[]','世夢短，劫壺寬，底人退步裏頭看。',46,'全唐诗/poet.song.101000.json','["世夢短，劫壺寬，底人退步裏頭看。", "豹變文而霧重，龍不卧而潭寒。", "欲使人人雙眼冷，要須先瀝髑髏乾。"]'),
('fa16979b-7f51-42f9-9f72-60cf89267643','偈頌二百零五首  其一四四','釋正覺','宋','宋诗','song-poetry','','[]','桃華浪裏振脩鱗，一躍龍門看化身。',32,'全唐诗/poet.song.101000.json','["桃華浪裏振脩鱗，一躍龍門看化身。", "諦了十方三世事，無始的的自家春。"]'),
('68d4237f-3670-403c-80d9-843a62a56572','偈頌二百零五首  其一四五','釋正覺','宋','宋诗','song-poetry','','[]','吸盡西江向汝道，馬師家風不草草。',32,'全唐诗/poet.song.101000.json','["吸盡西江向汝道，馬師家風不草草。", "截流一棹破煙寒，天水同秋清渺渺。"]'),
('2f5e71c7-7fe2-4b75-9aa4-b3d61ec75e4c','偈頌二百零五首  其一四六','釋正覺','宋','宋诗','song-poetry','','[]','白雲之賓青山伴，位裏借功看互換。',32,'全唐诗/poet.song.101000.json','["白雲之賓青山伴，位裏借功看互換。", "無底合盤轉手擎，穿心碗子通身飯。"]'),
('72454244-2c91-4526-adff-96eb853dbfb1','偈頌二百零五首  其一四七','釋正覺','宋','宋诗','song-poetry','','[]','春雲堆絮，春雨散絲，華開笑口柳申眉。',50,'全唐诗/poet.song.101000.json','["春雲堆絮，春雨散絲，華開笑口柳申眉。", "翻紫燕，嚼黄鸝，聲色叢中有路歧。", "家風鼻孔相摩觸，不獨觀音大士知。"]'),
('5059ef26-dca1-4df7-ae53-084c8b4b6132','偈頌二百零五首  其一四八','釋正覺','宋','宋诗','song-poetry','','[]','差之毫釐，失之千里。',41,'全唐诗/poet.song.101000.json','["差之毫釐，失之千里。", "會也打草驚蛇，不會也燒錢引鬼。", "荒田不揀老俱胝，只今信手拈來底。"]'),
('0cbacfdf-83f7-4511-af74-b04b90502e88','偈頌二百零五首  其一四九','釋正覺','宋','宋诗','song-poetry','','[]','主中賓，賓中主，相合回頭看裏許。',32,'全唐诗/poet.song.101000.json','["主中賓，賓中主，相合回頭看裏許。", "明月團團夜正央，昆侖抱出珊瑚樹。"]'),
('c693cf89-f211-41d1-adb3-098e568e8e00','偈頌二百零五首  其一五○','釋正覺','宋','宋诗','song-poetry','','[]','水不洗水，金不博金。',48,'全唐诗/poet.song.101000.json','["水不洗水，金不博金。", "眼不見眼，心不用心。", "不墮根境識，那涉去來今。", "迷裏忽然逢達磨，何曾特地作叢林。"]'),
('08061490-fd62-4efb-a9e7-9f5eb4efa600','偈頌二百零五首  其一五一','釋正覺','宋','宋诗','song-poetry','','[]','我住汝亦住，我行汝亦行。',178,'全唐诗/poet.song.101000.json','["我住汝亦住，我行汝亦行。", "結制順諸佛，禁足護衆生。", "金鎖無鬚兩頭動，靈犀有暈中間明。", "泥牛入海恰半夜，木雞喚月看五更。", "雲倚山是父子，眼約眉爲兄弟。", "三世同參或一段合宗家之事，大千等量破微塵出自己之經。", "瓊林寸寸寶，旃檀片片馨。", "物物頭頭有平出底多許，心心法法無外來底一星。", "抹抹撻撻憨皮袋，跛跛挈挈常不輕。", "無是無非長默默，非凡非聖獨惺惺。", "蒲團坐倚無他事，永日寥寥謝太平。"]'),
('beb35005-c642-42a8-83e7-e39dc206ea1f','偈頌二百零五首  其一五二','釋正覺','宋','宋诗','song-poetry','','[]','笊籬木杓，錢貫井索。',52,'全唐诗/poet.song.101000.json','["笊籬木杓，錢貫井索。", "受用見成，家風廓落。", "生涯放得信緣看，佛法更於何處著。", "不用安排只麽從，自然心地常安樂。"]'),
('9c0fbc1a-9c82-402e-a739-fc95af6e1e1c','偈頌二百零五首  其一五三','釋正覺','宋','宋诗','song-poetry','','[]','默默相投時節，燈燈不斷光明。',30,'全唐诗/poet.song.101000.json','["默默相投時節，燈燈不斷光明。", "其間著脚渾無地，望盡玉壺連底清。"]'),
('4ecdbbf8-e315-4a62-9b5a-06a63b66a8a1','偈頌二百零五首  其一五四','釋正覺','宋','宋诗','song-poetry','','[]','句裏明宗則易，宗中辨的則難。',74,'全唐诗/poet.song.101000.json','["句裏明宗則易，宗中辨的則難。", "也須是到箇時節，始得色轉不見身。", "功亡不知位。", "絕憐大匠一斲泥，不犯祖師三尺鼻。", "兒孫去後阿誰共守清貧，臣庶退時獨自難稱尊貴。"]'),
('2caf77c4-55f8-4b66-8595-40323d1e231a','偈頌二百零五首  其一五五','釋正覺','宋','宋诗','song-poetry','','[]','尋常撞搕，當面諱却。',22,'全唐诗/poet.song.101000.json','["尋常撞搕，當面諱却。", "可憐傅大師，處處失樓閣。"]'),
('07f1a5da-0125-4cb1-8255-04809faf3ca4','偈頌二百零五首  其一五六','釋正覺','宋','宋诗','song-poetry','','[]','來問此經低聲，大千卷自塵中出，三世佛從口裏生。',59,'全唐诗/poet.song.101000.json','["來問此經低聲，大千卷自塵中出，三世佛從口裏生。", "天得一以清，地得一以寧，空無依兮谷不盈。", "摩訶般若波羅密，落日漁樵歌太平。"]'),
('65f6af92-622d-4e09-ba75-df9c55eca11a','偈頌二百零五首  其一五七','釋正覺','宋','宋诗','song-poetry','','[]','塵塵三昧，彼彼不外。',36,'全唐诗/poet.song.101000.json','["塵塵三昧，彼彼不外。", "千峯向嶽，百川赴海。", "更無一法不如來，只箇堂堂觀自在。"]'),
('e043f417-76fa-4eb0-88db-0e0aef125047','偈頌二百零五首  其一五八','釋正覺','宋','宋诗','song-poetry','','[]','百城遊遍，遍詣文殊。',36,'全唐诗/poet.song.101000.json','["百城遊遍，遍詣文殊。", "不見其身，唯摩其頂。", "老眼就看青嶂骨，敗鞋行到白雲根。"]'),
('8a3b1fd2-9988-4cba-b0a4-c62bc4c951e2','偈頌二百零五首  其一五九','釋正覺','宋','宋诗','song-poetry','','[]','地藏栽田博飯，南泉買鎌割禾。',46,'全唐诗/poet.song.101000.json','["地藏栽田博飯，南泉買鎌割禾。", "六祖負舂明歷歷，金牛棒鉢笑呵呵。", "古人得恁飽參煞，爾輩莫嫌辛苦多。"]'),
('2bafa0c5-6a8b-4907-a5b1-42e85398b962','偈頌二百零五首  其一六○','釋正覺','宋','宋诗','song-poetry','','[]','難難難是遣情難，情盡圓明一顆寒。',40,'全唐诗/poet.song.101000.json','["難難難是遣情難，情盡圓明一顆寒。", "大法眼，不相謾。", "面前不破案山礙，直下無津識浪乾。"]'),
('ed19d422-a088-4489-98db-d3573ec6fb84','偈頌二百零五首  其一六一','釋正覺','宋','宋诗','song-poetry','','[]','木有火傷身，人有火傷神。',66,'全唐诗/poet.song.101000.json','["木有火傷身，人有火傷神。", "木無火不生，人無火不成。", "地水風火，亦復如是。", "四大普周同法界，各各普周無障礙。", "只者普周無礙時，自然無壞無不壞。"]'),
('1ae669d8-a010-43da-ae97-4414aa4eb0bf','偈頌二百零五首  其一六二','釋正覺','宋','宋诗','song-poetry','','[]','只者便是，非像非鏡。',57,'全唐诗/poet.song.101000.json','["只者便是，非像非鏡。", "誰主誰賓，何偏何正。", "縫罅莫我欺無孔之槌，錙銖莫我定無星之秤。", "聊將柱杖攪滄溟，令彼魚龍知水爲命。"]'),
('750698a1-afcd-4350-bb01-f6b82decfbf9','偈頌二百零五首  其一六三','釋正覺','宋','宋诗','song-poetry','','[]','須知風動心摇樹，果見雲生性起塵。',32,'全唐诗/poet.song.101000.json','["須知風動心摇樹，果見雲生性起塵。", "雨霖霖兮日杲杲，點頭彌勒解分身。"]'),
('d5fae948-f1ac-41c8-a033-6bf4c290246a','偈頌二百零五首  其一六四','釋正覺','宋','宋诗','song-poetry','','[]','玉壺著脚四圍寬，妙處其中轉側看。',44,'全唐诗/poet.song.101000.json','["玉壺著脚四圍寬，妙處其中轉側看。", "顧鑑功忘鼻孔直，津流識盡髑髏乾。", "夜橫河漢白，霜洗斗牛寒。"]'),
('932d7d65-3b1e-42c8-9ae1-49f0d20423fe','偈頌二百零五首  其一六五','釋正覺','宋','宋诗','song-poetry','','[]','休去歇去，絕言絕慮。',274,'全唐诗/poet.song.101000.json','["休去歇去，絕言絕慮。", "廓無所依，妙無所住。", "轉歷歷之機，運綿綿之步。", "神遊方外靈臺，道契環中虛處。", "藏身白雲雲外家，著脚青山山下路。", "宛轉窮通，旁參回互。", "十成收得返魂香，一等來撾荼毒鼓。", "肯觸氣於死蛇，要捋鬚於猛虎。", "却借其功，不謀而遇。", "枯木龍吟而起雲，南山豹變□披霧。", "律入春筒，影流曉戶。", "百億儀分，三千體露。", "大經掇出於微塵，古佛相交於露柱。", "歷代諸祖只箇生涯，一切衆生同時滅度。", "大用石火遲，全機電光遽。", "哆哆和和也問若剪答如裁，轟轟磕磕也喝如雷棒如雨。", "洞山佛對三斤麻，趙州衫重七斤布。", "道火不我燒唇，道水不我濡袴。", "無是無非，何規何矩。", "柱杖子裏許將來，鉢袋子那時分付。"]'),
('d9df220f-cc84-4d8e-85f5-79feba545974','偈頌二百零五首  其一六六','釋正覺','宋','宋诗','song-poetry','','[]','無對無待，有兼有带。',76,'全唐诗/poet.song.101000.json','["無對無待，有兼有带。", "歷歷物機，空空眼界。", "綿綿相柱兮箭鋒，恰恰相應兮函蓋。", "巨海飲毛，妙峯納芥。", "彼不見其有餘，我方知其無外。", "普明照世約同參，補怛落伽觀自在。"]'),
('6eb56c99-a895-47b1-9d61-e5851b96a00e','偈頌二百零五首  其一六七','釋正覺','宋','宋诗','song-poetry','','[]','靜沉沉，明蕩蕩，雪滿十方，雲迷四向。',102,'全唐诗/poet.song.101000.json','["靜沉沉，明蕩蕩，雪滿十方，雲迷四向。", "一色影裏是誰坐著功勳，百尺竿頭阿你變通伎倆。", "恁麽時須辨幾微，恁麽處須明的當。", "趁不去露地白牛，透得過流河香象。", "徹見其源，如指諸掌。", "恁麽盡去也無法可傳，恁麽却來也有人相亮。"]'),
('12c97edd-74d8-42c9-a418-e43b73a96f0e','偈頌二百零五首  其一六八','釋正覺','宋','宋诗','song-poetry','','[]','三世諸佛不知有，忉忉怛怛揚家醜。',80,'全唐诗/poet.song.101000.json','["三世諸佛不知有，忉忉怛怛揚家醜。", "狸奴白牯却知有，跛跛挈挈能自守。", "弄鱉鼻兮憶南山，透法身兮藏北斗。", "風飄白雪嶺頭梅，春撚金絲堤上柳。", "天童也要不沾唇，三盞清源白家酒。"]'),
('56b847b4-64d2-433f-af4c-8b6b33dbbff3','偈頌二百零五首  其一六九','釋正覺','宋','宋诗','song-poetry','','[]','你也恁麽住，我也恁麽住，作業相似貧相聚。',68,'全唐诗/poet.song.101000.json','["你也恁麽住，我也恁麽住，作業相似貧相聚。", "十方無壁，四面無門。", "遮醜無衣，禦寒無絮。", "直下不居功，箇中看轉處。", "采華蜂集萌不枝，卧月鳥棲無影樹。"]'),
('f355ef13-2cea-41ce-8581-ba231f80d31f','偈頌二百零五首  其一七○','釋正覺','宋','宋诗','song-poetry','','[]','三寸舌，兩片唇，無始時來賺殺人。',32,'全唐诗/poet.song.101000.json','["三寸舌，兩片唇，無始時來賺殺人。", "解弄不教圭角露，阿誰參見跛雲門。"]'),
('4c62d84f-f90b-4add-be5b-e130483d0efd','偈頌二百零五首  其一七一','釋正覺','宋','宋诗','song-poetry','','[]','老大叢林快說禪，不將禪拄口皮邊。',32,'全唐诗/poet.song.101000.json','["老大叢林快說禪，不將禪拄口皮邊。", "谷深山遠空無像，何處人呼應不圓。"]'),
('2c094ffe-1d2b-4370-aac1-7b76afeddcaa','偈頌二百零五首  其一七二','釋正覺','宋','宋诗','song-poetry','','[]','一頭白髮幾回春，方信閑身似癡人。',84,'全唐诗/poet.song.101000.json','["一頭白髮幾回春，方信閑身似癡人。", "直下放教平穩去，更將何法作根塵。", "法無根塵，心無向背。", "心無向背，道合自然。", "道合自然也，日日好日，年年好年。", "東君刀尺裁華木，付與過頭杖子禪。"]'),
('415a8ab5-4134-4c70-bb36-1a3b19e786fe','偈頌二百零五首  其一七三','釋正覺','宋','宋诗','song-poetry','','[]','三界無法，何處求心。',46,'全唐诗/poet.song.101000.json','["三界無法，何處求心。", "風生虎嘯，霧起龍吟。", "泥中有刺，綿裏有針。", "華鳥隔牆相喚甚，十分春事到家林。"]'),
('56818261-4ff5-403d-9f44-ed1afe44348a','偈頌二百零五首  其一七四','釋正覺','宋','宋诗','song-poetry','','[]','不墮前後，獨超古今。',54,'全唐诗/poet.song.101000.json','["不墮前後，獨超古今。", "喚回千歲夢，飛出九皋禽。", "無棲泊，勿猜斟，只箇虛空等樣心。", "直下一槌光迸散，斬新彈子出爐金。"]'),
('e6c54042-14fd-4414-b3d9-bdc332af5782','偈頌二百零五首  其一七五','釋正覺','宋','宋诗','song-poetry','','[]','山谷之響，水監之像。',84,'全唐诗/poet.song.101000.json','["山谷之響，水監之像。", "白雲之心，太虛之量。", "應機也乍卷乍舒，據令也全收全放。", "三千世界你夤緣，百億分身君伎倆。", "風行空，船駕浪，施受通同無住相。", "一言相送知不知，千僧在你鉢盂上。"]'),
('ea6b7248-01e1-4001-8791-9833d83d3ea2','偈頌二百零五首  其一七六','釋正覺','宋','宋诗','song-poetry','','[]','家法簡嚴，非二非三。',48,'全唐诗/poet.song.101000.json','["家法簡嚴，非二非三。", "月來明湛水，雲退露寒巖。", "真機自得妙處，誰參不是文殊。", "白槌後也應，千古屈瞿曇。"]'),
('60d42768-a744-43ec-96eb-2562eb6db450','偈頌二百零五首  其一七七','釋正覺','宋','宋诗','song-poetry','','[]','清浄性空水，光明法界身。',114,'全唐诗/poet.song.101000.json','["清浄性空水，光明法界身。", "依俙辨白處，便是誕生人。", "不洗體，不洗塵，妙觸宣明悟水因。", "借問當年向去事，如何今日却來親。", "二千年前此時候，指天指地師子吼。", "雲門居亂思太平，打殺不妨將餧狗。", "指東話西，將無作有。", "惡水潑君君莫嗔，而今看你如何受。"]'),
('3a2209b0-c4f4-4991-8561-e780393acdd1','偈頌二百零五首  其一七八','釋正覺','宋','宋诗','song-poetry','','[]','喫粥了，洗鉢去，法爾圓成正規矩。',66,'全唐诗/poet.song.101000.json','["喫粥了，洗鉢去，法爾圓成正規矩。", "可憐葉氏怕真龍，却怪謝郎欺猛虎。", "本常路，真實語，這僧且問如何悟。", "從來鼻孔大頭垂，不用安排兮自著處所。"]'),
('86777272-23bb-4f09-8731-d08c74467349','偈頌二百零五首  其一七九','釋正覺','宋','宋诗','song-poetry','','[]','泥泥水水一年農，收拾將來碓下舂。',32,'全唐诗/poet.song.101000.json','["泥泥水水一年農，收拾將來碓下舂。", "炊軟香分千鉢飯，肚皮參飽放頹慵。"]'),
('c7603d4e-93de-4a25-9ef7-22da6123696e','偈頌二百零五首  其一八○','釋正覺','宋','宋诗','song-poetry','','[]','一色是須轉，大功不我居，珠走碧盤盤走珠。',52,'全唐诗/poet.song.101000.json','["一色是須轉，大功不我居，珠走碧盤盤走珠。", "直下滄溟取明月，吾家自有崑崙奴。", "天宇豁空雲卷雨，溪容澄澈水懷秋。"]'),
('885678ab-ba6f-413f-a285-5b114b817f37','偈頌二百零五首  其一八一','釋正覺','宋','宋诗','song-poetry','','[]','乞食浙西蘇與秀，人人奉佛家家富。',32,'全唐诗/poet.song.101000.json','["乞食浙西蘇與秀，人人奉佛家家富。", "收拾幾成三萬緡，尚自不能供衆口。"]'),
('5e426f01-4041-44e2-ac75-e6d7f642cf8e','偈頌二百零五首  其一八二','釋正覺','宋','宋诗','song-poetry','','[]','却請和尚道，三世諸佛也靠倒。',52,'全唐诗/poet.song.101000.json','["却請和尚道，三世諸佛也靠倒。", "釋迦師，浄名老，毗耶摩竭心相照。", "倦鶴夜移巢，靈蛇寒入草，正偏轉側兮妙圓兼到。"]'),
('9e8a4ed3-5585-4a20-afcf-fc110dd2c772','偈頌二百零五首  其一八三','釋正覺','宋','宋诗','song-poetry','','[]','作麽生行，履得十成，去功業力爭英雄。',36,'全唐诗/poet.song.101000.json','["作麽生行，履得十成，去功業力爭英雄。", "劉項時，將太平。", "坐亨朴懋，羲軒世人。"]'),
('b20da775-7ea6-440e-9d80-4dd1ef34e9a6','偈頌二百零五首  其一八四','釋正覺','宋','宋诗','song-poetry','','[]','莫向枯龜版上鉆，衲僧開口見心肝。',32,'全唐诗/poet.song.101000.json','["莫向枯龜版上鉆，衲僧開口見心肝。", "蓮華荷葉出未出，做盡工夫轉覺難。"]'),
('b90c151c-c73f-418d-8ca9-a07d9f1c72e3','偈頌二百零五首  其一八五','釋正覺','宋','宋诗','song-poetry','','[]','不得諱，有頭底。',94,'全唐诗/poet.song.101000.json','["不得諱，有頭底。", "當時你带累別人，而今別人带累你。", "來生我家，作業相似，針線穿聯細中細。", "迦葉阿難不相知，人人各自住三昧。", "裏許轉功勳，這邊得遊戲，到底還須徹根蒂。", "望斷冥鴻沒處秋，蒼蒼一色天連水。"]'),
('45c06825-0f7a-44a1-9527-565d5e6aef1c','偈頌二百零五首  其一八六','釋正覺','宋','宋诗','song-poetry','','[]','地藏栽田做活計，南泉鎌子能收刈。',98,'全唐诗/poet.song.101000.json','["地藏栽田做活計，南泉鎌子能收刈。", "日用平懷穩便休，自然顆糝無遺棄。", "無遺棄，不容易。", "你也莫虧我，我也不虧你。", "兩家賓主平，四稜齊塌地。", "風不鳴條，雨不破塊，箇是叢林飽參底。", "牧來純熟水牯牛，檢點將來墮隨類。"]'),
('1cf9be25-2a71-4276-babd-2ef6e68cd8eb','偈頌二百零五首  其一八七','釋正覺','宋','宋诗','song-poetry','','[]','仲秋漸凉，蒲團放穩長連床。',81,'全唐诗/poet.song.101000.json','["仲秋漸凉，蒲團放穩長連床。", "身心澄徹見淵底，河漢淡淡秋磨光。", "二祖不短，少林不長，相傳笑殺威音王。", "你無所得，我無所藏，四無壁落渾大方。", "萬世清規信明白，夜寒吐月山蒼蒼。"]'),
('23ea9eb9-95c2-4fd9-926b-0fbcde964fb4','偈頌二百零五首  其一八八','釋正覺','宋','宋诗','song-poetry','','[]','經歸藏，禪歸海。',42,'全唐诗/poet.song.101000.json','["經歸藏，禪歸海。", "稽首歸依，合掌頂戴。", "王老師，超物外。", "二十年前恁麽來，而今去盡閒光彩。"]'),
('33bbe9ca-e5d3-45de-b6ac-0831ea708b40','偈頌二百零五首  其一八九','釋正覺','宋','宋诗','song-poetry','','[]','九月又重陽，菊華依舊黄。',28,'全唐诗/poet.song.101000.json','["九月又重陽，菊華依舊黄。", "淵明是醉不是酒，蕩蕩遊心於大方。"]'),
('c0f9129f-53ca-4e12-92aa-5d306b5f11f5','偈頌二百零五首  其一九○','釋正覺','宋','宋诗','song-poetry','','[]','無人接得渠，貴逼馬相如。',48,'全唐诗/poet.song.101000.json','["無人接得渠，貴逼馬相如。", "果來橋上也，記得柱頭書。", "無人識得渠，棋局醉樵夫。", "回頭斧柯爛，大海一成枯。"]'),
('ad1c55a7-cfda-4dfa-bfac-d71359c60a54','偈頌二百零五首  其一九一','釋正覺','宋','宋诗','song-poetry','','[]','玉女依稀夜動機，錦絲歷歷吐梭臍。',32,'全唐诗/poet.song.101000.json','["玉女依稀夜動機，錦絲歷歷吐梭臍。", "水天湛碧全功墮，雪月寒清一色迷。"]'),
('a4c41f13-ef84-4205-9a44-96806624448d','偈頌二百零五首  其一九二','釋正覺','宋','宋诗','song-poetry','','[]','釋迦自是釋迦，然燈莫要添些。',44,'全唐诗/poet.song.101000.json','["釋迦自是釋迦，然燈莫要添些。", "不用燒錢引鬼，何須勾賊破家。", "你那裏針劄不入，我這裏石上栽華。"]'),
('56c677d9-03ae-4680-8f8d-c01620dc9ee3','偈頌二百零五首  其一九三','釋正覺','宋','宋诗','song-poetry','','[]','諸見若盡，慎勿追尋。',20,'全唐诗/poet.song.101000.json','["諸見若盡，慎勿追尋。", "纔有是非，紛然失心。"]'),
('b5ed3ded-d0f8-4510-8a7d-c6009cdb426c','偈頌二百零五首  其一九四','釋正覺','宋','宋诗','song-poetry','','[]','不落階級，卓卓超出三際。',40,'全唐诗/poet.song.101000.json','["不落階級，卓卓超出三際。", "曷用安排，十方自然畐塞。", "五色線不我羈縻，七寶冠是誰嚴飾。"]'),
('cedbd735-e6da-47c3-9e96-df165cf48ebe','偈頌二百零五首  其一九五','釋正覺','宋','宋诗','song-poetry','','[]','香林臘月火燒山，關楗如今透底難。',32,'全唐诗/poet.song.101000.json','["香林臘月火燒山，關楗如今透底難。", "無礙機鋒能自在，虛空揮劍不成瘢。"]'),
('10a55694-f705-4b77-aca0-959c267d1feb','偈頌二百零五首  其一九六','釋正覺','宋','宋诗','song-poetry','','[]','若恁麽，也難得，清光浩蕩無瑕隙。',76,'全唐诗/poet.song.101000.json','["若恁麽，也難得，清光浩蕩無瑕隙。", "人言千里本同風，我道十方渾一色。", "渾一色，須轉側。", "纔轉側，透關隔。", "透關隔，酬爾平生今脫白。", "儂家龜鶴自成仙，昨夜龍門無宿客。"]');
